    void *(*hash_lookup)(struct hash_table *table, void *key, int release, int holding);

    // insert a hash node
    int (*hash_insert)(struct hash_table *table, void *node, int holding);

    // delete a hash node
    void (*hash_delete)(struct hash_table *table, void *node, int holding, int release);

    // hash up a key
    uint64 (*hash_key)(void *key);
}

static inline struct hash_entry *hash_get_entry(struct hash_table *table, void *key, int holding) {
    uint64 hash = table->op->hash_key(key);
    struct hash_entry *entry = &table->hash_head[hash % table->size];
    if (!holding) {
        acquire(&table->lock);
    }
    return entry;
}

static inline void hash_table_entry_init(struct hash_table *table) {
    table->hash_head = (struct hash_entry *) kmalloc(sizeof(struct hash_entry) * table->size);
    for (uint64 i = 0; i < table->size; i++) {
        INIT_LIST_HEAD(&table->hash_head[i].list);
    }
}

static inline uint64 partial_name_hash(unsigned long c, unsigned long prevhash) {
    return (prevhash + (c << 4) + (c >> 4)) * 11;
}

static inline uint64 full_name_hash(const unsigned char *name, unsigned int len) {
    unsigned long hash = init_name_hash();
    while (len--)
        hash = partial_name_hash(*name++, hash);
    return end_name_hash(hash);
}

struct list_head {
    struct list_head *next, *prev;
}

static inline void INIT_LIST_HEAD(struct list_head *list) {
    list->next = list;
    list->prev = list;
}

static inline void __list_add(struct list_head *pnew, struct list_head *prev, struct list_head *next) {
    next->prev = pnew;
    pnew->next = next;
    pnew->prev = prev;
    prev->next = pnew;
}

static inline void __list_del(struct list_head *prev, struct list_head *next) {
    next->prev = prev;
    prev->next = next;
}

static inline void list_del(struct list_head *entry) {
    __list_del_entry(entry);
    entry->next = (list_head_t *) NULL;
    entry->prev = (list_head_t *) NULL;
}

static inline void list_del_reinit(struct list_head *entry) {
    list_del(entry);
    INIT_LIST_HEAD(entry);
}

static inline void list_move(struct list_head *list, struct list_head *head) {
    __list_del_entry(list);
    list_add(list, head);
}

static inline void list_move_tail(struct list_head *list, struct list_head *head) {
    __list_del_entry(list);
    list_add_tail(list, head);
}

static inline int list_empty_atomic(const struct list_head *head, struct spinlock *lock) {
    acquire(lock);
    int ret = (head->next == head);
    release(lock);
    return ret;
}

static inline void __list_splice(struct list_head *list, struct list_head *head) {
    struct list_head *first = list->next;
    struct list_head *last = list->prev;
    struct list_head *at = head->next;

    first->prev = head;
    head->next = first;

    last->next = at;
    at->prev = last;
}

static inline void list_splice(struct list_head *list, struct list_head *head) {
    if (!list_empty(list))
        __list_splice(list, head);
}

static inline void list_join_given_first(struct list_head *first_new, struct list_head *first_old) {
    if (first_new != NULL && first_old != NULL) {
        struct list_head *last = first_new->prev;
        struct list_head *first = first_new;

        first_old->prev->next = first;
        first->prev = first_old->prev;

        last->next = first_old;
        first_old->prev = last;
    }
}

