    uint64 tms_utime; // user mode time(ticks)
    uint64 tms_stime; // system mode time(ticks)
}

fn panic(_info: &core::panic::PanicInfo) -> ! {
    loop {}
}

impl SDIo for SdIoImpl {
    fn read_data_at(&self, offset: usize) -> u64 {
        let addr = (SDIO_BASE + offset) as *mut u64;
        unsafe { addr.read_volatile() }
    }
    fn read_reg_at(&self, offset: usize) -> u32 {
        let addr = (SDIO_BASE + offset) as *mut u32;
        unsafe { addr.read_volatile() }
    }
    fn write_data_at(&mut self, offset: usize, val: u64) {
        let addr = (SDIO_BASE + offset) as *mut u64;
        unsafe { addr.write_volatile(val) }
    }
    fn write_reg_at(&mut self, offset: usize, val: u32) {
        let addr = (SDIO_BASE + offset) as *mut u32;
        unsafe { addr.write_volatile(val) }
    }
}

fn read_time() -> usize {
    riscv::register::time::read()
}

fn sleep_ms(ms: usize) {
    let start = read_time();
    while read_time() - start < ms * VF2_FREQ / 1000 {
        core::hint::spin_loop();
    }
}

fn sleep_ms_until(ms: usize, mut f: impl FnMut() -> bool) {
    let start = read_time();
    while read_time() - start < ms * VF2_FREQ / 1000 {
        if f() {
            return;
        }
        core::hint::spin_loop();
    }
}

impl SleepOps for SleepOpsImpl {
    fn sleep_ms(ms: usize) {
        sleep_ms(ms)
    }
    fn sleep_ms_until(ms: usize, f: impl FnMut() -> bool) {
        sleep_ms_until(ms, f)
    }
}

fn init_vf2_sd_driver() {
    unsafe {
        // 使用 compare_and_swap 确保只初始化一次
        if INIT.compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst).is_ok() {
            let driver = Vf2SdDriver::new(SdIoImpl);
            *VF2_SD_DRIVER.get() = Some(driver);
        }
    }
}

fn get_driver_mut() -> &'static mut Vf2SdDriver<SdIoImpl, SleepOpsImpl> {
    init_vf2_sd_driver();
    unsafe {
        // `unwrap` 这里是安全的，因为我们确保它已经被初始化
        (*VF2_SD_DRIVER.get()).as_mut().unwrap()
    }
}

pub extern "C" fn sd_init() -> usize {
    init_vf2_sd_driver();
    get_driver_mut().init();
    0
}

pub extern "C" fn sd_read_block(addr: usize, buf: &mut [u8; 512]) -> usize {
    get_driver_mut().read_block(addr, buf)
}

pub extern "C" fn sd_write_block(addr: usize, buf: &[u8; 512]) -> usize {
    get_driver_mut().write_block(addr, buf)
}

