        match self {
            Vf2SdDriverError::InitError => write!(f, "init error"),
            Vf2SdDriverError::ReadError => write!(f, "read error"),
            Vf2SdDriverError::WriteError => write!(f, "write error"),
            Vf2SdDriverError::TimeoutError => write!(f, "timeout error"),
