impl GetBit for u32 {
    type Output = u32;
    fn get_bit(&self, bit: u8) -> bool {
        (*self & (1 << bit)) != 0
    }
    fn get_bits(&self, start: u8, end: u8) -> Self::Output {
        let mask = (1 << (end - start + 1)) - 1;
        (*self >> start) & mask
    }
}

impl GetBit for u128 {
    type Output = u128;
    fn get_bit(&self, bit: u8) -> bool {
        (*self & (1 << bit)) != 0
    }
    fn get_bits(&self, start: u8, end: u8) -> Self::Output {
        let mask = (1 << (end - start + 1)) - 1;
        (*self >> start) & mask
    }
}

