struct disk {
    // the virtio driver and device mostly communicate through a set of
    // structures in RAM. pages[] allocates that memory. pages[] is a
    // global (instead of calls to kalloc()) because it must consist of
    // two contiguous pages of page-aligned physical memory.
    char pages[2 * PGSIZE];
    // a set (not a ring) of DMA descriptors, with which the
    // driver tells the device where to read and write individual
    // disk operations. there are NUM descriptors.
    // most commands consist of a "chain" (a linked list) of a couple of
    // these descriptors.
    struct virtq_desc *desc;

    // a ring in which the driver writes descriptor numbers
    // that the driver would like the device to process.  it only
    // includes the head descriptor of each chain. the ring has
    // NUM elements.
    struct virtq_avail *avail;

    // a ring in which the device writes descriptor numbers that
    // the device has finished processing (just the head of each chain).
    // there are NUM used ring entries.
    struct virtq_used *used;

    // our own book-keeping.
    char free[NUM]; // is a descriptor free?
    uint16 used_idx; // we've looked this far in used[2..NUM].

    // track info about in-flight operations,
    // for use when completion interrupt arrives.
    // indexed by first descriptor index of chain.
    struct {
        struct buffer_head *b;
        struct bio_vec *bvec;
        char status;
    } info[NUM];

    // disk command headers.
    // one-for-one with descriptors, for convenience.
    struct virtio_blk_req ops[NUM];

    struct spinlock vdisk_lock;

    struct semaphore sem_disk;

} __attribute__((aligned(PGSIZE)))

void print_blk_config() {
    printf("virtio_blk_config: capacity %d blk_size %d\n", blk_cfg.capacity, blk_cfg.blk_size);
    printf("virtio_blk_config: size %d seg_max %d\n", blk_cfg.size_max, blk_cfg.seg_max);
    printf("virtio_blk_config: geometry: heads %d cylinders %d sectors %d\n", blk_cfg.geometry.heads,
           blk_cfg.geometry.cylinders, blk_cfg.geometry.sectors);
}

void virtio_disk_init(void) {
    uint32 status = 0;

    init_lock(&disk.vdisk_lock, "virtio_disk");

    sem_init(&disk.sem_disk, 0, "sem_disk");

    if (*R(VIRTIO_MMIO_MAGIC_VALUE) != 0x74726976 || *R(VIRTIO_MMIO_VERSION) != 1 || *R(VIRTIO_MMIO_DEVICE_ID) != 2 ||
        *R(VIRTIO_MMIO_VENDOR_ID) != 0x554d4551) {
        panic("could not find virtio disk");
    }

    blk_cfg = *(struct virtio_blk_config *) R(VIRTIO_MMIO_BLK_CONFIG);

    // // reset device
    // *R(VIRTIO_MMIO_STATUS) = status;

    // // set ACKNOWLEDGE status bit
    status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
    *R(VIRTIO_MMIO_STATUS) = status;

    // set DRIVER status bit
    status |= VIRTIO_CONFIG_S_DRIVER;
    *R(VIRTIO_MMIO_STATUS) = status;

    // negotiate features
    uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
    features &= ~(1 << VIRTIO_BLK_F_RO);
    features &= ~(1 << VIRTIO_BLK_F_SCSI);
    features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
    features &= ~(1 << VIRTIO_BLK_F_MQ);
    features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
    features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
    features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
    *R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

    // tell device that feature negotiation is complete.
    status |= VIRTIO_CONFIG_S_FEATURES_OK;
    *R(VIRTIO_MMIO_STATUS) = status;

    // tell device we're completely ready.
    status |= VIRTIO_CONFIG_S_DRIVER_OK;
    *R(VIRTIO_MMIO_STATUS) = status;

    *R(VIRTIO_MMIO_GUEST_PAGE_SIZE) = PGSIZE;
    // initialize queue 0.
    *R(VIRTIO_MMIO_QUEUE_SEL) = 0;

    const uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
    if (max == 0)
        panic("virtio disk has no queue 0");
    if (max < NUM)
        panic("virtio disk max queue too short");

    *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;

    memset(disk.pages, 0, sizeof(disk.pages));
    *R(VIRTIO_MMIO_QUEUE_PFN) = ((uint64) disk.pages) >> PGSHIFT;

    disk.desc = (struct virtq_desc *) disk.pages;
    disk.avail = (struct virtq_avail *) (disk.pages + NUM * sizeof(struct virtq_desc));
    disk.used = (struct virtq_used *) (disk.pages + PGSIZE);


    // all NUM descriptors start out unused.
    for (int i = 0; i < NUM; i++)
        disk.free[i] = 1;


    // plic.c and trap.c arrange for interrupts from VIRTIO0_IRQ.
    printf("virtio_disk_init: success\n");

    print_blk_config();
}

static int alloc_desc() {
    for (int i = 0; i < NUM; i++) {
        if (disk.free[i]) {
            disk.free[i] = 0;
            return i;
        }
    }
    return -1;
}

static void free_desc(const int i) {
    if (i >= NUM)
        panic("free_desc 1");
    if (disk.free[i])
        panic("free_desc 2");
    disk.desc[i].addr = 0;
    disk.desc[i].len = 0;
    disk.desc[i].flags = 0;
    disk.desc[i].next = 0;
    disk.free[i] = 1;
    // wakeup(&disk.free[0]);
    sem_v(&disk.sem_disk);
}

static void free_chain(int i) {
    while (1) {
        const int flag = disk.desc[i].flags;
        const int nxt = disk.desc[i].next;
        free_desc(i);
        if (flag & VRING_DESC_F_NEXT)
            i = nxt;
        else
            break;
    }
}

static int alloc3_desc(int *idx) {
    for (int i = 0; i < 3; i++) {
        idx[i] = alloc_desc();
        if (idx[i] < 0) {
            for (int j = 0; j < i; j++)
                free_desc(idx[j]);
            return -1;
        }
    }
    return 0;
}

void virtio_disk_rw(void *b, const int write, const int type) {
    switch (type) {
        case BIO_STRUCT_BUFFER_HEAD:
            virtio_disk_rw_buffer_head(b, write);
            break;
        case BIO_STRUCT_BIO_VEC:
            virtio_disk_rw_bio_vec(b, write);
            break;
        default:
            panic("virtio_disk_rw: type");
    }
}

static void virtio_disk_rw_buffer_head(struct buffer_head *b, const int write) {
    const uint64 sector = b->blockno * (BSIZE / 512);

    acquire(&disk.vdisk_lock);
    int idx[3];
    while (1) {
        if (alloc3_desc(idx) == 0) {
            break;
        }
        release(&disk.vdisk_lock);
        sem_p(&disk.sem_disk);
        acquire(&disk.vdisk_lock);
    }

    // format the three descriptors.
    // qemu's virtio-blk.c reads them.

    struct virtio_blk_req *buf0 = &disk.ops[idx[0]];

    if (write)
        buf0->type = VIRTIO_BLK_T_OUT; // write the disk
    else
        buf0->type = VIRTIO_BLK_T_IN; // read the disk
    buf0->reserved = 0;
    buf0->sector = sector;

    disk.desc[idx[0]].addr = (uint64) buf0;
    disk.desc[idx[0]].len = sizeof(struct virtio_blk_req);
    disk.desc[idx[0]].flags = VRING_DESC_F_NEXT;
    disk.desc[idx[0]].next = idx[1];

    disk.desc[idx[1]].addr = (uint64) b->data;
    disk.desc[idx[1]].len = BSIZE;
    if (write)
        disk.desc[idx[1]].flags = 0; // device reads b->data
    else
        disk.desc[idx[1]].flags = VRING_DESC_F_WRITE; // device writes b->data
    disk.desc[idx[1]].flags |= VRING_DESC_F_NEXT;
    disk.desc[idx[1]].next = idx[2];

    disk.info[idx[0]].status = 0xff; // device writes 0 on success
    disk.desc[idx[2]].addr = (uint64) &disk.info[idx[0]].status;
    disk.desc[idx[2]].len = 1;
    disk.desc[idx[2]].flags = VRING_DESC_F_WRITE; // device writes the status
    disk.desc[idx[2]].next = 0;

    // record struct buffer_head for virtio_disk_intr().
    b->disk = 1;
    disk.info[idx[0]].b = b;

    // tell the device the first index in our chain of descriptors.
    disk.avail->ring[disk.avail->idx % NUM] = idx[0];

    __sync_synchronize();

    // tell the device another avail ring entry is available.
    disk.avail->idx += 1; // not % NUM ...

    __sync_synchronize();

    *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0; // value is queue number

    // Wait for virtio_disk_intr() to say request has finished.
    while (b->disk == 1) {
        release(&disk.vdisk_lock);
        sem_p(&b->sem_disk_done);
        acquire(&disk.vdisk_lock);
    }

    disk.info[idx[0]].b = 0;
    free_chain(idx[0]);

    release(&disk.vdisk_lock);
}

static void virtio_disk_rw_bio_vec(struct bio_vec *b, const int write) {
    struct bio_vec *b_vec = NULL;
    b_vec = b;
    const uint64 sector = b_vec->blockno_start * (BSIZE / 512);

    acquire(&disk.vdisk_lock);
    // the spec's Section 5.2 says that legacy block operations use
    // three descriptors: one for type/reserved/sector, one for the
    // data, one for a 1-byte status result.

    // allocate the three descriptors.
    int idx[3];
    while (1) {
        if (alloc3_desc(idx) == 0) {
            break;
        }
        release(&disk.vdisk_lock);
        sem_p(&disk.sem_disk);
        acquire(&disk.vdisk_lock);
    }

    // format the three descriptors.
    // qemu's virtio-blk.c reads them.

    struct virtio_blk_req *buf0 = &disk.ops[idx[0]];

    if (write)
        buf0->type = VIRTIO_BLK_T_OUT; // write the disk
    else
        buf0->type = VIRTIO_BLK_T_IN; // read the disk
    buf0->reserved = 0;
    buf0->sector = sector;

    disk.desc[idx[0]].addr = (uint64) buf0;
    disk.desc[idx[0]].len = sizeof(struct virtio_blk_req);
    disk.desc[idx[0]].flags = VRING_DESC_F_NEXT;
    disk.desc[idx[0]].next = idx[1];


    disk.desc[idx[1]].addr = (uint64) b_vec->data;
    disk.desc[idx[1]].len = BSIZE * b_vec->block_len;


    if (write)
        disk.desc[idx[1]].flags = 0; // device reads b->data
    else
        disk.desc[idx[1]].flags = VRING_DESC_F_WRITE; // device writes b->data
    disk.desc[idx[1]].flags |= VRING_DESC_F_NEXT;
    disk.desc[idx[1]].next = idx[2];

    disk.info[idx[0]].status = 0xff; // device writes 0 on success
    disk.desc[idx[2]].addr = (uint64) &disk.info[idx[0]].status;
    disk.desc[idx[2]].len = 1;
    disk.desc[idx[2]].flags = VRING_DESC_F_WRITE; // device writes the status
    disk.desc[idx[2]].next = 0;

    // record struct buffer_head for virtio_disk_intr().
    b_vec->disk = 1;
    disk.info[idx[0]].bvec = b_vec;


    // tell the device the first index in our chain of descriptors.
    disk.avail->ring[disk.avail->idx % NUM] = idx[0];

    __sync_synchronize();

    // tell the device another avail ring entry is available.
    disk.avail->idx += 1; // not % NUM ...

    __sync_synchronize();

    *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0; // value is queue number

    // Wait for virtio_disk_intr() to say request has finished.
    while (b_vec->disk == 1) {
        release(&disk.vdisk_lock);
        sem_p(&b_vec->sem_disk_done);
        acquire(&disk.vdisk_lock);
    }

    disk.info[idx[0]].bvec = 0;
    free_chain(idx[0]);

    release(&disk.vdisk_lock);
}

void virtio_disk_intr() {
    acquire(&disk.vdisk_lock);
    *R(VIRTIO_MMIO_INTERRUPT_ACK) = *R(VIRTIO_MMIO_INTERRUPT_STATUS) & 0x3;
    __sync_synchronize();
    while (disk.used_idx != disk.used->idx) {
        __sync_synchronize();
        const int id = disk.used->ring[disk.used_idx % NUM].id;

        if (disk.info[id].status != 0)
            panic("virtio_disk_intr status");

        // FIXME: should be able to handle both buffer_head and bio_vec
        struct buffer_head *b = disk.info[id].b;
        struct bio_vec *b_vec = disk.info[id].bvec;
        if (b != NULL && b->b_type == BIO_STRUCT_BUFFER_HEAD) {
            b->disk = 0;
            sem_v(&b->sem_disk_done);
        } else if (b_vec != NULL && b_vec->b_type == BIO_STRUCT_BIO_VEC) {
            b_vec->disk = 0;
            sem_v(&b_vec->sem_disk_done);
        } else {
            panic("virtio_disk_intr b_type");
        }
        disk.used_idx += 1;
    }

    release(&disk.vdisk_lock);
}

struct {
    struct spinlock lock;
    struct buffer_head buf[NBUF];

    list_head_t head;
}

void b_init(void) {
    init_lock(&bcache.lock, "bcache");

    INIT_LIST_HEAD(&bcache.head);
    for (struct buffer_head *b = bcache.buf; b < bcache.buf + NBUF; b++) {
        b->b_type = BIO_STRUCT_BUFFER_HEAD;
        b->dev = ~0;
        atomic_set(&b->refcnt, 0);
        sem_init(&b->sem_lock, 1, "buffer");
        sem_init(&b->sem_disk_done, 0, "buffer_disk_done");
        list_add(&b->lru, &bcache.head);
    }

    printf("binit done\n");
}

static struct buffer_head *bget(const uint dev, const uint blockno) {
    struct buffer_head *b;

    acquire(&bcache.lock);

    list_for_each_entry(b, &bcache.head, lru) {
        if (b->dev == dev && b->blockno == blockno) {
            atomic_increase(&b->refcnt);
            release(&bcache.lock);
            sem_p(&b->sem_lock);
            return b;
        }
    }
    list_for_each_entry_reverse(b, &bcache.head, lru) {
        if (atomic_read(&b->refcnt) == 0) {
            b->dev = dev;
            b->blockno = blockno;
            b->valid = 0;
            atomic_set(&b->refcnt, 1);
            release(&bcache.lock);
            sem_p(&b->sem_lock);
            return b;
        }
    }
    panic("bget: no buffers");
}

struct buffer_head *bread(const uint dev, const uint blockno) {
    struct buffer_head *b = bget(dev, blockno);
    if (!b->valid) {
        printf("bread: blockno %d\n", blockno);
        // virtio_disk_rw(b, DISK_READ, BIO_STRUCT_BUFFER_HEAD);
        // sd_read_block(b->blockno, b->data);
        disk_read(b);
        b->valid = 1;
        b->dirty = 0;
    }
    return b;
}

void bwrite(struct buffer_head *b) {
    printf("bwrite: blockno %d\n", b->blockno);
    b->dirty = 1;
}

void brelse(struct buffer_head *b) {
    if (b->dirty == 1) {
        printf("brelse: blockno %d\n", b->blockno);
        // virtio_disk_rw(b, DISK_WRITE, BIO_STRUCT_BUFFER_HEAD);
        // sd_write_block(b->blockno, b->data);
        disk_write(b);
        b->dirty = 0;
    }
    sem_v(&b->sem_lock);

    acquire(&bcache.lock);
    atomic_decrease(&b->refcnt);
    if (atomic_read(&b->refcnt) == 0) {
        list_del(&b->lru);
        list_add(&b->lru, &bcache.head);
    }

    release(&bcache.lock);
}

int bpin(struct buffer_head *b) {
    const int inc_ret = atomic_increase(&b->refcnt);
    return inc_ret;
}

int bunpin(struct buffer_head *b) {
    const int dec_ret = atomic_decrease(&b->refcnt);
    return dec_ret;
}

void disk_rw_bio(struct buffer_head *b, int rw) {
    struct bio bio_new;
    struct bio_vec vec_new;
    init_bio(&bio_new, &vec_new, b, rw);
    submit_bio(&bio_new, 0);
}

void init_bio(struct bio *bio_p, struct bio_vec *vec_p, struct buffer_head *b, const int rw) {
    INIT_LIST_HEAD(&bio_p->list_entry);
    bio_p->bi_rw = rw;
    bio_p->bi_bdev = b->dev;

    sem_init(&vec_p->sem_disk_done, 0, "bio_disk_done");
    INIT_LIST_HEAD(&vec_p->list);
    vec_p->blockno_start = b->blockno;
    vec_p->block_len = 1;
    vec_p->data = b->data;
    vec_p->disk = b->disk;
    list_add_tail(&vec_p->list, &bio_p->list_entry);
}

void submit_bio(const struct bio *bio, const int free) {
    struct bio_vec *vec_cur = NULL;
    struct bio_vec *vec_tmp = NULL;
    list_for_each_entry_safe(vec_cur, vec_tmp, &bio->list_entry, list) {
        struct buffer_head *b = kzalloc(sizeof(struct buffer_head));
        for (int i = 0; i < vec_cur->block_len; i++) {
            sem_init(&b->sem_lock, 1, "buffer");
            sem_init(&b->sem_disk_done, 0, "buffer_disk_done");
            b->dev = vec_cur->disk;
            b->blockno = vec_cur->blockno_start + i;
            b->valid = 0;
            b->dirty = 0;
            if (bio->bi_rw == DISK_READ) {
                // virtio_disk_rw(b, DISK_READ, BIO_STRUCT_BUFFER_HEAD);
                sd_read_block(b->blockno, b->data);
                memmove(vec_cur->data + i * BSIZE, b->data, BSIZE);
            } else {
                memmove(b->data, vec_cur->data + i * BSIZE, BSIZE);
                // virtio_disk_rw(b, DISK_WRITE, BIO_STRUCT_BUFFER_HEAD);
                sd_write_block(b->blockno, b->data);
            }
        }
        kfree(b);

        if (free) {
            kfree(vec_cur);
        }
    }
}

void fat32_bzero(const int dev, const int bno) {
    struct buffer_head *bp = bread(dev, bno);
    memset(bp->data, 0, BSIZE);
    bwrite(bp);
    brelse(bp);
}

