void sd_test(void) {
    uint8 buf[512];
    uint8 buf2[512];
    int r = 0;

    // check EXT4 magic number
    r = sd_read_block(2, &buf);
    printf("sd test: read returns %d\n", r);
    if (buf[56] != 0x53 || buf[57] != 0xEF) {
        printf("sd test failed\n");
        return;
    }

    // test r/w on block 0
    r = sd_read_block(0, &buf2);
    for (int i = 0; i < 512; i++) {
        buf[i] = i % 2 == 0 ? 0 : i % 256;
    }
    r = sd_write_block(0, &buf);
    printf("sd test: write returns %d\n", r);
    for (int i = 0; i < 512; i++) {
        buf[i] = 0;
    }
    r = sd_read_block(0, &buf);
    printf("sd test: read returns %d\n", r);
    for (int i = 0; i < 512; i++) {
        printf("%d ", buf[i]);
        // if (buf[i] != i + 1) {
        //     printf("sd test failed: [%d] == %d\n", i, buf[i]);
        //     return;
        // }
    }
    printf("\n");
    printf("sd test passed\n");
    sd_write_block(0, &buf2);
}

