void kill_proc(struct proc *p) {
    printf("process %s\n", p->name);
    printf("usertrap(): unexpected scause %p pid=%d\n", r_scause(), p->pid);
    printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());

    printf("ustack:\n");
    // print_ustack(p->mm->pagetable, USTACK + USTACK_PAGE * PGSIZE);
    printfGreen("sp: %p\n", thread_current()->trapframe->sp);

    proc_sendsignal_all_thread(p, SIGKILL, 1);
}

void thread_usertrap(void) {
    int which_dev = 0;

    tf_flstore(thread_current()->trapframe);
    if ((r_sstatus() & SSTATUS_SPP) != 0) {
        print_trapframe(thread_current()->trapframe);
        panic("usertrap: not from user mode");
    }

    // send interrupts and exceptions to kerneltrap(),
    // since we're now in the kernel.
    w_stvec((uint64) kernelvec);

    struct proc *p = proc_current();
    struct tcb *t = thread_current();

    // end user time
    utime_end(t);

    // save user program counter.
    t->trapframe->epc = r_sepc();

    if (r_scause() == 8) {
        // system call

        // start system time
        stime_start(t);

        if (thread_killed(t))
            do_exit(-1);

        // sepc points to the ecall instruction,
        // but we want to return to the next instruction.
        t->trapframe->epc += 4;

        // an interrupt will change sepc, scause, and sstatus,
        // so enable only now that we're done with those registers.
        intr_on();

        syscall();

        // end system time
        stime_end(t);

    } else if ((which_dev = devintr()) != 0) {
        // ok
    } else {
        // start system time
        stime_start(t);

        uint64 cause = r_scause();
        if (cause == INSTUCTION_PAGEFAULT || cause == LOAD_PAGEFAULT || cause == STORE_PAGEFAULT) {
            int r = page_fault(cause, p->mm->pagetable, r_stval());
            if (r < 0) {
                printf("pagefault on trap st_val: %p, cause: %p\n", r_stval(), cause);
                printf("returns %d\n", r);
                kill_proc(p);
            }
        } else {
            kill_proc(p);
        }

        // end system time
        stime_end(t);
    }

    if (proc_is_killed(p))
        do_exit(-1);

    // give up the CPU if this is a timer interrupt.
    if (which_dev == 2)
        thread_yield();

    // handle the signal
    signal_handle(t);

    thread_user_trap_ret();
}

void thread_user_trap_ret() {
    struct proc *p = proc_current();
    struct tcb *t = thread_current();
    // we're about to switch the destination of traps from
    // kerneltrap() to usertrap(), so turn off interrupts until
    // we're back in user space, where usertrap() is correct.
    intr_off();

    // start user time
    utime_start(t);

    // send syscalls, interrupts, and exceptions to uservec in trampoline.S
    uint64 trampoline_uservec = TRAMPOLINE + (uservec - trampoline);
    w_stvec(trampoline_uservec);

    // set up trapframe values that uservec will need when
    // the process next traps into the kernel.

    t->trapframe->kernel_satp = r_satp(); // kernel page table
    t->trapframe->kernel_sp = t->kstack + PGSIZE; // process's kernel stack
    t->trapframe->kernel_trap = (uint64) thread_usertrap;
    t->trapframe->kernel_hartid = r_tp(); // hartid for cpuid()

    // set up the registers that trampoline.S's sret will use
    // to get to user space.

    // set S Previous Privilege mode to User.
    unsigned long x = r_sstatus();
    x &= ~SSTATUS_SPP; // clear SPP to 0 for user mode
    x |= SSTATUS_SPIE; // enable interrupts in user mode
    w_sstatus(x);

    tf_flrestore(t->trapframe);

    // set S Exception Program Counter to the saved user pc.
    w_sepc(t->trapframe->epc);

    // tell trampoline.S the user page table to switch to.
    uint64 satp = MAKE_SATP(p->mm->pagetable);

    // write thread idx into sscratch
    w_sscratch(t->tidx);

    // jump to userret in trampoline.S at the top of memory, which
    // switches to the user page table, restores user registers,
    // and switches to user mode with sret.
    uint64 trampoline_userret = TRAMPOLINE + (userret - trampoline);
    ((void (*)(uint64)) trampoline_userret)(satp);
}

void kerneltrap() {
    int which_dev = 0;
    uint64 sepc = r_sepc();
    uint64 sstatus = r_sstatus();
    uint64 scause = r_scause();

    if ((sstatus & SSTATUS_SPP) == 0)
        panic("kerneltrap: not from supervisor mode");
    if (intr_get() != 0)
        panic("kerneltrap: interrupts enabled");

    if ((which_dev = devintr()) == 0) {
        backtrace();
        printf("scause %p\n", scause);
        printf("sepc=%p stval=%p\n", r_sepc(), r_stval());
        panic("kerneltrap");
    }

    // give up the CPU if this is a timer interrupt.
    if (which_dev == 2 && thread_current() != 0 && thread_current()->state == TCB_RUNNING)
        thread_yield();

    // the yield() may have caused some traps to occur,
    // so restore trap registers for use by kernelvec.S's sepc instruction.
    w_sepc(sepc);
    w_sstatus(sstatus);
}

void clockintr() {
    acquire(&ticks_lock);
    ticks++;
    timer_list_decrease_atomic(&timer_head);
    cond_broadcast(&cond_ticks);
    release(&ticks_lock);
    SET_TIMER();
}

int devintr() {
    uint64 scause = r_scause();

    if ((scause & 0x8000000000000000L) && (scause & 0xff) == 9) {
        // this is a supervisor external interrupt, via PLIC.

        // irq indicates which device interrupted.
        int irq = plic_claim();

        if (irq == UART0_IRQ) {
            uartintr();
        } else if (irq) {
            printf("unexpected interrupt irq=%d\n", irq);
        }

        // the PLIC allows each device to raise at most one
        // interrupt at a time; tell the PLIC the device is
        // now allowed to interrupt again.
        if (irq)
            plic_complete(irq);

        return 1;

    } else if (scause == 0x8000000000000005L) {
        clockintr();
        return 2;
    } else {
        return 0;
    }
}

