void cond_wait(struct cond *cond, struct spinlock *mutex) {
    struct tcb *t = thread_current();

    acquire(&t->lock);

    TCB_Q_changeState(t, TCB_SLEEPING);

    Queue_push_back(&cond->waiting_queue, t);

    t->wait_chan_entry = &cond->waiting_queue;

    release(mutex);

    thread_sched();

    // for signal
    int killed = t->killed;
    release(&t->lock);
    if (killed) {
        do_exit(-1);
    }

    // Reacquire original lock.
    acquire(mutex);
}

void cond_signal(struct cond *cond) {
    struct tcb *t;

    if (!Queue_isempty_atomic(&cond->waiting_queue)) {
        t = (struct tcb *) Queue_provide_atomic(&cond->waiting_queue, 1);

        if (t == NULL)
            panic("cond signal : this cond has no object waiting queue");
        if (t->state != TCB_SLEEPING) {
            printf("%s\n", t->state);
            panic("cond signal : this thread is not sleeping");
        }
        acquire(&t->lock);
        // ASSERT(t->wait_chan_entry != NULL);
        t->wait_chan_entry = NULL;
        TCB_Q_changeState(t, TCB_RUNNABLE);
        release(&t->lock);
    }
}

void cond_broadcast(struct cond *cond) {
    struct tcb *t;
    while (!Queue_isempty_atomic(&cond->waiting_queue)) {
        t = (struct tcb *) Queue_provide_atomic(&cond->waiting_queue, 1);

        if (t == NULL)
            panic("cond signal : this cond has no object waiting queue");
        if (t->state != TCB_SLEEPING) {
            continue;
        }
        acquire(&t->lock);
        ASSERT(t->wait_chan_entry != NULL);
        t->wait_chan_entry = NULL;
        TCB_Q_changeState(t, TCB_RUNNABLE);
        release(&t->lock);
    }
}

struct futex_hash_node {
    uint64 uaddr;
    struct futex *fp;
    struct list_head futex_hash_list_node;
}

static void *__futex_hash_lookup(struct hash_table *table, void *key, int release, int holding) {
    uint64 uaddr = (uint64) key;
    struct hash_entry *entry = hash_get_entry(table, key, holding);
    if (entry == NULL) {
        if (release) {
            release(&table->lock);
        }
        return NULL;
    }

    struct futex_hash_node *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, futex_hash_list_node) {
        if (pos->uaddr == uaddr) {
            if (release) {
                release(&table->lock);
            }
            return pos->fp;
        }
    }

    if (release) {
        release(&table->lock);
    }
    return NULL;
}

static void *__futex_hash_lookup_fhn(struct hash_table *table, void *key, int release, int holding) {
    uint64 uaddr = (uint64) key;
    struct hash_entry *entry = hash_get_entry(table, key, holding);
    if (entry == NULL) {
        if (release) {
            release(&table->lock);
        }
        return NULL;
    }

    struct futex_hash_node *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, futex_hash_list_node) {
        if (pos->uaddr == uaddr) {
            if (release) {
                release(&table->lock);
            }
            return pos;
        }
    }

    if (release) {
        release(&table->lock);
    }
    return NULL;
}

static int __futex_hash_insert(struct hash_table *table, void *fp, int holding) {
    struct futex_hash_node *fhn = (struct futex_hash_node *) fp;
    uint64 uaddr = fhn->uaddr;
    struct futex *fp_old = (struct futex *) __futex_hash_lookup(table, (void *) uaddr, 0, holding);
    if (fp_old != NULL) {
        // same futex hash node exists
        if (!holding) {
            release(&table->lock);
        }
        return -1;
    }
    // here we can be sure that we're holding the lock
    struct hash_entry *entry = hash_get_entry(table, (void *) uaddr, 1);
    if (entry == NULL) {
        if (!holding) {
            release(&table->lock);
        }
        return -1;
    }
    INIT_LIST_HEAD(&fhn->futex_hash_list_node);
    list_add_tail(&fhn->futex_hash_list_node, &entry->list);

    // printf("inserting futex hash node %p\n", fhn);

    if (!holding) {
        release(&table->lock);
    }
    return 0;
}

static void __futex_hash_delete(struct hash_table *table, void *uaddr, int holding, int release) {
    struct futex_hash_node *fhn =
            (struct futex *) __futex_hash_lookup_fhn(table, uaddr, 0, holding); // don't release here
    if (fhn == NULL) {
        if (release) {
            release(&table->lock);
        }
        return;
    }

    // printf("deleting futex hash node %p\n", fhn);

    // Should I free futex here?
    // Note that fp's lock is redundant, so it is NEVER acquired!
    struct futex *fp = fhn->fp;
    kfree(fp);

    list_del(&fhn->futex_hash_list_node);
    kfree(fhn);
    if (release) {
        release(&table->lock);
    }
    return;
}

void futex_hash_init() {
    init_lock(&futex_hashtable.lock, "futex hashtable");
    hash_table_entry_init(&futex_hashtable);
    futex_hashtable.op = &futex_hash_table_op;
}

void futex_init(struct futex *fp, char *name) {
    init_lock(&fp->lock, name);
    Queue_init(&fp->waiting_queue, name, TCB_WAIT_QUEUE);
}

struct futex *get_futex(uint64 uaddr, int assert) {
    struct futex *fp =
            futex_hashtable.op->hash_lookup(&futex_hashtable, (void *) uaddr, 1, 0); // release it, not holding lock
    if (fp) {
        /* find futex */
        return fp;
    } else {
        if (assert == 1) {
            return NULL;
        }
        /* create futex */
        struct futex *fp = (struct futex *) kzalloc(sizeof(struct futex));
        if (fp == NULL) {
            printf("mm : %d\n", get_free_mem());
            panic("get_futex : no free space\n");
        }
        futex_init(fp, "futex");
        struct futex_hash_node *fhn = (struct futex_hash_node *) kzalloc(sizeof(struct futex_hash_node));
        if (fhn == NULL) {
            printf("mm : %d\n", get_free_mem());
            panic("get_futex : no free space\n");
        }
        fhn->uaddr = uaddr;
        fhn->fp = fp;
        futex_hashtable.op->hash_insert(&futex_hashtable, (void *) fhn, 0); // not holding lock
        return fp;
    }
}

void futex_free(uint64 uaddr) {
    futex_hashtable.op->hash_delete(&futex_hashtable, (void *) uaddr, 0, 1); // not holding lock, release lock
}

int futex_wait(uint64 uaddr, uint val, struct timespec *ts) {
    uint u_val;
    struct proc *p = proc_current();

    acquire(&p->lock);
    if (copy_in(p->mm->pagetable, (char *) &u_val, uaddr, sizeof(uint)) < 0) {
        release(&p->lock);
        return -1;
    }

    if (u_val == val) {
        struct futex *fp = get_futex(uaddr, 0); // without assert
        struct tcb *t = thread_current();

        acquire(&t->lock);
        TCB_Q_changeState(t, TCB_SLEEPING);
        Queue_push_back(&fp->waiting_queue, t);

        release(&p->lock);
        if (ts != NULL) {
            t->time_out = TIMESEPC2NS((*ts));
        }
        t->wait_chan_entry = &fp->waiting_queue; // !!!!!

        int ret = thread_sched();
        release(&t->lock);

        if (ts != NULL)
            return ret ? -1 : 0;
        else
            return 0;
    } else {
        release(&p->lock);
        return 0;
    }
}

int futex_wakeup(uint64 uaddr, int nr_wake) {
    struct proc *p = proc_current();
    acquire(&p->lock);

    // ========atomic=========
    struct futex *fp = get_futex(uaddr, 1); // with assert
    if (fp == NULL) {
        release(&p->lock);
        return 0;
    }

    struct tcb *t = NULL;
    int ret = 0;

    while (!Queue_isempty(&fp->waiting_queue) && ret < nr_wake) {
        t = (struct tcb *) Queue_provide_atomic(&fp->waiting_queue, 1); // remove it

        if (t == NULL)
            panic("futex wakeup : no waiting queue");
        if (t->state != TCB_SLEEPING) {
            printf("%s\n", fp->waiting_queue.name);
            printf("%s\n", t->state);
            panic("futex wakeup : this thread is not sleeping");
        }
        acquire(&t->lock);
        ASSERT(t->wait_chan_entry != NULL);
        t->wait_chan_entry = NULL;
        TCB_Q_changeState(t, TCB_RUNNABLE);
        release(&t->lock);
        ret++;
    }

    if (Queue_isempty_atomic(&fp->waiting_queue)) {
        futex_free(uaddr);
    }

    // ==========atomic==========
    release(&p->lock);
    return ret;
}

int futex_requeue(uint64 uaddr1, int nr_wake, uint64 uaddr2, int nr_requeue) {
    futex_wakeup(uaddr1, nr_wake);
    // int nr_wake1 = futex_wakeup(uaddr1, nr_wake);
    // #ifdef __DEBUG_FUTEX__
    // printfRed("futex_requeue : has wakeup %d threads in uaddr1 : %x\n", nr_wake1, uaddr1); // debug
    // #endif

    struct proc *p = proc_current();

    acquire(&p->lock);
    // ==========atomic=========
    struct futex *fp_old = get_futex(uaddr1, 1); // with assert
    if (fp_old == NULL) {
        release(&p->lock);
        return 0;
    }
    struct futex *fp_new = get_futex(uaddr2, 0); // without assert
    if (fp_new == NULL) {
        panic("not tested\n");
    }
    struct tcb *t = NULL;
    int ret = 0;

    while (!Queue_isempty_atomic(&fp_old->waiting_queue) && ret < nr_requeue) {
        t = (struct tcb *) Queue_provide_atomic(&fp_old->waiting_queue, 1); // remove it
        if (t == NULL)
            panic("futex requeue : no waiting queue");
        if (t->state != TCB_SLEEPING) {
            printf("%s\n", fp_old->waiting_queue.name);
            printf("%s\n", t->state);
            panic("futex requeue : this thread is not sleeping");
        }
        Queue_push_back_atomic(&fp_new->waiting_queue, (void *) t); // move the rest of threads to new queue
        ret++;
    }
    if (Queue_isempty_atomic(&fp_old->waiting_queue)) {
        futex_free(uaddr1);
    }

    // ========atomic========
    release(&p->lock);

    return ret;
}

int do_futex(uint64 uaddr, int op, uint32 val, struct timespec *ts, uint64 uaddr2, uint32 val2, uint32 val3) {
    int cmd = op & FUTEX_CMD_MASK;

    int ret = -1;
    switch (cmd) {
        case FUTEX_WAIT:
            ret = futex_wait(uaddr, val, ts);
            break;

        case FUTEX_WAKE:
            ret = futex_wakeup(uaddr, val);
            break;

        case FUTEX_REQUEUE:
            ret = futex_requeue(uaddr, val, uaddr2, val2); // must use val2 as a limit of requeue
            break;

        default:
            panic("do_futex : error\n");
            break;
    }

    return ret;
}

void sem_init(sem *S, int value, char *name) {
    S->value = value;
    S->wakeup = 0;
    init_lock(&S->sem_lock, name);
    cond_init(&S->sem_cond, name);
}

void sem_p(sem *S) {
    acquire(&S->sem_lock);
    S->value--;
    if (S->value < 0) {
        do {
            cond_wait(&S->sem_cond, &S->sem_lock);
        } while (S->wakeup == 0);
        S->wakeup--;
    }
    release(&S->sem_lock);
}

void sem_v(sem *S) {
    acquire(&S->sem_lock);
    S->value++;
    if (S->value <= 0) {
        S->wakeup++;
        cond_signal(&S->sem_cond);
    }
    release(&S->sem_lock);
}

int atomic_read4(const int *addr) {
    int val;
    __atomic_load(addr, &val, __ATOMIC_SEQ_CST);
    return val;
}

void do_acquire(struct spinlock *lk) {
    push_off(); // disable interrupts to avoid deadlock.
    if (holding(lk)) {
        printf("%s\n", lk->name);
        panic("acquire");
    }

    while (__sync_lock_test_and_set(&lk->locked, 1) != 0)
        ;
    __sync_synchronize();
    lk->cpu = mycpu();
}

void do_release(struct spinlock *lk) {
    if (!holding(lk)) {
        printf("%s\n", lk->name);
        panic("release");
    }
    lk->cpu = 0;
    __sync_synchronize();
    __sync_lock_release(&lk->locked);

    pop_off();
}

void init_lock(struct spinlock *lk, char *name) {
    lk->locked = 0;
    lk->cpu = 0;
    strncpy(lk->name, name, strlen(name));
}

int holding(struct spinlock *lk) {
    int r;
    r = (lk->locked && lk->cpu == mycpu());
    return r;
}

void push_off(void) {
    int old = intr_get();
    intr_off();
    if (mycpu()->noff == 0)
        mycpu()->intena = old;
    mycpu()->noff += 1;
}

void pop_off(void) {
    struct thread_cpu *c = mycpu();
    if (intr_get())
        panic("pop_off - interruptible");
    if (c->noff < 1)
        panic("pop_off");
    c->noff -= 1;
    if (c->noff == 0 && c->intena)
        intr_on();
}

void console_putc(int c) {
    if (c == BACKSPACE) {
        // if the user typed backspace, overwrite with a space.
#ifdef VISIONFIVE
        uart8250_putc('\b');
        uart8250_putc(' ');
        uart8250_putc('\b');
#else
        sbi_console_putchar('\b');
        sbi_console_putchar(' ');
        sbi_console_putchar('\b');
#endif
    } else if (c == '\n' || c == '\r') {
#ifdef VISIONFIVE
        uart8250_putc('\r');
        uart8250_putc('\n');
#else
        sbi_console_putchar('\n');
#endif
    } else {
#ifdef VISIONFIVE
        uart8250_putc(c);
#else
        sbi_console_putchar(c);
#endif
    }
}

struct {
    struct spinlock lock;

    // input
#define INPUT_BUF_SIZE 128
    char buf[INPUT_BUF_SIZE];
    uint r; // Read index
    uint w; // Write index
    uint e; // Edit index

    struct semaphore sem_r;
    struct semaphore sem_w;
}

int consolewrite(int user_src, uint64 src, int n) {
    int i;

    sem_p(&cons.sem_w);
    for (i = 0; i < n; i++) {
        char c;
        if (either_copy_in(&c, user_src, src + i, 1) == -1)
            break;
#ifdef VISIONFIVE
    uart8250_putc(c);
#else
        sbi_console_putchar(c);
#endif
    }
    sem_v(&cons.sem_w);

    return i;
}

int consoleread(int user_dst, uint64 dst, int n) {
    uint target;
    int c;
    char cbuf;

    target = n;
    acquire(&cons.lock);
    while (n > 0) {
        // wait until interrupt handler has put some
        // input into cons.buffer.
        while (cons.r == cons.w) {
            if (proc_is_killed(proc_current())) {
                release(&cons.lock);
                return -1;
            }
            release(&cons.lock);
            sem_p(&cons.sem_r);
            acquire(&cons.lock);
        }

        c = cons.buf[cons.r++ % INPUT_BUF_SIZE];

        if (c == C('D')) { // end-of-file
            if (n < target) {
                // Save ^D for next time, to make sure
                // caller gets a 0-byte result.
                cons.r--;
            }
            break;
        }

        // copy the input byte to the user-space buffer.
        cbuf = c;
        if (either_copy_out(user_dst, dst, &cbuf, 1) == -1)
            break;

        dst++;
        --n;

        if (c == '\n') {
            // a whole line has arrived, return to
            // the user-level read().
            break;
        }
    }
    release(&cons.lock);

    return target - n;
}

void console_intr(int c) {
    acquire(&cons.lock);

    switch (c) {
        case C('P'): // Print process list.
            // procdump();
            break;
        case C('U'): // Kill line.
            while (cons.e != cons.w && cons.buf[(cons.e - 1) % INPUT_BUF_SIZE] != '\n') {
                cons.e--;
                console_putc(BACKSPACE);
            }
            break;
        case C('H'): // Backspace
        case '\x7f': // Delete key
            if (cons.e != cons.w) {
                cons.e--;
                console_putc(BACKSPACE);
            }
            break;
        default:
            if (c != 0 && cons.e - cons.r < INPUT_BUF_SIZE) {
                c = (c == '\r') ? '\n' : c;

                // echo back to the user.
                console_putc(c);

                // store for consumption by consoleread().
                cons.buf[cons.e++ % INPUT_BUF_SIZE] = c;

                if (c == '\n' || c == C('D') || cons.e - cons.r == INPUT_BUF_SIZE) {
                    // wake up consoleread() if a whole line (or end-of-file)
                    // has arrived.
                    cons.w = cons.e;
                    // wakeup(&cons.r);
                    sem_v(&cons.sem_r);
                }
            }
            break;
    }

    release(&cons.lock);
}

void console_init(void) {
    init_lock(&cons.lock, "cons");
    sem_init(&cons.sem_r, 0, "cons_sema_r");
    sem_init(&cons.sem_w, 1, "cons_sema_w");
#if defined(QEMU)
    uartinit();
#elif defined(VISIONFIVE)
    uart8250_init(UART0, 24000000, 115200, 2, 4, 0);
#endif
    cons.e = cons.w = cons.r = 0;
    // connect read and write system calls
    // to consoleread and consolewrite.
    devsw[CONSOLE].read = consoleread;
    devsw[CONSOLE].write = consolewrite;
}

int console_ready() {
    acquire(&cons.lock);
    const int ready = cons.w - cons.r;
    release(&cons.lock);
    return ready;
}

