uint64 sys_ppoll(void) {
    uint64 pfdaddr;
    int nfds;
    uint64 tsaddr;
    uint64 sigmaskaddr;
    struct proc *p = proc_current();

    arg_addr(0, &pfdaddr);
    arg_int(1, &nfds);
    arg_addr(2, &tsaddr);
    arg_addr(3, &sigmaskaddr);

    // ASSERT(nfds == 1);
    printf("nfds: %d\n", nfds);

    struct pollfd pfd;

    if (copy_in(p->mm->pagetable, (char *) &pfd, pfdaddr, sizeof(pfd)) < 0)
        return -1;

    ASSERT(pfd.fd == 0);
    // ASSERT(pfd.events == POLLIN);
    printf("fd: %d, events: %d\n", pfd.fd, pfd.events);

    struct file *f = p->_ofile[pfd.fd];

    struct timespec ts;
    if (tsaddr && copy_in(p->mm->pagetable, (char *) &ts, tsaddr, sizeof(struct timespec)) < 0)
        return -1;

    uint64 timeout = tsaddr ? ts2ticks(&ts) : -1;

    while (1) {
        switch (f->f_type) {
            case FD_PIPE:
                return 1;
            case FD_DEVICE:
                if (console_ready()) {
                    if (timeout == 0)
                        return 0;
                }
                break;
            default:
                panic("error");
        }

        if (timeout == -1)
            continue;

        if (timeout) {
            acquire(&cond_ticks.waiting_queue.lock);
            cond_wait(&cond_ticks, &cond_ticks.waiting_queue.lock);
            release(&cond_ticks.waiting_queue.lock);
            timeout--;
        } else {
            break;
        }
    }

    if (timeout == 0)
        return 0;

    pfd.revents = pfd.events;
    if (copy_out(p->mm->pagetable, pfdaddr, (char *) &pfd, sizeof(pfd)) < 0)
        return -1;

    return 1;
}

int do_select(int nfds, fd_set_bits *fds, uint64 timeout) {
    int retval;
    uint64 time_now = TIME2NS(rdtime());
    struct proc *p = proc_current();
    retval = 0;
    for (;;) {
        uint64 *rinp, *routp, *rexp, *inp, *outp, *exp;
        inp = fds->in;
        outp = fds->out;
        exp = fds->ex;
        rinp = fds->res_in;
        routp = fds->res_out;
        rexp = fds->res_ex;
        for (int i = 0; i < nfds; ++rinp, ++routp, ++rexp) {
            uint64 in, out, ex;
            uint64 bit = 1;
            uint64 res_in = 0, res_out = 0, res_ex = 0;
            struct file *file = NULL;
            in = *inp++;
            out = *outp++;
            ex = *exp++;
            uint64 all_bits = in | out | ex;
            if (all_bits == 0) {
                i += __NFDBITS;
                continue;
            }
            for (int j = 0; j < __NFDBITS; ++j, ++i, bit <<= 1) {
                if (i >= nfds) {
                    panic("i>=nfds : not tested\n");
                    break;
                }
                if (!(bit & all_bits))
                    continue;
                file = p->_ofile[i];
                if (file) {
                    switch (file->f_type) {
                        case FD_REG:
                            break;
                        case FD_PIPE: {
                        }
                        default:
                            printf("type: %d\n", file->f_type);
                            panic("this type not tested\n");
                    }
                    if (in & bit) {
                        res_in |= bit;
                        retval++;
                    }
                    if (out & bit) {
                        res_out |= bit;
                        retval++;
                    }
                    if (ex & bit) {
                        res_ex |= bit;
                        retval++;
                    }
                }
            }
            if (res_in)
                *rinp = res_in;
            if (res_out)
                *routp = res_out;
            if (res_ex)
                *rexp = res_ex;
        }
        if (retval || (TIME2NS(rdtime()) > time_now + timeout)) {

            break;
        } else {
        }
    }
    return retval;
}

int core_sys_select(int nfds, fd_set *readfds, fd_set *writefds, fd_set *exceptfds, uint64 timeout) {
    fd_set_bits fds;
    void *bits;
    int ret;
    uint32 size;

    long stack_fds[SELECT_STACK_ALLOC / sizeof(long)];
    ret = -EINVAL;
    if (nfds > NOFILE) {
        panic("nfds > NOFILE, not tested\n");
    }

    /*
     * We need 6 bitmaps (in/out/ex for both incoming and outgoing),
     * since we used fdset we need to allocate memory in units of
     * long-words.
     */
    size = FDS_BYTES(nfds);
    bits = stack_fds;
    if (size > sizeof(stack_fds) / 6) {
        /* Not enough space in on-stack array; must use kmalloc */
        ret = -ENOMEM;
        bits = kmalloc(6 * size);
        if (!bits)
            panic("no memory\n");
    }
    fds.in = bits;
    fds.out = bits + size;
    fds.ex = bits + 2 * size;
    fds.res_in = bits + 3 * size;
    fds.res_out = bits + 4 * size;
    fds.res_ex = bits + 5 * size;

    fds.in = (uint64 *) readfds;
    fds.out = (uint64 *) writefds;
    fds.ex = (uint64 *) exceptfds;
    zero_fd_set(nfds, fds.res_in);
    zero_fd_set(nfds, fds.res_out);
    zero_fd_set(nfds, fds.res_ex);
    ret = do_select(nfds, &fds, timeout);
    if (ret < 0) {
        panic("ret < 0, not tested\n");
    }

    return ret;
}

long do_pselect(int nfds, fd_set *readfds, fd_set *writefds, fd_set *exceptfds, struct timespec *tsp,
                const sigset_t *sigmask, size_t sigsetsize) {
    int ret;
    uint64 time_out = (tsp != NULL ? TIMESEPC2NS((*tsp)) : 0);
    ret = core_sys_select(nfds, readfds, writefds, exceptfds, time_out);
    return ret;
}

uint64 sys_pselect6(void) {
    int nfds;
    uint64 readfds_addr, writefds_addr, exceptfds_addr, timeout_addr;
    fd_set readfds, writefds, exceptfds;
    struct timespec timeout;
    arg_int(0, &nfds);
    arg_addr(1, &readfds_addr);
    arg_addr(2, &writefds_addr);
    arg_addr(3, &exceptfds_addr);
    arg_addr(4, &timeout_addr);
    struct proc *p = proc_current();
    if (readfds_addr && (copy_in(p->mm->pagetable, (char *) &readfds, readfds_addr, sizeof(readfds))) < 0)
        return -1;
    if (writefds_addr && (copy_in(p->mm->pagetable, (char *) &writefds, writefds_addr, sizeof(writefds))) < 0)
        return -1;
    if (exceptfds_addr && (copy_in(p->mm->pagetable, (char *) &exceptfds, exceptfds_addr, sizeof(exceptfds)) < 0))
        return -1;
    if (timeout_addr) {
        if (copy_in(p->mm->pagetable, (char *) &timeout, timeout_addr, sizeof(timeout)) < 0)
            return -1;
    }
    uint64 time_out = (timeout_addr != 0 ? TIMESEPC2NS(timeout) : 0);

    int ret = 0;
    struct file *fp;
    while (1) {
        if (readfds_addr) {
            for (int i = 0; i < nfds; i++) {
                fp = p->_ofile[i];
                if (fp) {
                    switch (fp->f_type) {
                        case FD_REG:
                            break;
                        case FD_PIPE: {
                            if (!fp->f_data.f_pipe->readopen || pipe_empty(fp->f_data.f_pipe)) {
                                FD_CLR(i, &readfds);
                                break;
                            }
                        }
                        case FD_DEVICE:
                        case FD_SOCKET: {
                            ret++;
                            break;
                        }
                        default:
                            printf("type: %d\n", fp->f_type);
                            panic("this type not tested\n");
                    }
                }
            }
        }
        if (writefds_addr) {
            for (int i = 0; i < nfds; i++) {
                fp = p->_ofile[i];
                if (fp) {
                    switch (fp->f_type) {
                        case FD_REG:
                            break;
                        case FD_PIPE: {
                            if (!fp->f_data.f_pipe->writeopen || pipe_full(fp->f_data.f_pipe)) {
                                FD_CLR(i, &writefds);
                                break;
                            }
                        }
                        case FD_DEVICE:
                        case FD_SOCKET: {
                            ret++;
                            break;
                        }
                        default:
                            printf("type: %d\n", fp->f_type);
                            panic("this type not tested\n");
                    }
                }
            }
        }
        if (exceptfds_addr) {
            for (int i = 0; i < nfds; i++) {
                FD_CLR(i, &exceptfds);
            }
        }

        uint64 time_now = TIME2NS(rdtime());
        if (ret || (TIME2NS(rdtime()) > time_now + time_out)) {
            break;
        } else {
        }
    }
    if (readfds_addr && (copy_out(p->mm->pagetable, readfds_addr, (char *) &readfds, sizeof(readfds)) < 0))
        return -1;
    if (writefds_addr && (copy_out(p->mm->pagetable, writefds_addr, (char *) &writefds, sizeof(writefds)) < 0))
        return -1;
    if (exceptfds_addr && (copy_out(p->mm->pagetable, exceptfds_addr, (char *) &exceptfds, sizeof(exceptfds)) < 0))
        return -1;
    return ret;
}

struct vfs_ext4_blockdev *vfs_ext4_blockdev_from_bd(struct ext4_blockdev *bd) {
    if (bd == NULL)
        return NULL;
    return container_of(bd, struct vfs_ext4_blockdev, bd);
}

static int vfs_ext4_blockdev_init(struct vfs_ext4_blockdev *vbdev, int dev) {
    uint8_t *ph_bbuf = NULL;
    struct ext4_blockdev *bd = NULL;
    struct ext4_blockdev_iface *iface = NULL;

    if (vbdev) {
        vbdev->dev = dev;

        bd = &vbdev->bd;
        iface = (struct ext4_blockdev_iface *) kzalloc(sizeof(struct ext4_blockdev_iface));
        if (iface == NULL) {
            return -ENOMEM;
        }

        bd->bdif = iface;
        bd->part_offset = 0;
#if defined(QEMU)
        // bd->part_size = blk_cfg.capacity * BSIZE;
        bd->part_size = 768 * 1024 * 1024;
#elif defined(VISIONFIVE)
        // FIXME: hard code the partition size here
        // 256M
        bd->part_size = 768 * 1024 * 1024;
#endif

        ph_bbuf = &vbdev->ph_bbuf[0];

        iface->lock = blockdev_lock;
        iface->unlock = blockdev_unlock;
        iface->open = blockdev_open;
        iface->bread = blockdev_read;
        iface->bwrite = blockdev_write;
        iface->close = blockdev_close;
#if defined(QEMU)
        // iface->ph_bsize = blk_cfg.blk_size;
        iface->ph_bsize = BSIZE;
#elif defined(VISIONFIVE)
        iface->ph_bsize = BSIZE;
#endif
        iface->ph_bbuf = ph_bbuf;
        iface->ph_bcnt = bd->part_size / (uint64)bd->bdif->ph_bsize;

        printf("vfs_ext4_blockdev_init: ph_bsize=%p, ph_bcnt=%p\n", iface->ph_bsize, iface->ph_bcnt);
    }

    return EOK;
}

struct vfs_ext4_blockdev *vfs_ext4_blockdev_create(int dev) {

    // init_lock(&bdevice_lock, "bdevice lock"); /* init lock here */

    struct vfs_ext4_blockdev *vbdev = kzalloc(sizeof(struct vfs_ext4_blockdev));
    if (vbdev == NULL)
        return NULL;
    int r = vfs_ext4_blockdev_init(vbdev, dev);
    if (r != EOK) {
        printf("vfs_ext4_blockdev_init failed: %d\n", r);
        kfree(vbdev);
        return NULL;
    }
    // FIXME: hard code the device name here
    r = ext4_device_register(&vbdev->bd, DEV_NAME);
    if (r != EOK) {
        printf("ext4_device_register failed: %d\n", r);
        kfree(vbdev);
        return NULL;
    }
    return vbdev;
}

int vfs_ext4_blockdev_destroy(struct vfs_ext4_blockdev *vbdev) {
    if (vbdev == NULL)
        return -EINVAL;
    kfree(vbdev->bd.bdif);
    kfree(vbdev);
    return EOK;
}

