static int blockdev_write(struct ext4_blockdev *bdev, const void *buf, uint64_t blk_id, uint32_t blk_cnt) {
    struct vfs_ext4_blockdev *vbdev = vfs_ext4_blockdev_from_bd(bdev);
    if (vbdev == NULL)
        return -EINVAL;

    // make up a bio_vec
    struct bio_vec bio_vec;
    bio_vec.b_type = BIO_STRUCT_BIO_VEC;
    bio_vec.blockno_start = blk_id;
    bio_vec.block_len = blk_cnt;
    bio_vec.data = (uchar *) buf;
    bio_vec.disk = 0;
    sem_init(&bio_vec.sem_disk_done, 0, "bio_disk_done");
    disk_write_batch(&bio_vec);

    return EOK;
}

int vfs_ext_init(void) {
    sem_init(&ext4_sem, 1, "ext4_sem");
    ext4_device_unregister_all(); /* zero s_bdevices */
    ext4_init_mountpoints();
    return 0;
}

int vfs_ext_mount(struct filesystem *fs, uint64_t rwflag, void *data) {
    int rc = 0;
    struct ext4_blockdev *bdev = NULL;
    struct vfs_ext4_blockdev *vbdev = NULL;

    vbdev = vfs_ext4_blockdev_create(fs->dev);

    if (vbdev == NULL) {
        rc = -ENOMEM;
        goto out;
    }

    printf("before mount\n");
    bdev = &vbdev->bd;
    rc = ext4_mount(DEV_NAME, fs->path, false);
    printf("ext4_mount returns %d\n", rc);
    if (rc != EOK) {
        vfs_ext4_blockdev_destroy(bdev);
        goto out;
    } else {
        ext4_mount_setup_locks(fs->path, &ext4_lock_ops);

        printf("before getting superblock\n");
        /* Get superblock. */
        ext4_get_sblock(fs->path, &fs->fs_data);
        printf("after getting super block\n");
    }

out:
    return rc;
}

int vfs_ext_umount(struct filesystem *fs) {
    int rc = 0;
    struct vfs_ext4_blockdev *vbdev = (struct vfs_ext4_blockdev *) fs->fs_data;

    if (vbdev == NULL) {
        rc = -EINVAL;
        goto out;
    }

    rc = ext4_umount(fs->path);
    if (rc != EOK) {
        goto out;
    }

    vfs_ext4_blockdev_destroy(vbdev);

out:
    return rc;
}

int vfs_ext_statfs(struct filesystem *fs, struct statfs *buf) {
    struct ext4_sblock *sb = NULL;
    int err = EOK;

    err = ext4_get_sblock(fs->path, &sb);
    if (err != EOK) {
        return err;
    }

    buf->f_bsize = ext4_sb_get_block_size(sb);
    buf->f_blocks = ext4_sb_get_blocks_cnt(sb);
    buf->f_bfree = ext4_sb_get_free_blocks_cnt(sb);
    buf->f_bavail = ext4_sb_get_free_blocks_cnt(sb);
    buf->f_type = sb->magic;
    buf->f_files = sb->inodes_count;
    buf->f_ffree = sb->free_inodes_count;
    buf->f_frsize = ext4_sb_get_block_size(sb);
    buf->f_bavail = sb->free_inodes_count;
    buf->f_fsid.val[0] = 2; /* why 2? */
    buf->f_flags = 0;
    buf->f_namelen = 32;
    return err;
}

