int vfs_ext_ioctl(struct file *f, int cmd, void *args) {
    int r = 0;
    struct file_vnode *fv = f->f_data.f_vnode;
    struct ext4_file *file = (struct ext4_file *) fv->data;

    if (file == NULL) {
        panic("can't get file");
    }

    switch (cmd) {
        case FIOCLEX:
            f->f_flags |= O_CLOEXEC;
            break;
        case FIONCLEX:
            f->f_flags &= ~O_CLOEXEC;
            break;
        case FIONREAD:
            r = ext4_fsize(file);
            break;
        case FIONBIO:
            break;
        case FIOASYNC:
            break;
        default:
            r = -EINVAL;
            break;
    }

    return r;
}

int vfs_ext_read(struct file *f, int is_user_addr, const uint64 addr, int n) {
    // from user space
    size_t bytesread = 0;
    struct file_vnode *fv = f->f_data.f_vnode;
    struct ext4_file *file = (struct ext4_file *) fv->data;

    if (file == NULL) {
        panic("can't get file");
    }

    char *kbuf = NULL;
    if (is_user_addr) {
        kbuf = (char *) kmalloc(n + 1);
        if (kbuf == NULL) {
            return -ENOMEM;
        }
    } else {
        kbuf = (char *) addr;
    }


    int r = ext4_fread(file, kbuf, n, &bytesread);
    if (r != EOK) {
        if (is_user_addr)
            kfree(kbuf);
        return 0;
    }

    f->f_pos = file->fpos;

    if (is_user_addr) {
        if (copy_out(proc_current()->mm->pagetable, addr, kbuf, bytesread) != 0) {
            kfree(kbuf);
            return -EFAULT;
        }
        kfree(kbuf);
    } else {
        memmove((char *) addr, kbuf, bytesread);
    }

    return bytesread;
}

int vfs_ext_readat(struct file *f, int is_user_addr, const uint64 addr, int n, int offset) {
    // from user space
    size_t bytesread = 0;
    struct file_vnode *fv = f->f_data.f_vnode;
    struct ext4_file *file = (struct ext4_file *) fv->data;

    if (file == NULL) {
        panic("can't get file");
    }

    char *kbuf = NULL;
    if (is_user_addr) {
        kbuf = (char *) kmalloc(n + 1);
        if (kbuf == NULL) {
            return -ENOMEM;
        }
    } else {
        kbuf = (char *) addr;
    }

    /* set file->fpos to offset */
    int r = ext4_fseek(file, offset, SEEK_SET);
    if (r != EOK) {
        if (is_user_addr)
            kfree(kbuf);
        return -1;
    }

    /* read file */
    r = ext4_fread(file, kbuf, n, &bytesread);
    if (r != EOK) {
        if (is_user_addr)
            kfree(kbuf);
        return 0;
    }

    /* set file->fpos back */
    r = ext4_fseek(file, f->f_pos, SEEK_SET);
    if (r != EOK) {
        if (is_user_addr)
            kfree(kbuf);
        return -1;
    }

    if (is_user_addr) {
        if (copy_out(proc_current()->mm->pagetable, addr, kbuf, bytesread) != 0) {
            kfree(kbuf);
            return -EFAULT;
        }

        kfree(kbuf);
    }

    return bytesread;
}

int vfs_ext_write(struct file *f, int is_user_addr, const uint64 addr, int n) {
    // from user space
    size_t byteswritten = 0;
    struct file_vnode *fv = f->f_data.f_vnode;
    struct ext4_file *file = (struct ext4_file *) fv->data;

    if (file == NULL) {
        panic("can't get file");
    }

    char *kbuf = NULL;
    if (is_user_addr) {
        kbuf = (char *) kmalloc(n + 1);
        if (kbuf == NULL) {
            return 0;
        }

        if (copy_in(proc_current()->mm->pagetable, kbuf, addr, n) != 0) {
            kfree(kbuf);
            return 0;
        }
    } else {
        kbuf = (char *) addr;
    }

    int r = ext4_fwrite(file, kbuf, n, &byteswritten);
    if (r != EOK) {
        kfree(kbuf);
        return 0;
    }

    f->f_pos = file->fpos;

    if (is_user_addr) {
        kfree(kbuf);
    }
    return byteswritten;
}

