int vfs_ext_lseek(struct file *f, int offset, int whence) {
    int r;
    struct ext4_file *file = (struct ext4_file *) f->f_data.f_vnode->data;

    if (file == NULL) {
        panic("can't get file");
    }
    if (whence == SEEK_END && offset < 0) {
        offset = -offset;
    }
    r = ext4_fseek(file, offset, whence);
    if (r != EOK) {
        return -r;
    }

    f->f_pos = file->fpos;
    return f->f_pos;
}

int vfs_ext_fclose(struct file *f) {
    struct file_vnode *fv = f->f_data.f_vnode;
    struct ext4_file *file = (struct ext4_file *) fv->data;
    if (strncmp(fv->path, "/tmp", 4) == 0) {
        kfree(file);
        memset(fv, 0, sizeof(struct file_vnode));
        return ext4_fremove(fv->path);
    }
    if (file == NULL) {
        panic("can't get file");
    }

    int r = ext4_fclose(file);
    if (r != EOK) {
        return -r;
    }

    kfree(file);
    memset(fv, 0, sizeof(struct file_vnode));

    return EOK;
}

int vfs_ext_openat(struct file *f) {
    struct file_vnode *fv = f->f_data.f_vnode;
    struct ext4_file *file = NULL;
    struct ext4_dir *dir = NULL;
    union {
        ext4_dir dir;
        ext4_file f;
    } var;
    int r;
    r = ext4_dir_open(&(var.dir), fv->path);
    if (r == EOK) {
        dir = (struct ext4_dir *) kmalloc(sizeof(struct ext4_dir));
        if (dir == NULL)
            return -ENOMEM;
        *dir = var.dir;
        fv->data = dir;
    } else {
        file = (struct ext4_file *) kmalloc(sizeof(struct ext4_file));
        if (file == NULL) {
            return -ENOMEM;
        }
        r = ext4_fopen2(file, f->f_data.f_vnode->path, f->f_flags);
        if (r != EOK) {
            kfree(file);
            return -r;
        }
        fv->data = file;
        f->f_pos = file->fpos;
    }
    f->f_count = 1;
    struct ext4_inode inode;
    uint32_t ino;
    if (ext4_raw_inode_fill(fv->path, &ino, &inode) == EOK) {
        struct ext4_sblock *sb = NULL;
        ext4_get_sblock(fv->fs->path, &sb);
        if (ext4_inode_type(sb, &inode) == EXT4_INODE_MODE_CHARDEV) {
            f->f_type = FD_DEVICE;
            f->f_major = ext4_inode_get_dev(&inode);
        } else {
            f->f_type = FD_REG;
        }
    }

    return EOK;
}

