struct inode *vfs_ext_namei(const char *name) {
    struct inode *inode = NULL;
    struct ext4_inode *ext4_i = NULL;
    uint32_t ino;

    inode = kmalloc(sizeof(struct inode));
    if (inode == NULL) {
        return NULL;
    }

    ext4_i = &inode->ext4_i;
    int r = ext4_raw_inode_fill(name, &ino, ext4_i);
    if (r != EOK) {
        kfree(inode);
        return NULL;
    }
    strncpy(&inode->ext4_i.fname, name, EXT4_PATH_LONG_MAX - 1);

    inode->i_ino = ino;
    inode->i_op = &ext4_inode_op;

    /* Other fields are not needed. */

    return inode;
}

ssize_t vfs_ext_readi(struct inode *self, int user_dst, uint64 addr, uint off, uint n) {
    struct ext4_inode *ext4_i = &self->ext4_i;
    struct ext4_file file;
    int r;
    size_t bytesread = 0;
    char *kbuf = NULL;

    kbuf = (char *) kmalloc(n + 1);
    if (kbuf == NULL) {
        return -ENOMEM;
    }

    r = ext4_fopen2(&file, self->ext4_i.fname, O_RDONLY);
    if (r != EOK) {
        kfree(kbuf);
        return -r;
    }

    uint64_t oldoff = file.fpos;
    r = ext4_fseek(&file, off, SEEK_SET);
    if (r != EOK) {
        kfree(kbuf);
        return -1;
    }

    r = ext4_fread(&file, kbuf, n, &bytesread);
    if (r != EOK) {
        kfree(kbuf);
        return 0;
    }

    r = ext4_fseek(&file, oldoff, SEEK_SET);
    if (r != EOK) {
        kfree(kbuf);
        return -1;
    }

    if (user_dst) {
        if (copy_out(proc_current()->mm->pagetable, addr, kbuf, bytesread) != 0) {
            kfree(kbuf);
            return -EFAULT;
        }
    } else {
        memmove((char *) addr, kbuf, bytesread);
    }

    kfree(kbuf);
    return bytesread;
}

