int ext4_fs_check_features(struct ext4_fs *fs, bool *read_only) {
    ext4_assert(fs && read_only);
    uint32_t v;
    if (ext4_get32(&fs->sb, rev_level) == 0) {
        *read_only = false;
        return EOK;
    }

    ext4_dbg(DEBUG_FS, DBG_INFO "sblock features_incompatible:\n");
    ext4_fs_debug_features_inc(ext4_get32(&fs->sb, features_incompatible));

    ext4_dbg(DEBUG_FS, DBG_INFO "sblock features_compatible:\n");
    ext4_fs_debug_features_comp(ext4_get32(&fs->sb, features_compatible));

    ext4_dbg(DEBUG_FS, DBG_INFO "sblock features_read_only:\n");
    ext4_fs_debug_features_ro(ext4_get32(&fs->sb, features_read_only));

    /*Check features_incompatible*/
    v = (ext4_get32(&fs->sb, features_incompatible) & (~CONFIG_SUPPORTED_FINCOM));
    if (v) {
        ext4_dbg(DEBUG_FS, DBG_ERROR "sblock has unsupported features incompatible:\n");
        ext4_fs_debug_features_inc(v);
        return ENOTSUP;
    }

    /*Check features_read_only*/
    v = ext4_get32(&fs->sb, features_read_only);
    v &= ~CONFIG_SUPPORTED_FRO_COM;
    if (v) {
        ext4_dbg(DEBUG_FS, DBG_WARN "sblock has unsupported features read only:\n");
        ext4_fs_debug_features_ro(v);
        *read_only = true;
        return EOK;
    }
    *read_only = false;

    return EOK;
}

static bool ext4_block_in_group(struct ext4_sblock *s, ext4_fsblk_t baddr, uint32_t bgid) {
    uint32_t actual_bgid;
    actual_bgid = ext4_balloc_get_bgid_of_block(s, baddr);
    if (actual_bgid == bgid)
        return true;
    return false;
}

static void ext4_fs_mark_bitmap_end(int start_bit, int end_bit, void *bitmap) {
    int i;

    if (start_bit >= end_bit)
        return;

    for (i = start_bit; (unsigned) i < ((start_bit + 7) & ~7UL); i++)
        ext4_bmap_bit_set(bitmap, i);

    if (i < end_bit)
        memset((char *) bitmap + (i >> 3), 0xff, (end_bit - i) >> 3);
}

static int ext4_fs_init_block_bitmap(struct ext4_block_group_ref *bg_ref) {
    struct ext4_sblock *sb = &bg_ref->fs->sb;
    struct ext4_bgroup *bg = bg_ref->block_group;
    int rc;

    uint32_t bit, bit_max;
    uint32_t group_blocks;
    uint16_t inode_size = ext4_get16(sb, inode_size);
    uint32_t block_size = ext4_sb_get_block_size(sb);
    uint32_t inodes_per_group = ext4_get32(sb, inodes_per_group);

    ext4_fsblk_t i;
    ext4_fsblk_t bmp_blk = ext4_bg_get_block_bitmap(bg, sb);
    ext4_fsblk_t bmp_inode = ext4_bg_get_inode_bitmap(bg, sb);
    ext4_fsblk_t inode_table = ext4_bg_get_inode_table_first_block(bg, sb);
    ext4_fsblk_t first_bg = ext4_balloc_get_block_of_bgid(sb, bg_ref->index);

    uint32_t dsc_per_block = block_size / ext4_sb_get_desc_size(sb);

    bool flex_bg = ext4_sb_feature_incom(sb, EXT4_FINCOM_FLEX_BG);
    bool meta_bg = ext4_sb_feature_incom(sb, EXT4_FINCOM_META_BG);

    uint32_t inode_table_bcnt = inodes_per_group * inode_size / block_size;

    struct ext4_block block_bitmap;
    rc = ext4_trans_block_get_noread(bg_ref->fs->bdev, &block_bitmap, bmp_blk);
    if (rc != EOK)
        return rc;

    memset(block_bitmap.data, 0, block_size);
    bit_max = ext4_sb_is_super_in_bg(sb, bg_ref->index);

    uint32_t count = ext4_sb_first_meta_bg(sb) * dsc_per_block;
    if (!meta_bg || bg_ref->index < count) {
        if (bit_max) {
            bit_max += ext4_bg_num_gdb(sb, bg_ref->index);
            bit_max += ext4_get16(sb, s_reserved_gdt_blocks);
        }
    } else { /* For META_BG_BLOCK_GROUPS */
        bit_max += ext4_bg_num_gdb(sb, bg_ref->index);
    }
    for (bit = 0; bit < bit_max; bit++)
        ext4_bmap_bit_set(block_bitmap.data, bit);

    if (bg_ref->index == ext4_block_group_cnt(sb) - 1) {
        /*
         * Even though mke2fs always initialize first and last group
         * if some other tool enabled the EXT4_BG_BLOCK_UNINIT we need
         * to make sure we calculate the right free blocks
         */

        group_blocks = (uint32_t) (ext4_sb_get_blocks_cnt(sb) - ext4_get32(sb, first_data_block) -
                                   ext4_get32(sb, blocks_per_group) * (ext4_block_group_cnt(sb) - 1));
    } else {
        group_blocks = ext4_get32(sb, blocks_per_group);
    }

    bool in_bg;
    in_bg = ext4_block_in_group(sb, bmp_blk, bg_ref->index);
    if (!flex_bg || in_bg)
        ext4_bmap_bit_set(block_bitmap.data, (uint32_t) (bmp_blk - first_bg));

    in_bg = ext4_block_in_group(sb, bmp_inode, bg_ref->index);
    if (!flex_bg || in_bg)
        ext4_bmap_bit_set(block_bitmap.data, (uint32_t) (bmp_inode - first_bg));

    for (i = inode_table; i < inode_table + inode_table_bcnt; i++) {
        in_bg = ext4_block_in_group(sb, i, bg_ref->index);
        if (!flex_bg || in_bg)
            ext4_bmap_bit_set(block_bitmap.data, (uint32_t) (i - first_bg));
    }
    /*
     * Also if the number of blocks within the group is
     * less than the blocksize * 8 ( which is the size
     * of bitmap ), set rest of the block bitmap to 1
     */
    ext4_fs_mark_bitmap_end(group_blocks, block_size * 8, block_bitmap.data);
    ext4_trans_set_block_dirty(block_bitmap.buf);

    ext4_balloc_set_bitmap_csum(sb, bg_ref->block_group, block_bitmap.data);
    bg_ref->dirty = true;

    /* Save bitmap */
    return ext4_block_set(bg_ref->fs->bdev, &block_bitmap);
}

static int ext4_fs_init_inode_bitmap(struct ext4_block_group_ref *bg_ref) {
    int rc;
    struct ext4_sblock *sb = &bg_ref->fs->sb;
    struct ext4_bgroup *bg = bg_ref->block_group;

    /* Load bitmap */
    ext4_fsblk_t bitmap_block_addr = ext4_bg_get_inode_bitmap(bg, sb);

    struct ext4_block b;
    rc = ext4_trans_block_get_noread(bg_ref->fs->bdev, &b, bitmap_block_addr);
    if (rc != EOK)
        return rc;

    /* Initialize all bitmap bits to zero */
    uint32_t block_size = ext4_sb_get_block_size(sb);
    uint32_t inodes_per_group = ext4_get32(sb, inodes_per_group);

    memset(b.data, 0, (inodes_per_group + 7) / 8);

    uint32_t start_bit = inodes_per_group;
    uint32_t end_bit = block_size * 8;

    uint32_t i;
    for (i = start_bit; i < ((start_bit + 7) & ~7UL); i++)
        ext4_bmap_bit_set(b.data, i);

    if (i < end_bit)
        memset(b.data + (i >> 3), 0xff, (end_bit - i) >> 3);

    ext4_trans_set_block_dirty(b.buf);

    ext4_ialloc_set_bitmap_csum(sb, bg, b.data);
    bg_ref->dirty = true;

    /* Save bitmap */
    return ext4_block_set(bg_ref->fs->bdev, &b);
}

static int ext4_fs_init_inode_table(struct ext4_block_group_ref *bg_ref) {
    struct ext4_sblock *sb = &bg_ref->fs->sb;
    struct ext4_bgroup *bg = bg_ref->block_group;

    uint32_t inode_size = ext4_get16(sb, inode_size);
    uint32_t block_size = ext4_sb_get_block_size(sb);
    uint32_t inodes_per_block = block_size / inode_size;
    uint32_t inodes_in_group = ext4_inodes_in_group_cnt(sb, bg_ref->index);
    uint32_t table_blocks = inodes_in_group / inodes_per_block;
    ext4_fsblk_t fblock;

    if (inodes_in_group % inodes_per_block)
        table_blocks++;

    /* Compute initialization bounds */
    ext4_fsblk_t first_block = ext4_bg_get_inode_table_first_block(bg, sb);

    ext4_fsblk_t last_block = first_block + table_blocks - 1;

    /* Initialization of all itable blocks */
    for (fblock = first_block; fblock <= last_block; ++fblock) {
        struct ext4_block b;
        int rc = ext4_trans_block_get_noread(bg_ref->fs->bdev, &b, fblock);
        if (rc != EOK)
            return rc;

        memset(b.data, 0, block_size);
        ext4_trans_set_block_dirty(b.buf);

        rc = ext4_block_set(bg_ref->fs->bdev, &b);
        if (rc != EOK)
            return rc;
    }

    return EOK;
}

static ext4_fsblk_t ext4_fs_get_descriptor_block(struct ext4_sblock *s, uint32_t bgid, uint32_t dsc_per_block) {
    uint32_t first_meta_bg, dsc_id;
    int has_super = 0;
    dsc_id = bgid / dsc_per_block;
    first_meta_bg = ext4_sb_first_meta_bg(s);

    bool meta_bg = ext4_sb_feature_incom(s, EXT4_FINCOM_META_BG);

    if (!meta_bg || dsc_id < first_meta_bg)
        return ext4_get32(s, first_data_block) + dsc_id + 1;

    if (ext4_sb_is_super_in_bg(s, bgid))
        has_super = 1;

    return (has_super + ext4_fs_first_bg_block_no(s, bgid));
}

static uint16_t ext4_fs_bg_checksum(struct ext4_sblock *sb, uint32_t bgid, struct ext4_bgroup *bg) {
    /* If checksum not supported, 0 will be returned */
    uint16_t crc = 0;
#if CONFIG_META_CSUM_ENABLE
    /* Compute the checksum only if the filesystem supports it */
    if (ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM)) {
        /* Use metadata_csum algorithm instead */
        uint32_t le32_bgid = to_le32(bgid);
        uint32_t orig_checksum, checksum;

        /* Preparation: temporarily set bg checksum to 0 */
        orig_checksum = bg->checksum;
        bg->checksum = 0;

        /* First calculate crc32 checksum against fs uuid */
        checksum = ext4_crc32c(EXT4_CRC32_INIT, sb->uuid, sizeof(sb->uuid));
        /* Then calculate crc32 checksum against bgid */
        checksum = ext4_crc32c(checksum, &le32_bgid, sizeof(bgid));
        /* Finally calculate crc32 checksum against block_group_desc */
        checksum = ext4_crc32c(checksum, bg, ext4_sb_get_desc_size(sb));
        bg->checksum = orig_checksum;

        crc = checksum & 0xFFFF;
        return crc;
    }
#endif
    if (ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_GDT_CSUM)) {
        uint8_t *base = (uint8_t *) bg;
        uint8_t *checksum = (uint8_t *) &bg->checksum;

        uint32_t offset = (uint32_t) (checksum - base);

        /* Convert block group index to little endian */
        uint32_t group = to_le32(bgid);

        /* Initialization */
        crc = ext4_bg_crc16(~0, sb->uuid, sizeof(sb->uuid));

        /* Include index of block group */
        crc = ext4_bg_crc16(crc, (uint8_t *) &group, sizeof(group));

        /* Compute crc from the first part (stop before checksum field)
         */
        crc = ext4_bg_crc16(crc, (uint8_t *) bg, offset);

        /* Skip checksum */
        offset += sizeof(bg->checksum);

        /* Checksum of the rest of block group descriptor */
        if ((ext4_sb_feature_incom(sb, EXT4_FINCOM_64BIT)) && (offset < ext4_sb_get_desc_size(sb))) {

            const uint8_t *start = ((uint8_t *) bg) + offset;
            size_t len = ext4_sb_get_desc_size(sb) - offset;
            crc = ext4_bg_crc16(crc, start, len);
        }
    }
    return crc;
}

static bool ext4_fs_verify_bg_csum(struct ext4_sblock *sb, uint32_t bgid, struct ext4_bgroup *bg) {
    if (!ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM))
        return true;

    return ext4_fs_bg_checksum(sb, bgid, bg) == to_le16(bg->checksum);
}

int ext4_fs_get_block_group_ref(struct ext4_fs *fs, uint32_t bgid, struct ext4_block_group_ref *ref) {
    /* Compute number of descriptors, that fits in one data block */
    uint32_t block_size = ext4_sb_get_block_size(&fs->sb);
    uint32_t dsc_cnt = block_size / ext4_sb_get_desc_size(&fs->sb);

    /* Block group descriptor table starts at the next block after
     * superblock */
    uint64_t block_id = ext4_fs_get_descriptor_block(&fs->sb, bgid, dsc_cnt);

    uint32_t offset = (bgid % dsc_cnt) * ext4_sb_get_desc_size(&fs->sb);

    int rc = ext4_trans_block_get(fs->bdev, &ref->block, block_id);
    if (rc != EOK)
        return rc;

    ref->block_group = (void *) (ref->block.data + offset);
    ref->fs = fs;
    ref->index = bgid;
    ref->dirty = false;
    struct ext4_bgroup *bg = ref->block_group;

    if (!ext4_fs_verify_bg_csum(&fs->sb, bgid, bg)) {
        ext4_dbg(DEBUG_FS,
                 DBG_WARN "Block group descriptor checksum failed."
                          "Block group index: %" PRIu32 "\n",
                 bgid);
    }

    if (ext4_bg_has_flag(bg, EXT4_BLOCK_GROUP_BLOCK_UNINIT)) {
        rc = ext4_fs_init_block_bitmap(ref);
        if (rc != EOK) {
            ext4_block_set(fs->bdev, &ref->block);
            return rc;
        }
        ext4_bg_clear_flag(bg, EXT4_BLOCK_GROUP_BLOCK_UNINIT);
        ref->dirty = true;
    }

    if (ext4_bg_has_flag(bg, EXT4_BLOCK_GROUP_INODE_UNINIT)) {
        rc = ext4_fs_init_inode_bitmap(ref);
        if (rc != EOK) {
            ext4_block_set(ref->fs->bdev, &ref->block);
            return rc;
        }

        ext4_bg_clear_flag(bg, EXT4_BLOCK_GROUP_INODE_UNINIT);

        if (!ext4_bg_has_flag(bg, EXT4_BLOCK_GROUP_ITABLE_ZEROED)) {
            rc = ext4_fs_init_inode_table(ref);
            if (rc != EOK) {
                ext4_block_set(fs->bdev, &ref->block);
                return rc;
            }

            ext4_bg_set_flag(bg, EXT4_BLOCK_GROUP_ITABLE_ZEROED);
        }

        ref->dirty = true;
    }

    return EOK;
}

int ext4_fs_put_block_group_ref(struct ext4_block_group_ref *ref) {
    /* Check if reference modified */
    if (ref->dirty) {
        /* Compute new checksum of block group */
        uint16_t cs;
        cs = ext4_fs_bg_checksum(&ref->fs->sb, ref->index, ref->block_group);
        ref->block_group->checksum = to_le16(cs);

        /* Mark block dirty for writing changes to physical device */
        ext4_trans_set_block_dirty(ref->block.buf);
    }

    /* Put back block, that contains block group descriptor */
    return ext4_block_set(ref->fs->bdev, &ref->block);
}

static uint32_t ext4_fs_inode_checksum(struct ext4_inode_ref *inode_ref) {
    uint32_t checksum = 0;
    struct ext4_sblock *sb = &inode_ref->fs->sb;
    uint16_t inode_size = ext4_get16(sb, inode_size);

    if (ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM)) {
        uint32_t orig_checksum;

        uint32_t ino_index = to_le32(inode_ref->index);
        uint32_t ino_gen = to_le32(ext4_inode_get_generation(inode_ref->inode));

        /* Preparation: temporarily set bg checksum to 0 */
        orig_checksum = ext4_inode_get_csum(sb, inode_ref->inode);
        ext4_inode_set_csum(sb, inode_ref->inode, 0);

        /* First calculate crc32 checksum against fs uuid */
        checksum = ext4_crc32c(EXT4_CRC32_INIT, sb->uuid, sizeof(sb->uuid));
        /* Then calculate crc32 checksum against inode number
         * and inode generation */
        checksum = ext4_crc32c(checksum, &ino_index, sizeof(ino_index));
        checksum = ext4_crc32c(checksum, &ino_gen, sizeof(ino_gen));
        /* Finally calculate crc32 checksum against
         * the entire inode */
        checksum = ext4_crc32c(checksum, inode_ref->inode, inode_size);
        ext4_inode_set_csum(sb, inode_ref->inode, orig_checksum);

        /* If inode size is not large enough to hold the
         * upper 16bit of the checksum */
        if (inode_size == EXT4_GOOD_OLD_INODE_SIZE)
            checksum &= 0xFFFF;
    }
    return checksum;
}

static void ext4_fs_set_inode_checksum(struct ext4_inode_ref *inode_ref) {
    struct ext4_sblock *sb = &inode_ref->fs->sb;
    if (!ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM))
        return;

    uint32_t csum = ext4_fs_inode_checksum(inode_ref);
    ext4_inode_set_csum(sb, inode_ref->inode, csum);
}

static bool ext4_fs_verify_inode_csum(struct ext4_inode_ref *inode_ref) {
    struct ext4_sblock *sb = &inode_ref->fs->sb;
    if (!ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM))
        return true;

    return ext4_inode_get_csum(sb, inode_ref->inode) == ext4_fs_inode_checksum(inode_ref);
}

static int __ext4_fs_get_inode_ref(struct ext4_fs *fs, uint32_t index, struct ext4_inode_ref *ref, bool initialized) {
    /* Compute number of i-nodes, that fits in one data block */
    uint32_t inodes_per_group = ext4_get32(&fs->sb, inodes_per_group);

    /*
     * Inode numbers are 1-based, but it is simpler to work with 0-based
     * when computing indices
     */
    index -= 1;
    uint32_t block_group = index / inodes_per_group;
    uint32_t offset_in_group = index % inodes_per_group;

    /* Load block group, where i-node is located */
    struct ext4_block_group_ref bg_ref;

    int rc = ext4_fs_get_block_group_ref(fs, block_group, &bg_ref);
    if (rc != EOK) {
        return rc;
    }

    /* Load block address, where i-node table is located */
    ext4_fsblk_t inode_table_start = ext4_bg_get_inode_table_first_block(bg_ref.block_group, &fs->sb);

    /* Put back block group reference (not needed more) */
    rc = ext4_fs_put_block_group_ref(&bg_ref);
    if (rc != EOK) {
        return rc;
    }

    /* Compute position of i-node in the block group */
    uint16_t inode_size = ext4_get16(&fs->sb, inode_size);
    uint32_t block_size = ext4_sb_get_block_size(&fs->sb);
    uint32_t byte_offset_in_group = offset_in_group * inode_size;

    /* Compute block address */
    ext4_fsblk_t block_id = inode_table_start + (byte_offset_in_group / block_size);

    rc = ext4_trans_block_get(fs->bdev, &ref->block, block_id);
    if (rc != EOK) {
        return rc;
    }

    /* Compute position of i-node in the data block */
    uint32_t offset_in_block = byte_offset_in_group % block_size;
    ref->inode = (struct ext4_inode *) (ref->block.data + offset_in_block);

    /* We need to store the original value of index in the reference */
    ref->index = index + 1;
    ref->fs = fs;
    ref->dirty = false;

    if (initialized && !ext4_fs_verify_inode_csum(ref)) {
        ext4_dbg(DEBUG_FS,
                 DBG_WARN "Inode checksum failed."
                          "Inode: %" PRIu32 "\n",
                 ref->index);
    }

    return EOK;
}

int ext4_fs_get_inode_ref(struct ext4_fs *fs, uint32_t index, struct ext4_inode_ref *ref) {
    return __ext4_fs_get_inode_ref(fs, index, ref, true);
}

int ext4_fs_put_inode_ref(struct ext4_inode_ref *ref) {
    /* Check if reference modified */
    if (ref->dirty) {
        /* Mark block dirty for writing changes to physical device */
        ext4_fs_set_inode_checksum(ref);
        ext4_trans_set_block_dirty(ref->block.buf);
    }

    /* Put back block, that contains i-node */
    return ext4_block_set(ref->fs->bdev, &ref->block);
}

void ext4_fs_inode_blocks_init(struct ext4_fs *fs, struct ext4_inode_ref *inode_ref) {
    struct ext4_inode *inode = inode_ref->inode;

    /* Reset blocks array. For inode which is not directory or file, just
     * fill in blocks with 0 */
    switch (ext4_inode_type(&fs->sb, inode_ref->inode)) {
        case EXT4_INODE_MODE_FILE:
        case EXT4_INODE_MODE_DIRECTORY:
            break;
        default:
            return;
    }

#if CONFIG_EXTENT_ENABLE && CONFIG_EXTENTS_ENABLE
    /* Initialize extents if needed */
    if (ext4_sb_feature_incom(&fs->sb, EXT4_FINCOM_EXTENTS)) {
        ext4_inode_set_flag(inode, EXT4_INODE_FLAG_EXTENTS);

        /* Initialize extent root header */
        ext4_extent_tree_init(inode_ref);
    }

    inode_ref->dirty = true;
#endif
}

uint32_t ext4_fs_correspond_inode_mode(int filetype) {
    switch (filetype) {
        case EXT4_DE_DIR:
            return EXT4_INODE_MODE_DIRECTORY;
        case EXT4_DE_REG_FILE:
            return EXT4_INODE_MODE_FILE;
        case EXT4_DE_SYMLINK:
            return EXT4_INODE_MODE_SOFTLINK;
        case EXT4_DE_CHRDEV:
            return EXT4_INODE_MODE_CHARDEV;
        case EXT4_DE_BLKDEV:
            return EXT4_INODE_MODE_BLOCKDEV;
        case EXT4_DE_FIFO:
            return EXT4_INODE_MODE_FIFO;
        case EXT4_DE_SOCK:
            return EXT4_INODE_MODE_SOCKET;
    }
    /* FIXME: unsupported filetype */
    return EXT4_INODE_MODE_FILE;
}

int ext4_fs_alloc_inode(struct ext4_fs *fs, struct ext4_inode_ref *inode_ref, int filetype) {
    /* Check if newly allocated i-node will be a directory */
    bool is_dir;
    uint16_t inode_size = ext4_get16(&fs->sb, inode_size);

    is_dir = (filetype == EXT4_DE_DIR);

    /* Allocate inode by allocation algorithm */
    uint32_t index;
    int rc = ext4_ialloc_alloc_inode(fs, &index, is_dir);
    if (rc != EOK)
        return rc;

    /* Load i-node from on-disk i-node table */
    rc = __ext4_fs_get_inode_ref(fs, index, inode_ref, false);
    if (rc != EOK) {
        ext4_ialloc_free_inode(fs, index, is_dir);
        return rc;
    }

    /* Initialize i-node */
    struct ext4_inode *inode = inode_ref->inode;

    memset(inode, 0, inode_size);

    uint32_t mode;
    if (is_dir) {
        /*
         * Default directory permissions to be compatible with other
         * systems
         * 0777 (octal) == rwxrwxrwx
         */

        mode = 0777;
        mode |= EXT4_INODE_MODE_DIRECTORY;
    } else if (filetype == EXT4_DE_SYMLINK) {
        /*
         * Default symbolic link permissions to be compatible with other systems
         * 0777 (octal) == rwxrwxrwx
         */

        mode = 0777;
        mode |= EXT4_INODE_MODE_SOFTLINK;
    } else {
        /*
         * Default file permissions to be compatible with other systems
         * 0666 (octal) == rw-rw-rw-
         */

        mode = 0666;
        mode |= ext4_fs_correspond_inode_mode(filetype);
    }
    ext4_inode_set_mode(&fs->sb, inode, mode);

    ext4_inode_set_links_cnt(inode, 0);
    ext4_inode_set_uid(inode, 0);
    ext4_inode_set_gid(inode, 0);
    ext4_inode_set_size(inode, 0);
    ext4_inode_set_access_time(inode, 0);
    ext4_inode_set_change_inode_time(inode, 0);
    ext4_inode_set_modif_time(inode, 0);
    ext4_inode_set_del_time(inode, 0);
    ext4_inode_set_blocks_count(&fs->sb, inode, 0);
    ext4_inode_set_flags(inode, 0);
    ext4_inode_set_generation(inode, 0);
    if (inode_size > EXT4_GOOD_OLD_INODE_SIZE) {
        uint16_t size = ext4_get16(&fs->sb, want_extra_isize);
        ext4_inode_set_extra_isize(&fs->sb, inode, size);
    }

    memset(inode->blocks, 0, sizeof(inode->blocks));
    inode_ref->dirty = true;

    return EOK;
}

int ext4_fs_free_inode(struct ext4_inode_ref *inode_ref) {
    struct ext4_fs *fs = inode_ref->fs;
    uint32_t offset;
    uint32_t suboff;
    int rc;
#if CONFIG_EXTENT_ENABLE && CONFIG_EXTENTS_ENABLE
    /* For extents must be data block destroyed by other way */
    if ((ext4_sb_feature_incom(&fs->sb, EXT4_FINCOM_EXTENTS)) &&
        (ext4_inode_has_flag(inode_ref->inode, EXT4_INODE_FLAG_EXTENTS))) {
        /* Data structures are released during truncate operation... */
        goto finish;
    }
#endif
    /* Release all indirect (no data) blocks */

    /* 1) Single indirect */
    ext4_fsblk_t fblock = ext4_inode_get_indirect_block(inode_ref->inode, 0);
    if (fblock != 0) {
        int rc = ext4_balloc_free_block(inode_ref, fblock);
        if (rc != EOK)
            return rc;

        ext4_inode_set_indirect_block(inode_ref->inode, 0, 0);
    }

    uint32_t block_size = ext4_sb_get_block_size(&fs->sb);
    uint32_t count = block_size / sizeof(uint32_t);

    struct ext4_block block;

    /* 2) Double indirect */
    fblock = ext4_inode_get_indirect_block(inode_ref->inode, 1);
    if (fblock != 0) {
        int rc = ext4_trans_block_get(fs->bdev, &block, fblock);
        if (rc != EOK)
            return rc;

        ext4_fsblk_t ind_block;
        for (offset = 0; offset < count; ++offset) {
            ind_block = to_le32(((uint32_t *) block.data)[offset]);

            if (ind_block == 0)
                continue;
            rc = ext4_balloc_free_block(inode_ref, ind_block);
            if (rc != EOK) {
                ext4_block_set(fs->bdev, &block);
                return rc;
            }
        }

        ext4_block_set(fs->bdev, &block);
        rc = ext4_balloc_free_block(inode_ref, fblock);
        if (rc != EOK)
            return rc;

        ext4_inode_set_indirect_block(inode_ref->inode, 1, 0);
    }

    /* 3) Tripple indirect */
    struct ext4_block subblock;
    fblock = ext4_inode_get_indirect_block(inode_ref->inode, 2);
    if (fblock == 0)
        goto finish;
    rc = ext4_trans_block_get(fs->bdev, &block, fblock);
    if (rc != EOK)
        return rc;

    ext4_fsblk_t ind_block;
    for (offset = 0; offset < count; ++offset) {
        ind_block = to_le32(((uint32_t *) block.data)[offset]);

        if (ind_block == 0)
            continue;
        rc = ext4_trans_block_get(fs->bdev, &subblock, ind_block);
        if (rc != EOK) {
            ext4_block_set(fs->bdev, &block);
            return rc;
        }

        ext4_fsblk_t ind_subblk;
        for (suboff = 0; suboff < count; ++suboff) {
            ind_subblk = to_le32(((uint32_t *) subblock.data)[suboff]);

            if (ind_subblk == 0)
                continue;
            rc = ext4_balloc_free_block(inode_ref, ind_subblk);
            if (rc != EOK) {
                ext4_block_set(fs->bdev, &subblock);
                ext4_block_set(fs->bdev, &block);
                return rc;
            }
        }

        ext4_block_set(fs->bdev, &subblock);

        rc = ext4_balloc_free_block(inode_ref, ind_block);
        if (rc != EOK) {
            ext4_block_set(fs->bdev, &block);
            return rc;
        }
    }

    ext4_block_set(fs->bdev, &block);
    rc = ext4_balloc_free_block(inode_ref, fblock);
    if (rc != EOK)
        return rc;

    ext4_inode_set_indirect_block(inode_ref->inode, 2, 0);
finish:
    /* Mark inode dirty for writing to the physical device */
    inode_ref->dirty = true;

    /* Free block with extended attributes if present */
    ext4_fsblk_t xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);
    if (xattr_block) {
        int rc = ext4_balloc_free_block(inode_ref, xattr_block);
        if (rc != EOK)
            return rc;

        ext4_inode_set_file_acl(inode_ref->inode, &fs->sb, 0);
    }

    /* Free inode by allocator */
    if (ext4_inode_is_type(&fs->sb, inode_ref->inode, EXT4_INODE_MODE_DIRECTORY))
        rc = ext4_ialloc_free_inode(fs, inode_ref->index, true);
    else
        rc = ext4_ialloc_free_inode(fs, inode_ref->index, false);

    return rc;
}

static int ext4_fs_release_inode_block(struct ext4_inode_ref *inode_ref, ext4_lblk_t iblock) {
    ext4_fsblk_t fblock;

    struct ext4_fs *fs = inode_ref->fs;

    /* Extents are handled otherwise = there is not support in this function
     */
    ext4_assert(!(ext4_sb_feature_incom(&fs->sb, EXT4_FINCOM_EXTENTS) &&
                  (ext4_inode_has_flag(inode_ref->inode, EXT4_INODE_FLAG_EXTENTS))));

    struct ext4_inode *inode = inode_ref->inode;

    /* Handle simple case when we are dealing with direct reference */
    if (iblock < EXT4_INODE_DIRECT_BLOCK_COUNT) {
        fblock = ext4_inode_get_direct_block(inode, iblock);

        /* Sparse file */
        if (fblock == 0)
            return EOK;

        ext4_inode_set_direct_block(inode, iblock, 0);
        return ext4_balloc_free_block(inode_ref, fblock);
    }

    /* Determine the indirection level needed to get the desired block */
    unsigned int level = 0;
    unsigned int i;
    for (i = 1; i < 4; i++) {
        if (iblock < fs->inode_block_limits[i]) {
            level = i;
            break;
        }
    }

    if (level == 0)
        return EIO;

    /* Compute offsets for the topmost level */
    uint32_t block_offset_in_level = (uint32_t) (iblock - fs->inode_block_limits[level - 1]);
    ext4_fsblk_t current_block = ext4_inode_get_indirect_block(inode, level - 1);
    uint32_t offset_in_block = (uint32_t) (block_offset_in_level / fs->inode_blocks_per_level[level - 1]);

    /*
     * Navigate through other levels, until we find the block number
     * or find null reference meaning we are dealing with sparse file
     */
    struct ext4_block block;

    while (level > 0) {

        /* Sparse check */
        if (current_block == 0)
            return EOK;

        int rc = ext4_trans_block_get(fs->bdev, &block, current_block);
        if (rc != EOK)
            return rc;

        current_block = to_le32(((uint32_t *) block.data)[offset_in_block]);

        /* Set zero if physical data block address found */
        if (level == 1) {
            ((uint32_t *) block.data)[offset_in_block] = to_le32(0);
            ext4_trans_set_block_dirty(block.buf);
        }

        rc = ext4_block_set(fs->bdev, &block);
        if (rc != EOK)
            return rc;

        level--;

        /*
         * If we are on the last level, break here as
         * there is no next level to visit
         */
        if (level == 0)
            break;

        /* Visit the next level */
        block_offset_in_level %= fs->inode_blocks_per_level[level];
        offset_in_block = (uint32_t) (block_offset_in_level / fs->inode_blocks_per_level[level - 1]);
    }

    fblock = current_block;
    if (fblock == 0)
        return EOK;

    /* Physical block is not referenced, it can be released */
    return ext4_balloc_free_block(inode_ref, fblock);
}

int ext4_fs_truncate_inode(struct ext4_inode_ref *inode_ref, uint64_t new_size) {
    struct ext4_sblock *sb = &inode_ref->fs->sb;
    uint32_t i;
    int r;
    bool v;

    /* Check flags, if i-node can be truncated */
    if (!ext4_inode_can_truncate(sb, inode_ref->inode))
        return EINVAL;

    /* If sizes are equal, nothing has to be done. */
    uint64_t old_size = ext4_inode_get_size(sb, inode_ref->inode);
    if (old_size == new_size)
        return EOK;

    /* It's not supported to make the larger file by truncate operation */
    if (old_size < new_size)
        return EINVAL;

    /* For symbolic link which is small enough */
    v = ext4_inode_is_type(sb, inode_ref->inode, EXT4_INODE_MODE_SOFTLINK);
    if (v && old_size < sizeof(inode_ref->inode->blocks) && !ext4_inode_get_blocks_count(sb, inode_ref->inode)) {
        char *content = (char *) inode_ref->inode->blocks + new_size;
        memset(content, 0, sizeof(inode_ref->inode->blocks) - (uint32_t) new_size);
        ext4_inode_set_size(inode_ref->inode, new_size);
        inode_ref->dirty = true;

        return EOK;
    }

    i = ext4_inode_type(sb, inode_ref->inode);
    if (i == EXT4_INODE_MODE_CHARDEV || i == EXT4_INODE_MODE_BLOCKDEV || i == EXT4_INODE_MODE_SOCKET) {
        inode_ref->inode->blocks[0] = 0;
        inode_ref->inode->blocks[1] = 0;

        inode_ref->dirty = true;
        return EOK;
    }

    /* Compute how many blocks will be released */
    uint32_t block_size = ext4_sb_get_block_size(sb);
    uint32_t new_blocks_cnt = (uint32_t) ((new_size + block_size - 1) / block_size);
    uint32_t old_blocks_cnt = (uint32_t) ((old_size + block_size - 1) / block_size);
    uint32_t diff_blocks_cnt = old_blocks_cnt - new_blocks_cnt;
#if CONFIG_EXTENT_ENABLE && CONFIG_EXTENTS_ENABLE
    if ((ext4_sb_feature_incom(sb, EXT4_FINCOM_EXTENTS)) &&
        (ext4_inode_has_flag(inode_ref->inode, EXT4_INODE_FLAG_EXTENTS))) {

        /* Extents require special operation */
        if (diff_blocks_cnt) {
            r = ext4_extent_remove_space(inode_ref, new_blocks_cnt, EXT_MAX_BLOCKS);
            if (r != EOK)
                return r;
        }
    } else
#endif
    {
        /* Release data blocks from the end of file */

        /* Starting from 1 because of logical blocks are numbered from 0
         */
        for (i = 0; i < diff_blocks_cnt; ++i) {
            r = ext4_fs_release_inode_block(inode_ref, new_blocks_cnt + i);
            if (r != EOK)
                return r;
        }
    }

    /* Update i-node */
    ext4_inode_set_size(inode_ref->inode, new_size);
    inode_ref->dirty = true;

    return EOK;
}

ext4_fsblk_t ext4_fs_inode_to_goal_block(struct ext4_inode_ref *inode_ref) {
    uint32_t grp_inodes = ext4_get32(&inode_ref->fs->sb, inodes_per_group);
    return (inode_ref->index - 1) / grp_inodes;
}

int ext4_fs_indirect_find_goal(struct ext4_inode_ref *inode_ref, ext4_fsblk_t *goal) {
    int r;
    struct ext4_sblock *sb = &inode_ref->fs->sb;
    *goal = 0;

    uint64_t inode_size = ext4_inode_get_size(sb, inode_ref->inode);
    uint32_t block_size = ext4_sb_get_block_size(sb);
    uint32_t iblock_cnt = (uint32_t) (inode_size / block_size);

    if (inode_size % block_size != 0)
        iblock_cnt++;

    /* If inode has some blocks, get last block address + 1 */
    if (iblock_cnt > 0) {
        r = ext4_fs_get_inode_dblk_idx(inode_ref, iblock_cnt - 1, goal, false);
        if (r != EOK)
            return r;

        if (*goal != 0) {
            (*goal)++;
            return r;
        }

        /* If goal == 0, sparse file -> continue */
    }

    /* Identify block group of inode */

    uint32_t inodes_per_bg = ext4_get32(sb, inodes_per_group);
    uint32_t block_group = (inode_ref->index - 1) / inodes_per_bg;
    block_size = ext4_sb_get_block_size(sb);

    /* Load block group reference */
    struct ext4_block_group_ref bg_ref;
    r = ext4_fs_get_block_group_ref(inode_ref->fs, block_group, &bg_ref);
    if (r != EOK)
        return r;

    struct ext4_bgroup *bg = bg_ref.block_group;

    /* Compute indexes */
    uint32_t bg_count = ext4_block_group_cnt(sb);
    ext4_fsblk_t itab_first_block = ext4_bg_get_inode_table_first_block(bg, sb);
    uint16_t itab_item_size = ext4_get16(sb, inode_size);
    uint32_t itab_bytes;

    /* Check for last block group */
    if (block_group < bg_count - 1) {
        itab_bytes = inodes_per_bg * itab_item_size;
    } else {
        /* Last block group could be smaller */
        uint32_t inodes_cnt = ext4_get32(sb, inodes_count);

        itab_bytes = (inodes_cnt - ((bg_count - 1) * inodes_per_bg));
        itab_bytes *= itab_item_size;
    }

    ext4_fsblk_t inode_table_blocks = itab_bytes / block_size;

    if (itab_bytes % block_size)
        inode_table_blocks++;

    *goal = itab_first_block + inode_table_blocks;

    return ext4_fs_put_block_group_ref(&bg_ref);
}

static int ext4_fs_get_inode_dblk_idx_internal(struct ext4_inode_ref *inode_ref, ext4_lblk_t iblock,
                                               ext4_fsblk_t *fblock, bool extent_create,
                                               bool support_unwritten __unused) {
    struct ext4_fs *fs = inode_ref->fs;

    /* For empty file is situation simple */
    if (ext4_inode_get_size(&fs->sb, inode_ref->inode) == 0) {
        *fblock = 0;
        return EOK;
    }

    ext4_fsblk_t current_block;

    (void) extent_create;
#if CONFIG_EXTENT_ENABLE && CONFIG_EXTENTS_ENABLE
    /* Handle i-node using extents */
    if ((ext4_sb_feature_incom(&fs->sb, EXT4_FINCOM_EXTENTS)) &&
        (ext4_inode_has_flag(inode_ref->inode, EXT4_INODE_FLAG_EXTENTS))) {

        ext4_fsblk_t current_fsblk;
        int rc = ext4_extent_get_blocks(inode_ref, iblock, 1, &current_fsblk, extent_create, NULL);
        if (rc != EOK)
            return rc;

        current_block = current_fsblk;
        *fblock = current_block;

        ext4_assert(*fblock || support_unwritten);
        return EOK;
    }
#endif

    struct ext4_inode *inode = inode_ref->inode;

    /* Direct block are read directly from array in i-node structure */
    if (iblock < EXT4_INODE_DIRECT_BLOCK_COUNT) {
        current_block = ext4_inode_get_direct_block(inode, (uint32_t) iblock);
        *fblock = current_block;
        return EOK;
    }

    /* Determine indirection level of the target block */
    unsigned int l = 0;
    unsigned int i;
    for (i = 1; i < 4; i++) {
        if (iblock < fs->inode_block_limits[i]) {
            l = i;
            break;
        }
    }

    if (l == 0)
        return EIO;

    /* Compute offsets for the topmost level */
    uint32_t blk_off_in_lvl = (uint32_t) (iblock - fs->inode_block_limits[l - 1]);
    current_block = ext4_inode_get_indirect_block(inode, l - 1);
    uint32_t off_in_blk = (uint32_t) (blk_off_in_lvl / fs->inode_blocks_per_level[l - 1]);

    /* Sparse file */
    if (current_block == 0) {
        *fblock = 0;
        return EOK;
    }

    struct ext4_block block;

    /*
     * Navigate through other levels, until we find the block number
     * or find null reference meaning we are dealing with sparse file
     */
    while (l > 0) {
        /* Load indirect block */
        int rc = ext4_trans_block_get(fs->bdev, &block, current_block);
        if (rc != EOK)
            return rc;

        /* Read block address from indirect block */
        current_block = to_le32(((uint32_t *) block.data)[off_in_blk]);

        /* Put back indirect block untouched */
        rc = ext4_block_set(fs->bdev, &block);
        if (rc != EOK)
            return rc;

        /* Check for sparse file */
        if (current_block == 0) {
            *fblock = 0;
            return EOK;
        }

        /* Jump to the next level */
        l--;

        /* Termination condition - we have address of data block loaded
         */
        if (l == 0)
            break;

        /* Visit the next level */
        blk_off_in_lvl %= fs->inode_blocks_per_level[l];
        off_in_blk = (uint32_t) (blk_off_in_lvl / fs->inode_blocks_per_level[l - 1]);
    }

    *fblock = current_block;

    return EOK;
}

int ext4_fs_get_inode_dblk_idx(struct ext4_inode_ref *inode_ref, ext4_lblk_t iblock, ext4_fsblk_t *fblock,
                               bool support_unwritten) {
    return ext4_fs_get_inode_dblk_idx_internal(inode_ref, iblock, fblock, false, support_unwritten);
}

int ext4_fs_init_inode_dblk_idx(struct ext4_inode_ref *inode_ref, ext4_lblk_t iblock, ext4_fsblk_t *fblock) {
    return ext4_fs_get_inode_dblk_idx_internal(inode_ref, iblock, fblock, true, true);
}

static int ext4_fs_set_inode_data_block_index(struct ext4_inode_ref *inode_ref, ext4_lblk_t iblock,
                                              ext4_fsblk_t fblock) {
    struct ext4_fs *fs = inode_ref->fs;

#if CONFIG_EXTENT_ENABLE && CONFIG_EXTENTS_ENABLE
    /* Handle inode using extents */
    if ((ext4_sb_feature_incom(&fs->sb, EXT4_FINCOM_EXTENTS)) &&
        (ext4_inode_has_flag(inode_ref->inode, EXT4_INODE_FLAG_EXTENTS))) {
        /* Not reachable */
        return ENOTSUP;
    }
#endif

    /* Handle simple case when we are dealing with direct reference */
    if (iblock < EXT4_INODE_DIRECT_BLOCK_COUNT) {
        ext4_inode_set_direct_block(inode_ref->inode, (uint32_t) iblock, (uint32_t) fblock);
        inode_ref->dirty = true;

        return EOK;
    }

    /* Determine the indirection level needed to get the desired block */
    unsigned int l = 0;
    unsigned int i;
    for (i = 1; i < 4; i++) {
        if (iblock < fs->inode_block_limits[i]) {
            l = i;
            break;
        }
    }

    if (l == 0)
        return EIO;

    uint32_t block_size = ext4_sb_get_block_size(&fs->sb);

    /* Compute offsets for the topmost level */
    uint32_t blk_off_in_lvl = (uint32_t) (iblock - fs->inode_block_limits[l - 1]);
    ext4_fsblk_t current_block = ext4_inode_get_indirect_block(inode_ref->inode, l - 1);
    uint32_t off_in_blk = (uint32_t) (blk_off_in_lvl / fs->inode_blocks_per_level[l - 1]);

    ext4_fsblk_t new_blk;

    struct ext4_block block;
    struct ext4_block new_block;

    /* Is needed to allocate indirect block on the i-node level */
    if (current_block == 0) {
        /* Allocate new indirect block */
        ext4_fsblk_t goal;
        int rc = ext4_fs_indirect_find_goal(inode_ref, &goal);
        if (rc != EOK)
            return rc;

        rc = ext4_balloc_alloc_block(inode_ref, goal, &new_blk);
        if (rc != EOK)
            return rc;

        /* Update i-node */
        ext4_inode_set_indirect_block(inode_ref->inode, l - 1, (uint32_t) new_blk);
        inode_ref->dirty = true;

        /* Load newly allocated block */
        rc = ext4_trans_block_get_noread(fs->bdev, &new_block, new_blk);
        if (rc != EOK) {
            ext4_balloc_free_block(inode_ref, new_blk);
            return rc;
        }

        /* Initialize new block */
        memset(new_block.data, 0, block_size);
        ext4_trans_set_block_dirty(new_block.buf);

        /* Put back the allocated block */
        rc = ext4_block_set(fs->bdev, &new_block);
        if (rc != EOK)
            return rc;

        current_block = new_blk;
    }

    /*
     * Navigate through other levels, until we find the block number
     * or find null reference meaning we are dealing with sparse file
     */
    while (l > 0) {
        int rc = ext4_trans_block_get(fs->bdev, &block, current_block);
        if (rc != EOK)
            return rc;

        current_block = to_le32(((uint32_t *) block.data)[off_in_blk]);
        if ((l > 1) && (current_block == 0)) {
            ext4_fsblk_t goal;
            rc = ext4_fs_indirect_find_goal(inode_ref, &goal);
            if (rc != EOK) {
                ext4_block_set(fs->bdev, &block);
                return rc;
            }

            /* Allocate new block */
            rc = ext4_balloc_alloc_block(inode_ref, goal, &new_blk);
            if (rc != EOK) {
                ext4_block_set(fs->bdev, &block);
                return rc;
            }

            /* Load newly allocated block */
            rc = ext4_trans_block_get_noread(fs->bdev, &new_block, new_blk);

            if (rc != EOK) {
                ext4_block_set(fs->bdev, &block);
                return rc;
            }

            /* Initialize allocated block */
            memset(new_block.data, 0, block_size);
            ext4_trans_set_block_dirty(new_block.buf);

            rc = ext4_block_set(fs->bdev, &new_block);
            if (rc != EOK) {
                ext4_block_set(fs->bdev, &block);
                return rc;
            }

            /* Write block address to the parent */
            uint32_t *p = (uint32_t *) block.data;
            p[off_in_blk] = to_le32((uint32_t) new_blk);
            ext4_trans_set_block_dirty(block.buf);
            current_block = new_blk;
        }

        /* Will be finished, write the fblock address */
        if (l == 1) {
            uint32_t *p = (uint32_t *) block.data;
            p[off_in_blk] = to_le32((uint32_t) fblock);
            ext4_trans_set_block_dirty(block.buf);
        }

        rc = ext4_block_set(fs->bdev, &block);
        if (rc != EOK)
            return rc;

        l--;

        /*
         * If we are on the last level, break here as
         * there is no next level to visit
         */
        if (l == 0)
            break;

        /* Visit the next level */
        blk_off_in_lvl %= fs->inode_blocks_per_level[l];
        off_in_blk = (uint32_t) (blk_off_in_lvl / fs->inode_blocks_per_level[l - 1]);
    }

    return EOK;
}

int ext4_fs_append_inode_dblk(struct ext4_inode_ref *inode_ref, ext4_fsblk_t *fblock, ext4_lblk_t *iblock) {
#if CONFIG_EXTENT_ENABLE && CONFIG_EXTENTS_ENABLE
    /* Handle extents separately */
    if ((ext4_sb_feature_incom(&inode_ref->fs->sb, EXT4_FINCOM_EXTENTS)) &&
        (ext4_inode_has_flag(inode_ref->inode, EXT4_INODE_FLAG_EXTENTS))) {
        int rc;
        ext4_fsblk_t current_fsblk;
        struct ext4_sblock *sb = &inode_ref->fs->sb;
        uint64_t inode_size = ext4_inode_get_size(sb, inode_ref->inode);
        uint32_t block_size = ext4_sb_get_block_size(sb);
        *iblock = (uint32_t) ((inode_size + block_size - 1) / block_size);

        rc = ext4_extent_get_blocks(inode_ref, *iblock, 1, &current_fsblk, true, NULL);
        if (rc != EOK)
            return rc;

        *fblock = current_fsblk;
        ext4_assert(*fblock);

        ext4_inode_set_size(inode_ref->inode, inode_size + block_size);
        inode_ref->dirty = true;


        return rc;
    }
#endif
    struct ext4_sblock *sb = &inode_ref->fs->sb;

    /* Compute next block index and allocate data block */
    uint64_t inode_size = ext4_inode_get_size(sb, inode_ref->inode);
    uint32_t block_size = ext4_sb_get_block_size(sb);

    /* Align size i-node size */
    if ((inode_size % block_size) != 0)
        inode_size += block_size - (inode_size % block_size);

    /* Logical blocks are numbered from 0 */
    uint32_t new_block_idx = (uint32_t) (inode_size / block_size);

    /* Allocate new physical block */
    ext4_fsblk_t goal, phys_block;
    int rc = ext4_fs_indirect_find_goal(inode_ref, &goal);
    if (rc != EOK)
        return rc;

    rc = ext4_balloc_alloc_block(inode_ref, goal, &phys_block);
    if (rc != EOK)
        return rc;

    /* Add physical block address to the i-node */
    rc = ext4_fs_set_inode_data_block_index(inode_ref, new_block_idx, phys_block);
    if (rc != EOK) {
        ext4_balloc_free_block(inode_ref, phys_block);
        return rc;
    }

    /* Update i-node */
    ext4_inode_set_size(inode_ref->inode, inode_size + block_size);
    inode_ref->dirty = true;

    *fblock = phys_block;
    *iblock = new_block_idx;

    return EOK;
}

void ext4_fs_inode_links_count_inc(struct ext4_inode_ref *inode_ref) {
    uint16_t link;
    bool is_dx;
    link = ext4_inode_get_links_cnt(inode_ref->inode);
    link++;
    ext4_inode_set_links_cnt(inode_ref->inode, link);

    is_dx = ext4_sb_feature_com(&inode_ref->fs->sb, EXT4_FCOM_DIR_INDEX) &&
            ext4_inode_has_flag(inode_ref->inode, EXT4_INODE_FLAG_INDEX);

    if (is_dx && link > 1) {
        if (link >= EXT4_LINK_MAX || link == 2) {
            ext4_inode_set_links_cnt(inode_ref->inode, 1);

            uint32_t v;
            v = ext4_get32(&inode_ref->fs->sb, features_read_only);
            v |= EXT4_FRO_COM_DIR_NLINK;
            ext4_set32(&inode_ref->fs->sb, features_read_only, v);
        }
    }
}

void ext4_fs_inode_links_count_dec(struct ext4_inode_ref *inode_ref) {
    uint16_t links = ext4_inode_get_links_cnt(inode_ref->inode);
    if (!ext4_inode_is_type(&inode_ref->fs->sb, inode_ref->inode, EXT4_INODE_MODE_DIRECTORY)) {
        if (links > 0)
            ext4_inode_set_links_cnt(inode_ref->inode, links - 1);
        return;
    }

    if (links > 2)
        ext4_inode_set_links_cnt(inode_ref->inode, links - 1);
}

static void ext2_half_md4(uint32_t hash[4], uint32_t data[8]) {
    uint32_t a = hash[0], b = hash[1], c = hash[2], d = hash[3];

    /* Round 1 */
    FF(a, b, c, d, data[0], 3);
    FF(d, a, b, c, data[1], 7);
    FF(c, d, a, b, data[2], 11);
    FF(b, c, d, a, data[3], 19);
    FF(a, b, c, d, data[4], 3);
    FF(d, a, b, c, data[5], 7);
    FF(c, d, a, b, data[6], 11);
    FF(b, c, d, a, data[7], 19);

    /* Round 2 */
    GG(a, b, c, d, data[1], 3);
    GG(d, a, b, c, data[3], 5);
    GG(c, d, a, b, data[5], 9);
    GG(b, c, d, a, data[7], 13);
    GG(a, b, c, d, data[0], 3);
    GG(d, a, b, c, data[2], 5);
    GG(c, d, a, b, data[4], 9);
    GG(b, c, d, a, data[6], 13);

    /* Round 3 */
    HH(a, b, c, d, data[3], 3);
    HH(d, a, b, c, data[7], 9);
    HH(c, d, a, b, data[2], 11);
    HH(b, c, d, a, data[6], 15);
    HH(a, b, c, d, data[1], 3);
    HH(d, a, b, c, data[5], 9);
    HH(c, d, a, b, data[0], 11);
    HH(b, c, d, a, data[4], 15);

    hash[0] += a;
    hash[1] += b;
    hash[2] += c;
    hash[3] += d;
}

static void ext2_tea(uint32_t hash[4], uint32_t data[8]) {
    uint32_t tea_delta = 0x9E3779B9;
    uint32_t sum;
    uint32_t x = hash[0], y = hash[1];
    int n = 16;
    int i = 1;

    while (n-- > 0) {
        sum = i * tea_delta;
        x += ((y << 4) + data[0]) ^ (y + sum) ^ ((y >> 5) + data[1]);
        y += ((x << 4) + data[2]) ^ (x + sum) ^ ((x >> 5) + data[3]);
        i++;
    }

    hash[0] += x;
    hash[1] += y;
}

static uint32_t ext2_legacy_hash(const char *name, int len, int unsigned_char) {
    uint32_t h0, h1 = 0x12A3FE2D, h2 = 0x37ABE8F9;
    uint32_t multi = 0x6D22F5;
    const unsigned char *uname = (const unsigned char *) name;
    const signed char *sname = (const signed char *) name;
    int val, i;

    for (i = 0; i < len; i++) {
        if (unsigned_char)
            val = (unsigned int) *uname++;
        else
            val = (int) *sname++;

        h0 = h2 + (h1 ^ (val * multi));
        if (h0 & 0x80000000)
            h0 -= 0x7FFFFFFF;
        h2 = h1;
        h1 = h0;
    }

    return (h1 << 1);
}

static void ext2_prep_hashbuf(const char *src, uint32_t slen, uint32_t *dst, int dlen, int unsigned_char) {
    uint32_t padding = slen | (slen << 8) | (slen << 16) | (slen << 24);
    uint32_t buf_val;
    int len, i;
    int buf_byte;
    const unsigned char *ubuf = (const unsigned char *) src;
    const signed char *sbuf = (const signed char *) src;

    if (slen > (uint32_t) dlen)
        len = dlen;
    else
        len = slen;

    buf_val = padding;

    for (i = 0; i < len; i++) {
        if (unsigned_char)
            buf_byte = (unsigned int) ubuf[i];
        else
            buf_byte = (int) sbuf[i];

        if ((i % 4) == 0)
            buf_val = padding;

        buf_val <<= 8;
        buf_val += buf_byte;

        if ((i % 4) == 3) {
            *dst++ = buf_val;
            dlen -= sizeof(uint32_t);
            buf_val = padding;
        }
    }

    dlen -= sizeof(uint32_t);
    if (dlen >= 0)
        *dst++ = buf_val;

    dlen -= sizeof(uint32_t);
    while (dlen >= 0) {
        *dst++ = padding;
        dlen -= sizeof(uint32_t);
    }
}

int ext2_htree_hash(const char *name, int len, const uint32_t *hash_seed, int hash_version, uint32_t *hash_major,
                    uint32_t *hash_minor) {
    uint32_t hash[4];
    uint32_t data[8];
    uint32_t major = 0, minor = 0;
    int unsigned_char = 0;

    if (!name || !hash_major)
        return (-1);

    if (len < 1 || len > 255)
        goto error;

    hash[0] = 0x67452301;
    hash[1] = 0xEFCDAB89;
    hash[2] = 0x98BADCFE;
    hash[3] = 0x10325476;

    if (hash_seed)
        memcpy(hash, hash_seed, sizeof(hash));

    switch (hash_version) {
        case EXT2_HTREE_TEA_UNSIGNED:
            unsigned_char = 1;
            /* FALLTHRU */
        case EXT2_HTREE_TEA:
            while (len > 0) {
                ext2_prep_hashbuf(name, len, data, 16, unsigned_char);
                ext2_tea(hash, data);
                len -= 16;
                name += 16;
            }
            major = hash[0];
            minor = hash[1];
            break;
        case EXT2_HTREE_LEGACY_UNSIGNED:
            unsigned_char = 1;
            /* FALLTHRU */
        case EXT2_HTREE_LEGACY:
            major = ext2_legacy_hash(name, len, unsigned_char);
            break;
        case EXT2_HTREE_HALF_MD4_UNSIGNED:
            unsigned_char = 1;
            /* FALLTHRU */
        case EXT2_HTREE_HALF_MD4:
            while (len > 0) {
                ext2_prep_hashbuf(name, len, data, 32, unsigned_char);
                ext2_half_md4(hash, data);
                len -= 32;
                name += 32;
            }
            major = hash[1];
            minor = hash[2];
            break;
        default:
            goto error;
    }

    major &= ~1;
    if (major == (EXT2_HTREE_EOF << 1))
        major = (EXT2_HTREE_EOF - 1) << 1;
    *hash_major = major;
    if (hash_minor)
        *hash_minor = minor;

    return EOK;

error:
    *hash_major = 0;
    if (hash_minor)
        *hash_minor = 0;
    return ENOTSUP;
}

static uint32_t ext4_ialloc_inode_to_bgidx(struct ext4_sblock *sb, uint32_t inode) {
    uint32_t inodes_per_group = ext4_get32(sb, inodes_per_group);
    return (inode - 1) % inodes_per_group;
}

static uint32_t ext4_ialloc_bgidx_to_inode(struct ext4_sblock *sb, uint32_t index, uint32_t bgid) {
    uint32_t inodes_per_group = ext4_get32(sb, inodes_per_group);
    return bgid * inodes_per_group + (index + 1);
}

static uint32_t ext4_ialloc_get_bgid_of_inode(struct ext4_sblock *sb, uint32_t inode) {
    uint32_t inodes_per_group = ext4_get32(sb, inodes_per_group);
    return (inode - 1) / inodes_per_group;
}

static uint32_t ext4_ialloc_bitmap_csum(struct ext4_sblock *sb, void *bitmap) {
    uint32_t csum = 0;
    if (ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM)) {
        uint32_t inodes_per_group = ext4_get32(sb, inodes_per_group);

        /* First calculate crc32 checksum against fs uuid */
        csum = ext4_crc32c(EXT4_CRC32_INIT, sb->uuid, sizeof(sb->uuid));
        /* Then calculate crc32 checksum against inode bitmap */
        csum = ext4_crc32c(csum, bitmap, (inodes_per_group + 7) / 8);
    }
    return csum;
}

void ext4_ialloc_set_bitmap_csum(struct ext4_sblock *sb, struct ext4_bgroup *bg, void *bitmap __unused) {
    int desc_size = ext4_sb_get_desc_size(sb);
    uint32_t csum = ext4_ialloc_bitmap_csum(sb, bitmap);
    uint16_t lo_csum = to_le16(csum & 0xFFFF), hi_csum = to_le16(csum >> 16);

    if (!ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM))
        return;

    /* See if we need to assign a 32bit checksum */
    bg->inode_bitmap_csum_lo = lo_csum;
    if (desc_size == EXT4_MAX_BLOCK_GROUP_DESCRIPTOR_SIZE)
        bg->inode_bitmap_csum_hi = hi_csum;
}

static bool ext4_ialloc_verify_bitmap_csum(struct ext4_sblock *sb, struct ext4_bgroup *bg, void *bitmap __unused) {

    int desc_size = ext4_sb_get_desc_size(sb);
    uint32_t csum = ext4_ialloc_bitmap_csum(sb, bitmap);
    uint16_t lo_csum = to_le16(csum & 0xFFFF), hi_csum = to_le16(csum >> 16);

    if (!ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM))
        return true;

    if (bg->inode_bitmap_csum_lo != lo_csum)
        return false;

    if (desc_size == EXT4_MAX_BLOCK_GROUP_DESCRIPTOR_SIZE)
        if (bg->inode_bitmap_csum_hi != hi_csum)
            return false;

    return true;
}

int ext4_ialloc_free_inode(struct ext4_fs *fs, uint32_t index, bool is_dir) {
    struct ext4_sblock *sb = &fs->sb;

    /* Compute index of block group and load it */
    uint32_t block_group = ext4_ialloc_get_bgid_of_inode(sb, index);

    struct ext4_block_group_ref bg_ref;
    int rc = ext4_fs_get_block_group_ref(fs, block_group, &bg_ref);
    if (rc != EOK)
        return rc;

    struct ext4_bgroup *bg = bg_ref.block_group;

    /* Load i-node bitmap */
    ext4_fsblk_t bitmap_block_addr = ext4_bg_get_inode_bitmap(bg, sb);

    struct ext4_block b;
    rc = ext4_trans_block_get(fs->bdev, &b, bitmap_block_addr);
    if (rc != EOK)
        return rc;

    if (!ext4_ialloc_verify_bitmap_csum(sb, bg, b.data)) {
        ext4_dbg(DEBUG_IALLOC,
                 DBG_WARN "Bitmap checksum failed."
                          "Group: %" PRIu32 "\n",
                 bg_ref.index);
    }

    /* Free i-node in the bitmap */
    uint32_t index_in_group = ext4_ialloc_inode_to_bgidx(sb, index);
    ext4_bmap_bit_clr(b.data, index_in_group);
    ext4_ialloc_set_bitmap_csum(sb, bg, b.data);
    ext4_trans_set_block_dirty(b.buf);

    /* Put back the block with bitmap */
    rc = ext4_block_set(fs->bdev, &b);
    if (rc != EOK) {
        /* Error in saving bitmap */
        ext4_fs_put_block_group_ref(&bg_ref);
        return rc;
    }

    /* If released i-node is a directory, decrement used directories count
     */
    if (is_dir) {
        uint32_t bg_used_dirs = ext4_bg_get_used_dirs_count(bg, sb);
        bg_used_dirs--;
        ext4_bg_set_used_dirs_count(bg, sb, bg_used_dirs);
    }

    /* Update block group free inodes count */
    uint32_t free_inodes = ext4_bg_get_free_inodes_count(bg, sb);
    free_inodes++;
    ext4_bg_set_free_inodes_count(bg, sb, free_inodes);

    bg_ref.dirty = true;

    /* Put back the modified block group */
    rc = ext4_fs_put_block_group_ref(&bg_ref);
    if (rc != EOK)
        return rc;

    /* Update superblock free inodes count */
    ext4_set32(sb, free_inodes_count, ext4_get32(sb, free_inodes_count) + 1);

    return EOK;
}

int ext4_ialloc_alloc_inode(struct ext4_fs *fs, uint32_t *idx, bool is_dir) {
    struct ext4_sblock *sb = &fs->sb;

    uint32_t bgid = fs->last_inode_bg_id;
    uint32_t bg_count = ext4_block_group_cnt(sb);
    uint32_t sb_free_inodes = ext4_get32(sb, free_inodes_count);
    bool rewind = false;

    /* Try to find free i-node in all block groups */
    while (bgid <= bg_count) {

        if (bgid == bg_count) {
            if (rewind)
                break;
            bg_count = fs->last_inode_bg_id;
            bgid = 0;
            rewind = true;
            continue;
        }

        /* Load block group to check */
        struct ext4_block_group_ref bg_ref;
        int rc = ext4_fs_get_block_group_ref(fs, bgid, &bg_ref);
        if (rc != EOK)
            return rc;

        struct ext4_bgroup *bg = bg_ref.block_group;

        /* Read necessary values for algorithm */
        uint32_t free_inodes = ext4_bg_get_free_inodes_count(bg, sb);
        uint32_t used_dirs = ext4_bg_get_used_dirs_count(bg, sb);

        /* Check if this block group is good candidate for allocation */
        if (free_inodes > 0) {
            /* Load block with bitmap */
            ext4_fsblk_t bmp_blk_add = ext4_bg_get_inode_bitmap(bg, sb);

            struct ext4_block b;
            rc = ext4_trans_block_get(fs->bdev, &b, bmp_blk_add);
            if (rc != EOK) {
                ext4_fs_put_block_group_ref(&bg_ref);
                return rc;
            }

            if (!ext4_ialloc_verify_bitmap_csum(sb, bg, b.data)) {
                ext4_dbg(DEBUG_IALLOC,
                         DBG_WARN "Bitmap checksum failed."
                                  "Group: %" PRIu32 "\n",
                         bg_ref.index);
            }

            /* Try to allocate i-node in the bitmap */
            uint32_t inodes_in_bg;
            uint32_t idx_in_bg;

            inodes_in_bg = ext4_inodes_in_group_cnt(sb, bgid);
            rc = ext4_bmap_bit_find_clr(b.data, 0, inodes_in_bg, &idx_in_bg);
            /* Block group has not any free i-node */
            if (rc == ENOSPC) {
                rc = ext4_block_set(fs->bdev, &b);
                if (rc != EOK) {
                    ext4_fs_put_block_group_ref(&bg_ref);
                    return rc;
                }

                rc = ext4_fs_put_block_group_ref(&bg_ref);
                if (rc != EOK)
                    return rc;

                continue;
            }

            ext4_bmap_bit_set(b.data, idx_in_bg);

            /* Free i-node found, save the bitmap */
            ext4_ialloc_set_bitmap_csum(sb, bg, b.data);
            ext4_trans_set_block_dirty(b.buf);

            ext4_block_set(fs->bdev, &b);
            if (rc != EOK) {
                ext4_fs_put_block_group_ref(&bg_ref);
                return rc;
            }

            /* Modify filesystem counters */
            free_inodes--;
            ext4_bg_set_free_inodes_count(bg, sb, free_inodes);

            /* Increment used directories counter */
            if (is_dir) {
                used_dirs++;
                ext4_bg_set_used_dirs_count(bg, sb, used_dirs);
            }

            /* Decrease unused inodes count */
            uint32_t unused = ext4_bg_get_itable_unused(bg, sb);

            uint32_t free = inodes_in_bg - unused;

            if (idx_in_bg >= free) {
                unused = inodes_in_bg - (idx_in_bg + 1);
                ext4_bg_set_itable_unused(bg, sb, unused);
            }

            /* Save modified block group */
            bg_ref.dirty = true;

            rc = ext4_fs_put_block_group_ref(&bg_ref);
            if (rc != EOK)
                return rc;

            /* Update superblock */
            sb_free_inodes--;
            ext4_set32(sb, free_inodes_count, sb_free_inodes);

            /* Compute the absolute i-nodex number */
            *idx = ext4_ialloc_bgidx_to_inode(sb, idx_in_bg, bgid);

            fs->last_inode_bg_id = bgid;

            return EOK;
        }

        /* Block group not modified, put it and jump to the next block
         * group */
        ext4_fs_put_block_group_ref(&bg_ref);
        if (rc != EOK)
            return rc;

        ++bgid;
    }

    return ENOSPC;
}

static uint32_t ext4_inode_block_bits_count(uint32_t block_size) {
    uint32_t bits = 8;
    uint32_t size = block_size;

    do {
        bits++;
        size = size >> 1;
    } while (size > 256);

    return bits;
}

uint32_t ext4_inode_get_mode(struct ext4_sblock *sb, struct ext4_inode *inode) {
    uint32_t v = to_le16(inode->mode);

    if (ext4_get32(sb, creator_os) == EXT4_SUPERBLOCK_OS_HURD) {
        v |= ((uint32_t) to_le16(inode->osd2.hurd2.mode_high)) << 16;
    }

    return v;
}

void ext4_inode_set_mode(struct ext4_sblock *sb, struct ext4_inode *inode, uint32_t mode) {
    inode->mode = to_le16((mode << 16) >> 16);

    if (ext4_get32(sb, creator_os) == EXT4_SUPERBLOCK_OS_HURD)
        inode->osd2.hurd2.mode_high = to_le16(mode >> 16);
}

uint64_t ext4_inode_get_size(struct ext4_sblock *sb, struct ext4_inode *inode) {
    uint64_t v = to_le32(inode->size_lo);

    if ((ext4_get32(sb, rev_level) > 0) && (ext4_inode_is_type(sb, inode, EXT4_INODE_MODE_FILE)))
        v |= ((uint64_t) to_le32(inode->size_hi)) << 32;

    return v;
}

void ext4_inode_set_size(struct ext4_inode *inode, uint64_t size) {
    inode->size_lo = to_le32((size << 32) >> 32);
    inode->size_hi = to_le32(size >> 32);
}

uint32_t ext4_inode_get_csum(struct ext4_sblock *sb, struct ext4_inode *inode) {
    uint16_t inode_size = ext4_get16(sb, inode_size);
    uint32_t v = to_le16(inode->osd2.linux2.checksum_lo);

    if (inode_size > EXT4_GOOD_OLD_INODE_SIZE)
        v |= ((uint32_t) to_le16(inode->checksum_hi)) << 16;

    return v;
}

void ext4_inode_set_csum(struct ext4_sblock *sb, struct ext4_inode *inode, uint32_t checksum) {
    uint16_t inode_size = ext4_get16(sb, inode_size);
    inode->osd2.linux2.checksum_lo = to_le16((checksum << 16) >> 16);

    if (inode_size > EXT4_GOOD_OLD_INODE_SIZE)
        inode->checksum_hi = to_le16(checksum >> 16);
}

uint64_t ext4_inode_get_access_time(struct ext4_inode *inode) {
    return inode->access_time | ((uint64_t) inode->atime_extra << 32);
}

void ext4_inode_set_access_time(struct ext4_inode *inode, uint64_t time) {
    inode->access_time = to_le32(time);
    inode->atime_extra = time >> 32;
}

void ext4_inode_set_change_inode_time(struct ext4_inode *inode, uint64_t time) {
    inode->change_inode_time = to_le32(time);
    inode->ctime_extra = time >> 32;
}

uint64_t ext4_inode_get_modif_time(struct ext4_inode *inode) {
    return inode->modification_time | ((uint64_t) inode->mtime_extra << 32);
}

void ext4_inode_set_modif_time(struct ext4_inode *inode, uint64_t time) {
    inode->modification_time = to_le32(time);
    inode->mtime_extra = time >> 32;
}

uint64_t ext4_inode_get_blocks_count(struct ext4_sblock *sb, struct ext4_inode *inode) {
    uint64_t cnt = to_le32(inode->blocks_count_lo);

    if (ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_HUGE_FILE)) {

        /* 48-bit field */
        cnt |= (uint64_t) to_le16(inode->osd2.linux2.blocks_high) << 32;

        if (ext4_inode_has_flag(inode, EXT4_INODE_FLAG_HUGE_FILE)) {

            uint32_t block_count = ext4_sb_get_block_size(sb);
            uint32_t b = ext4_inode_block_bits_count(block_count);
            return cnt << (b - 9);
        }
    }

    return cnt;
}

int ext4_inode_set_blocks_count(struct ext4_sblock *sb, struct ext4_inode *inode, uint64_t count) {
    /* 32-bit maximum */
    uint64_t max = 0;
    max = ~max >> 32;

    if (count <= max) {
        inode->blocks_count_lo = to_le32((uint32_t) count);
        inode->osd2.linux2.blocks_high = 0;
        ext4_inode_clear_flag(inode, EXT4_INODE_FLAG_HUGE_FILE);

        return EOK;
    }

    /* Check if there can be used huge files (many blocks) */
    if (!ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_HUGE_FILE))
        return EINVAL;

    /* 48-bit maximum */
    max = 0;
    max = ~max >> 16;

    if (count <= max) {
        inode->blocks_count_lo = to_le32((uint32_t) count);
        inode->osd2.linux2.blocks_high = to_le16((uint16_t) (count >> 32));
        ext4_inode_clear_flag(inode, EXT4_INODE_FLAG_HUGE_FILE);
    } else {
        uint32_t block_count = ext4_sb_get_block_size(sb);
        uint32_t block_bits = ext4_inode_block_bits_count(block_count);

        ext4_inode_set_flag(inode, EXT4_INODE_FLAG_HUGE_FILE);
        count = count >> (block_bits - 9);
        inode->blocks_count_lo = to_le32((uint32_t) count);
        inode->osd2.linux2.blocks_high = to_le16((uint16_t) (count >> 32));
    }

    return EOK;
}

uint16_t ext4_inode_get_extra_isize(struct ext4_sblock *sb, struct ext4_inode *inode) {
    uint16_t inode_size = ext4_get16(sb, inode_size);
    if (inode_size > EXT4_GOOD_OLD_INODE_SIZE)
        return to_le16(inode->extra_isize);
    else
        return 0;
}

void ext4_inode_set_extra_isize(struct ext4_sblock *sb, struct ext4_inode *inode, uint16_t size) {
    uint16_t inode_size = ext4_get16(sb, inode_size);
    if (inode_size > EXT4_GOOD_OLD_INODE_SIZE)
        inode->extra_isize = to_le16(size);
}

uint64_t ext4_inode_get_file_acl(struct ext4_inode *inode, struct ext4_sblock *sb) {
    uint64_t v = to_le32(inode->file_acl_lo);

    if (ext4_get32(sb, creator_os) == EXT4_SUPERBLOCK_OS_LINUX)
        v |= (uint32_t) to_le16(inode->osd2.linux2.file_acl_high) << 16;

    return v;
}

void ext4_inode_set_file_acl(struct ext4_inode *inode, struct ext4_sblock *sb, uint64_t acl) {
    inode->file_acl_lo = to_le32((acl << 32) >> 32);

    if (ext4_get32(sb, creator_os) == EXT4_SUPERBLOCK_OS_LINUX)
        inode->osd2.linux2.file_acl_high = to_le16((uint16_t) (acl >> 32));
}

void ext4_inode_set_direct_block(struct ext4_inode *inode, uint32_t idx, uint32_t block) {
    inode->blocks[idx] = to_le32(block);
}

uint32_t ext4_inode_get_indirect_block(struct ext4_inode *inode, uint32_t idx) {
    return to_le32(inode->blocks[idx + EXT4_INODE_INDIRECT_BLOCK]);
}

void ext4_inode_set_indirect_block(struct ext4_inode *inode, uint32_t idx, uint32_t block) {
    inode->blocks[idx + EXT4_INODE_INDIRECT_BLOCK] = to_le32(block);
}

uint32_t ext4_inode_get_dev(struct ext4_inode *inode) {
    uint32_t dev_0 = 0, dev_1 = 0;
    dev_0 = ext4_inode_get_direct_block(inode, 0);
    dev_1 = ext4_inode_get_direct_block(inode, 1);

    if (dev_0)
        return dev_0;
    else
        return dev_1;
}

void ext4_inode_set_dev(struct ext4_inode *inode, uint32_t dev) {
    if (dev & ~0xFFFF)
        ext4_inode_set_direct_block(inode, 1, dev);
    else
        ext4_inode_set_direct_block(inode, 0, dev);
}

uint32_t ext4_inode_type(struct ext4_sblock *sb, struct ext4_inode *inode) {
    return (ext4_inode_get_mode(sb, inode) & EXT4_INODE_MODE_TYPE_MASK);
}

bool ext4_inode_is_type(struct ext4_sblock *sb, struct ext4_inode *inode, uint32_t type) {
    return ext4_inode_type(sb, inode) == type;
}

void ext4_inode_clear_flag(struct ext4_inode *inode, uint32_t f) {
    uint32_t flags = ext4_inode_get_flags(inode);
    flags = flags & (~f);
    ext4_inode_set_flags(inode, flags);
}

void ext4_inode_set_flag(struct ext4_inode *inode, uint32_t f) {
    uint32_t flags = ext4_inode_get_flags(inode);
    flags = flags | f;
    ext4_inode_set_flags(inode, flags);
}

bool ext4_inode_can_truncate(struct ext4_sblock *sb, struct ext4_inode *inode) {
    if ((ext4_inode_has_flag(inode, EXT4_INODE_FLAG_APPEND)) || (ext4_inode_has_flag(inode, EXT4_INODE_FLAG_IMMUTABLE)))
        return false;

    if ((ext4_inode_is_type(sb, inode, EXT4_INODE_MODE_FILE)) ||
        (ext4_inode_is_type(sb, inode, EXT4_INODE_MODE_DIRECTORY)) ||
        (ext4_inode_is_type(sb, inode, EXT4_INODE_MODE_SOFTLINK)))
        return true;

    return false;
}

struct ext4_extent_header *ext4_inode_get_extent_header(struct ext4_inode *inode) {
    return (struct ext4_extent_header *) inode->blocks;
}

struct revoke_entry {
    /**@brief  Block number not to be replayed.*/
    ext4_fsblk_t block;

    /**@brief  For any transaction id smaller
     *         than trans_id, records of @block
     *         in those transactions should not
     *         be replayed.*/
    uint32_t trans_id;

    /**@brief  Revoke tree node.*/
    RB_ENTRY(revoke_entry) revoke_node;
}

struct recover_info {
    /**@brief  Starting transaction id.*/
    uint32_t start_trans_id;

    /**@brief  Ending transaction id.*/
    uint32_t last_trans_id;

    /**@brief  Used as internal argument.*/
    uint32_t this_trans_id;

    /**@brief  No of transactions went through.*/
    uint32_t trans_cnt;

    /**@brief  RB-Tree storing revoke entries.*/
    RB_HEAD(jbd_revoke, revoke_entry) revoke_root;
}

struct replay_arg {
    /**@brief  Journal replay information.*/
    struct recover_info *info;

    /**@brief  Current block we are on.*/
    uint32_t *this_block;

    /**@brief  Current trans_id we are on.*/
    uint32_t this_trans_id;
}

static inline int32_t trans_id_diff(uint32_t x, uint32_t y) {
    int32_t diff = x - y;
    return diff;
}

static int jbd_revoke_entry_cmp(struct revoke_entry *a, struct revoke_entry *b) {
    if (a->block > b->block)
        return 1;
    else if (a->block < b->block)
        return -1;
    return 0;
}

static int jbd_block_rec_cmp(struct jbd_block_rec *a, struct jbd_block_rec *b) {
    if (a->lba > b->lba)
        return 1;
    else if (a->lba < b->lba)
        return -1;
    return 0;
}

static int jbd_revoke_rec_cmp(struct jbd_revoke_rec *a, struct jbd_revoke_rec *b) {
    if (a->lba > b->lba)
        return 1;
    else if (a->lba < b->lba)
        return -1;
    return 0;
}

static int jbd_has_csum(struct jbd_sb *jbd_sb) {
    if (JBD_HAS_INCOMPAT_FEATURE(jbd_sb, JBD_FEATURE_INCOMPAT_CSUM_V2))
        return 2;

    if (JBD_HAS_INCOMPAT_FEATURE(jbd_sb, JBD_FEATURE_INCOMPAT_CSUM_V3))
        return 3;

    return 0;
}

static uint32_t jbd_sb_csum(struct jbd_sb *jbd_sb) {
    uint32_t checksum = 0;

    if (jbd_has_csum(jbd_sb)) {
        uint32_t orig_checksum = jbd_sb->checksum;
        jbd_set32(jbd_sb, checksum, 0);
        /* Calculate crc32c checksum against tho whole superblock */
        checksum = ext4_crc32c(EXT4_CRC32_INIT, jbd_sb, JBD_SUPERBLOCK_SIZE);
        jbd_sb->checksum = orig_checksum;
    }
    return checksum;
}

static void jbd_sb_csum_set(struct jbd_sb *jbd_sb) {
    if (!jbd_has_csum(jbd_sb))
        return;

    jbd_set32(jbd_sb, checksum, jbd_sb_csum(jbd_sb));
}

static bool jbd_verify_sb_csum(struct jbd_sb *jbd_sb) {
    if (!jbd_has_csum(jbd_sb))
        return true;

    return jbd_sb_csum(jbd_sb) == jbd_get32(jbd_sb, checksum);
}

static uint32_t jbd_meta_csum(struct jbd_fs *jbd_fs, struct jbd_bhdr *bhdr) {
    uint32_t checksum = 0;

    if (jbd_has_csum(&jbd_fs->sb)) {
        uint32_t block_size = jbd_get32(&jbd_fs->sb, blocksize);
        struct jbd_block_tail *tail =
                (struct jbd_block_tail *) ((char *) bhdr + block_size - sizeof(struct jbd_block_tail));
        uint32_t orig_checksum = tail->checksum;
        tail->checksum = 0;

        /* First calculate crc32c checksum against fs uuid */
        checksum = ext4_crc32c(EXT4_CRC32_INIT, jbd_fs->sb.uuid, sizeof(jbd_fs->sb.uuid));
        /* Calculate crc32c checksum against tho whole block */
        checksum = ext4_crc32c(checksum, bhdr, block_size);
        tail->checksum = orig_checksum;
    }
    return checksum;
}

static void jbd_meta_csum_set(struct jbd_fs *jbd_fs, struct jbd_bhdr *bhdr) {
    uint32_t block_size = jbd_get32(&jbd_fs->sb, blocksize);
    struct jbd_block_tail *tail =
            (struct jbd_block_tail *) ((char *) bhdr + block_size - sizeof(struct jbd_block_tail));
    if (!jbd_has_csum(&jbd_fs->sb))
        return;

    tail->checksum = to_be32(jbd_meta_csum(jbd_fs, bhdr));
}

static bool jbd_verify_meta_csum(struct jbd_fs *jbd_fs, struct jbd_bhdr *bhdr) {
    uint32_t block_size = jbd_get32(&jbd_fs->sb, blocksize);
    struct jbd_block_tail *tail =
            (struct jbd_block_tail *) ((char *) bhdr + block_size - sizeof(struct jbd_block_tail));
    if (!jbd_has_csum(&jbd_fs->sb))
        return true;

    return jbd_meta_csum(jbd_fs, bhdr) == to_be32(tail->checksum);
}

static uint32_t jbd_commit_csum(struct jbd_fs *jbd_fs, struct jbd_commit_header *header) {
    uint32_t checksum = 0;

    if (jbd_has_csum(&jbd_fs->sb)) {
        uint8_t orig_checksum_type = header->chksum_type, orig_checksum_size = header->chksum_size;
        uint32_t orig_checksum = header->chksum[0];
        uint32_t block_size = jbd_get32(&jbd_fs->sb, blocksize);
        header->chksum_type = 0;
        header->chksum_size = 0;
        header->chksum[0] = 0;

        /* First calculate crc32c checksum against fs uuid */
        checksum = ext4_crc32c(EXT4_CRC32_INIT, jbd_fs->sb.uuid, sizeof(jbd_fs->sb.uuid));
        /* Calculate crc32c checksum against tho whole block */
        checksum = ext4_crc32c(checksum, header, block_size);

        header->chksum_type = orig_checksum_type;
        header->chksum_size = orig_checksum_size;
        header->chksum[0] = orig_checksum;
    }
    return checksum;
}

static void jbd_commit_csum_set(struct jbd_fs *jbd_fs, struct jbd_commit_header *header) {
    if (!jbd_has_csum(&jbd_fs->sb))
        return;

    header->chksum_type = 0;
    header->chksum_size = 0;
    header->chksum[0] = jbd_commit_csum(jbd_fs, header);
}

static bool jbd_verify_commit_csum(struct jbd_fs *jbd_fs, struct jbd_commit_header *header) {
    if (!jbd_has_csum(&jbd_fs->sb))
        return true;

    return header->chksum[0] == to_be32(jbd_commit_csum(jbd_fs, header));
}

static uint32_t jbd_block_csum(struct jbd_fs *jbd_fs, const void *buf, uint32_t csum, uint32_t sequence) {
    uint32_t checksum = 0;

    if (jbd_has_csum(&jbd_fs->sb)) {
        uint32_t block_size = jbd_get32(&jbd_fs->sb, blocksize);
        /* First calculate crc32c checksum against fs uuid */
        checksum = ext4_crc32c(EXT4_CRC32_INIT, jbd_fs->sb.uuid, sizeof(jbd_fs->sb.uuid));
        /* Then calculate crc32c checksum against sequence no. */
        checksum = ext4_crc32c(checksum, &sequence, sizeof(uint32_t));
        /* Calculate crc32c checksum against tho whole block */
        checksum = ext4_crc32c(checksum, buf, block_size);
    } else if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_COMPAT_CHECKSUM)) {
        uint32_t block_size = jbd_get32(&jbd_fs->sb, blocksize);
        /* Calculate crc32c checksum against tho whole block */
        checksum = ext4_crc32(csum, buf, block_size);
    }
    return checksum;
}

static void jbd_block_tag_csum_set(struct jbd_fs *jbd_fs, void *__tag, uint32_t checksum) {
    int ver = jbd_has_csum(&jbd_fs->sb);
    if (!ver)
        return;

    if (ver == 2) {
        struct jbd_block_tag *tag = __tag;
        tag->checksum = (uint16_t) to_be32(checksum);
    } else {
        struct jbd_block_tag3 *tag = __tag;
        tag->checksum = to_be32(checksum);
    }
}

static int jbd_sb_write(struct jbd_fs *jbd_fs, struct jbd_sb *s) {
    int rc;
    struct ext4_fs *fs = jbd_fs->inode_ref.fs;
    uint64_t offset;
    ext4_fsblk_t fblock;
    rc = jbd_inode_bmap(jbd_fs, 0, &fblock);
    if (rc != EOK)
        return rc;

    jbd_sb_csum_set(s);
    offset = fblock * ext4_sb_get_block_size(&fs->sb);
    return ext4_block_writebytes(fs->bdev, offset, s, EXT4_SUPERBLOCK_SIZE);
}

static int jbd_sb_read(struct jbd_fs *jbd_fs, struct jbd_sb *s) {
    int rc;
    struct ext4_fs *fs = jbd_fs->inode_ref.fs;
    uint64_t offset;
    ext4_fsblk_t fblock;
    rc = jbd_inode_bmap(jbd_fs, 0, &fblock);
    if (rc != EOK)
        return rc;

    offset = fblock * ext4_sb_get_block_size(&fs->sb);
    return ext4_block_readbytes(fs->bdev, offset, s, EXT4_SUPERBLOCK_SIZE);
}

static bool jbd_verify_sb(struct jbd_sb *sb) {
    struct jbd_bhdr *header = &sb->header;
    if (jbd_get32(header, magic) != JBD_MAGIC_NUMBER)
        return false;

    if (jbd_get32(header, blocktype) != JBD_SUPERBLOCK && jbd_get32(header, blocktype) != JBD_SUPERBLOCK_V2)
        return false;

    return jbd_verify_sb_csum(sb);
}

static int jbd_write_sb(struct jbd_fs *jbd_fs) {
    int rc = EOK;
    if (jbd_fs->dirty) {
        rc = jbd_sb_write(jbd_fs, &jbd_fs->sb);
        if (rc != EOK)
            return rc;

        jbd_fs->dirty = false;
    }
    return rc;
}

int jbd_get_fs(struct ext4_fs *fs, struct jbd_fs *jbd_fs) {
    int rc;
    uint32_t journal_ino;

    memset(jbd_fs, 0, sizeof(struct jbd_fs));
    /* See if there is journal inode on this filesystem.*/
    /* FIXME: detection on existance ofbkejournal bdev is
     *        missing.*/
    journal_ino = ext4_get32(&fs->sb, journal_inode_number);

    rc = ext4_fs_get_inode_ref(fs, journal_ino, &jbd_fs->inode_ref);
    if (rc != EOK)
        return rc;

    rc = jbd_sb_read(jbd_fs, &jbd_fs->sb);
    if (rc != EOK)
        goto Error;

    if (!jbd_verify_sb(&jbd_fs->sb)) {
        rc = EIO;
        goto Error;
    }

    if (rc == EOK)
        jbd_fs->bdev = fs->bdev;

    return rc;
Error:
    ext4_fs_put_inode_ref(&jbd_fs->inode_ref);
    memset(jbd_fs, 0, sizeof(struct jbd_fs));

    return rc;
}

int jbd_put_fs(struct jbd_fs *jbd_fs) {
    int rc = EOK;
    rc = jbd_write_sb(jbd_fs);

    ext4_fs_put_inode_ref(&jbd_fs->inode_ref);
    return rc;
}

int jbd_inode_bmap(struct jbd_fs *jbd_fs, ext4_lblk_t iblock, ext4_fsblk_t *fblock) {
    int rc = ext4_fs_get_inode_dblk_idx(&jbd_fs->inode_ref, iblock, fblock, false);
    return rc;
}

static int jbd_block_get(struct jbd_fs *jbd_fs, struct ext4_block *block, ext4_fsblk_t fblock) {
    /* TODO: journal device. */
    int rc;
    struct ext4_blockdev *bdev = jbd_fs->bdev;
    ext4_lblk_t iblock = (ext4_lblk_t) fblock;

    /* Lookup the logical block address of
     * fblock.*/
    rc = jbd_inode_bmap(jbd_fs, iblock, &fblock);
    if (rc != EOK)
        return rc;

    rc = ext4_block_get(bdev, block, fblock);

    /* If succeeded, mark buffer as BC_FLUSH to indicate
     * that data should be written to disk immediately.*/
    if (rc == EOK) {
        ext4_bcache_set_flag(block->buf, BC_FLUSH);
        /* As we don't want to occupy too much space
         * in block cache, we set this buffer BC_TMP.*/
        ext4_bcache_set_flag(block->buf, BC_TMP);
    }

    return rc;
}

static int jbd_block_get_noread(struct jbd_fs *jbd_fs, struct ext4_block *block, ext4_fsblk_t fblock) {
    /* TODO: journal device. */
    int rc;
    struct ext4_blockdev *bdev = jbd_fs->bdev;
    ext4_lblk_t iblock = (ext4_lblk_t) fblock;
    rc = jbd_inode_bmap(jbd_fs, iblock, &fblock);
    if (rc != EOK)
        return rc;

    rc = ext4_block_get_noread(bdev, block, fblock);
    if (rc == EOK)
        ext4_bcache_set_flag(block->buf, BC_FLUSH);

    return rc;
}

static int jbd_block_set(struct jbd_fs *jbd_fs, struct ext4_block *block) {
    struct ext4_blockdev *bdev = jbd_fs->bdev;
    return ext4_block_set(bdev, block);
}

static int jbd_tag_bytes(struct jbd_fs *jbd_fs) {
    int size;

    /* It is very easy to deal with the case which
     * JBD_FEATURE_INCOMPAT_CSUM_V3 is enabled.*/
    if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_CSUM_V3))
        return sizeof(struct jbd_block_tag3);

    size = sizeof(struct jbd_block_tag);

    /* If JBD_FEATURE_INCOMPAT_CSUM_V2 is enabled,
     * add 2 bytes to size.*/
    if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_CSUM_V2))
        size += sizeof(uint16_t);

    if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_64BIT))
        return size;

    /* If block number is 4 bytes in size,
     * minus 4 bytes from size */
    return size - sizeof(uint32_t);
}

struct tag_info {
    /**@brief  Tag size in bytes, including UUID part.*/
    int tag_bytes;

    /**@brief  block number stored in this tag.*/
    ext4_fsblk_t block;

    /**@brief  Is the first 4 bytes of block equals to
     *	   JBD_MAGIC_NUMBER? */
    bool is_escape;

    /**@brief  whether UUID part exists or not.*/
    bool uuid_exist;

    /**@brief  UUID content if UUID part exists.*/
    uint8_t uuid[UUID_SIZE];

    /**@brief  Is this the last tag? */
    bool last_tag;

    /**@brief  crc32c checksum. */
    uint32_t checksum;
}

static int jbd_extract_block_tag(struct jbd_fs *jbd_fs, void *__tag, int tag_bytes, int32_t remain_buf_size,
                                 struct tag_info *tag_info) {
    char *uuid_start;
    tag_info->tag_bytes = tag_bytes;
    tag_info->uuid_exist = false;
    tag_info->last_tag = false;
    tag_info->is_escape = false;

    /* See whether it is possible to hold a valid block tag.*/
    if (remain_buf_size - tag_bytes < 0)
        return EINVAL;

    if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_CSUM_V3)) {
        struct jbd_block_tag3 *tag = __tag;
        tag_info->block = jbd_get32(tag, blocknr);
        if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_64BIT))
            tag_info->block |= (uint64_t) jbd_get32(tag, blocknr_high) << 32;

        if (jbd_get32(tag, flags) & JBD_FLAG_ESCAPE)
            tag_info->is_escape = true;

        if (!(jbd_get32(tag, flags) & JBD_FLAG_SAME_UUID)) {
            /* See whether it is possible to hold UUID part.*/
            if (remain_buf_size - tag_bytes < UUID_SIZE)
                return EINVAL;

            uuid_start = (char *) tag + tag_bytes;
            tag_info->uuid_exist = true;
            tag_info->tag_bytes += UUID_SIZE;
            memcpy(tag_info->uuid, uuid_start, UUID_SIZE);
        }

        if (jbd_get32(tag, flags) & JBD_FLAG_LAST_TAG)
            tag_info->last_tag = true;

    } else {
        struct jbd_block_tag *tag = __tag;
        tag_info->block = jbd_get32(tag, blocknr);
        if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_64BIT))
            tag_info->block |= (uint64_t) jbd_get32(tag, blocknr_high) << 32;

        if (jbd_get16(tag, flags) & JBD_FLAG_ESCAPE)
            tag_info->is_escape = true;

        if (!(jbd_get16(tag, flags) & JBD_FLAG_SAME_UUID)) {
            /* See whether it is possible to hold UUID part.*/
            if (remain_buf_size - tag_bytes < UUID_SIZE)
                return EINVAL;

            uuid_start = (char *) tag + tag_bytes;
            tag_info->uuid_exist = true;
            tag_info->tag_bytes += UUID_SIZE;
            memcpy(tag_info->uuid, uuid_start, UUID_SIZE);
        }

        if (jbd_get16(tag, flags) & JBD_FLAG_LAST_TAG)
            tag_info->last_tag = true;
    }
    return EOK;
}

static int jbd_write_block_tag(struct jbd_fs *jbd_fs, void *__tag, int32_t remain_buf_size, struct tag_info *tag_info) {
    char *uuid_start;
    int tag_bytes = jbd_tag_bytes(jbd_fs);

    tag_info->tag_bytes = tag_bytes;

    /* See whether it is possible to hold a valid block tag.*/
    if (remain_buf_size - tag_bytes < 0)
        return EINVAL;

    if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_CSUM_V3)) {
        struct jbd_block_tag3 *tag = __tag;
        memset(tag, 0, sizeof(struct jbd_block_tag3));
        jbd_set32(tag, blocknr, (uint32_t) tag_info->block);
        if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_64BIT))
            jbd_set32(tag, blocknr_high, tag_info->block >> 32);

        if (tag_info->uuid_exist) {
            /* See whether it is possible to hold UUID part.*/
            if (remain_buf_size - tag_bytes < UUID_SIZE)
                return EINVAL;

            uuid_start = (char *) tag + tag_bytes;
            tag_info->tag_bytes += UUID_SIZE;
            memcpy(uuid_start, tag_info->uuid, UUID_SIZE);
        } else
            jbd_set32(tag, flags, jbd_get32(tag, flags) | JBD_FLAG_SAME_UUID);

        jbd_block_tag_csum_set(jbd_fs, __tag, tag_info->checksum);

        if (tag_info->last_tag)
            jbd_set32(tag, flags, jbd_get32(tag, flags) | JBD_FLAG_LAST_TAG);

        if (tag_info->is_escape)
            jbd_set32(tag, flags, jbd_get32(tag, flags) | JBD_FLAG_ESCAPE);

    } else {
        struct jbd_block_tag *tag = __tag;
        memset(tag, 0, sizeof(struct jbd_block_tag));
        jbd_set32(tag, blocknr, (uint32_t) tag_info->block);
        if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_64BIT))
            jbd_set32(tag, blocknr_high, tag_info->block >> 32);

        if (tag_info->uuid_exist) {
            /* See whether it is possible to hold UUID part.*/
            if (remain_buf_size - tag_bytes < UUID_SIZE)
                return EINVAL;

            uuid_start = (char *) tag + tag_bytes;
            tag_info->tag_bytes += UUID_SIZE;
            memcpy(uuid_start, tag_info->uuid, UUID_SIZE);
        } else
            jbd_set16(tag, flags, jbd_get16(tag, flags) | JBD_FLAG_SAME_UUID);

        jbd_block_tag_csum_set(jbd_fs, __tag, tag_info->checksum);

        if (tag_info->last_tag)
            jbd_set16(tag, flags, jbd_get16(tag, flags) | JBD_FLAG_LAST_TAG);


        if (tag_info->is_escape)
            jbd_set16(tag, flags, jbd_get16(tag, flags) | JBD_FLAG_ESCAPE);
    }
    return EOK;
}

static void jbd_iterate_block_table(struct jbd_fs *jbd_fs, void *__tag_start, int32_t tag_tbl_size,
                                    void (*func)(struct jbd_fs *jbd_fs, struct tag_info *tag_info, void *arg),
                                    void *arg) {
    char *tag_start, *tag_ptr;
    int tag_bytes = jbd_tag_bytes(jbd_fs);
    tag_start = __tag_start;
    tag_ptr = tag_start;

    /* Cut off the size of block tail storing checksum. */
    if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_CSUM_V2) ||
        JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_CSUM_V3))
        tag_tbl_size -= sizeof(struct jbd_block_tail);

    while (tag_tbl_size) {
        struct tag_info tag_info;
        int rc = jbd_extract_block_tag(jbd_fs, tag_ptr, tag_bytes, tag_tbl_size, &tag_info);
        if (rc != EOK)
            break;

        if (func)
            func(jbd_fs, &tag_info, arg);

        /* Stop the iteration when we reach the last tag. */
        if (tag_info.last_tag)
            break;

        tag_ptr += tag_info.tag_bytes;
        tag_tbl_size -= tag_info.tag_bytes;
    }
}

static void jbd_display_block_tags(struct jbd_fs *jbd_fs, struct tag_info *tag_info, void *arg) {
    uint32_t *iblock = arg;
    ext4_dbg(DEBUG_JBD, "Block in block_tag: %" PRIu64 "\n", tag_info->block);
    (*iblock)++;
    wrap(&jbd_fs->sb, *iblock);
    (void) jbd_fs;
    return;
}

static struct revoke_entry *jbd_revoke_entry_lookup(struct recover_info *info, ext4_fsblk_t block) {
    struct revoke_entry tmp = {.block = block};

    return RB_FIND(jbd_revoke, &info->revoke_root, &tmp);
}

static void jbd_replay_block_tags(struct jbd_fs *jbd_fs, struct tag_info *tag_info, void *__arg) {
    int r;
    struct replay_arg *arg = __arg;
    struct recover_info *info = arg->info;
    uint32_t *this_block = arg->this_block;
    struct revoke_entry *revoke_entry;
    struct ext4_block journal_block, ext4_block;
    struct ext4_fs *fs = jbd_fs->inode_ref.fs;

    (*this_block)++;
    wrap(&jbd_fs->sb, *this_block);

    /* We replay this block only if the current transaction id
     * is equal or greater than that in revoke entry.*/
    revoke_entry = jbd_revoke_entry_lookup(info, tag_info->block);
    if (revoke_entry && trans_id_diff(arg->this_trans_id, revoke_entry->trans_id) <= 0)
        return;

    ext4_dbg(DEBUG_JBD, "Replaying block in block_tag: %" PRIu64 "\n", tag_info->block);

    r = jbd_block_get(jbd_fs, &journal_block, *this_block);
    if (r != EOK)
        return;

    /* We need special treatment for ext4 superblock. */
    if (tag_info->block) {
        r = ext4_block_get_noread(fs->bdev, &ext4_block, tag_info->block);
        if (r != EOK) {
            jbd_block_set(jbd_fs, &journal_block);
            return;
        }

        memcpy(ext4_block.data, journal_block.data, jbd_get32(&jbd_fs->sb, blocksize));

        if (tag_info->is_escape)
            ((struct jbd_bhdr *) ext4_block.data)->magic = to_be32(JBD_MAGIC_NUMBER);

        ext4_bcache_set_dirty(ext4_block.buf);
        ext4_block_set(fs->bdev, &ext4_block);
    } else {
        uint16_t mount_count, state;
        mount_count = ext4_get16(&fs->sb, mount_count);
        state = ext4_get16(&fs->sb, state);

        memcpy(&fs->sb, journal_block.data + EXT4_SUPERBLOCK_OFFSET, EXT4_SUPERBLOCK_SIZE);

        /* Mark system as mounted */
        ext4_set16(&fs->sb, state, state);
        r = ext4_sb_write(fs->bdev, &fs->sb);
        if (r != EOK)
            return;

        /*Update mount count*/
        ext4_set16(&fs->sb, mount_count, mount_count);
    }

    jbd_block_set(jbd_fs, &journal_block);

    return;
}

static void jbd_add_revoke_block_tags(struct recover_info *info, ext4_fsblk_t block) {
    struct revoke_entry *revoke_entry;

    ext4_dbg(DEBUG_JBD, "Add block %" PRIu64 " to revoke tree\n", block);
    /* If the revoke entry with respect to the block address
     * exists already, update its transaction id.*/
    revoke_entry = jbd_revoke_entry_lookup(info, block);
    if (revoke_entry) {
        revoke_entry->trans_id = info->this_trans_id;
        return;
    }

    revoke_entry = jbd_alloc_revoke_entry();
    ext4_assert(revoke_entry);
    revoke_entry->block = block;
    revoke_entry->trans_id = info->this_trans_id;
    RB_INSERT(jbd_revoke, &info->revoke_root, revoke_entry);

    return;
}

static void jbd_destroy_revoke_tree(struct recover_info *info) {
    while (!RB_EMPTY(&info->revoke_root)) {
        struct revoke_entry *revoke_entry = RB_MIN(jbd_revoke, &info->revoke_root);
        ext4_assert(revoke_entry);
        RB_REMOVE(jbd_revoke, &info->revoke_root, revoke_entry);
        jbd_free_revoke_entry(revoke_entry);
    }
}

static void jbd_build_revoke_tree(struct jbd_fs *jbd_fs, struct jbd_bhdr *header, struct recover_info *info) {
    char *blocks_entry;
    struct jbd_revoke_header *revoke_hdr = (struct jbd_revoke_header *) header;
    uint32_t i, nr_entries, record_len = 4;

    /* If we are working on a 64bit jbd filesystem, */
    if (JBD_HAS_INCOMPAT_FEATURE(&jbd_fs->sb, JBD_FEATURE_INCOMPAT_64BIT))
        record_len = 8;

    nr_entries = (jbd_get32(revoke_hdr, count) - sizeof(struct jbd_revoke_header)) / record_len;

    blocks_entry = (char *) (revoke_hdr + 1);

    for (i = 0; i < nr_entries; i++) {
        if (record_len == 8) {
            uint64_t *blocks = (uint64_t *) blocks_entry;
            jbd_add_revoke_block_tags(info, to_be64(*blocks));
        } else {
            uint32_t *blocks = (uint32_t *) blocks_entry;
            jbd_add_revoke_block_tags(info, to_be32(*blocks));
        }
        blocks_entry += record_len;
    }
}

static void jbd_debug_descriptor_block(struct jbd_fs *jbd_fs, struct jbd_bhdr *header, uint32_t *iblock) {
    jbd_iterate_block_table(jbd_fs, header + 1, jbd_get32(&jbd_fs->sb, blocksize) - sizeof(struct jbd_bhdr),
                            jbd_display_block_tags, iblock);
}

static void jbd_replay_descriptor_block(struct jbd_fs *jbd_fs, struct jbd_bhdr *header, struct replay_arg *arg) {
    jbd_iterate_block_table(jbd_fs, header + 1, jbd_get32(&jbd_fs->sb, blocksize) - sizeof(struct jbd_bhdr),
                            jbd_replay_block_tags, arg);
}

static int jbd_iterate_log(struct jbd_fs *jbd_fs, struct recover_info *info, int action) {
    int r = EOK;
    bool log_end = false;
    struct jbd_sb *sb = &jbd_fs->sb;
    uint32_t start_trans_id, this_trans_id;
    uint32_t start_block, this_block;

    /* We start iterating valid blocks in the whole journal.*/
    start_trans_id = this_trans_id = jbd_get32(sb, sequence);
    start_block = this_block = jbd_get32(sb, start);
    if (action == ACTION_SCAN)
        info->trans_cnt = 0;
    else if (!info->trans_cnt)
        log_end = true;

    ext4_dbg(DEBUG_JBD, "Start of journal at trans id: %" PRIu32 "\n", start_trans_id);

    while (!log_end) {
        struct ext4_block block;
        struct jbd_bhdr *header;
        /* If we are not scanning for the last
         * valid transaction in the journal,
         * we will stop when we reach the end of
         * the journal.*/
        if (action != ACTION_SCAN)
            if (trans_id_diff(this_trans_id, info->last_trans_id) > 0) {
                log_end = true;
                continue;
            }

        r = jbd_block_get(jbd_fs, &block, this_block);
        if (r != EOK)
            break;

        header = (struct jbd_bhdr *) block.data;
        /* This block does not have a valid magic number,
         * so we have reached the end of the journal.*/
        if (jbd_get32(header, magic) != JBD_MAGIC_NUMBER) {
            jbd_block_set(jbd_fs, &block);
            log_end = true;
            continue;
        }

        /* If the transaction id we found is not expected,
         * we may have reached the end of the journal.
         *
         * If we are not scanning the journal, something
         * bad might have taken place. :-( */
        if (jbd_get32(header, sequence) != this_trans_id) {
            if (action != ACTION_SCAN)
                r = EIO;

            jbd_block_set(jbd_fs, &block);
            log_end = true;
            continue;
        }

        switch (jbd_get32(header, blocktype)) {
            case JBD_DESCRIPTOR_BLOCK:
                if (!jbd_verify_meta_csum(jbd_fs, header)) {
                    ext4_dbg(DEBUG_JBD,
                             DBG_WARN "Descriptor block checksum failed."
                                      "Journal block: %" PRIu32 "\n",
                             this_block);
                    log_end = true;
                    break;
                }
                ext4_dbg(DEBUG_JBD,
                         "Descriptor block: %" PRIu32 ", "
                         "trans_id: %" PRIu32 "\n",
                         this_block, this_trans_id);
                if (action == ACTION_RECOVER) {
                    struct replay_arg replay_arg;
                    replay_arg.info = info;
                    replay_arg.this_block = &this_block;
                    replay_arg.this_trans_id = this_trans_id;

                    jbd_replay_descriptor_block(jbd_fs, header, &replay_arg);
                } else
                    jbd_debug_descriptor_block(jbd_fs, header, &this_block);

                break;
            case JBD_COMMIT_BLOCK:
                if (!jbd_verify_commit_csum(jbd_fs, (struct jbd_commit_header *) header)) {
                    ext4_dbg(DEBUG_JBD,
                             DBG_WARN "Commit block checksum failed."
                                      "Journal block: %" PRIu32 "\n",
                             this_block);
                    log_end = true;
                    break;
                }
                ext4_dbg(DEBUG_JBD,
                         "Commit block: %" PRIu32 ", "
                         "trans_id: %" PRIu32 "\n",
                         this_block, this_trans_id);
                /*
                 * This is the end of a transaction,
                 * we may now proceed to the next transaction.
                 */
                this_trans_id++;
                if (action == ACTION_SCAN)
                    info->trans_cnt++;
                break;
            case JBD_REVOKE_BLOCK:
                if (!jbd_verify_meta_csum(jbd_fs, header)) {
                    ext4_dbg(DEBUG_JBD,
                             DBG_WARN "Revoke block checksum failed."
                                      "Journal block: %" PRIu32 "\n",
                             this_block);
                    log_end = true;
                    break;
                }
                ext4_dbg(DEBUG_JBD,
                         "Revoke block: %" PRIu32 ", "
                         "trans_id: %" PRIu32 "\n",
                         this_block, this_trans_id);
                if (action == ACTION_REVOKE) {
                    info->this_trans_id = this_trans_id;
                    jbd_build_revoke_tree(jbd_fs, header, info);
                }
                break;
            default:
                log_end = true;
                break;
        }
        jbd_block_set(jbd_fs, &block);
        this_block++;
        wrap(sb, this_block);
        if (this_block == start_block)
            log_end = true;
    }
    ext4_dbg(DEBUG_JBD, "End of journal.\n");
    if (r == EOK && action == ACTION_SCAN) {
        /* We have finished scanning the journal. */
        info->start_trans_id = start_trans_id;
        if (trans_id_diff(this_trans_id, start_trans_id) > 0)
            info->last_trans_id = this_trans_id - 1;
        else
            info->last_trans_id = this_trans_id;
    }

    return r;
}

int jbd_recover(struct jbd_fs *jbd_fs) {
    int r;
    struct recover_info info;
    struct jbd_sb *sb = &jbd_fs->sb;
    if (!sb->start)
        return EOK;

    RB_INIT(&info.revoke_root);

    r = jbd_iterate_log(jbd_fs, &info, ACTION_SCAN);
    if (r != EOK)
        return r;

    r = jbd_iterate_log(jbd_fs, &info, ACTION_REVOKE);
    if (r != EOK)
        return r;

    r = jbd_iterate_log(jbd_fs, &info, ACTION_RECOVER);
    if (r == EOK) {
        /* If we successfully replay the journal,
         * clear EXT4_FINCOM_RECOVER flag on the
         * ext4 superblock, and set the start of
         * journal to 0.*/
        uint32_t features_incompatible = ext4_get32(&jbd_fs->inode_ref.fs->sb, features_incompatible);
        jbd_set32(&jbd_fs->sb, start, 0);
        jbd_set32(&jbd_fs->sb, sequence, info.last_trans_id);
        features_incompatible &= ~EXT4_FINCOM_RECOVER;
        ext4_set32(&jbd_fs->inode_ref.fs->sb, features_incompatible, features_incompatible);
        jbd_fs->dirty = true;
        r = ext4_sb_write(jbd_fs->bdev, &jbd_fs->inode_ref.fs->sb);
    }
    jbd_destroy_revoke_tree(&info);
    return r;
}

static void jbd_journal_write_sb(struct jbd_journal *journal) {
    struct jbd_fs *jbd_fs = journal->jbd_fs;
    jbd_set32(&jbd_fs->sb, start, journal->start);
    jbd_set32(&jbd_fs->sb, sequence, journal->trans_id);
    jbd_fs->dirty = true;
}

int jbd_journal_start(struct jbd_fs *jbd_fs, struct jbd_journal *journal) {
    int r;
    uint32_t features_incompatible = ext4_get32(&jbd_fs->inode_ref.fs->sb, features_incompatible);
    features_incompatible |= EXT4_FINCOM_RECOVER;
    ext4_set32(&jbd_fs->inode_ref.fs->sb, features_incompatible, features_incompatible);
    r = ext4_sb_write(jbd_fs->bdev, &jbd_fs->inode_ref.fs->sb);
    if (r != EOK)
        return r;

    journal->first = jbd_get32(&jbd_fs->sb, first);
    journal->start = journal->first;
    journal->last = journal->first;
    /*
     * To invalidate any stale records we need to start from
     * the checkpoint transaction ID of the previous journalling session
     * plus 1.
     */
    journal->trans_id = jbd_get32(&jbd_fs->sb, sequence) + 1;
    journal->alloc_trans_id = journal->trans_id;

    journal->block_size = jbd_get32(&jbd_fs->sb, blocksize);

    TAILQ_INIT(&journal->cp_queue);
    RB_INIT(&journal->block_rec_root);
    journal->jbd_fs = jbd_fs;
    jbd_journal_write_sb(journal);
    r = jbd_write_sb(jbd_fs);
    if (r != EOK)
        return r;

    jbd_fs->bdev->journal = journal;
    return EOK;
}

static void jbd_journal_flush_trans(struct jbd_trans *trans) {
    struct jbd_buf *jbd_buf, *tmp;
    struct jbd_journal *journal = trans->journal;
    struct ext4_fs *fs = journal->jbd_fs->inode_ref.fs;
    void *tmp_data = ext4_malloc(journal->block_size);
    ext4_assert(tmp_data);

    TAILQ_FOREACH_SAFE(jbd_buf, &trans->buf_queue, buf_node, tmp) {
        struct ext4_buf *buf;
        struct ext4_block block;
        /* The buffer is not yet flushed. */
        buf = ext4_bcache_find_get(fs->bdev->bc, &block, jbd_buf->block_rec->lba);
        if (!(buf && ext4_bcache_test_flag(buf, BC_UPTODATE) && jbd_buf->block_rec->trans == trans)) {
            int r;
            struct ext4_block jbd_block = EXT4_BLOCK_ZERO();
            r = jbd_block_get(journal->jbd_fs, &jbd_block, jbd_buf->jbd_lba);
            ext4_assert(r == EOK);
            memcpy(tmp_data, jbd_block.data, journal->block_size);
            ext4_block_set(fs->bdev, &jbd_block);
            r = ext4_blocks_set_direct(fs->bdev, tmp_data, jbd_buf->block_rec->lba, 1);
            jbd_trans_end_write(fs->bdev->bc, buf, r, jbd_buf);
        } else
            ext4_block_flush_buf(fs->bdev, buf);

        if (buf)
            ext4_block_set(fs->bdev, &block);
    }

    ext4_free(tmp_data);
}

static void jbd_journal_skip_pure_revoke(struct jbd_journal *journal, struct jbd_trans *trans) {
    journal->start = trans->start_iblock + trans->alloc_blocks;
    wrap(&journal->jbd_fs->sb, journal->start);
    journal->trans_id = trans->trans_id + 1;
    jbd_journal_free_trans(journal, trans, false);
    jbd_journal_write_sb(journal);
}

void jbd_journal_purge_cp_trans(struct jbd_journal *journal, bool flush, bool once) {
    struct jbd_trans *trans;
    while ((trans = TAILQ_FIRST(&journal->cp_queue))) {
        if (!trans->data_cnt) {
            TAILQ_REMOVE(&journal->cp_queue, trans, trans_node);
            jbd_journal_skip_pure_revoke(journal, trans);
        } else {
            if (trans->data_cnt == trans->written_cnt) {
                journal->start = trans->start_iblock + trans->alloc_blocks;
                wrap(&journal->jbd_fs->sb, journal->start);
                journal->trans_id = trans->trans_id + 1;
                TAILQ_REMOVE(&journal->cp_queue, trans, trans_node);
                jbd_journal_free_trans(journal, trans, false);
                jbd_journal_write_sb(journal);
            } else if (!flush) {
                journal->start = trans->start_iblock;
                wrap(&journal->jbd_fs->sb, journal->start);
                journal->trans_id = trans->trans_id;
                jbd_journal_write_sb(journal);
                break;
            } else
                jbd_journal_flush_trans(trans);
        }
        if (once)
            break;
    }
}

int jbd_journal_stop(struct jbd_journal *journal) {
    int r;
    struct jbd_fs *jbd_fs = journal->jbd_fs;
    uint32_t features_incompatible;

    /* Make sure that journalled content have reached
     * the disk.*/
    jbd_journal_purge_cp_trans(journal, true, false);

    /* There should be no block record in this journal
     * session. */
    if (!RB_EMPTY(&journal->block_rec_root))
        ext4_dbg(DEBUG_JBD, DBG_WARN "There are still block records "
                                     "in this journal session!\n");

    features_incompatible = ext4_get32(&jbd_fs->inode_ref.fs->sb, features_incompatible);
    features_incompatible &= ~EXT4_FINCOM_RECOVER;
    ext4_set32(&jbd_fs->inode_ref.fs->sb, features_incompatible, features_incompatible);
    r = ext4_sb_write(jbd_fs->bdev, &jbd_fs->inode_ref.fs->sb);
    if (r != EOK)
        return r;

    journal->start = 0;
    journal->trans_id = 0;
    jbd_journal_write_sb(journal);
    return jbd_write_sb(journal->jbd_fs);
}

static uint32_t jbd_journal_alloc_block(struct jbd_journal *journal, struct jbd_trans *trans) {
    uint32_t start_block;

    start_block = journal->last++;
    trans->alloc_blocks++;
    wrap(&journal->jbd_fs->sb, journal->last);

    /* If there is no space left, flush just one journalled
     * transaction.*/
    if (journal->last == journal->start) {
        jbd_journal_purge_cp_trans(journal, true, true);
        ext4_assert(journal->last != journal->start);
    }

    return start_block;
}

static struct jbd_block_rec *jbd_trans_block_rec_lookup(struct jbd_journal *journal, ext4_fsblk_t lba) {
    struct jbd_block_rec tmp = {.lba = lba};

    return RB_FIND(jbd_block, &journal->block_rec_root, &tmp);
}

static void jbd_trans_change_ownership(struct jbd_block_rec *block_rec, struct jbd_trans *new_trans) {
    LIST_REMOVE(block_rec, tbrec_node);
    if (new_trans) {
        /* Now this block record belongs to this transaction. */
        LIST_INSERT_HEAD(&new_trans->tbrec_list, block_rec, tbrec_node);
    }
    block_rec->trans = new_trans;
}

static inline struct jbd_block_rec *jbd_trans_insert_block_rec(struct jbd_trans *trans, ext4_fsblk_t lba) {
    struct jbd_block_rec *block_rec;
    block_rec = jbd_trans_block_rec_lookup(trans->journal, lba);
    if (block_rec) {
        jbd_trans_change_ownership(block_rec, trans);
        return block_rec;
    }
    block_rec = ext4_calloc(1, sizeof(struct jbd_block_rec));
    if (!block_rec)
        return NULL;

    block_rec->lba = lba;
    block_rec->trans = trans;
    TAILQ_INIT(&block_rec->dirty_buf_queue);
    LIST_INSERT_HEAD(&trans->tbrec_list, block_rec, tbrec_node);
    RB_INSERT(jbd_block, &trans->journal->block_rec_root, block_rec);
    return block_rec;
}

static void jbd_trans_finish_callback(struct jbd_journal *journal, const struct jbd_trans *trans,
                                      struct jbd_block_rec *block_rec, bool abort, bool revoke) {
    struct ext4_fs *fs = journal->jbd_fs->inode_ref.fs;
    if (block_rec->trans != trans)
        return;

    if (!abort) {
        struct jbd_buf *jbd_buf, *tmp;
        TAILQ_FOREACH_SAFE(jbd_buf, &block_rec->dirty_buf_queue, dirty_buf_node, tmp) {
            jbd_trans_end_write(fs->bdev->bc, NULL, EOK, jbd_buf);
        }
    } else {
        /*
         * We have to roll back data if the block is going to be
         * aborted.
         */
        struct jbd_buf *jbd_buf;
        struct ext4_block jbd_block = EXT4_BLOCK_ZERO(), block = EXT4_BLOCK_ZERO();
        jbd_buf = TAILQ_LAST(&block_rec->dirty_buf_queue, jbd_buf_dirty);
        if (jbd_buf) {
            if (!revoke) {
                int r;
                r = ext4_block_get_noread(fs->bdev, &block, block_rec->lba);
                ext4_assert(r == EOK);
                r = jbd_block_get(journal->jbd_fs, &jbd_block, jbd_buf->jbd_lba);
                ext4_assert(r == EOK);
                memcpy(block.data, jbd_block.data, journal->block_size);

                jbd_trans_change_ownership(block_rec, jbd_buf->trans);

                block.buf->end_write = jbd_trans_end_write;
                block.buf->end_write_arg = jbd_buf;

                ext4_bcache_set_flag(jbd_block.buf, BC_TMP);
                ext4_bcache_set_dirty(block.buf);

                ext4_block_set(fs->bdev, &jbd_block);
                ext4_block_set(fs->bdev, &block);
                return;
            } else {
                /* The revoked buffer is yet written. */
                jbd_trans_change_ownership(block_rec, jbd_buf->trans);
            }
        }
    }
}

static inline void jbd_trans_remove_block_rec(struct jbd_journal *journal, struct jbd_block_rec *block_rec,
                                              struct jbd_trans *trans) {
    /* If this block record doesn't belong to this transaction,
     * give up.*/
    if (block_rec->trans == trans) {
        LIST_REMOVE(block_rec, tbrec_node);
        RB_REMOVE(jbd_block, &journal->block_rec_root, block_rec);
        ext4_free(block_rec);
    }
}

int jbd_trans_set_block_dirty(struct jbd_trans *trans, struct ext4_block *block) {
    struct jbd_buf *jbd_buf;
    struct jbd_revoke_rec *rec, tmp_rec = {.lba = block->lb_id};
    struct jbd_block_rec *block_rec;

    if (block->buf->end_write == jbd_trans_end_write) {
        jbd_buf = block->buf->end_write_arg;
        if (jbd_buf && jbd_buf->trans == trans)
            return EOK;
    }
    jbd_buf = ext4_calloc(1, sizeof(struct jbd_buf));
    if (!jbd_buf)
        return ENOMEM;

    if ((block_rec = jbd_trans_insert_block_rec(trans, block->lb_id)) == NULL) {
        ext4_free(jbd_buf);
        return ENOMEM;
    }

    TAILQ_INSERT_TAIL(&block_rec->dirty_buf_queue, jbd_buf, dirty_buf_node);

    jbd_buf->block_rec = block_rec;
    jbd_buf->trans = trans;
    jbd_buf->block = *block;
    ext4_bcache_inc_ref(block->buf);

    /* If the content reach the disk, notify us
     * so that we may do a checkpoint. */
    block->buf->end_write = jbd_trans_end_write;
    block->buf->end_write_arg = jbd_buf;

    trans->data_cnt++;
    TAILQ_INSERT_HEAD(&trans->buf_queue, jbd_buf, buf_node);

    ext4_bcache_set_dirty(block->buf);
    rec = RB_FIND(jbd_revoke_tree, &trans->revoke_root, &tmp_rec);
    if (rec) {
        RB_REMOVE(jbd_revoke_tree, &trans->revoke_root, rec);
        ext4_free(rec);
    }

    return EOK;
}

int jbd_trans_revoke_block(struct jbd_trans *trans, ext4_fsblk_t lba) {
    struct jbd_revoke_rec tmp_rec = {.lba = lba}, *rec;
    rec = RB_FIND(jbd_revoke_tree, &trans->revoke_root, &tmp_rec);
    if (rec)
        return EOK;

    rec = ext4_calloc(1, sizeof(struct jbd_revoke_rec));
    if (!rec)
        return ENOMEM;

    rec->lba = lba;
    RB_INSERT(jbd_revoke_tree, &trans->revoke_root, rec);
    return EOK;
}

int jbd_trans_try_revoke_block(struct jbd_trans *trans, ext4_fsblk_t lba) {
    struct jbd_journal *journal = trans->journal;
    struct jbd_block_rec *block_rec = jbd_trans_block_rec_lookup(journal, lba);

    if (block_rec) {
        if (block_rec->trans == trans) {
            struct jbd_buf *jbd_buf = TAILQ_LAST(&block_rec->dirty_buf_queue, jbd_buf_dirty);
            /* If there are still unwritten buffers. */
            if (TAILQ_FIRST(&block_rec->dirty_buf_queue) != jbd_buf)
                jbd_trans_revoke_block(trans, lba);

        } else
            jbd_trans_revoke_block(trans, lba);
    }

    return EOK;
}

void jbd_journal_free_trans(struct jbd_journal *journal, struct jbd_trans *trans, bool abort) {
    struct jbd_buf *jbd_buf, *tmp;
    struct jbd_revoke_rec *rec, *tmp2;
    struct jbd_block_rec *block_rec, *tmp3;
    struct ext4_fs *fs = journal->jbd_fs->inode_ref.fs;
    TAILQ_FOREACH_SAFE(jbd_buf, &trans->buf_queue, buf_node, tmp) {
        block_rec = jbd_buf->block_rec;
        if (abort) {
            jbd_buf->block.buf->end_write = NULL;
            jbd_buf->block.buf->end_write_arg = NULL;
            ext4_bcache_clear_dirty(jbd_buf->block.buf);
            ext4_block_set(fs->bdev, &jbd_buf->block);
        }

        TAILQ_REMOVE(&jbd_buf->block_rec->dirty_buf_queue, jbd_buf, dirty_buf_node);
        jbd_trans_finish_callback(journal, trans, block_rec, abort, false);
        TAILQ_REMOVE(&trans->buf_queue, jbd_buf, buf_node);
        ext4_free(jbd_buf);
    }
    RB_FOREACH_SAFE(rec, jbd_revoke_tree, &trans->revoke_root, tmp2) {
        RB_REMOVE(jbd_revoke_tree, &trans->revoke_root, rec);
        ext4_free(rec);
    }
    LIST_FOREACH_SAFE(block_rec, &trans->tbrec_list, tbrec_node, tmp3) {
        jbd_trans_remove_block_rec(journal, block_rec, trans);
    }

    ext4_free(trans);
}

static int jbd_trans_write_commit_block(struct jbd_trans *trans) {
    int rc;
    struct ext4_block block;
    struct jbd_commit_header *header;
    uint32_t commit_iblock;
    struct jbd_journal *journal = trans->journal;

    commit_iblock = jbd_journal_alloc_block(journal, trans);

    rc = jbd_block_get_noread(journal->jbd_fs, &block, commit_iblock);
    if (rc != EOK)
        return rc;

    header = (struct jbd_commit_header *) block.data;
    jbd_set32(&header->header, magic, JBD_MAGIC_NUMBER);
    jbd_set32(&header->header, blocktype, JBD_COMMIT_BLOCK);
    jbd_set32(&header->header, sequence, trans->trans_id);

    if (JBD_HAS_INCOMPAT_FEATURE(&journal->jbd_fs->sb, JBD_FEATURE_COMPAT_CHECKSUM)) {
        header->chksum_type = JBD_CRC32_CHKSUM;
        header->chksum_size = JBD_CRC32_CHKSUM_SIZE;
        jbd_set32(header, chksum[0], trans->data_csum);
    }
    jbd_commit_csum_set(journal->jbd_fs, header);
    ext4_bcache_set_dirty(block.buf);
    ext4_bcache_set_flag(block.buf, BC_TMP);
    rc = jbd_block_set(journal->jbd_fs, &block);
    return rc;
}

static int jbd_journal_prepare(struct jbd_journal *journal, struct jbd_trans *trans) {
    int rc = EOK, i = 0;
    struct ext4_block desc_block = EXT4_BLOCK_ZERO(), data_block = EXT4_BLOCK_ZERO();
    int32_t tag_tbl_size = 0;
    uint32_t desc_iblock = 0;
    uint32_t data_iblock = 0;
    char *tag_start = NULL, *tag_ptr = NULL;
    struct jbd_buf *jbd_buf, *tmp;
    struct ext4_fs *fs = journal->jbd_fs->inode_ref.fs;
    uint32_t checksum = EXT4_CRC32_INIT;
    struct jbd_bhdr *bhdr = NULL;
    void *data;

    /* Try to remove any non-dirty buffers from the tail of
     * buf_queue. */
    TAILQ_FOREACH_REVERSE_SAFE(jbd_buf, &trans->buf_queue, jbd_trans_buf, buf_node, tmp) {
        struct jbd_revoke_rec tmp_rec = {.lba = jbd_buf->block_rec->lba};
        /* We stop the iteration when we find a dirty buffer. */
        if (ext4_bcache_test_flag(jbd_buf->block.buf, BC_DIRTY))
            break;

        TAILQ_REMOVE(&jbd_buf->block_rec->dirty_buf_queue, jbd_buf, dirty_buf_node);

        jbd_buf->block.buf->end_write = NULL;
        jbd_buf->block.buf->end_write_arg = NULL;
        jbd_trans_finish_callback(journal, trans, jbd_buf->block_rec, true,
                                  RB_FIND(jbd_revoke_tree, &trans->revoke_root, &tmp_rec));
        jbd_trans_remove_block_rec(journal, jbd_buf->block_rec, trans);
        trans->data_cnt--;

        ext4_block_set(fs->bdev, &jbd_buf->block);
        TAILQ_REMOVE(&trans->buf_queue, jbd_buf, buf_node);
        ext4_free(jbd_buf);
    }

    TAILQ_FOREACH_SAFE(jbd_buf, &trans->buf_queue, buf_node, tmp) {
        struct tag_info tag_info;
        bool uuid_exist = false;
        bool is_escape = false;
        struct jbd_revoke_rec tmp_rec = {.lba = jbd_buf->block_rec->lba};
        if (!ext4_bcache_test_flag(jbd_buf->block.buf, BC_DIRTY)) {
            TAILQ_REMOVE(&jbd_buf->block_rec->dirty_buf_queue, jbd_buf, dirty_buf_node);

            jbd_buf->block.buf->end_write = NULL;
            jbd_buf->block.buf->end_write_arg = NULL;

            /* The buffer has not been modified, just release
             * that jbd_buf. */
            jbd_trans_finish_callback(journal, trans, jbd_buf->block_rec, true,
                                      RB_FIND(jbd_revoke_tree, &trans->revoke_root, &tmp_rec));
            jbd_trans_remove_block_rec(journal, jbd_buf->block_rec, trans);
            trans->data_cnt--;

            ext4_block_set(fs->bdev, &jbd_buf->block);
            TAILQ_REMOVE(&trans->buf_queue, jbd_buf, buf_node);
            ext4_free(jbd_buf);
            continue;
        }
        checksum = jbd_block_csum(journal->jbd_fs, jbd_buf->block.data, checksum, trans->trans_id);
        if (((struct jbd_bhdr *) jbd_buf->block.data)->magic == to_be32(JBD_MAGIC_NUMBER))
            is_escape = true;

    again:
        if (!desc_iblock) {
            desc_iblock = jbd_journal_alloc_block(journal, trans);
            rc = jbd_block_get_noread(journal->jbd_fs, &desc_block, desc_iblock);
            if (rc != EOK)
                break;

            bhdr = (struct jbd_bhdr *) desc_block.data;
            jbd_set32(bhdr, magic, JBD_MAGIC_NUMBER);
            jbd_set32(bhdr, blocktype, JBD_DESCRIPTOR_BLOCK);
            jbd_set32(bhdr, sequence, trans->trans_id);

            tag_start = (char *) (bhdr + 1);
            tag_ptr = tag_start;
            uuid_exist = true;
            tag_tbl_size = journal->block_size - sizeof(struct jbd_bhdr);

            if (jbd_has_csum(&journal->jbd_fs->sb))
                tag_tbl_size -= sizeof(struct jbd_block_tail);

            if (!trans->start_iblock)
                trans->start_iblock = desc_iblock;

            ext4_bcache_set_dirty(desc_block.buf);
            ext4_bcache_set_flag(desc_block.buf, BC_TMP);
        }
        tag_info.block = jbd_buf->block.lb_id;
        tag_info.uuid_exist = uuid_exist;
        tag_info.is_escape = is_escape;
        if (i == trans->data_cnt - 1)
            tag_info.last_tag = true;
        else
            tag_info.last_tag = false;

        tag_info.checksum = checksum;

        if (uuid_exist)
            memcpy(tag_info.uuid, journal->jbd_fs->sb.uuid, UUID_SIZE);

        rc = jbd_write_block_tag(journal->jbd_fs, tag_ptr, tag_tbl_size, &tag_info);
        if (rc != EOK) {
            jbd_meta_csum_set(journal->jbd_fs, bhdr);
            desc_iblock = 0;
            rc = jbd_block_set(journal->jbd_fs, &desc_block);
            if (rc != EOK)
                break;

            goto again;
        }

        data_iblock = jbd_journal_alloc_block(journal, trans);
        rc = jbd_block_get_noread(journal->jbd_fs, &data_block, data_iblock);
        if (rc != EOK) {
            desc_iblock = 0;
            ext4_bcache_clear_dirty(desc_block.buf);
            jbd_block_set(journal->jbd_fs, &desc_block);
            break;
        }

        data = data_block.data;
        memcpy(data, jbd_buf->block.data, journal->block_size);
        if (is_escape)
            ((struct jbd_bhdr *) data)->magic = 0;

        ext4_bcache_set_dirty(data_block.buf);
        ext4_bcache_set_flag(data_block.buf, BC_TMP);
        rc = jbd_block_set(journal->jbd_fs, &data_block);
        if (rc != EOK) {
            desc_iblock = 0;
            ext4_bcache_clear_dirty(desc_block.buf);
            jbd_block_set(journal->jbd_fs, &desc_block);
            break;
        }
        jbd_buf->jbd_lba = data_iblock;

        tag_ptr += tag_info.tag_bytes;
        tag_tbl_size -= tag_info.tag_bytes;

        i++;
    }
    if (rc == EOK && desc_iblock) {
        jbd_meta_csum_set(journal->jbd_fs, (struct jbd_bhdr *) bhdr);
        trans->data_csum = checksum;
        rc = jbd_block_set(journal->jbd_fs, &desc_block);
    }

    return rc;
}

static int jbd_journal_prepare_revoke(struct jbd_journal *journal, struct jbd_trans *trans) {
    int rc = EOK, i = 0;
    struct ext4_block desc_block = EXT4_BLOCK_ZERO();
    int32_t tag_tbl_size = 0;
    uint32_t desc_iblock = 0;
    char *blocks_entry = NULL;
    struct jbd_revoke_rec *rec, *tmp;
    struct jbd_revoke_header *header = NULL;
    int32_t record_len = 4;
    struct jbd_bhdr *bhdr = NULL;

    if (JBD_HAS_INCOMPAT_FEATURE(&journal->jbd_fs->sb, JBD_FEATURE_INCOMPAT_64BIT))
        record_len = 8;

    RB_FOREACH_SAFE(rec, jbd_revoke_tree, &trans->revoke_root, tmp) {
    again:
        if (!desc_iblock) {
            desc_iblock = jbd_journal_alloc_block(journal, trans);
            rc = jbd_block_get_noread(journal->jbd_fs, &desc_block, desc_iblock);
            if (rc != EOK)
                break;

            bhdr = (struct jbd_bhdr *) desc_block.data;
            jbd_set32(bhdr, magic, JBD_MAGIC_NUMBER);
            jbd_set32(bhdr, blocktype, JBD_REVOKE_BLOCK);
            jbd_set32(bhdr, sequence, trans->trans_id);

            header = (struct jbd_revoke_header *) bhdr;
            blocks_entry = (char *) (header + 1);
            tag_tbl_size = journal->block_size - sizeof(struct jbd_revoke_header);

            if (jbd_has_csum(&journal->jbd_fs->sb))
                tag_tbl_size -= sizeof(struct jbd_block_tail);

            if (!trans->start_iblock)
                trans->start_iblock = desc_iblock;

            ext4_bcache_set_dirty(desc_block.buf);
            ext4_bcache_set_flag(desc_block.buf, BC_TMP);
        }

        if (tag_tbl_size < record_len) {
            jbd_set32(header, count, journal->block_size - tag_tbl_size);
            jbd_meta_csum_set(journal->jbd_fs, bhdr);
            bhdr = NULL;
            desc_iblock = 0;
            header = NULL;
            rc = jbd_block_set(journal->jbd_fs, &desc_block);
            if (rc != EOK)
                break;

            goto again;
        }
        if (record_len == 8) {
            uint64_t *blocks = (uint64_t *) blocks_entry;
            *blocks = to_be64(rec->lba);
        } else {
            uint32_t *blocks = (uint32_t *) blocks_entry;
            *blocks = to_be32((uint32_t) rec->lba);
        }
        blocks_entry += record_len;
        tag_tbl_size -= record_len;

        i++;
    }
    if (rc == EOK && desc_iblock) {
        if (header != NULL)
            jbd_set32(header, count, journal->block_size - tag_tbl_size);

        jbd_meta_csum_set(journal->jbd_fs, bhdr);
        rc = jbd_block_set(journal->jbd_fs, &desc_block);
    }

    return rc;
}

void jbd_journal_cp_trans(struct jbd_journal *journal, struct jbd_trans *trans) {
    struct jbd_buf *jbd_buf, *tmp;
    struct ext4_fs *fs = journal->jbd_fs->inode_ref.fs;
    TAILQ_FOREACH_SAFE(jbd_buf, &trans->buf_queue, buf_node, tmp) {
        struct ext4_block block = jbd_buf->block;
        ext4_block_set(fs->bdev, &block);
    }
}

static void jbd_trans_end_write(struct ext4_bcache *bc __unused, struct ext4_buf *buf, int res, void *arg) {
    struct jbd_buf *jbd_buf = arg;
    struct jbd_trans *trans = jbd_buf->trans;
    struct jbd_block_rec *block_rec = jbd_buf->block_rec;
    struct jbd_journal *journal = trans->journal;
    bool first_in_queue = trans == TAILQ_FIRST(&journal->cp_queue);
    if (res != EOK)
        trans->error = res;

    TAILQ_REMOVE(&trans->buf_queue, jbd_buf, buf_node);
    TAILQ_REMOVE(&block_rec->dirty_buf_queue, jbd_buf, dirty_buf_node);

    jbd_trans_finish_callback(journal, trans, jbd_buf->block_rec, false, false);
    if (block_rec->trans == trans && buf) {
        /* Clear the end_write and end_write_arg fields. */
        buf->end_write = NULL;
        buf->end_write_arg = NULL;
    }

    ext4_free(jbd_buf);

    trans->written_cnt++;
    if (trans->written_cnt == trans->data_cnt) {
        /* If it is the first transaction on checkpoint queue,
         * we will shift the start of the journal to the next
         * transaction, and remove subsequent written
         * transactions from checkpoint queue until we find
         * an unwritten one. */
        if (first_in_queue) {
            journal->start = trans->start_iblock + trans->alloc_blocks;
            wrap(&journal->jbd_fs->sb, journal->start);
            journal->trans_id = trans->trans_id + 1;
            TAILQ_REMOVE(&journal->cp_queue, trans, trans_node);
            jbd_journal_free_trans(journal, trans, false);

            jbd_journal_purge_cp_trans(journal, false, false);
            jbd_journal_write_sb(journal);
            jbd_write_sb(journal->jbd_fs);
        }
    }
}

static int __jbd_journal_commit_trans(struct jbd_journal *journal, struct jbd_trans *trans) {
    int rc = EOK;
    uint32_t last = journal->last;
    struct jbd_revoke_rec *rec, *tmp;

    trans->trans_id = journal->alloc_trans_id;
    rc = jbd_journal_prepare(journal, trans);
    if (rc != EOK)
        goto Finish;

    rc = jbd_journal_prepare_revoke(journal, trans);
    if (rc != EOK)
        goto Finish;

    if (TAILQ_EMPTY(&trans->buf_queue) && RB_EMPTY(&trans->revoke_root)) {
        /* Since there are no entries in both buffer list
         * and revoke entry list, we do not consider trans as
         * complete transaction and just return EOK.*/
        jbd_journal_free_trans(journal, trans, false);
        goto Finish;
    }

    rc = jbd_trans_write_commit_block(trans);
    if (rc != EOK)
        goto Finish;

    journal->alloc_trans_id++;

    /* Complete the checkpoint of buffers which are revoked. */
    RB_FOREACH_SAFE(rec, jbd_revoke_tree, &trans->revoke_root, tmp) {
        struct jbd_block_rec *block_rec = jbd_trans_block_rec_lookup(journal, rec->lba);
        struct jbd_buf *jbd_buf = NULL;
        if (block_rec)
            jbd_buf = TAILQ_LAST(&block_rec->dirty_buf_queue, jbd_buf_dirty);
        if (jbd_buf) {
            struct ext4_buf *buf;
            struct ext4_block block = EXT4_BLOCK_ZERO();
            /*
             * We do this to reset the ext4_buf::end_write and
             * ext4_buf::end_write_arg fields so that the checkpoint
             * callback won't be triggered again.
             */
            buf = ext4_bcache_find_get(journal->jbd_fs->bdev->bc, &block, jbd_buf->block_rec->lba);
            jbd_trans_end_write(journal->jbd_fs->bdev->bc, buf, EOK, jbd_buf);
            if (buf)
                ext4_block_set(journal->jbd_fs->bdev, &block);
        }
    }

    if (TAILQ_EMPTY(&journal->cp_queue)) {
        /*
         * This transaction is going to be the first object in the
         * checkpoint queue.
         * When the first transaction in checkpoint queue is completely
         * written to disk, we shift the tail of the log to right.
         */
        if (trans->data_cnt) {
            journal->start = trans->start_iblock;
            wrap(&journal->jbd_fs->sb, journal->start);
            journal->trans_id = trans->trans_id;
            jbd_journal_write_sb(journal);
            jbd_write_sb(journal->jbd_fs);
            TAILQ_INSERT_TAIL(&journal->cp_queue, trans, trans_node);
            jbd_journal_cp_trans(journal, trans);
        } else {
            journal->start = trans->start_iblock + trans->alloc_blocks;
            wrap(&journal->jbd_fs->sb, journal->start);
            journal->trans_id = trans->trans_id + 1;
            jbd_journal_write_sb(journal);
            jbd_journal_free_trans(journal, trans, false);
        }
    } else {
        /* No need to do anything to the JBD superblock. */
        TAILQ_INSERT_TAIL(&journal->cp_queue, trans, trans_node);
        if (trans->data_cnt)
            jbd_journal_cp_trans(journal, trans);
    }
Finish:
    if (rc != EOK && rc != ENOSPC) {
        journal->last = last;
        jbd_journal_free_trans(journal, trans, true);
    }
    return rc;
}

struct jbd_trans *jbd_journal_new_trans(struct jbd_journal *journal) {
    struct jbd_trans *trans = NULL;
    trans = ext4_calloc(1, sizeof(struct jbd_trans));
    if (!trans)
        return NULL;

    /* We will assign a trans_id to this transaction,
     * once it has been committed.*/
    trans->journal = journal;
    trans->data_csum = EXT4_CRC32_INIT;
    trans->error = EOK;
    TAILQ_INIT(&trans->buf_queue);
    return trans;
}

int jbd_journal_commit_trans(struct jbd_journal *journal, struct jbd_trans *trans) {
    int r = EOK;
    r = __jbd_journal_commit_trans(journal, trans);
    return r;
}

struct ext4_part_entry {
    uint8_t status;
    uint8_t chs1[3];
    uint8_t type;
    uint8_t chs2[3];
    uint32_t first_lba;
    uint32_t sectors;
}

struct ext4_mbr {
    uint8_t bootstrap[442];
    uint32_t disk_id;
    struct ext4_part_entry part_entry[4];
    uint16_t signature;
}

int ext4_mbr_scan(struct ext4_blockdev *parent, struct ext4_mbr_bdevs *bdevs) {
    int r;
    size_t i;

    ext4_dbg(DEBUG_MBR, DBG_INFO "ext4_mbr_scan\n");
    memset(bdevs, 0, sizeof(struct ext4_mbr_bdevs));
    r = ext4_block_init(parent);
    if (r != EOK)
        return r;

    r = ext4_block_readbytes(parent, 0, parent->bdif->ph_bbuf, 512);
    if (r != EOK) {
        goto blockdev_fini;
    }

    const struct ext4_mbr *mbr = (void *) parent->bdif->ph_bbuf;

    if (to_le16(mbr->signature) != MBR_SIGNATURE) {
        ext4_dbg(DEBUG_MBR,
                 DBG_ERROR "ext4_mbr_scan: unknown "
                           "signature: 0x%x\n",
                 to_le16(mbr->signature));
        r = ENOENT;
        goto blockdev_fini;
    }

    /*Show bootstrap code*/
    ext4_dbg(DEBUG_MBR, "mbr_part: bootstrap:");
    for (i = 0; i < sizeof(mbr->bootstrap); ++i) {
        if (!(i & 0xF))
            ext4_dbg(DEBUG_MBR | DEBUG_NOPREFIX, "\n");
        ext4_dbg(DEBUG_MBR | DEBUG_NOPREFIX, "%02x, ", mbr->bootstrap[i]);
    }

    ext4_dbg(DEBUG_MBR | DEBUG_NOPREFIX, "\n\n");
    for (i = 0; i < 4; ++i) {
        const struct ext4_part_entry *pe = &mbr->part_entry[i];
        ext4_dbg(DEBUG_MBR, "mbr_part: %d\n", (int) i);
        ext4_dbg(DEBUG_MBR, "\tstatus: 0x%x\n", pe->status);
        ext4_dbg(DEBUG_MBR, "\ttype 0x%x:\n", pe->type);
        ext4_dbg(DEBUG_MBR, "\tfirst_lba: 0x%" PRIx32 "\n", pe->first_lba);
        ext4_dbg(DEBUG_MBR, "\tsectors: 0x%" PRIx32 "\n", pe->sectors);

        if (!pe->sectors)
            continue; /*Empty entry*/

        if (pe->type != 0x83)
            continue; /*Unsupported entry. 0x83 - linux native*/

        bdevs->partitions[i].bdif = parent->bdif;
        bdevs->partitions[i].part_offset = (uint64_t) pe->first_lba * parent->bdif->ph_bsize;
        bdevs->partitions[i].part_size = (uint64_t) pe->sectors * parent->bdif->ph_bsize;
    }

blockdev_fini:
    ext4_block_fini(parent);
    return r;
}

int ext4_mbr_write(struct ext4_blockdev *parent, struct ext4_mbr_parts *parts, uint32_t disk_id) {
    int r;
    uint64_t disk_size;
    uint32_t division_sum = parts->division[0] + parts->division[1] + parts->division[2] + parts->division[3];

    if (division_sum > 100)
        return EINVAL;

    ext4_dbg(DEBUG_MBR, DBG_INFO "ext4_mbr_write\n");
    r = ext4_block_init(parent);
    if (r != EOK)
        return r;

    disk_size = parent->part_size;

    /*Calculate CHS*/
    uint32_t k = 16;
    while ((k < 256) && ((disk_size / k / 63) > 1024))
        k *= 2;

    if (k == 256)
        --k;

    const uint32_t cyl_size = 63 * k;
    const uint32_t cyl_count = disk_size / cyl_size;

    struct ext4_mbr *mbr = (void *) parent->bdif->ph_bbuf;
    memset(mbr, 0, sizeof(struct ext4_mbr));

    mbr->disk_id = disk_id;

    uint32_t cyl_it = 0;
    for (int i = 0; i < 4; ++i) {
        uint32_t cyl_part = cyl_count * parts->division[i] / 100;
        if (!cyl_part)
            continue;

        uint32_t part_start = cyl_it * cyl_size;
        uint32_t part_size = cyl_part * cyl_size;

        if (i == 0) {
            part_start += 63;
            part_size -= 63 * parent->bdif->ph_bsize;
        }

        uint32_t cyl_end = cyl_part + cyl_it - 1;

        mbr->part_entry[i].status = 0;
        mbr->part_entry[i].chs1[0] = i ? 0 : 1;
        ;
        mbr->part_entry[i].chs1[1] = (cyl_it >> 2) + 1;
        mbr->part_entry[i].chs1[2] = cyl_it;
        mbr->part_entry[i].type = 0x83;
        mbr->part_entry[i].chs2[0] = k - 1;
        mbr->part_entry[i].chs2[1] = (cyl_end >> 2) + 63;
        mbr->part_entry[i].chs2[2] = cyl_end;

        mbr->part_entry[i].first_lba = part_start;
        mbr->part_entry[i].sectors = part_size / parent->bdif->ph_bsize;

        cyl_it += cyl_part;
    }

    mbr->signature = MBR_SIGNATURE;
    r = ext4_block_writebytes(parent, 0, parent->bdif->ph_bbuf, 512);
    if (r != EOK)
        goto blockdev_fini;


blockdev_fini:
    ext4_block_fini(parent);
    return r;
}

struct fs_aux_info {
    struct ext4_sblock *sb;
    uint8_t *bg_desc_blk;
    struct xattr_list_element *xattrs;
    uint32_t first_data_block;
    uint64_t len_blocks;
    uint32_t inode_table_blocks;
    uint32_t groups;
    uint32_t bg_desc_blocks;
    uint32_t default_i_flags;
    uint32_t blocks_per_ind;
    uint32_t blocks_per_dind;
    uint32_t blocks_per_tind;
}

static inline int log_2(int j) {
    int i;

    for (i = 0; j > 0; i++)
        j >>= 1;

    return i - 1;
}

static int sb2info(struct ext4_sblock *sb, struct ext4_mkfs_info *info) {
    if (to_le16(sb->magic) != EXT4_SUPERBLOCK_MAGIC)
        return EINVAL;

    info->block_size = 1024 << to_le32(sb->log_block_size);
    info->blocks_per_group = to_le32(sb->blocks_per_group);
    info->inodes_per_group = to_le32(sb->inodes_per_group);
    info->inode_size = to_le16(sb->inode_size);
    info->inodes = to_le32(sb->inodes_count);
    info->feat_ro_compat = to_le32(sb->features_read_only);
    info->feat_compat = to_le32(sb->features_compatible);
    info->feat_incompat = to_le32(sb->features_incompatible);
    info->bg_desc_reserve_blocks = to_le16(sb->s_reserved_gdt_blocks);
    info->label = sb->volume_name;
    info->len = (uint64_t) info->block_size * ext4_sb_get_blocks_cnt(sb);
    info->dsc_size = to_le16(sb->desc_size);
    memcpy(info->uuid, sb->uuid, UUID_SIZE);

    return EOK;
}

static uint32_t compute_inodes(struct ext4_mkfs_info *info) {
    return (uint32_t) EXT4_DIV_ROUND_UP(info->len, info->block_size) / 4;
}

static uint32_t compute_inodes_per_group(struct ext4_mkfs_info *info) {
    uint32_t blocks = (uint32_t) EXT4_DIV_ROUND_UP(info->len, info->block_size);
    uint32_t block_groups = EXT4_DIV_ROUND_UP(blocks, info->blocks_per_group);
    uint32_t inodes = EXT4_DIV_ROUND_UP(info->inodes, block_groups);
    inodes = EXT4_ALIGN(inodes, (info->block_size / info->inode_size));

    /* After properly rounding up the number of inodes/group,
     * make sure to update the total inodes field in the info struct.
     */
    info->inodes = inodes * block_groups;

    return inodes;
}

static uint32_t compute_journal_blocks(struct ext4_mkfs_info *info) {
    uint32_t journal_blocks = (uint32_t) EXT4_DIV_ROUND_UP(info->len, info->block_size) / 64;
    if (journal_blocks < 1024)
        journal_blocks = 1024;
    if (journal_blocks > 32768)
        journal_blocks = 32768;
    return journal_blocks;
}

static bool has_superblock(struct ext4_mkfs_info *info, uint32_t bgid) {
    if (!(info->feat_ro_compat & EXT4_FRO_COM_SPARSE_SUPER))
        return true;

    return ext4_sb_sparse(bgid);
}

static int create_fs_aux_info(struct fs_aux_info *aux_info, struct ext4_mkfs_info *info) {
    aux_info->first_data_block = (info->block_size > 1024) ? 0 : 1;
    aux_info->len_blocks = info->len / info->block_size;
    aux_info->inode_table_blocks = EXT4_DIV_ROUND_UP(info->inodes_per_group * info->inode_size, info->block_size);
    aux_info->groups =
            (uint32_t) EXT4_DIV_ROUND_UP(aux_info->len_blocks - aux_info->first_data_block, info->blocks_per_group);
    aux_info->blocks_per_ind = info->block_size / sizeof(uint32_t);
    aux_info->blocks_per_dind = aux_info->blocks_per_ind * aux_info->blocks_per_ind;
    aux_info->blocks_per_tind = aux_info->blocks_per_dind * aux_info->blocks_per_dind;

    aux_info->bg_desc_blocks = EXT4_DIV_ROUND_UP(aux_info->groups * info->dsc_size, info->block_size);

    aux_info->default_i_flags = EXT4_INODE_FLAG_NOATIME;

    uint32_t last_group_size = aux_info->len_blocks % info->blocks_per_group;
    uint32_t last_header_size = 2 + aux_info->inode_table_blocks;
    if (has_superblock(info, aux_info->groups - 1))
        last_header_size += 1 + aux_info->bg_desc_blocks + info->bg_desc_reserve_blocks;

    if (last_group_size > 0 && last_group_size < last_header_size) {
        aux_info->groups--;
        aux_info->len_blocks -= last_group_size;
    }

    aux_info->sb = ext4_calloc(1, EXT4_SUPERBLOCK_SIZE);
    if (!aux_info->sb)
        return ENOMEM;

    aux_info->bg_desc_blk = ext4_calloc(1, info->block_size);
    if (!aux_info->bg_desc_blk)
        return ENOMEM;

    aux_info->xattrs = NULL;


    ext4_dbg(DEBUG_MKFS, DBG_INFO "create_fs_aux_info\n");
    ext4_dbg(DEBUG_MKFS, DBG_NONE "first_data_block: %" PRIu32 "\n", aux_info->first_data_block);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "len_blocks: %" PRIu64 "\n", aux_info->len_blocks);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "inode_table_blocks: %" PRIu32 "\n", aux_info->inode_table_blocks);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "groups: %" PRIu32 "\n", aux_info->groups);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "bg_desc_blocks: %" PRIu32 "\n", aux_info->bg_desc_blocks);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "default_i_flags: %" PRIu32 "\n", aux_info->default_i_flags);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "blocks_per_ind: %" PRIu32 "\n", aux_info->blocks_per_ind);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "blocks_per_dind: %" PRIu32 "\n", aux_info->blocks_per_dind);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "blocks_per_tind: %" PRIu32 "\n", aux_info->blocks_per_tind);

    return EOK;
}

static void release_fs_aux_info(struct fs_aux_info *aux_info) {
    if (aux_info->sb)
        ext4_free(aux_info->sb);
    if (aux_info->bg_desc_blk)
        ext4_free(aux_info->bg_desc_blk);
}

static void fill_sb(struct fs_aux_info *aux_info, struct ext4_mkfs_info *info) {
    struct ext4_sblock *sb = aux_info->sb;

    sb->inodes_count = to_le32(info->inodes_per_group * aux_info->groups);

    ext4_sb_set_blocks_cnt(sb, aux_info->len_blocks);
    ext4_sb_set_free_blocks_cnt(sb, aux_info->len_blocks);
    sb->free_inodes_count = to_le32(info->inodes_per_group * aux_info->groups);

    sb->reserved_blocks_count_lo = to_le32(0);
    sb->first_data_block = to_le32(aux_info->first_data_block);
    sb->log_block_size = to_le32(log_2(info->block_size / 1024));
    sb->log_cluster_size = to_le32(log_2(info->block_size / 1024));
    sb->blocks_per_group = to_le32(info->blocks_per_group);
    sb->frags_per_group = to_le32(info->blocks_per_group);
    sb->inodes_per_group = to_le32(info->inodes_per_group);
    sb->mount_time = to_le32(0);
    sb->write_time = to_le32(0);
    sb->mount_count = to_le16(0);
    sb->max_mount_count = to_le16(0xFFFF);
    sb->magic = to_le16(EXT4_SUPERBLOCK_MAGIC);
    sb->state = to_le16(EXT4_SUPERBLOCK_STATE_VALID_FS);
    sb->errors = to_le16(EXT4_SUPERBLOCK_ERRORS_RO);
    sb->minor_rev_level = to_le16(0);
    sb->last_check_time = to_le32(0);
    sb->check_interval = to_le32(0);
    sb->creator_os = to_le32(EXT4_SUPERBLOCK_OS_LINUX);
    sb->rev_level = to_le32(1);
    sb->def_resuid = to_le16(0);
    sb->def_resgid = to_le16(0);

    sb->first_inode = to_le32(EXT4_GOOD_OLD_FIRST_INO);
    sb->inode_size = to_le16(info->inode_size);
    sb->block_group_index = to_le16(0);

    sb->features_compatible = to_le32(info->feat_compat);
    sb->features_incompatible = to_le32(info->feat_incompat);
    sb->features_read_only = to_le32(info->feat_ro_compat);

    memcpy(sb->uuid, info->uuid, UUID_SIZE);

    memset(sb->volume_name, 0, sizeof(sb->volume_name));
    strncpy(sb->volume_name, info->label, sizeof(sb->volume_name));
    memset(sb->last_mounted, 0, sizeof(sb->last_mounted));

    sb->algorithm_usage_bitmap = to_le32(0);
    sb->s_prealloc_blocks = 0;
    sb->s_prealloc_dir_blocks = 0;
    sb->s_reserved_gdt_blocks = to_le16(info->bg_desc_reserve_blocks);

    if (info->feat_compat & EXT4_FCOM_HAS_JOURNAL)
        sb->journal_inode_number = to_le32(EXT4_JOURNAL_INO);

    sb->journal_backup_type = 1;
    sb->journal_dev = to_le32(0);
    sb->last_orphan = to_le32(0);
    sb->hash_seed[0] = to_le32(0x11111111);
    sb->hash_seed[1] = to_le32(0x22222222);
    sb->hash_seed[2] = to_le32(0x33333333);
    sb->hash_seed[3] = to_le32(0x44444444);
    sb->default_hash_version = EXT2_HTREE_HALF_MD4;
    sb->checksum_type = 1;
    sb->desc_size = to_le16(info->dsc_size);
    sb->default_mount_opts = to_le32(0);
    sb->first_meta_bg = to_le32(0);
    sb->mkfs_time = to_le32(0);

    sb->reserved_blocks_count_hi = to_le32(0);
    sb->min_extra_isize = to_le32(sizeof(struct ext4_inode) - EXT4_GOOD_OLD_INODE_SIZE);
    sb->want_extra_isize = to_le32(sizeof(struct ext4_inode) - EXT4_GOOD_OLD_INODE_SIZE);
    sb->flags = to_le32(EXT4_SUPERBLOCK_FLAGS_SIGNED_HASH);
}

static int write_bgroup_block(struct ext4_blockdev *bd, struct fs_aux_info *aux_info, struct ext4_mkfs_info *info,
                              uint32_t blk) {
    int r = EOK;
    uint32_t j;
    struct ext4_block b;

    uint32_t block_size = ext4_sb_get_block_size(aux_info->sb);

    for (j = 0; j < aux_info->groups; j++) {
        uint64_t bg_start_block = aux_info->first_data_block + j * info->blocks_per_group;
        uint32_t blk_off = 0;

        blk_off += aux_info->bg_desc_blocks;
        if (has_superblock(info, j)) {
            bg_start_block++;
            blk_off += info->bg_desc_reserve_blocks;
        }

        uint64_t dsc_blk = bg_start_block + blk;

        r = ext4_block_get_noread(bd, &b, dsc_blk);
        if (r != EOK)
            return r;

        memcpy(b.data, aux_info->bg_desc_blk, block_size);

        ext4_bcache_set_dirty(b.buf);
        r = ext4_block_set(bd, &b);
        if (r != EOK)
            return r;
    }

    return r;
}

static int write_bgroups(struct ext4_blockdev *bd, struct fs_aux_info *aux_info, struct ext4_mkfs_info *info) {
    int r = EOK;

    struct ext4_block b;
    struct ext4_bgroup *bg_desc;

    uint32_t i;
    uint32_t bg_free_blk = 0;
    uint64_t sb_free_blk = 0;
    uint32_t block_size = ext4_sb_get_block_size(aux_info->sb);
    uint32_t dsc_size = ext4_sb_get_desc_size(aux_info->sb);
    uint32_t dsc_per_block = block_size / dsc_size;
    uint32_t k = 0;

    for (i = 0; i < aux_info->groups; i++) {
        uint64_t bg_start_block = aux_info->first_data_block + aux_info->first_data_block + i * info->blocks_per_group;
        uint32_t blk_off = 0;

        bg_desc = (void *) (aux_info->bg_desc_blk + k * dsc_size);
        bg_free_blk = info->blocks_per_group - aux_info->inode_table_blocks;

        bg_free_blk -= 2;
        blk_off += aux_info->bg_desc_blocks;

        if (i == (aux_info->groups - 1))
            bg_free_blk -= aux_info->first_data_block;

        if (has_superblock(info, i)) {
            bg_start_block++;
            blk_off += info->bg_desc_reserve_blocks;
            bg_free_blk -= info->bg_desc_reserve_blocks + 1;
            bg_free_blk -= aux_info->bg_desc_blocks;
        }

        ext4_bg_set_block_bitmap(bg_desc, aux_info->sb, bg_start_block + blk_off + 1);

        ext4_bg_set_inode_bitmap(bg_desc, aux_info->sb, bg_start_block + blk_off + 2);

        ext4_bg_set_inode_table_first_block(bg_desc, aux_info->sb, bg_start_block + blk_off + 3);

        ext4_bg_set_free_blocks_count(bg_desc, aux_info->sb, bg_free_blk);

        ext4_bg_set_free_inodes_count(bg_desc, aux_info->sb, to_le32(aux_info->sb->inodes_per_group));

        ext4_bg_set_used_dirs_count(bg_desc, aux_info->sb, 0);

        ext4_bg_set_flag(bg_desc, EXT4_BLOCK_GROUP_BLOCK_UNINIT | EXT4_BLOCK_GROUP_INODE_UNINIT);

        sb_free_blk += bg_free_blk;

        r = ext4_block_get_noread(bd, &b, bg_start_block + blk_off + 1);
        if (r != EOK)
            return r;
        memset(b.data, 0, block_size);
        ext4_bcache_set_dirty(b.buf);
        r = ext4_block_set(bd, &b);
        if (r != EOK)
            return r;
        r = ext4_block_get_noread(bd, &b, bg_start_block + blk_off + 2);
        if (r != EOK)
            return r;
        memset(b.data, 0, block_size);
        ext4_bcache_set_dirty(b.buf);
        r = ext4_block_set(bd, &b);
        if (r != EOK)
            return r;

        if (++k != dsc_per_block)
            continue;

        k = 0;
        r = write_bgroup_block(bd, aux_info, info, i / dsc_per_block);
        if (r != EOK)
            return r;
    }

    r = write_bgroup_block(bd, aux_info, info, i / dsc_per_block);
    if (r != EOK)
        return r;

    ext4_sb_set_free_blocks_cnt(aux_info->sb, sb_free_blk);
    return r;
}

static int write_sblocks(struct ext4_blockdev *bd, struct fs_aux_info *aux_info, struct ext4_mkfs_info *info) {
    uint64_t offset;
    uint32_t i;
    int r;

    /* write out the backup superblocks */
    for (i = 1; i < aux_info->groups; i++) {
        if (has_superblock(info, i)) {
            offset = info->block_size * (aux_info->first_data_block + i * info->blocks_per_group);

            aux_info->sb->block_group_index = to_le16(i);
            r = ext4_block_writebytes(bd, offset, aux_info->sb, EXT4_SUPERBLOCK_SIZE);
            if (r != EOK)
                return r;
        }
    }

    /* write out the primary superblock */
    aux_info->sb->block_group_index = to_le16(0);
    return ext4_block_writebytes(bd, 1024, aux_info->sb, EXT4_SUPERBLOCK_SIZE);
}

int ext4_mkfs_read_info(struct ext4_blockdev *bd, struct ext4_mkfs_info *info) {
    int r;
    struct ext4_sblock *sb = NULL;
    r = ext4_block_init(bd);
    if (r != EOK)
        return r;

    sb = ext4_malloc(EXT4_SUPERBLOCK_SIZE);
    if (!sb)
        goto Finish;


    r = ext4_sb_read(bd, sb);
    if (r != EOK)
        goto Finish;

    r = sb2info(sb, info);

Finish:
    if (sb)
        ext4_free(sb);
    ext4_block_fini(bd);
    return r;
}

static int mkfs_init(struct ext4_blockdev *bd, struct ext4_mkfs_info *info) {
    int r;
    struct fs_aux_info aux_info;
    memset(&aux_info, 0, sizeof(struct fs_aux_info));

    r = create_fs_aux_info(&aux_info, info);
    if (r != EOK)
        goto Finish;

    fill_sb(&aux_info, info);

    r = write_bgroups(bd, &aux_info, info);
    if (r != EOK)
        goto Finish;

    r = write_sblocks(bd, &aux_info, info);
    if (r != EOK)
        goto Finish;

Finish:
    release_fs_aux_info(&aux_info);
    return r;
}

static int init_bgs(struct ext4_fs *fs) {
    int r = EOK;
    struct ext4_block_group_ref ref;
    uint32_t i;
    uint32_t bg_count = ext4_block_group_cnt(&fs->sb);
    for (i = 0; i < bg_count; ++i) {
        r = ext4_fs_get_block_group_ref(fs, i, &ref);
        if (r != EOK)
            break;

        r = ext4_fs_put_block_group_ref(&ref);
        if (r != EOK)
            break;
    }
    return r;
}

static int alloc_inodes(struct ext4_fs *fs) {
    int r = EOK;
    int i;
    struct ext4_inode_ref inode_ref;
    for (i = 1; i < 12; ++i) {
        int filetype = EXT4_DE_REG_FILE;

        switch (i) {
            case EXT4_ROOT_INO:
            case EXT4_GOOD_OLD_FIRST_INO:
                filetype = EXT4_DE_DIR;
                break;
            default:
                break;
        }

        r = ext4_fs_alloc_inode(fs, &inode_ref, filetype);
        if (r != EOK)
            return r;

        ext4_inode_set_mode(&fs->sb, inode_ref.inode, 0);

        switch (i) {
            case EXT4_ROOT_INO:
            case EXT4_JOURNAL_INO:
                ext4_fs_inode_blocks_init(fs, &inode_ref);
                break;
        }

        ext4_fs_put_inode_ref(&inode_ref);
    }

    return r;
}

static int create_dirs(struct ext4_fs *fs) {
    int r = EOK;
    struct ext4_inode_ref root;
    struct ext4_inode_ref child;

    r = ext4_fs_get_inode_ref(fs, EXT4_ROOT_INO, &root);
    if (r != EOK)
        return r;

    r = ext4_fs_get_inode_ref(fs, EXT4_GOOD_OLD_FIRST_INO, &child);
    if (r != EOK)
        return r;

    ext4_inode_set_mode(&fs->sb, child.inode, EXT4_INODE_MODE_DIRECTORY | 0777);

    ext4_inode_set_mode(&fs->sb, root.inode, EXT4_INODE_MODE_DIRECTORY | 0777);

#if CONFIG_DIR_INDEX_ENABLE
    /* Initialize directory index if supported */
    if (ext4_sb_feature_com(&fs->sb, EXT4_FCOM_DIR_INDEX)) {
        r = ext4_dir_dx_init(&root, &root);
        if (r != EOK)
            return r;

        r = ext4_dir_dx_init(&child, &root);
        if (r != EOK)
            return r;

        ext4_inode_set_flag(root.inode, EXT4_INODE_FLAG_INDEX);
        ext4_inode_set_flag(child.inode, EXT4_INODE_FLAG_INDEX);
    } else
#endif
    {
        r = ext4_dir_add_entry(&root, ".", strlen("."), &root);
        if (r != EOK)
            return r;

        r = ext4_dir_add_entry(&root, "..", strlen(".."), &root);
        if (r != EOK)
            return r;

        r = ext4_dir_add_entry(&child, ".", strlen("."), &child);
        if (r != EOK)
            return r;

        r = ext4_dir_add_entry(&child, "..", strlen(".."), &root);
        if (r != EOK)
            return r;
    }

    r = ext4_dir_add_entry(&root, "lost+found", strlen("lost+found"), &child);
    if (r != EOK)
        return r;

    ext4_inode_set_links_cnt(root.inode, 3);
    ext4_inode_set_links_cnt(child.inode, 2);

    child.dirty = true;
    root.dirty = true;
    ext4_fs_put_inode_ref(&child);
    ext4_fs_put_inode_ref(&root);
    return r;
}

static int create_journal_inode(struct ext4_fs *fs, struct ext4_mkfs_info *info) {
    int ret;
    struct ext4_inode_ref inode_ref;
    uint64_t blocks_count;

    if (!info->journal)
        return EOK;

    ret = ext4_fs_get_inode_ref(fs, EXT4_JOURNAL_INO, &inode_ref);
    if (ret != EOK)
        return ret;

    struct ext4_inode *inode = inode_ref.inode;

    ext4_inode_set_mode(&fs->sb, inode, EXT4_INODE_MODE_FILE | 0600);
    ext4_inode_set_links_cnt(inode, 1);

    blocks_count = ext4_inode_get_blocks_count(&fs->sb, inode);

    while (blocks_count++ < info->journal_blocks) {
        ext4_fsblk_t fblock;
        ext4_lblk_t iblock;
        struct ext4_block blk;

        ret = ext4_fs_append_inode_dblk(&inode_ref, &fblock, &iblock);
        if (ret != EOK)
            goto Finish;

        if (iblock != 0)
            continue;

        ret = ext4_block_get(fs->bdev, &blk, fblock);
        if (ret != EOK)
            goto Finish;


        struct jbd_sb *jbd_sb = (struct jbd_sb *) blk.data;
        memset(jbd_sb, 0, sizeof(struct jbd_sb));

        jbd_sb->header.magic = to_be32(JBD_MAGIC_NUMBER);
        jbd_sb->header.blocktype = to_be32(JBD_SUPERBLOCK_V2);
        jbd_sb->blocksize = to_be32(info->block_size);
        jbd_sb->maxlen = to_be32(info->journal_blocks);
        jbd_sb->nr_users = to_be32(1);
        jbd_sb->first = to_be32(1);
        jbd_sb->sequence = to_be32(1);

        ext4_bcache_set_dirty(blk.buf);
        ret = ext4_block_set(fs->bdev, &blk);
        if (ret != EOK)
            goto Finish;
    }

    memcpy(fs->sb.journal_blocks, inode->blocks, sizeof(inode->blocks));

Finish:
    ext4_fs_put_inode_ref(&inode_ref);

    return ret;
}

int ext4_mkfs(struct ext4_fs *fs, struct ext4_blockdev *bd, struct ext4_mkfs_info *info, int fs_type) {
    int r;

    r = ext4_block_init(bd);
    if (r != EOK)
        return r;

    bd->fs = fs;

    if (info->len == 0)
        info->len = bd->part_size;

    if (info->block_size == 0)
        info->block_size = 4096; /*Set block size to default value*/

    /* Round down the filesystem length to be a multiple of the block size */
    info->len &= ~((uint64_t) info->block_size - 1);

    if (info->journal_blocks == 0)
        info->journal_blocks = compute_journal_blocks(info);

    if (info->blocks_per_group == 0)
        info->blocks_per_group = compute_blocks_per_group(info);

    if (info->inodes == 0)
        info->inodes = compute_inodes(info);

    if (info->inode_size == 0)
        info->inode_size = 256;

    if (info->label == NULL)
        info->label = "";

    info->inodes_per_group = compute_inodes_per_group(info);

    info->feat_compat = EXT4_SUPPORTED_FCOM;
    info->feat_ro_compat = EXT4_SUPPORTED_FRO_COM;
    info->feat_incompat = EXT4_SUPPORTED_FINCOM;

    /*TODO: handle this features some day...*/
    info->feat_incompat &= ~EXT4_FINCOM_META_BG;
    info->feat_incompat &= ~EXT4_FINCOM_FLEX_BG;
    info->feat_incompat &= ~EXT4_FINCOM_64BIT;

    info->feat_ro_compat &= ~EXT4_FRO_COM_METADATA_CSUM;
    info->feat_ro_compat &= ~EXT4_FRO_COM_GDT_CSUM;
    info->feat_ro_compat &= ~EXT4_FRO_COM_DIR_NLINK;
    info->feat_ro_compat &= ~EXT4_FRO_COM_EXTRA_ISIZE;
    info->feat_ro_compat &= ~EXT4_FRO_COM_HUGE_FILE;

    if (info->journal)
        info->feat_compat |= EXT4_FCOM_HAS_JOURNAL;

    if (info->dsc_size == 0) {

        if (info->feat_incompat & EXT4_FINCOM_64BIT)
            info->dsc_size = EXT4_MAX_BLOCK_GROUP_DESCRIPTOR_SIZE;
        else
            info->dsc_size = EXT4_MIN_BLOCK_GROUP_DESCRIPTOR_SIZE;
    }

    info->bg_desc_reserve_blocks = 0;

    ext4_dbg(DEBUG_MKFS, DBG_INFO "Creating filesystem with parameters:\n");
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Size: %" PRIu64 "\n", info->len);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Block size: %" PRIu32 "\n", info->block_size);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Blocks per group: %" PRIu32 "\n", info->blocks_per_group);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Inodes per group: %" PRIu32 "\n", info->inodes_per_group);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Inode size: %" PRIu32 "\n", info->inode_size);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Inodes: %" PRIu32 "\n", info->inodes);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Journal blocks: %" PRIu32 "\n", info->journal_blocks);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Features ro_compat: 0x%x\n", info->feat_ro_compat);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Features compat: 0x%x\n", info->feat_compat);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Features incompat: 0x%x\n", info->feat_incompat);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "BG desc reserve: %" PRIu32 "\n", info->bg_desc_reserve_blocks);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Descriptor size: %" PRIu16 "\n", info->dsc_size);
    ext4_dbg(DEBUG_MKFS, DBG_NONE "journal: %s\n", info->journal ? "yes" : "no");
    ext4_dbg(DEBUG_MKFS, DBG_NONE "Label: %s\n", info->label);

    struct ext4_bcache bc;

    memset(&bc, 0, sizeof(struct ext4_bcache));
    ext4_block_set_lb_size(bd, info->block_size);

    r = ext4_bcache_init_dynamic(&bc, CONFIG_BLOCK_DEV_CACHE_SIZE, info->block_size);
    if (r != EOK)
        goto block_fini;

    /*Bind block cache to block device*/
    r = ext4_block_bind_bcache(bd, &bc);
    if (r != EOK)
        goto cache_fini;

    r = ext4_block_cache_write_back(bd, 1);
    if (r != EOK)
        goto cache_fini;

    r = mkfs_init(bd, info);
    if (r != EOK)
        goto cache_fini;

    r = ext4_fs_init(fs, bd, false);
    if (r != EOK)
        goto cache_fini;

    r = init_bgs(fs);
    if (r != EOK)
        goto fs_fini;

    r = alloc_inodes(fs);
    if (r != EOK)
        goto fs_fini;

    r = create_dirs(fs);
    if (r != EOK)
        goto fs_fini;

    r = create_journal_inode(fs, info);
    if (r != EOK)
        goto fs_fini;

fs_fini:
    ext4_fs_fini(fs);

cache_fini:
    ext4_block_cache_write_back(bd, 0);
    ext4_bcache_fini_dynamic(&bc);

block_fini:
    ext4_block_fini(bd);

    return r;
}

uint32_t ext4_block_group_cnt(struct ext4_sblock *s) {
    uint64_t blocks_count = ext4_sb_get_blocks_cnt(s);
    uint32_t blocks_per_group = ext4_get32(s, blocks_per_group);

    uint32_t block_groups_count = (uint32_t) (blocks_count / blocks_per_group);

    if (blocks_count % blocks_per_group)
        block_groups_count++;

    return block_groups_count;
}

uint32_t ext4_blocks_in_group_cnt(struct ext4_sblock *s, uint32_t bgid) {
    uint32_t block_group_count = ext4_block_group_cnt(s);
    uint32_t blocks_per_group = ext4_get32(s, blocks_per_group);
    uint64_t total_blocks = ext4_sb_get_blocks_cnt(s);

    if (bgid < block_group_count - 1)
        return blocks_per_group;

    return (uint32_t) (total_blocks - ((block_group_count - 1) * blocks_per_group));
}

uint32_t ext4_inodes_in_group_cnt(struct ext4_sblock *s, uint32_t bgid) {
    uint32_t block_group_count = ext4_block_group_cnt(s);
    uint32_t inodes_per_group = ext4_get32(s, inodes_per_group);
    uint32_t total_inodes = ext4_get32(s, inodes_count);

    if (bgid < block_group_count - 1)
        return inodes_per_group;

    return (total_inodes - ((block_group_count - 1) * inodes_per_group));
}

static uint32_t ext4_sb_csum(struct ext4_sblock *s) {

    return ext4_crc32c(EXT4_CRC32_INIT, s, offsetof(struct ext4_sblock, checksum));
}

static bool ext4_sb_verify_csum(struct ext4_sblock *s) {
    if (!ext4_sb_feature_ro_com(s, EXT4_FRO_COM_METADATA_CSUM))
        return true;

    if (s->checksum_type != to_le32(EXT4_CHECKSUM_CRC32C))
        return false;

    return s->checksum == to_le32(ext4_sb_csum(s));
}

static void ext4_sb_set_csum(struct ext4_sblock *s) {
    if (!ext4_sb_feature_ro_com(s, EXT4_FRO_COM_METADATA_CSUM))
        return;

    s->checksum = to_le32(ext4_sb_csum(s));
}

int ext4_sb_write(struct ext4_blockdev *bdev, struct ext4_sblock *s) {
    ext4_sb_set_csum(s);
    return ext4_block_writebytes(bdev, EXT4_SUPERBLOCK_OFFSET, s, EXT4_SUPERBLOCK_SIZE);
}

int ext4_sb_read(struct ext4_blockdev *bdev, struct ext4_sblock *s) {
    return ext4_block_readbytes(bdev, EXT4_SUPERBLOCK_OFFSET, s, EXT4_SUPERBLOCK_SIZE);
}

bool ext4_sb_check(struct ext4_sblock *s) {
    if (ext4_get16(s, magic) != EXT4_SUPERBLOCK_MAGIC)
        return false;

    if (ext4_get32(s, inodes_count) == 0)
        return false;

    if (ext4_sb_get_blocks_cnt(s) == 0)
        return false;

    if (ext4_get32(s, blocks_per_group) == 0)
        return false;

    if (ext4_get32(s, inodes_per_group) == 0)
        return false;

    if (ext4_get16(s, inode_size) < 128)
        return false;

    if (ext4_get32(s, first_inode) < 11)
        return false;

    if (ext4_sb_get_desc_size(s) < EXT4_MIN_BLOCK_GROUP_DESCRIPTOR_SIZE)
        return false;

    if (ext4_sb_get_desc_size(s) > EXT4_MAX_BLOCK_GROUP_DESCRIPTOR_SIZE)
        return false;

    if (!ext4_sb_verify_csum(s))
        return false;

    return true;
}

static inline int is_power_of(uint32_t a, uint32_t b) {
    while (1) {
        if (a < b)
            return 0;
        if (a == b)
            return 1;
        if ((a % b) != 0)
            return 0;
        a = a / b;
    }
}

bool ext4_sb_sparse(uint32_t group) {
    if (group <= 1)
        return 1;

    if (!(group & 1))
        return 0;

    return (is_power_of(group, 7) || is_power_of(group, 5) || is_power_of(group, 3));
}

bool ext4_sb_is_super_in_bg(struct ext4_sblock *s, uint32_t group) {
    if (ext4_sb_feature_ro_com(s, EXT4_FRO_COM_SPARSE_SUPER) && !ext4_sb_sparse(group))
        return false;
    return true;
}

static uint32_t ext4_bg_num_gdb_meta(struct ext4_sblock *s, uint32_t group) {
    uint32_t dsc_per_block = ext4_sb_get_block_size(s) / ext4_sb_get_desc_size(s);

    uint32_t metagroup = group / dsc_per_block;
    uint32_t first = metagroup * dsc_per_block;
    uint32_t last = first + dsc_per_block - 1;

    if (group == first || group == first + 1 || group == last)
        return 1;
    return 0;
}

static uint32_t ext4_bg_num_gdb_nometa(struct ext4_sblock *s, uint32_t group) {
    if (!ext4_sb_is_super_in_bg(s, group))
        return 0;
    uint32_t dsc_per_block = ext4_sb_get_block_size(s) / ext4_sb_get_desc_size(s);

    uint32_t db_count = (ext4_block_group_cnt(s) + dsc_per_block - 1) / dsc_per_block;

    if (ext4_sb_feature_incom(s, EXT4_FINCOM_META_BG))
        return ext4_sb_first_meta_bg(s);

    return db_count;
}

uint32_t ext4_bg_num_gdb(struct ext4_sblock *s, uint32_t group) {
    uint32_t dsc_per_block = ext4_sb_get_block_size(s) / ext4_sb_get_desc_size(s);
    uint32_t first_meta_bg = ext4_sb_first_meta_bg(s);
    uint32_t metagroup = group / dsc_per_block;

    if (!ext4_sb_feature_incom(s, EXT4_FINCOM_META_BG) || metagroup < first_meta_bg)
        return ext4_bg_num_gdb_nometa(s, group);

    return ext4_bg_num_gdb_meta(s, group);
}

uint32_t ext4_num_base_meta_clusters(struct ext4_sblock *s, uint32_t block_group) {
    uint32_t num;
    uint32_t dsc_per_block = ext4_sb_get_block_size(s) / ext4_sb_get_desc_size(s);

    num = ext4_sb_is_super_in_bg(s, block_group);

    if (!ext4_sb_feature_incom(s, EXT4_FINCOM_META_BG) || block_group < ext4_sb_first_meta_bg(s) * dsc_per_block) {
        if (num) {
            num += ext4_bg_num_gdb(s, block_group);
            num += ext4_get16(s, s_reserved_gdt_blocks);
        }
    } else {
        num += ext4_bg_num_gdb(s, block_group);
    }

    uint32_t clustersize = 1024 << ext4_get32(s, log_cluster_size);
    uint32_t cluster_ratio = clustersize / ext4_sb_get_block_size(s);
    uint32_t v = (num + cluster_ratio - 1) >> ext4_get32(s, log_cluster_size);

    return v;
}

int ext4_trans_set_block_dirty(struct ext4_buf *buf) {
    int r = EOK;
#if CONFIG_JOURNALING_ENABLE
    struct ext4_fs *fs = buf->bc->bdev->fs;
    struct ext4_block block = {.lb_id = buf->lba, .data = buf->data, .buf = buf};

    if (fs->jbd_journal && fs->curr_trans) {
        struct jbd_trans *trans = fs->curr_trans;
        return jbd_trans_set_block_dirty(trans, &block);
    }
#endif
    ext4_bcache_set_dirty(buf);
    return r;
}

int ext4_trans_block_get_noread(struct ext4_blockdev *bdev, struct ext4_block *b, uint64_t lba) {
    int r = ext4_block_get_noread(bdev, b, lba);
    if (r != EOK)
        return r;

    return r;
}

int ext4_trans_block_get(struct ext4_blockdev *bdev, struct ext4_block *b, uint64_t lba) {
    int r = ext4_block_get(bdev, b, lba);
    if (r != EOK)
        return r;

    return r;
}

int ext4_trans_try_revoke_block(struct ext4_blockdev *bdev __unused, uint64_t lba __unused) {
    int r = EOK;
#if CONFIG_JOURNALING_ENABLE
    struct ext4_fs *fs = bdev->fs;
    if (fs->jbd_journal && fs->curr_trans) {
        struct jbd_trans *trans = fs->curr_trans;
        r = jbd_trans_try_revoke_block(trans, lba);
    } else if (fs->jbd_journal) {
        r = ext4_block_flush_lba(fs->bdev, lba);
    }
#endif
    return r;
}

struct ext4_xattr_header {
    uint32_t h_magic; /* magic number for identification */
    uint32_t h_refcount; /* reference count */
    uint32_t h_blocks; /* number of disk blocks used */
    uint32_t h_hash; /* hash value of all attributes */
    uint32_t h_checksum; /* crc32c(uuid+id+xattrblock) */
    /* id = inum if refcount=1, blknum otherwise */
    uint32_t h_reserved[3]; /* zero right now */
}

struct ext4_xattr_ibody_header {
    uint32_t h_magic; /* magic number for identification */
}

static inline void ext4_xattr_compute_hash(struct ext4_xattr_header *header, struct ext4_xattr_entry *entry) {
    uint32_t hash = 0;
    char *name = EXT4_XATTR_NAME(entry);
    int n;

    for (n = 0; n < entry->e_name_len; n++) {
        hash = (hash << NAME_HASH_SHIFT) ^ (hash >> (8 * sizeof(hash) - NAME_HASH_SHIFT)) ^ *name++;
    }

    if (entry->e_value_block == 0 && entry->e_value_size != 0) {
        uint32_t *value = (uint32_t *) ((char *) header + to_le16(entry->e_value_offs));
        for (n = (to_le32(entry->e_value_size) + EXT4_XATTR_ROUND) >> EXT4_XATTR_PAD_BITS; n; n--) {
            hash = (hash << VALUE_HASH_SHIFT) ^ (hash >> (8 * sizeof(hash) - VALUE_HASH_SHIFT)) ^ to_le32(*value++);
        }
    }
    entry->e_hash = to_le32(hash);
}

static void ext4_xattr_rehash(struct ext4_xattr_header *header, struct ext4_xattr_entry *entry) {
    struct ext4_xattr_entry *here;
    uint32_t hash = 0;

    ext4_xattr_compute_hash(header, entry);
    here = EXT4_XATTR_ENTRY(header + 1);
    while (!EXT4_XATTR_IS_LAST_ENTRY(here)) {
        if (!here->e_hash) {
            /* Block is not shared if an entry's hash value == 0 */
            hash = 0;
            break;
        }
        hash = (hash << BLOCK_HASH_SHIFT) ^ (hash >> (8 * sizeof(hash) - BLOCK_HASH_SHIFT)) ^ to_le32(here->e_hash);
        here = EXT4_XATTR_NEXT(here);
    }
    header->h_hash = to_le32(hash);
}

static uint32_t ext4_xattr_block_checksum(struct ext4_inode_ref *inode_ref, ext4_fsblk_t blocknr,
                                          struct ext4_xattr_header *header) {
    uint32_t checksum = 0;
    uint64_t le64_blocknr = blocknr;
    struct ext4_sblock *sb = &inode_ref->fs->sb;

    if (ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM)) {
        uint32_t orig_checksum;

        /* Preparation: temporarily set bg checksum to 0 */
        orig_checksum = header->h_checksum;
        header->h_checksum = 0;
        /* First calculate crc32 checksum against fs uuid */
        checksum = ext4_crc32c(EXT4_CRC32_INIT, sb->uuid, sizeof(sb->uuid));
        /* Then calculate crc32 checksum block number */
        checksum = ext4_crc32c(checksum, &le64_blocknr, sizeof(le64_blocknr));
        /* Finally calculate crc32 checksum against
         * the entire xattr block */
        checksum = ext4_crc32c(checksum, header, ext4_sb_get_block_size(sb));
        header->h_checksum = orig_checksum;
    }
    return checksum;
}

static void ext4_xattr_set_block_checksum(struct ext4_inode_ref *inode_ref, ext4_fsblk_t blocknr __unused,
                                          struct ext4_xattr_header *header) {
    struct ext4_sblock *sb = &inode_ref->fs->sb;
    if (!ext4_sb_feature_ro_com(sb, EXT4_FRO_COM_METADATA_CSUM))
        return;

    header->h_checksum = ext4_xattr_block_checksum(inode_ref, blocknr, header);
}

struct xattr_prefix {
    const char *prefix;
    uint8_t name_index;
}

const char *ext4_extract_xattr_name(const char *full_name, size_t full_name_len, uint8_t *name_index, size_t *name_len,
                                    bool *found) {
    int i;
    ext4_assert(name_index);
    ext4_assert(found);

    *found = false;

    if (!full_name_len) {
        if (name_len)
            *name_len = 0;

        return NULL;
    }

    for (i = 0; prefix_tbl[i].prefix; i++) {
        size_t prefix_len = strlen(prefix_tbl[i].prefix);
        if (full_name_len >= prefix_len && !memcmp(full_name, prefix_tbl[i].prefix, prefix_len)) {
            bool require_name = prefix_tbl[i].prefix[prefix_len - 1] == '.';
            *name_index = prefix_tbl[i].name_index;
            if (name_len)
                *name_len = full_name_len - prefix_len;

            if (!(full_name_len - prefix_len) && require_name)
                return NULL;

            *found = true;
            if (require_name)
                return full_name + prefix_len;

            return NULL;
        }
    }
    if (name_len)
        *name_len = 0;

    return NULL;
}

const char *ext4_get_xattr_name_prefix(uint8_t name_index, size_t *ret_prefix_len) {
    int i;

    for (i = 0; prefix_tbl[i].prefix; i++) {
        size_t prefix_len = strlen(prefix_tbl[i].prefix);
        if (prefix_tbl[i].name_index == name_index) {
            if (ret_prefix_len)
                *ret_prefix_len = prefix_len;

            return prefix_tbl[i].prefix;
        }
    }
    if (ret_prefix_len)
        *ret_prefix_len = 0;

    return NULL;
}

static int ext4_xattr_set_entry(struct ext4_xattr_info *i, struct ext4_xattr_search *s, bool dry_run) {
    struct ext4_xattr_entry *last;
    size_t free, min_offs = (char *) s->end - (char *) s->base, name_len = i->name_len;

    /*
     * If the entry is going to be removed but not found, return 0 to
     * indicate success.
     */
    if (!i->value && s->not_found)
        return EOK;

    /* Compute min_offs and last. */
    last = s->first;
    for (; !EXT4_XATTR_IS_LAST_ENTRY(last); last = EXT4_XATTR_NEXT(last)) {
        if (last->e_value_size) {
            size_t offs = to_le16(last->e_value_offs);
            if (offs < min_offs)
                min_offs = offs;
        }
    }

    /* Calculate free space in the block. */
    free = min_offs - ((char *) last - (char *) s->base) - sizeof(uint32_t);
    if (!s->not_found)
        free += EXT4_XATTR_SIZE(s->here->e_value_size) + EXT4_XATTR_LEN(s->here->e_name_len);

    if (i->value) {
        /* See whether there is enough space to hold new entry */
        if (free < EXT4_XATTR_SIZE(i->value_len) + EXT4_XATTR_LEN(name_len))
            return ENOSPC;
    }

    /* Return EOK now if we do not intend to modify the content. */
    if (dry_run)
        return EOK;

    /* First remove the old entry's data part */
    if (!s->not_found) {
        size_t value_offs = to_le16(s->here->e_value_offs);
        void *value = (char *) s->base + value_offs;
        void *first_value = (char *) s->base + min_offs;
        size_t value_size = EXT4_XATTR_SIZE(to_le32(s->here->e_value_size));

        if (value_offs) {
            /* Remove the data part. */
            memmove((char *) first_value + value_size, first_value, (char *) value - (char *) first_value);

            /* Zero the gap created */
            memset(first_value, 0, value_size);

            /*
             * Calculate the new min_offs after removal of the old
             * entry's data part
             */
            min_offs += value_size;
        }

        /*
         * Adjust the value offset of entries which has value offset
         * prior to the s->here. The offset of these entries won't be
         * shifted if the size of the entry we removed is zero.
         */
        for (last = s->first; !EXT4_XATTR_IS_LAST_ENTRY(last); last = EXT4_XATTR_NEXT(last)) {
            size_t offs = to_le16(last->e_value_offs);

            /* For zero-value-length entry, offs will be zero. */
            if (offs < value_offs)
                last->e_value_offs = to_le16(offs + value_size);
        }
    }

    /* If caller wants us to insert... */
    if (i->value) {
        size_t value_offs;
        if (i->value_len)
            value_offs = min_offs - EXT4_XATTR_SIZE(i->value_len);
        else
            value_offs = 0;

        if (!s->not_found) {
            struct ext4_xattr_entry *here = s->here;

            /* Reuse the current entry we have got */
            here->e_value_offs = to_le16(value_offs);
            here->e_value_size = to_le32(i->value_len);
        } else {
            /* Insert a new entry */
            last->e_name_len = (uint8_t) name_len;
            last->e_name_index = i->name_index;
            last->e_value_offs = to_le16(value_offs);
            last->e_value_block = 0;
            last->e_value_size = to_le32(i->value_len);
            memcpy(EXT4_XATTR_NAME(last), i->name, name_len);

            /* Set valid last entry indicator */
            *(uint32_t *) EXT4_XATTR_NEXT(last) = 0;

            s->here = last;
        }

        /* Insert the value's part */
        if (value_offs) {
            memcpy((char *) s->base + value_offs, i->value, i->value_len);

            /* Clear the padding bytes if there is */
            if (EXT4_XATTR_SIZE(i->value_len) != i->value_len)
                memset((char *) s->base + value_offs + i->value_len, 0, EXT4_XATTR_SIZE(i->value_len) - i->value_len);
        }
    } else {
        size_t shift_offs;

        /* Remove the whole entry */
        shift_offs = (char *) EXT4_XATTR_NEXT(s->here) - (char *) s->here;
        memmove(s->here, EXT4_XATTR_NEXT(s->here),
                (char *) last + sizeof(uint32_t) - (char *) EXT4_XATTR_NEXT(s->here));

        /* Zero the gap created */
        memset((char *) last - shift_offs + sizeof(uint32_t), 0, shift_offs);

        s->here = NULL;
    }

    return EOK;
}

static inline bool ext4_xattr_is_empty(struct ext4_xattr_search *s) {
    if (!EXT4_XATTR_IS_LAST_ENTRY(s->first))
        return false;

    return true;
}

static void ext4_xattr_find_entry(struct ext4_xattr_info *i, struct ext4_xattr_search *s) {
    struct ext4_xattr_entry *entry = NULL;

    s->not_found = true;
    s->here = NULL;

    /*
     * Find the wanted EA entry by simply comparing the namespace,
     * name and the length of name.
     */
    for (entry = s->first; !EXT4_XATTR_IS_LAST_ENTRY(entry); entry = EXT4_XATTR_NEXT(entry)) {
        size_t name_len = entry->e_name_len;
        const char *name = EXT4_XATTR_NAME(entry);
        if (name_len == i->name_len && entry->e_name_index == i->name_index && !memcmp(name, i->name, name_len)) {
            s->here = entry;
            s->not_found = false;
            i->value_len = to_le32(entry->e_value_size);
            if (i->value_len)
                i->value = (char *) s->base + to_le16(entry->e_value_offs);
            else
                i->value = NULL;

            return;
        }
    }
}

static bool ext4_xattr_is_block_valid(struct ext4_inode_ref *inode_ref, struct ext4_block *block) {

    void *base = block->data, *end = block->data + ext4_sb_get_block_size(&inode_ref->fs->sb);
    size_t min_offs = (char *) end - (char *) base;
    struct ext4_xattr_header *header = EXT4_XATTR_BHDR(block);
    struct ext4_xattr_entry *entry = EXT4_XATTR_BFIRST(block);

    /*
     * Check whether the magic number in the header is correct.
     */
    if (header->h_magic != to_le32(EXT4_XATTR_MAGIC))
        return false;

    /*
     * The in-kernel filesystem driver only supports 1 block currently.
     */
    if (header->h_blocks != to_le32(1))
        return false;

    /*
     * Check if those entries are maliciously corrupted to inflict harm
     * upon us.
     */
    for (; !EXT4_XATTR_IS_LAST_ENTRY(entry); entry = EXT4_XATTR_NEXT(entry)) {
        if (!to_le32(entry->e_value_size) && to_le16(entry->e_value_offs))
            return false;

        if ((char *) base + to_le16(entry->e_value_offs) + to_le32(entry->e_value_size) > (char *) end)
            return false;

        /*
         * The name length field should also be correct,
         * also there should be an 4-byte zero entry at the
         * end.
         */
        if ((char *) EXT4_XATTR_NEXT(entry) + sizeof(uint32_t) > (char *) end)
            return false;

        if (to_le32(entry->e_value_size)) {
            size_t offs = to_le16(entry->e_value_offs);
            if (offs < min_offs)
                min_offs = offs;
        }
    }
    /*
     * Entry field and data field do not override each other.
     */
    if ((char *) base + min_offs < (char *) entry + sizeof(uint32_t))
        return false;

    return true;
}

static bool ext4_xattr_is_ibody_valid(struct ext4_inode_ref *inode_ref) {
    size_t min_offs;
    void *base, *end;
    struct ext4_fs *fs = inode_ref->fs;
    struct ext4_xattr_ibody_header *iheader;
    struct ext4_xattr_entry *entry;
    size_t inode_size = ext4_get16(&fs->sb, inode_size);

    iheader = EXT4_XATTR_IHDR(&fs->sb, inode_ref->inode);
    entry = EXT4_XATTR_IFIRST(iheader);
    base = iheader;
    end = (char *) inode_ref->inode + inode_size;
    min_offs = (char *) end - (char *) base;

    /*
     * Check whether the magic number in the header is correct.
     */
    if (iheader->h_magic != to_le32(EXT4_XATTR_MAGIC))
        return false;

    /*
     * Check if those entries are maliciously corrupted to inflict harm
     * upon us.
     */
    for (; !EXT4_XATTR_IS_LAST_ENTRY(entry); entry = EXT4_XATTR_NEXT(entry)) {
        if (!to_le32(entry->e_value_size) && to_le16(entry->e_value_offs))
            return false;

        if ((char *) base + to_le16(entry->e_value_offs) + to_le32(entry->e_value_size) > (char *) end)
            return false;

        /*
         * The name length field should also be correct,
         * also there should be an 4-byte zero entry at the
         * end.
         */
        if ((char *) EXT4_XATTR_NEXT(entry) + sizeof(uint32_t) > (char *) end)
            return false;

        if (to_le32(entry->e_value_size)) {
            size_t offs = to_le16(entry->e_value_offs);
            if (offs < min_offs)
                min_offs = offs;
        }
    }
    /*
     * Entry field and data field do not override each other.
     */
    if ((char *) base + min_offs < (char *) entry + sizeof(uint32_t))
        return false;

    return true;
}

struct ext4_xattr_finder {
    /**
     * @brief The information of the EA entry to be find
     */
    struct ext4_xattr_info i;

    /**
     * @brief Search context block of the current search
     */
    struct ext4_xattr_search s;

    /**
     * @brief Inode reference to the corresponding inode
     */
    struct ext4_inode_ref *inode_ref;
}

static void ext4_xattr_ibody_initialize(struct ext4_inode_ref *inode_ref) {
    struct ext4_xattr_ibody_header *header;
    struct ext4_fs *fs = inode_ref->fs;
    size_t extra_isize = ext4_inode_get_extra_isize(&fs->sb, inode_ref->inode);
    size_t inode_size = ext4_get16(&fs->sb, inode_size);
    if (!extra_isize)
        return;

    header = EXT4_XATTR_IHDR(&fs->sb, inode_ref->inode);
    memset(header, 0, inode_size - EXT4_GOOD_OLD_INODE_SIZE - extra_isize);
    header->h_magic = to_le32(EXT4_XATTR_MAGIC);
    inode_ref->dirty = true;
}

static void ext4_xattr_block_initialize(struct ext4_inode_ref *inode_ref, struct ext4_block *block) {
    struct ext4_xattr_header *header;
    struct ext4_fs *fs = inode_ref->fs;

    memset(block->data, 0, ext4_sb_get_block_size(&fs->sb));

    header = EXT4_XATTR_BHDR(block);
    header->h_magic = to_le32(EXT4_XATTR_MAGIC);
    header->h_refcount = to_le32(1);
    header->h_blocks = to_le32(1);

    ext4_trans_set_block_dirty(block->buf);
}

static void ext4_xattr_block_init_search(struct ext4_inode_ref *inode_ref, struct ext4_xattr_search *s,
                                         struct ext4_block *block) {
    s->base = block->data;
    s->end = block->data + ext4_sb_get_block_size(&inode_ref->fs->sb);
    s->first = EXT4_XATTR_BFIRST(block);
    s->here = NULL;
    s->not_found = true;
}

static int ext4_xattr_block_find_entry(struct ext4_inode_ref *inode_ref, struct ext4_xattr_finder *finder,
                                       struct ext4_block *block) {
    int ret = EOK;

    /* Initialize the caller-given finder */
    finder->inode_ref = inode_ref;
    memset(&finder->s, 0, sizeof(finder->s));

    if (ret != EOK)
        return ret;

    /* Check the validity of the buffer */
    if (!ext4_xattr_is_block_valid(inode_ref, block))
        return EIO;

    ext4_xattr_block_init_search(inode_ref, &finder->s, block);
    ext4_xattr_find_entry(&finder->i, &finder->s);
    return EOK;
}

static int ext4_xattr_ibody_find_entry(struct ext4_inode_ref *inode_ref, struct ext4_xattr_finder *finder) {
    struct ext4_fs *fs = inode_ref->fs;
    struct ext4_xattr_ibody_header *iheader;
    size_t extra_isize = ext4_inode_get_extra_isize(&fs->sb, inode_ref->inode);
    size_t inode_size = ext4_get16(&fs->sb, inode_size);

    /* Initialize the caller-given finder */
    finder->inode_ref = inode_ref;
    memset(&finder->s, 0, sizeof(finder->s));

    /*
     * If there is no extra inode space
     * set ext4_xattr_ibody_finder::s::not_found to true and return EOK
     */
    if (!extra_isize) {
        finder->s.not_found = true;
        return EOK;
    }

    /* Check the validity of the buffer */
    if (!ext4_xattr_is_ibody_valid(inode_ref))
        return EIO;

    iheader = EXT4_XATTR_IHDR(&fs->sb, inode_ref->inode);
    finder->s.base = EXT4_XATTR_IFIRST(iheader);
    finder->s.end = (char *) inode_ref->inode + inode_size;
    finder->s.first = EXT4_XATTR_IFIRST(iheader);
    ext4_xattr_find_entry(&finder->i, &finder->s);
    return EOK;
}

static int ext4_xattr_try_alloc_block(struct ext4_inode_ref *inode_ref) {
    int ret = EOK;

    ext4_fsblk_t xattr_block = 0;
    xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &inode_ref->fs->sb);

    /*
     * Only allocate a xattr block when there is no xattr block
     * used by the inode.
     */
    if (!xattr_block) {
        ext4_fsblk_t goal = ext4_fs_inode_to_goal_block(inode_ref);

        ret = ext4_balloc_alloc_block(inode_ref, goal, &xattr_block);
        if (ret != EOK)
            goto Finish;

        ext4_inode_set_file_acl(inode_ref->inode, &inode_ref->fs->sb, xattr_block);
    }

Finish:
    return ret;
}

static void ext4_xattr_try_free_block(struct ext4_inode_ref *inode_ref) {
    ext4_fsblk_t xattr_block;
    xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &inode_ref->fs->sb);
    /*
     * Free the xattr block used by the inode when there is one.
     */
    if (xattr_block) {
        ext4_inode_set_file_acl(inode_ref->inode, &inode_ref->fs->sb, 0);
        ext4_balloc_free_block(inode_ref, xattr_block);
        inode_ref->dirty = true;
    }
}

int ext4_xattr_list(struct ext4_inode_ref *inode_ref, struct ext4_xattr_list_entry *list, size_t *list_len) {
    int ret = EOK;
    size_t buf_len = 0;
    struct ext4_fs *fs = inode_ref->fs;
    struct ext4_xattr_ibody_header *iheader;
    size_t extra_isize = ext4_inode_get_extra_isize(&fs->sb, inode_ref->inode);
    struct ext4_block block;
    bool block_loaded = false;
    ext4_fsblk_t xattr_block = 0;
    struct ext4_xattr_entry *entry;
    struct ext4_xattr_list_entry *list_prev = NULL;
    xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);

    /*
     * If there is extra inode space and the xattr buffer in the
     * inode is valid.
     */
    if (extra_isize && ext4_xattr_is_ibody_valid(inode_ref)) {
        iheader = EXT4_XATTR_IHDR(&fs->sb, inode_ref->inode);
        entry = EXT4_XATTR_IFIRST(iheader);

        /*
         * The format of the list should be like this:
         *
         * name_len indicates the length in bytes of the name
         * of the EA entry. The string is null-terminated.
         *
         * list->name => (char *)(list + 1);
         * list->next => (void *)((char *)(list + 1) + name_len + 1);
         */
        for (; !EXT4_XATTR_IS_LAST_ENTRY(entry); entry = EXT4_XATTR_NEXT(entry)) {
            size_t name_len = entry->e_name_len;
            if (list) {
                list->name_index = entry->e_name_index;
                list->name_len = name_len;
                list->name = (char *) (list + 1);
                memcpy(list->name, EXT4_XATTR_NAME(entry), list->name_len);

                if (list_prev)
                    list_prev->next = list;

                list_prev = list;
                list = (struct ext4_xattr_list_entry *) (list->name + name_len + 1);
            }

            /*
             * Size calculation by pointer arithmetics.
             */
            buf_len += (char *) ((struct ext4_xattr_list_entry *) 0 + 1) + name_len + 1 -
                       (char *) (struct ext4_xattr_list_entry *) 0;
        }
    }

    /*
     * If there is a xattr block used by the inode
     */
    if (xattr_block) {
        ret = ext4_trans_block_get(fs->bdev, &block, xattr_block);
        if (ret != EOK)
            goto out;

        block_loaded = true;

        /*
         * As we don't allow the content in the block being invalid,
         * bail out.
         */
        if (!ext4_xattr_is_block_valid(inode_ref, &block)) {
            ret = EIO;
            goto out;
        }

        entry = EXT4_XATTR_BFIRST(&block);

        /*
         * The format of the list should be like this:
         *
         * name_len indicates the length in bytes of the name
         * of the EA entry. The string is null-terminated.
         *
         * list->name => (char *)(list + 1);
         * list->next => (void *)((char *)(list + 1) + name_len + 1);
         *
         * Same as above actually.
         */
        for (; !EXT4_XATTR_IS_LAST_ENTRY(entry); entry = EXT4_XATTR_NEXT(entry)) {
            size_t name_len = entry->e_name_len;
            if (list) {
                list->name_index = entry->e_name_index;
                list->name_len = name_len;
                list->name = (char *) (list + 1);
                memcpy(list->name, EXT4_XATTR_NAME(entry), list->name_len);

                if (list_prev)
                    list_prev->next = list;

                list_prev = list;
                list = (struct ext4_xattr_list_entry *) (list->name + name_len + 1);
            }

            /*
             * Size calculation by pointer arithmetics.
             */
            buf_len += (char *) ((struct ext4_xattr_list_entry *) 0 + 1) + name_len + 1 -
                       (char *) (struct ext4_xattr_list_entry *) 0;
        }
    }
    if (list_prev)
        list_prev->next = NULL;
out:
    if (ret == EOK && list_len)
        *list_len = buf_len;

    if (block_loaded)
        ext4_block_set(fs->bdev, &block);

    return ret;
}

int ext4_xattr_get(struct ext4_inode_ref *inode_ref, uint8_t name_index, const char *name, size_t name_len, void *buf,
                   size_t buf_len, size_t *data_len) {
    int ret = EOK;
    struct ext4_xattr_finder ibody_finder;
    struct ext4_xattr_finder block_finder;
    struct ext4_xattr_info i;
    size_t value_len = 0;
    size_t value_offs = 0;
    struct ext4_fs *fs = inode_ref->fs;
    ext4_fsblk_t xattr_block;
    xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);

    i.name_index = name_index;
    i.name = name;
    i.name_len = name_len;
    i.value = 0;
    i.value_len = 0;
    if (data_len)
        *data_len = 0;

    ibody_finder.i = i;
    ret = ext4_xattr_ibody_find_entry(inode_ref, &ibody_finder);
    if (ret != EOK)
        goto out;

    if (!ibody_finder.s.not_found) {
        value_len = to_le32(ibody_finder.s.here->e_value_size);
        value_offs = to_le32(ibody_finder.s.here->e_value_offs);
        if (buf_len && buf) {
            void *data_loc = (char *) ibody_finder.s.base + value_offs;
            memcpy(buf, data_loc, (buf_len < value_len) ? buf_len : value_len);
        }
    } else {
        struct ext4_block block;

        /* Return ENODATA if there is no EA block */
        if (!xattr_block) {
            ret = ENODATA;
            goto out;
        }

        block_finder.i = i;
        ret = ext4_trans_block_get(fs->bdev, &block, xattr_block);
        if (ret != EOK)
            goto out;

        ret = ext4_xattr_block_find_entry(inode_ref, &block_finder, &block);
        if (ret != EOK) {
            ext4_block_set(fs->bdev, &block);
            goto out;
        }

        /* Return ENODATA if entry is not found */
        if (block_finder.s.not_found) {
            ext4_block_set(fs->bdev, &block);
            ret = ENODATA;
            goto out;
        }

        value_len = to_le32(block_finder.s.here->e_value_size);
        value_offs = to_le32(block_finder.s.here->e_value_offs);
        if (buf_len && buf) {
            void *data_loc = (char *) block_finder.s.base + value_offs;
            memcpy(buf, data_loc, (buf_len < value_len) ? buf_len : value_len);
        }

        /*
         * Free the xattr block buffer returned by
         * ext4_xattr_block_find_entry.
         */
        ext4_block_set(fs->bdev, &block);
    }

out:
    if (ret == EOK && data_len)
        *data_len = value_len;

    return ret;
}

static int ext4_xattr_copy_new_block(struct ext4_inode_ref *inode_ref, struct ext4_block *block,
                                     struct ext4_block *new_block, ext4_fsblk_t *orig_block, bool *allocated) {
    int ret = EOK;
    ext4_fsblk_t xattr_block = 0;
    struct ext4_xattr_header *header;
    struct ext4_fs *fs = inode_ref->fs;
    header = EXT4_XATTR_BHDR(block);

    if (orig_block)
        *orig_block = block->lb_id;

    if (allocated)
        *allocated = false;

    /* Only do copy when a block is referenced by more than one inode. */
    if (to_le32(header->h_refcount) > 1) {
        ext4_fsblk_t goal = ext4_fs_inode_to_goal_block(inode_ref);

        /* Allocate a new block to be used by this inode */
        ret = ext4_balloc_alloc_block(inode_ref, goal, &xattr_block);
        if (ret != EOK)
            goto out;

        ret = ext4_trans_block_get(fs->bdev, new_block, xattr_block);
        if (ret != EOK)
            goto out;

        /* Copy the content of the whole block */
        memcpy(new_block->data, block->data, ext4_sb_get_block_size(&inode_ref->fs->sb));

        /*
         * Decrement the reference count of the original xattr block
         * by one
         */
        header->h_refcount = to_le32(to_le32(header->h_refcount) - 1);
        ext4_trans_set_block_dirty(block->buf);
        ext4_trans_set_block_dirty(new_block->buf);

        header = EXT4_XATTR_BHDR(new_block);
        header->h_refcount = to_le32(1);

        if (allocated)
            *allocated = true;
    }
out:
    if (xattr_block) {
        if (ret != EOK)
            ext4_balloc_free_block(inode_ref, xattr_block);
        else {
            /*
             * Modify the in-inode pointer to point to the new xattr block
             */
            ext4_inode_set_file_acl(inode_ref->inode, &fs->sb, xattr_block);
            inode_ref->dirty = true;
        }
    }

    return ret;
}

int ext4_xattr_remove(struct ext4_inode_ref *inode_ref, uint8_t name_index, const char *name, size_t name_len) {
    int ret = EOK;
    struct ext4_block block;
    struct ext4_xattr_finder ibody_finder;
    struct ext4_xattr_finder block_finder;
    bool use_block = false;
    bool block_loaded = false;
    struct ext4_xattr_info i;
    struct ext4_fs *fs = inode_ref->fs;
    ext4_fsblk_t xattr_block;

    xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);

    i.name_index = name_index;
    i.name = name;
    i.name_len = name_len;
    i.value = NULL;
    i.value_len = 0;

    ibody_finder.i = i;
    block_finder.i = i;

    ret = ext4_xattr_ibody_find_entry(inode_ref, &ibody_finder);
    if (ret != EOK)
        goto out;

    if (ibody_finder.s.not_found && xattr_block) {
        ret = ext4_trans_block_get(fs->bdev, &block, xattr_block);
        if (ret != EOK)
            goto out;

        block_loaded = true;
        block_finder.i = i;
        ret = ext4_xattr_block_find_entry(inode_ref, &block_finder, &block);
        if (ret != EOK)
            goto out;

        /* Return ENODATA if entry is not found */
        if (block_finder.s.not_found) {
            ret = ENODATA;
            goto out;
        }
        use_block = true;
    }

    if (use_block) {
        bool allocated = false;
        struct ext4_block new_block;

        /*
         * There will be no effect when the xattr block is only referenced
         * once.
         */
        ret = ext4_xattr_copy_new_block(inode_ref, &block, &new_block, &xattr_block, &allocated);
        if (ret != EOK)
            goto out;

        if (!allocated) {
            /* Prevent double-freeing */
            block_loaded = false;
            new_block = block;
        }

        ret = ext4_xattr_block_find_entry(inode_ref, &block_finder, &new_block);
        if (ret != EOK)
            goto out;

        /* Now remove the entry */
        ext4_xattr_set_entry(&i, &block_finder.s, false);

        if (ext4_xattr_is_empty(&block_finder.s)) {
            ext4_block_set(fs->bdev, &new_block);
            ext4_xattr_try_free_block(inode_ref);
        } else {
            struct ext4_xattr_header *header = EXT4_XATTR_BHDR(&new_block);
            header = EXT4_XATTR_BHDR(&new_block);
            ext4_assert(block_finder.s.first);
            ext4_xattr_rehash(header, block_finder.s.first);
            ext4_xattr_set_block_checksum(inode_ref, block.lb_id, header);

            ext4_trans_set_block_dirty(new_block.buf);
            ext4_block_set(fs->bdev, &new_block);
        }

    } else {
        /* Now remove the entry */
        ext4_xattr_set_entry(&i, &block_finder.s, false);
        inode_ref->dirty = true;
    }
out:
    if (block_loaded)
        ext4_block_set(fs->bdev, &block);

    return ret;
}

static int ext4_xattr_block_set(struct ext4_inode_ref *inode_ref, struct ext4_xattr_info *i, bool no_insert) {
    int ret = EOK;
    bool allocated = false;
    struct ext4_fs *fs = inode_ref->fs;
    struct ext4_block block, new_block;
    ext4_fsblk_t orig_xattr_block;

    orig_xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);

    ext4_assert(i->value);
    if (!orig_xattr_block) {
        struct ext4_xattr_search s;
        struct ext4_xattr_header *header;

        /* If insertion of new entry is not allowed... */
        if (no_insert) {
            ret = ENODATA;
            goto out;
        }

        ret = ext4_xattr_try_alloc_block(inode_ref);
        if (ret != EOK)
            goto out;

        orig_xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);
        ret = ext4_trans_block_get(fs->bdev, &block, orig_xattr_block);
        if (ret != EOK) {
            ext4_xattr_try_free_block(inode_ref);
            goto out;
        }

        ext4_xattr_block_initialize(inode_ref, &block);
        ext4_xattr_block_init_search(inode_ref, &s, &block);

        ret = ext4_xattr_set_entry(i, &s, false);
        if (ret == EOK) {
            header = EXT4_XATTR_BHDR(&block);

            ext4_assert(s.here);
            ext4_assert(s.first);
            ext4_xattr_compute_hash(header, s.here);
            ext4_xattr_rehash(header, s.first);
            ext4_xattr_set_block_checksum(inode_ref, block.lb_id, header);
            ext4_trans_set_block_dirty(block.buf);
        }
        ext4_block_set(fs->bdev, &block);
        if (ret != EOK)
            ext4_xattr_try_free_block(inode_ref);

    } else {
        struct ext4_xattr_finder finder;
        struct ext4_xattr_header *header;
        finder.i = *i;
        ret = ext4_trans_block_get(fs->bdev, &block, orig_xattr_block);
        if (ret != EOK)
            goto out;

        header = EXT4_XATTR_BHDR(&block);

        /*
         * Consider the following case when insertion of new
         * entry is not allowed
         */
        if (to_le32(header->h_refcount) > 1 && no_insert) {
            /*
             * There are other people referencing the
             * same xattr block
             */
            ret = ext4_xattr_block_find_entry(inode_ref, &finder, &block);
            if (ret != EOK) {
                ext4_block_set(fs->bdev, &block);
                goto out;
            }
            if (finder.s.not_found) {
                ext4_block_set(fs->bdev, &block);
                ret = ENODATA;
                goto out;
            }
        }

        /*
         * There will be no effect when the xattr block is only referenced
         * once.
         */
        ret = ext4_xattr_copy_new_block(inode_ref, &block, &new_block, &orig_xattr_block, &allocated);
        if (ret != EOK) {
            ext4_block_set(fs->bdev, &block);
            goto out;
        }

        if (allocated) {
            ext4_block_set(fs->bdev, &block);
            new_block = block;
        }

        ret = ext4_xattr_block_find_entry(inode_ref, &finder, &block);
        if (ret != EOK) {
            ext4_block_set(fs->bdev, &block);
            goto out;
        }

        ret = ext4_xattr_set_entry(i, &finder.s, false);
        if (ret == EOK) {
            header = EXT4_XATTR_BHDR(&block);

            ext4_assert(finder.s.here);
            ext4_assert(finder.s.first);
            ext4_xattr_compute_hash(header, finder.s.here);
            ext4_xattr_rehash(header, finder.s.first);
            ext4_xattr_set_block_checksum(inode_ref, block.lb_id, header);
            ext4_trans_set_block_dirty(block.buf);
        }
        ext4_block_set(fs->bdev, &block);
    }
out:
    return ret;
}

static int ext4_xattr_block_remove(struct ext4_inode_ref *inode_ref, struct ext4_xattr_info *i) {
    int ret = EOK;
    bool allocated = false;
    const void *value = i->value;
    struct ext4_fs *fs = inode_ref->fs;
    struct ext4_xattr_finder finder;
    struct ext4_block block, new_block;
    struct ext4_xattr_header *header;
    ext4_fsblk_t orig_xattr_block;
    orig_xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);

    ext4_assert(orig_xattr_block);
    ret = ext4_trans_block_get(fs->bdev, &block, orig_xattr_block);
    if (ret != EOK)
        goto out;

    /*
     * There will be no effect when the xattr block is only referenced
     * once.
     */
    ret = ext4_xattr_copy_new_block(inode_ref, &block, &new_block, &orig_xattr_block, &allocated);
    if (ret != EOK) {
        ext4_block_set(fs->bdev, &block);
        goto out;
    }

    if (allocated) {
        ext4_block_set(fs->bdev, &block);
        block = new_block;
    }

    ext4_xattr_block_find_entry(inode_ref, &finder, &block);

    if (!finder.s.not_found) {
        i->value = NULL;
        ret = ext4_xattr_set_entry(i, &finder.s, false);
        i->value = value;

        header = EXT4_XATTR_BHDR(&block);
        ext4_assert(finder.s.first);
        ext4_xattr_rehash(header, finder.s.first);
        ext4_xattr_set_block_checksum(inode_ref, block.lb_id, header);
        ext4_trans_set_block_dirty(block.buf);
    }

    ext4_block_set(fs->bdev, &block);
out:
    return ret;
}

int ext4_xattr_set(struct ext4_inode_ref *inode_ref, uint8_t name_index, const char *name, size_t name_len,
                   const void *value, size_t value_len) {
    int ret = EOK;
    struct ext4_fs *fs = inode_ref->fs;
    struct ext4_xattr_finder ibody_finder;
    struct ext4_xattr_info i;
    bool block_found = false;
    ext4_fsblk_t orig_xattr_block;
    size_t extra_isize = ext4_inode_get_extra_isize(&fs->sb, inode_ref->inode);

    i.name_index = name_index;
    i.name = name;
    i.name_len = name_len;
    i.value = (value_len) ? value : &ext4_xattr_empty_value;
    i.value_len = value_len;

    ibody_finder.i = i;

    orig_xattr_block = ext4_inode_get_file_acl(inode_ref->inode, &fs->sb);

    /*
     * Even if entry is not found, search context block inside the
     * finder is still valid and can be used to insert entry.
     */
    ret = ext4_xattr_ibody_find_entry(inode_ref, &ibody_finder);
    if (ret != EOK) {
        ext4_xattr_ibody_initialize(inode_ref);
        ext4_xattr_ibody_find_entry(inode_ref, &ibody_finder);
    }

    if (ibody_finder.s.not_found) {
        if (orig_xattr_block) {
            block_found = true;
            ret = ext4_xattr_block_set(inode_ref, &i, true);
            if (ret == ENOSPC)
                goto try_insert;
            else if (ret == ENODATA)
                goto try_insert;
            else if (ret != EOK)
                goto out;

        } else
            goto try_insert;

    } else {
    try_insert:
        /* Only try to set entry in ibody if inode is sufficiently large */
        if (extra_isize)
            ret = ext4_xattr_set_entry(&i, &ibody_finder.s, false);
        else
            ret = ENOSPC;

        if (ret == ENOSPC) {
            if (!block_found) {
                ret = ext4_xattr_block_set(inode_ref, &i, false);
                ibody_finder.i.value = NULL;
                ext4_xattr_set_entry(&ibody_finder.i, &ibody_finder.s, false);
                inode_ref->dirty = true;
            }

        } else if (ret == EOK) {
            if (block_found)
                ret = ext4_xattr_block_remove(inode_ref, &i);

            inode_ref->dirty = true;
        }
    }

out:
    return ret;
}

void fat32_fat_bitmap_init(int dev, const struct fat32_superblock *sb) {
    int c = 0;
    // cluster 0 and cluster 1 is reserved, cluster 2 belongs to root
    int sec = FAT_BASE;
    uint64 map_mini = 0;
    const int map_mini_size = sizeof(map_mini) << 3; // * 8
    uint64 *map = (uint64 *) sb->bitmap;
    FAT_entry_t *fat_table = (FAT_entry_t *) sb->fat_table;
    while (c < FAT_CLUSTER_MAX) {
        struct buffer_head *bp = bread(fat32_sb.s_dev, sec);
        const FAT_entry_t *fats = bp->data;
        for (int s = 0; s < FAT_PER_SECTOR; s++) {
            const uint64 idx = BIT_INDEX(c, map_mini_size);
            const uint64 off = BIT_OFFSET(c, map_mini_size);
            fat_table[c] = fats[s]; // copy fat table to memory
            if (fat_table[c] != FREE_MASK) {
                SET_BIT(map_mini, off); // set to
            } else {
                CLEAR_BIT(map_mini, off); // set to 0
            }
            c++;
            int save_flag = (off + 1 == map_mini_size);
            if (save_flag) {
                map[idx] = map_mini;
            }
            if (c > FAT_CLUSTER_MAX) {
                brelse(bp);
                if (!save_flag) {
                    // remember to save the last map_mini
                    map[idx] = map_mini;
                }
                return;
            }
        }
        sec++;
        brelse(bp);
    }
    panic("fat32_fat_bitmap_init : can't reach here\n");
}

FAT_entry_t fat32_bitmap_alloc_with_hint(const struct fat32_superblock *sb, const FAT_entry_t hint) {
    // using hint speed up
    uint64 map_mini = 0;
    const int map_mini_size = sizeof(map_mini) << 3; // * 8
    uint64 *map = (uint64 *) sb->bitmap;
    FAT_entry_t c = hint;
    // cluster 0 and cluster 1 is reserved, cluster 2 is for root
    int idx = BIT_INDEX(hint, map_mini_size);
    int off_init = BIT_OFFSET(hint, map_mini_size);
    // idx is similar to cluster
    // off is similar to FAT entry in cluster
    while (c < FAT_CLUSTER_MAX) {
        map_mini = map[idx];
        for (int off = off_init; off < map_mini_size; off++) {
            if (!TEST_BIT(map_mini, off)) {
                SET_BIT(map_mini, off);
                map[idx] = map_mini;
                return c;
            }
            c++;
            if (c > FAT_CLUSTER_MAX) {
                return 0;
            }
        }
        off_init = 0;
        idx++;
    }
    return 0;
}

void fat32_bitmap_op(struct fat32_superblock *sb, const FAT_entry_t cluster, const int set) {
    acquire(&sb->lock);
    uint64 *map = (uint64 *) sb->bitmap;
    const int map_mini_size = sizeof(uint64) << 3; // * 8
    const int idx = BIT_INDEX(cluster, map_mini_size);
    const int off = BIT_OFFSET(cluster, map_mini_size);
    if (set) {
        SET_BIT(map[idx], off);
    } else {
        CLEAR_BIT(map[idx], off);
    }
    release(&sb->lock);
}

void fat32_fat_cache_set(const FAT_entry_t cluster, const FAT_entry_t value) {
    if (!(cluster >= 2 && cluster <= FAT_CLUSTER_MAX)) {
        printfRed("cluster : %d(%x)\n", cluster, cluster);
        panic("fat32_fat_cache_set, cluster error\n");
    }
    if (!(value >= 2 && value <= FAT_CLUSTER_MAX) && value != EOC && value != FREE_MASK) {
        printfRed("value : %d(%x)\n", value, value);
        panic("fat32_fat_cache_set, value error\n");
    }
    FAT_entry_t *fats = (FAT_entry_t *) fat32_sb.fat_table;
    fats[cluster] = value;
}

FAT_entry_t fat32_fat_cache_get(const FAT_entry_t cluster) {
    if (!(cluster >= 2 && cluster <= FAT_CLUSTER_MAX)) {
        printfRed("cluster_cur : %d(%x)\n", cluster, cluster);
        panic("fat32_fat_cache_get, cluster_cur error\n");
    }
    const FAT_entry_t *fats = (FAT_entry_t *) fat32_sb.fat_table;
    const FAT_entry_t fat_next = fats[cluster];

    if (fat_next == 0) {
        printfRed("cluster_cur : %d(%x)\n", cluster, cluster);
        panic("fat32_fat_cache_get, fat_next error\n");
    }
    return fat_next;
}

void fat32_writeback_fat(int dev, const struct fat32_superblock *sb) {
    int c = 0;
    // cluster 0 and cluster 1 is reserved, cluster 2 belongs to root
    int sec = FAT_BASE;
    const FAT_entry_t *fat_table = (FAT_entry_t *) sb->fat_table;
    while (c < FAT_CLUSTER_MAX) {
        struct buffer_head *bp = bread(fat32_sb.s_dev, sec);
        FAT_entry_t *fats = (FAT_entry_t *) (bp->data);
        for (int s = 0; s < FAT_PER_SECTOR; s++) {
            fats[s] = fat_table[c];
            c++;
            if (c > FAT_CLUSTER_MAX) {
                bwrite(bp);
                brelse(bp);
                return;
            }
        }
        sec++;
        bwrite(bp);
        brelse(bp);
    }
    panic("fat32_fat_bitmap_writeback : can't reach here\n");
}

void shutdown_bitmap_writeback() {
    fat32_writeback_fat(fat32_sb.s_dev, &fat32_sb);
    fat32_update_fsinfo(fat32_sb.s_dev);
}

int fat32_get_block(struct inode *ip, struct bio *bio_p, uint off, uint n, int alloc) {
    // need alignment
    ASSERT(!PGMASK(off));
    // suppose it is an integer multiple of BSIZE
    ASSERT(n % __BPB_BytsPerSec == 0);
    ASSERT(n > 0);
    ASSERT(off >= 0);
    ASSERT(list_empty(&bio_p->list_entry));

    // move cursor
    const uint C_NUM_off = LOGISTIC_C_NUM(off) + 1;
    FAT_entry_t iter_c_n = fat32_fat_travel(ip, C_NUM_off);
    int init_s_n = LOGISTIC_S_NUM(off);
    int init_s_offset = LOGISTIC_S_OFFSET(off);
    ASSERT(init_s_offset == 0);
    // The unit of cur_s_n and tot_s_n is sector(512 B, if the size of block is 512B)
    uint cur_s_n = 0;
    const uint tot_s_n = CEIL_DIVIDE(n, __BPB_BytsPerSec);
    const uint b_per_c_n = ip->i_sb->sectors_per_block;

    struct bio_vec *vec_cur = NULL;
    while (!ISEOF(iter_c_n) && cur_s_n < tot_s_n) {
        const int first_sector = FirstSectorofCluster(iter_c_n);

        if (vec_cur == NULL || !CLUSTER_ADJACENT(vec_cur, first_sector)) {
            if ((vec_cur = (struct bio_vec *) kzalloc(sizeof(struct bio_vec))) == NULL) {
                panic("fat_get_block : no free memory\n");
            }

            sem_init(&vec_cur->sem_disk_done, 0, "bio_disk_done"); // !!! don't forget it
            INIT_LIST_HEAD(&vec_cur->list); // !!! don't forget it
            list_add_tail(&vec_cur->list, &bio_p->list_entry);
        }

        const uint blocks_n = MIN(b_per_c_n - init_s_n, tot_s_n - cur_s_n);
        if (vec_cur->blockno_start == 0) {
            vec_cur->blockno_start = first_sector + init_s_n;
            vec_cur->block_len = blocks_n;
        } else {
            vec_cur->block_len += blocks_n;
        }

        cur_s_n += blocks_n;

        if (cur_s_n == tot_s_n)
            break; // don't forget it

        init_s_n = 0;
        init_s_offset = 0;

        if (alloc) {
            const FAT_entry_t next = fat32_fat_cache_get(iter_c_n);
            if (ISEOF(next)) {
                const FAT_entry_t fat_new = fat32_cluster_alloc(ROOTDEV);
                fat32_fat_cache_set(iter_c_n, fat_new);
                iter_c_n = fat_new;
                ip->fat32_i.cluster_cnt++;
                ip->fat32_i.cluster_end = fat_new;
            } else {
                iter_c_n = next;
            }
        } else {
            iter_c_n = fat32_fat_cache_get(iter_c_n);
        }
    }
    return cur_s_n;
}

static uint64 __fat32_page_alloc(int n) {
    uint64 idx_page;
    if ((idx_page = (uint64) kzalloc(PGSIZE * n)) == 0) {
        panic("page alloc : no enough memory\n");
    }
    return idx_page;
}

int fat32_fs_mount(const int dev, struct fat32_superblock *sb) {
    /* superblock initialization */
    sb->s_op = TODO();
    sb->s_dev = dev;
    sem_init(&sb->sem, 1, "fat32_sb_sem");
    init_lock(&sb->lock, "fat32_sb_lock");

    /* read boot sector in sector 0 */
    struct buffer_head *bp = bread(dev, SECTOR_BPB);
    fat32_boot_sector_parser(sb, (fat_bpb_t *) bp->data);
    brelse(bp);

    /* read fsinfo sector in sector 1 */
    bp = bread(dev, SECTOR_FSINFO);
    fat32_fsinfo_parser(sb, bp->data);
    brelse(bp);

    /* 初始化bitmap和FAT表缓存 */
    Info("---------Initializing Bitmap and FAT table cache---------\n");
    int n = DIV_ROUND_UP((FAT_CLUSTER_MAX >> 3), PGSIZE); // ÷ 8
    sb->bitmap = __fat32_page_alloc(n);
    Info("bit map : %d pages\n", n);
    n = DIV_ROUND_UP((FAT_CLUSTER_MAX << 2), PGSIZE); // x 4
    sb->fat_table = __fat32_page_alloc(n);
    Info("fat table : %d pages\n", n);

    fat32_fat_bitmap_init(dev, sb);

    /* 调用fat32_root_entry_init，获取到root根目录的fat_entry*/
    sb->root = fat32_root_inode_init(sb);
    sb->s_mount = sb->root;

    // dirty list and lock protecting it
    INIT_LIST_HEAD(&sb->s_dirty_inodes);
    init_lock(&sb->dirty_lock, "dirty_lock");

    return 0;
}

int fat32_fsinfo_parser(struct fat32_superblock *sb, fsinfo_t *fsinfo) {
    /* superblock fsinfo fileds initialization */
    sb->fat32_sb_info.free_count = fsinfo->Free_Count;
    sb->fat32_sb_info.nxt_free = fsinfo->Nxt_Free;

    // disable hint at the beginning
    sb->fat32_sb_info.hint_enabled = 0;

    ////////////////////////////////////////////////////////////////////////////////
    Info("=============FSINFO==========\n");
    Info("Free_Count : %d\n", fsinfo->Free_Count);
    Info("Nxt_Free : %d\n", fsinfo->Nxt_Free);
    return 0;
}

int fat32_boot_sector_parser(struct fat32_superblock *sb, fat_bpb_t *fat_bpb) {
    Info("=============BOOT Sector==========\n");
    /* superblock initialization */
    // common
    sb->sector_size = fat_bpb->BytsPerSec;
    sb->n_sectors = fat_bpb->TotSec32;
    sb->sectors_per_block = fat_bpb->SecPerClus;

    // specail for fat32 superblock
    sb->fat32_sb_info.fatbase = fat_bpb->RsvdSecCnt;
    sb->fat32_sb_info.n_fats = fat_bpb->NumFATs;
    sb->fat32_sb_info.n_sectors_fat = fat_bpb->FATSz32;
    sb->fat32_sb_info.root_cluster_s = fat_bpb->RootClus;

    // repeat with sb->s_blocksize
    sb->cluster_size = (sb->sector_size) * (sb->sectors_per_block);
    sb->s_blocksize = sb->cluster_size;

    //////////////////////////////////////////////////////////////////
    /*然后是打印fat32的所有信息*/
    Info("OEMNAME : %s\n", fat_bpb->OEMName);

    Info("BytsPerSec : %d\n", fat_bpb->BytsPerSec);
    Info("SecPerClus : %d\n", fat_bpb->SecPerClus);

    Info("RsvdSecCnt : %d\n", fat_bpb->RsvdSecCnt);

    Info("NumFATs : %d\n", fat_bpb->NumFATs);

    Info("SecPerTrk : %d\n", fat_bpb->SecPerTrk);
    Info("NumHeads : %d\n", fat_bpb->NumHeads);
    Info("TotSec32 : %d\n", fat_bpb->TotSec32);

    Info("FATSz32 : %d\n", fat_bpb->FATSz32);

    Info("RootClus : %d\n", fat_bpb->RootClus);

    Info("FSInfo : %d\n", fat_bpb->FSInfo);

    Info("BkBootSec : %d\n", fat_bpb->BkBootSec);

    Info("FilSysType : ");
    printf("%.5s\n", fat_bpb->FilSysType);

    return 0;
}

ssize_t fat32_getdents(struct inode *dp, char *buf, const size_t len) {
    struct trav_control tc;
    tc.kbuf = buf;
    tc.start_off = 0;
    tc.end_off = len;
    tc.ops = TRAV_GETDENTS;
    ssize_t nreads = 0;
    tc.retval = (void *) &nreads;
    if (dp->i_hash_table == NULL) {
        inode_hash_table_init(dp);
    }
    fat32_inode_general_trav(dp, &tc, fat32_inode_travel_fcb_handler);
    return nreads;
}

static int fat32_mount(filesystem_t *fs, unsigned long rwflag, const void *data) {
    fs->fs_data = &fat32_sb;
    return fat32_fs_mount(fs->dev, fs->fs_data);
}

static int fat32_statfs(filesystem_t *fs, struct statfs *kbuf) {
    struct fat32_superblock *sb = fs->fs_data;
    kbuf->f_type = MSDOS_SUPER_MAGIC;
    kbuf->f_bsize = BSIZE;
    kbuf->f_blocks = __TotSec;
    kbuf->f_bfree = fat32_sb.fat32_sb_info.free_count; // not so important
    kbuf->f_bavail = fat32_sb.fat32_sb_info.free_count; // not so important
    kbuf->f_files = NINODE;
    kbuf->f_ffree = NINODE >> 2; // not so important
    kbuf->f_namelen = NAME_LONG_MAX;
    kbuf->f_frsize = BSIZE;
    kbuf->f_fsid.val[0] = 2; // not so important
    kbuf->f_flags = 0;

    return 0;
}

struct inode *fat32_root_inode_init(struct fat32_superblock *sb) {
    // root inode initialization
    struct inode *root_ip = (struct inode *) kalloc();
    sem_init(&root_ip->i_sem, 1, "fat_root_inode");
    sem_init(&root_ip->i_read_lock, 1, "read_root_inode");
    root_ip->i_dev = sb->s_dev;
    root_ip->i_mode = IMODE_NONE;
    // set root inode num to 0
    root_ip->i_ino = 0;
    root_ip->ref = 0;
    root_ip->valid = 1;
    // file size
    root_ip->i_mount = root_ip;
    root_ip->i_sb = sb;
    root_ip->i_nlink = 1;
    root_ip->i_op = get_inodeops[FAT32]();
    root_ip->fs_type = FAT32;

    // the parent of the root is itself
    root_ip->parent = root_ip;
    root_ip->fat32_i.cluster_start = 2;
    root_ip->fat32_i.parent_off = 0;
    root_ip->fat32_i.fname[0] = '/';
    root_ip->fat32_i.fname[1] = '\0';

    // root inode doesn't have these fields, so set these to 0
    root_ip->i_atime = 0;
    root_ip->i_mtime = 0;
    root_ip->i_ctime = 0;

    root_ip->fat32_i.cluster_cnt = fat32_fat_travel(root_ip, 0);
    root_ip->i_size = DIRLENGTH(root_ip);
    root_ip->i_sb = sb;
    root_ip->fat32_i.DIR_FileSize = 0;
    root_ip->i_type = T_DIR;
    DIR_SET(root_ip->fat32_i.Attr);

    // inode hash table
    root_ip->i_hash_table = NULL;

    // speed up dirlookup using hint
    root_ip->off_hint = 0;

    // mapping for root
    root_ip->i_mapping = NULL;

    // dirty and dirty_list
    INIT_LIST_HEAD(&root_ip->dirty_list);

    // is dirty in parent ?
    root_ip->dirty_in_parent = 0;

    // for inode create
    root_ip->create_cnt = 0;
    root_ip->create_first = 0;

    init_lock(&root_ip->tree_lock, "radix_tree_lock_root");
    init_lock(&root_ip->i_lock, "i_lock_root");
    ASSERT(root_ip->fat32_i.cluster_start == 2);

    return root_ip;
}

uint32 fat32_fat_travel(struct inode *ip, uint num) {
    FAT_entry_t iter_n = ip->fat32_i.cluster_start;
    int cnt = 0;
    int prev = 0;
    while (!ISEOF(iter_n) && (num > ++cnt || num == 0)) {
        prev = iter_n;
        iter_n = fat32_fat_cache_get(iter_n);
    }

    if (num == 0) {
        ip->fat32_i.cluster_end = prev;
        return cnt;
    }
    if (num > cnt)
        return prev;
    return iter_n;
}

static void fat32_get_absolute_path(const struct inode *ip, char *buf) {
    if (ip->fat32_i.fname[0] != '/') {
        fat32_get_absolute_path(ip->parent, buf);
    }
    const size_t n0 = strlen(buf);
    const size_t n1 = strlen(ip->fat32_i.fname);
    strncpy(buf + n0, ip->fat32_i.fname, n1);
    if (ip->fat32_i.fname[0] != '/') {
        strncpy(buf + n0 + n1, "/", 2);
    }
}

void fat32_getcwd(char *buf) {
    // note: buf must have size PATH_LONG_MAX
    if (buf == NULL)
        return;
    const struct proc *p = proc_current();
    fat32_get_absolute_path(p->cwd.data, buf);
    const size_t n = strlen(buf);
    if (n > 1) {
        buf[n - 1] = 0; // clear '/'
    }
}

uint fat32_next_cluster(uint cluster_cur) {
    ASSERT(cluster_cur >= 2 && cluster_cur < FAT_CLUSTER_MAX);
    const uint sector_num = ThisFATEntSecNum(cluster_cur);
    struct buffer_head *bp = bread(fat32_sb.s_dev, sector_num);
    const FAT_entry_t fat_next = FAT32ClusEntryVal(bp->data, cluster_cur);
    brelse(bp);
    return fat_next;
}

void fat32_update_fsinfo(const uint dev) {
    sem_p(&fat32_sb.sem);
    if (!fat32_sb.fat32_sb_info.dirty) {
        sem_v(&fat32_sb.sem);
        return;
    }

    // update fsinfo
    struct buffer_head *bp = bread(dev, SECTOR_FSINFO);
    fsinfo_t *fsinfo_tmp = bp->data;
    fsinfo_tmp->Free_Count = fat32_sb.fat32_sb_info.free_count;
    fsinfo_tmp->Nxt_Free = fat32_sb.fat32_sb_info.nxt_free;
    bwrite(bp);
    brelse(bp);

    // update fsinfo backup
    bp = bread(dev, SECTOR_FSINFO_BACKUP);
    fsinfo_tmp = (fsinfo_t *) (bp->data);
    fsinfo_tmp->Free_Count = fat32_sb.fat32_sb_info.free_count;
    fsinfo_tmp->Nxt_Free = fat32_sb.fat32_sb_info.nxt_free;
    bwrite(bp);
    brelse(bp);

    fat32_sb.fat32_sb_info.dirty = 0;
    sem_v(&fat32_sb.sem);
}

uint fat32_cluster_alloc(const uint dev) {
    acquire(&fat32_sb.lock);
    if (!fat32_sb.fat32_sb_info.free_count) {
        panic("no disk space!!!\n");
    }

    FAT_entry_t free_num = fat32_sb.fat32_sb_info.nxt_free;
    fat32_sb.fat32_sb_info.free_count--;
retry:;
    const int hint = fat32_sb.fat32_sb_info.hint_enabled ? fat32_sb.fat32_sb_info.nxt_free : 0;
    const FAT_entry_t fat_next = fat32_bitmap_alloc_with_hint(&fat32_sb, hint);

    fat32_sb.fat32_sb_info.nxt_free = fat_next + 1; // !!!
    if (fat32_sb.fat32_sb_info.nxt_free >= FAT_CLUSTER_MAX) {
        fat32_sb.fat32_sb_info.nxt_free = 3;
    }
    fat32_sb.fat32_sb_info.hint_enabled = 1; // using hint!
    if (fat_next == 0)
        goto retry;

    free_num = fat_next;

    fat32_sb.fat32_sb_info.dirty = 1; // sync input

    fat32_fat_cache_set(free_num, EOC);
    release(&fat32_sb.lock);
    return free_num;
}

uint fat32_fat_alloc() {

    int c = 3;
    int sec = FAT_BASE;
    while (c < FAT_CLUSTER_MAX) {
        struct buffer_head *bp = bread(fat32_sb.s_dev, sec);
        const FAT_entry_t *fats = (FAT_entry_t *) (bp->data);
        for (int s = 0; s < FAT_PER_SECTOR; s++) {
            if (fats[s] == FREE_MASK) {
                brelse(bp); // !!!!
                fat32_fat_set(c, EOC);
                return c;
            }
            c++;
            if (c > FAT_CLUSTER_MAX) {
                brelse(bp);
                return 0;
            }
        }
        sec++;
        brelse(bp);
    }
    return 0;
}

void fat32_fat_set(uint cluster, uint value) {
    const uint sector_num = ThisFATEntSecNum(cluster);
    struct buffer_head *bp = bread(fat32_sb.s_dev, sector_num);
    SetFAT32ClusEntryVal(bp->data, cluster, value);
    bwrite(bp);
    brelse(bp);
}

ssize_t fat32_inode_read(struct inode *ip, const int user_dst, const uint64 dst, const uint off, uint n) {
    const int fileSize = ip->i_size;
    if (off > fileSize || off + n < off)
        return 0;
    if (off + n > fileSize)
        n = fileSize - off;

    if (n == 0) {
        return 0;
    }
    if (ip->i_mapping == NULL) {
        i_mapping_init(ip);
    }
    const int ret = do_generic_read(ip->i_mapping, user_dst, dst, off, n);

    return ret;
}

static int __get_blocks(const int size) {
    const int q = size / __CLUSTER_SIZE;
    const int r = size & (__CLUSTER_SIZE - 1);
    return (q + (r != 0));
}

ssize_t fat32_inode_write(struct inode *ip, const int user_src, const uint64 src, const uint off, const uint n) {
    const int fileSize = ip->i_size;
    if (off + n < off)
        return -1;

    // init the i_mapping
    if (ip->i_mapping == NULL) {
        i_mapping_init(ip);
    }

    const int tot = do_generic_write(ip->i_mapping, user_src, src, off, n);
    if (tot == -1) {
        return -1;
    }

    acquire(&ip->i_sb->dirty_lock);
    if (list_empty(&ip->dirty_list)) {
        list_add_tail(&ip->dirty_list, &ip->i_sb->s_dirty_inodes);
    }
    release(&ip->i_sb->dirty_lock);

    if (off + n > fileSize) {
        if (ip->i_type == T_REG)
            ip->i_size = off + tot;
        else
            ip->i_size = CEIL_DIVIDE(off + tot, ip->i_sb->cluster_size) * (ip->i_sb->cluster_size);
        ip->i_blocks = __get_blocks(ip->i_size); // bug!!!
        ip->dirty_in_parent = 1;
    }

    return tot;
}

struct inode *fat32_inode_get(const uint dev, const uint inum, const char *name, const uint parentoff) {
    struct inode *ip = NULL, *empty = NULL;
    acquire(&inode_table.lock);

    empty = 0;
    for (ip = inode_table.inode_entry; ip < &inode_table.inode_entry[NINODE]; ip++) {
        if (ip->ref > 0 && ip->i_nlink == 0) {
            fat32_inode_lock(ip);
            release(&inode_table.lock);
            fat32_inode_trunc(ip);
            fat32_inode_unlock(ip);
            acquire(&inode_table.lock);
            ip->ref = 0;
        }
        if (ip->ref > 0 && ip->i_dev == dev && ip->i_ino == inum && ip->fat32_i.parent_off == parentoff &&
            ip->i_nlink != 0 && !strcmp(ip->fat32_i.fname, name)) {
            ip->ref++;
            release(&inode_table.lock);
            return ip;
        }
        if (!list_empty(&ip->dirty_list)) {
            continue;
        }
        if (empty == 0 && ip->ref == 0) // Remember empty slot.
            empty = ip;
    }

    if (empty == 0) {
        printf("mm : %lu\n", get_free_mem());
        panic("fat32_inode_get: no space");
    }

    // init the inode pointer
    ip = empty;
    ip->i_sb = &fat32_sb;
    ip->i_dev = dev;
    ip->i_ino = inum;
    ip->ref = 1;
    ip->valid = 0;
    ip->fat32_i.parent_off = parentoff; // very important!!!
    ip->i_op = get_inodeops[FAT32]();
    ip->fs_type = FAT32;

    ip->i_hash_table = NULL;

    ip->off_hint = 0;

    if (!list_empty(&ip->dirty_list)) {
        panic("fat32_inode_get : get dirty inode\n");
    }

    ip->i_mapping = NULL;

    ip->i_nlink = 1;

    ip->dirty_in_parent = 0; // !!!

    strncpy(ip->fat32_i.fname, name, strlen(name));

    ip->create_cnt = 0;
    ip->create_first = 0;

    release(&inode_table.lock);
    return ip;
}

int fat32_fcb_copy_entry_and_rename(struct inode *dp, const struct inode *ip, const char *new_name) {
    const int str_len = strlen(ip->fat32_i.fname);

    const int long_dir_len = CEIL_DIVIDE(str_len, FAT_LFN_LENGTH);
    const int fcb_char_len = (long_dir_len + 1) * 32;
    const int off = (ip->fat32_i.parent_off - long_dir_len) * 32; // we need to copy long and short entry
    ASSERT(off > 0);
    uchar *fcb_char = kzalloc(fcb_char_len);

    // read
    const int nread = fat32_inode_read(ip->parent, 0, (uint64) fcb_char, off, fcb_char_len);
    ASSERT(nread == fcb_char_len);

    // rename if new_name is not null
    if (new_name != NULL) {
        /* TODO: manipulate fcb_char in order to rename the file */
        /* it's difficult, because we should also move the fcbs behind the current one */
    }

    // write
    uint off_write = fat32_dir_fcb_insert_offset(dp, fcb_char_len) * 32; // unit of offset is 32 Bytes
    uint nwrite = fat32_inode_write(dp, 0, (uint64) fcb_char, off_write, fcb_char_len);
    ASSERT(nwrite == fcb_char_len);

    kfree(fcb_char);

    return 0;
}

void fat32_inode_lock(struct inode *ip) {
    if (ip == 0 || ip->ref < 1) {
        panic("inode lock");
    }
    sem_p(&ip->i_sem);
    if (ip->valid == 0) {
        fat32_inode_load_from_disk(ip);
    }
}

int fat32_inode_load_from_disk(struct inode *ip) {
    const uchar bp[32] = {0}; // pay attention to stack overflow!!!
    const int off = ip->fat32_i.parent_off * 32; // the size of short entry or long entry is 32B

    if (ip->parent->valid == 0) {
        panic("error");
    }

    const int ret = fat32_inode_read(ip->parent, 0, bp, off, 32); // read fcb using its parent, rather than itself!!!

    ASSERT(ret == 32);
    const dirent_s_t *dirent_s_tmp = bp;

    ip->fat32_i.Attr = dirent_s_tmp->DIR_Attr;
    ip->fat32_i.cluster_start = DIR_FIRST_CLUS(dirent_s_tmp->DIR_FstClusHI, dirent_s_tmp->DIR_FstClusLO);
    if (ip->fat32_i.cluster_start == fat32_sb.fat32_sb_info.root_cluster_s && !fat32_namecmp(ip->fat32_i.fname, "/")) {
        return -1;
    }
    // !!!
    if (ip->fat32_i.cluster_start != 0) {
        ip->fat32_i.cluster_cnt = fat32_fat_travel(ip, 0);
    } else {
        printfRed("the cluster_start of the file %s is zero\n ", ip->fat32_i.fname);
    }
    ip->fat32_i.DIR_CrtTimeTenth = dirent_s_tmp->DIR_CrtTimeTenth;

    ip->fat32_i.DIR_CrtTime = dirent_s_tmp->DIR_CrtTime;
    ip->fat32_i.DIR_CrtDate = dirent_s_tmp->DIR_CrtDate;
    ip->fat32_i.DIR_LstAccDate = dirent_s_tmp->DIR_LstAccDate;
    ip->fat32_i.DIR_WrtTime = dirent_s_tmp->DIR_WrtTime;
    ip->fat32_i.DIR_CrtDate = dirent_s_tmp->DIR_CrtDate;
    ip->fat32_i.DIR_FileSize = dirent_s_tmp->DIR_FileSize;

    ip->i_rdev = dirent_s_tmp->DIR_Dev;

    if (ip->i_rdev)
        ip->i_type = T_CHR; // device?
    else if (DIR_BOOL(ip->fat32_i.Attr))
        ip->i_type = T_DIR;
    else
        ip->i_type = T_REG;

    if (ip->i_type == T_REG)
        ip->i_size = ip->fat32_i.DIR_FileSize;
    else if (ip->i_type == T_DIR)
        ip->i_size = DIRLENGTH(ip);
    else if (ip->i_type == T_CHR)
        ip->i_size = 0;

    ip->i_mode = READONLY_GET(dirent_s_tmp->DIR_Attr);

    ip->valid = 1;
    if (ip->fat32_i.Attr == 0)
        panic("fat32_inode_lock: no Attr");
    return 1;
}

void fat32_inode_unlock(struct inode *ip) {
    if (ip == 0 || ip->ref < 1)
        panic("fat32 unlock");
    sem_v(&ip->i_sem);
}

void fat32_inode_put(struct inode *ip) {
    acquire(&inode_table.lock);

    if (ip->valid && ip->i_nlink == 0) {
        inode_hash_table_destroy(ip);
        i_mapping_writeback(ip);
        i_mapping_destroy(ip);
    }

    release(&inode_table.lock);
}

void fat32_inode_unlock_put(struct inode *ip) {
    fat32_inode_unlock(ip);
    fat32_inode_put(ip);
}

void fat32_inode_trunc(struct inode *ip) {
    FAT_entry_t iter_n = ip->fat32_i.cluster_start;
    while (!ISEOF(iter_n)) {

        const FAT_entry_t fat_next = fat32_fat_cache_get(iter_n);
        fat32_bitmap_op(&fat32_sb, iter_n, 0); // bitmap set free
        fat32_fat_cache_set(iter_n, FREE_MASK); // fat table cache set free
        iter_n = fat_next;
    }

    acquire(&fat32_sb.lock);
    fat32_sb.fat32_sb_info.free_count += ip->fat32_i.cluster_cnt;
    release(&fat32_sb.lock);

    ip->fat32_i.cluster_start = 0;
    ip->fat32_i.cluster_end = 0;
    ip->fat32_i.cluster_cnt = 0;
    ip->fat32_i.DIR_FileSize = 0;
    ip->fat32_i.Attr = 0;
    ip->i_rdev = 0;
    ip->i_mode = IMODE_NONE;
    ip->i_size = 0;
    ip->i_blocks = 0;
    ip->fat32_i.parent_off = -1; // ???

    ip->i_hash_table = NULL; // !!!

    // speed up dirlookup
    ip->off_hint = 0;
}

void fat32_inode_update(const struct inode *ip) {
    if (ip->i_ino == ROOT_INO) {
        return;
    }

    const uchar bp[32] = {0}; // pay attention to stack overflow!!!
    const int off = ip->fat32_i.parent_off * 32; // the size of short entry or long entry is 32B

    if (ip->parent->valid == 0) {
        panic("error");
    }
    const int ret = fat32_inode_read(ip->parent, 0, bp, off, 32); // read fcb using its parent, rather than itself!!!

    ASSERT(ret == 32);

    dirent_s_t *dirent_s_tmp = bp;

    dirent_s_tmp->DIR_Attr = ip->fat32_i.Attr;
    dirent_s_tmp->DIR_LstAccDate = ip->fat32_i.DIR_LstAccDate;
    dirent_s_tmp->DIR_WrtDate = ip->fat32_i.DIR_WrtDate;
    dirent_s_tmp->DIR_WrtTime = ip->fat32_i.DIR_WrtTime;
    dirent_s_tmp->DIR_FstClusHI = DIR_FIRST_HIGH(ip->fat32_i.cluster_start);
    dirent_s_tmp->DIR_FstClusLO = DIR_FIRST_LOW(ip->fat32_i.cluster_start);
    if (ip->i_type == T_DIR || ip->i_type == T_CHR) {
        dirent_s_tmp->DIR_FileSize = 0;
    } else {
        dirent_s_tmp->DIR_FileSize = ip->i_size;
    }

    dirent_s_tmp->DIR_Attr |= ip->i_mode;
    if (ip->i_type == T_CHR)
        dirent_s_tmp->DIR_Dev = ip->i_dev;
    else
        dirent_s_tmp->DIR_Dev = 0;

    if (ip->parent->valid == 0) {
        panic("error");
    }

    fat32_inode_write(ip->parent, 0, bp, off, 32);
}

int fat32_filter_longname(const dirent_l_t *dirent_l_tmp, char *ret_name) {
    int idx = 0;
    for (int i = 0; i < 5; i++) {
        ret_name[idx++] = LONG_NAME_CHAR_MASK(dirent_l_tmp->LDIR_Name1[i]);
        if (!LONG_NAME_CHAR_VALID(dirent_l_tmp->LDIR_Name1[i]))
            return idx;
    }
    for (int i = 0; i < 6; i++) {
        ret_name[idx++] = LONG_NAME_CHAR_MASK(dirent_l_tmp->LDIR_Name2[i]);
        if (!LONG_NAME_CHAR_VALID(dirent_l_tmp->LDIR_Name2[i]))
            return idx;
    }
    for (int i = 0; i < 2; i++) {
        ret_name[idx++] = LONG_NAME_CHAR_MASK(dirent_l_tmp->LDIR_Name3[i]);
        if (!LONG_NAME_CHAR_VALID(dirent_l_tmp->LDIR_Name3[i]))
            return idx;
    }
    return idx;
}

ushort fat32_longname_popstack(Stack_t *fcb_stack, const uchar *fcb_s_name, char *name_buf) {
    int name_idx = 0;
    dirent_l_t fcb_l_tmp;
    if (stack_is_empty(fcb_stack)) {
        return 0;
    }
    uchar cnt = 1;
    while (!stack_is_empty(fcb_stack)) {
        fcb_l_tmp = stack_pop(fcb_stack);
        if (!stack_is_empty(fcb_stack) && cnt != fcb_l_tmp.LDIR_Ord) {
            return 0;
        }
        cnt++;
        const uchar checksum = ChkSum(fcb_s_name);
        if (fcb_l_tmp.LDIR_Chksum != checksum) {
            panic("check sum error");
        }
        char l_tmp[14] = {0};
        const int l_tmp_len = fat32_filter_longname(&fcb_l_tmp, l_tmp);
        for (int i = 0; i < l_tmp_len; i++) {
            name_buf[name_idx++] = l_tmp[i];
        }
    }
    name_buf[name_idx] = '\0';
    const ushort long_valid = LAST_LONG_ENTRY_BOOL(fcb_l_tmp.LDIR_Ord) ? 1 : 0;
    return long_valid;
}

uchar ChkSum(const uchar *pFcbName) {
    uchar Sum = 0;
    for (short FcbNameLen = 11; FcbNameLen != 0; FcbNameLen--) {
        Sum = ((Sum & 1) ? 0x80 : 0) + (Sum >> 1) + *pFcbName++;
    }
    return Sum;
}

struct inode *fat32_inode_dirlookup(struct inode *ip, const char *name, uint *poff) {
    return __fat32_inode_dirlookup_hash_table(ip, name, poff);
}

static struct inode *__fat32_inode_dirlookup_with_hint(struct inode *ip, const char *name, uint *poff) {
    struct trav_control tc;
    tc.start_off = 0 * 32;
    tc.end_off = ip->i_size;
    tc.kbuf = NULL;
    tc.ops = TRAV_DIRLOOKUP;
    strncpy(tc.name_search, name, strlen(name));
    tc.poff = poff;
    tc.retval = NULL;
    fat32_inode_general_trav(ip, &tc, fat32_inode_travel_fcb_handler);
    return tc.retval;
}

static struct inode *__fat32_inode_dirlookup_hash_table(struct inode *ip, const char *name, uint *poff) {
    if (!DIR_BOOL((ip->fat32_i.Attr)))
        panic("dirlookup not DIR");
    struct inode *ip_search = NULL;
    if (ip->i_hash_table == NULL) {
        inode_hash_table_init(ip);
    } else {
        ip_search = ip->i_hash_table->op->hash_lookup(ip->i_hash_table, (void *) name, 1, 0);
        if (ip_search != NULL) {
            ip_search->ref++;
            return ip_search;
        }
    }
    ip_search = __fat32_inode_dirlookup_with_hint(ip, name, poff);
    return ip_search;
}

int fat32_inode_dirlink(struct inode *dp, const char *name) {
    // int off;
    struct inode *ip;

    // Check that name is not present.
    if ((ip = fat32_inode_dirlookup(dp, name, 0)) != 0) {
        fat32_inode_put(ip);
        return -1;
    }
    ip->i_nlink++;
    fat32_inode_put(ip);
    return 0;
}

struct inode *fat32_inode_create(struct inode *dp, const char *name, const uchar type, const short major,
                                 const short minor) {
    struct inode *ip = NULL;
    ASSERT(dp);
    dp->i_op->lock(dp);
    if ((ip = dp->i_op->dirlookup(dp, name, 0)) != 0) {
        dp->i_op->unlock(dp);
        ip->i_op->lock(ip);
        if (type == ip->i_type) {
            return ip;
        }
        ip->i_op->unlock(ip);
        return 0;
    }

    // haven't exited
    if ((ip = fat32_inode_alloc(dp, name, type)) == 0) {
        dp->i_op->unlock_put(dp);
        return 0;
    }
    ip->i_op->lock(ip);

    ip->i_nlink = 1;
    ip->i_rdev = mkrdev(major, minor);
    ip->i_type = type;
    ip->i_op->update(ip);
    if (type == T_DIR) { // Create . and .. entries.
        // TODO : dirlink
        const uchar fcb_dot_char[32] = {0};
        fat32_fcb_init(ip, ".", ATTR_DIRECTORY, fcb_dot_char);
        uint tot = ip->i_op->write(ip, 0, fcb_dot_char, 0, 32);
        ASSERT(tot == 32);
        const uchar fcb_dotdot_char[32] = {0};
        fat32_fcb_init(ip, "..", ATTR_DIRECTORY, fcb_dotdot_char);
        tot = ip->i_op->write(ip, 0, fcb_dotdot_char, 32, 32);
        ASSERT(tot == 32);
    }

    dp->i_op->unlock(dp);

    return ip;
}

struct inode *fat32_inode_alloc(struct inode *dp, const char *name, const uchar type) {
    uchar attr;
    if (type == T_DIR)
        DIR_SET(attr);
    else
        NONE_DIR_SET(attr);
    uchar fcb_char[FCB_MAX_LENGTH] = {0};
    const int fcb_cnt = fat32_fcb_init(dp, (const uchar *) name, attr, fcb_char);
    const uint offset = fat32_dir_fcb_insert_offset(dp, fcb_cnt);
    const uint tot = fat32_inode_write(dp, 0, fcb_char, offset * sizeof(dirent_l_t), fcb_cnt * sizeof(dirent_l_t));

    ASSERT(tot == fcb_cnt * sizeof(dirent_l_t));

    const uint fcb_new_off = (offset + fcb_cnt - 1) * sizeof(dirent_s_t);
    const uint C_NUM = LOGISTIC_C_NUM(fcb_new_off) + 1;
    // find the target cluster of off
    const uint target_cluster = fat32_fat_travel(dp, C_NUM);
    const uint first_sector = FirstSectorofCluster(target_cluster);

    const uint C_OFFSET = LOGISTIC_C_OFFSET(fcb_new_off);
    const uint sector_num = first_sector + C_OFFSET / fat32_sb.sector_size;
    const uint sector_offset = (C_OFFSET % fat32_sb.sector_size) / sizeof(dirent_l_t);
    const uint fat_num = SECTOR_TO_FATINUM(sector_num, sector_offset);

    struct inode *ip_new = fat32_inode_get(dp->i_dev, fat_num, name, offset + fcb_cnt - 1);
    ip_new->i_nlink = 1;
    ip_new->ref = 1;
    ip_new->parent = dp;
    ip_new->i_type = type;

    ip_new->i_op = get_inodeops[FAT32]();
    ip_new->fs_type = FAT32;
    return ip_new;
}

int fat32_fcb_init(struct inode *ip_parent, const uchar *long_name, uchar attr, char *fcb_char) {
    dirent_s_t dirent_s_cur = {0};
    dirent_s_cur.DIR_Attr = attr;
    uint long_idx;

    // . and ..
    if (!fat32_namecmp((const char *) long_name, ".") || !fat32_namecmp((const char *) long_name, "..")) {
        strncpy((char *) dirent_s_cur.DIR_Name, (const char *) long_name, strlen((const char *) long_name));
        dirent_s_cur.DIR_FileSize = 0;
        dirent_s_cur.DIR_FstClusHI = DIR_FIRST_HIGH(ip_parent->fat32_i.cluster_start);
        dirent_s_cur.DIR_FstClusLO = DIR_FIRST_LOW(ip_parent->fat32_i.cluster_start);
        memmove(fcb_char, &dirent_s_cur, sizeof(dirent_s_cur));
        return 1;
    }

    int ret_cnt = 0;
    char file_name[NAME_LONG_MAX];
    /*short dirent*/
    const int name_len = strlen((const char *) long_name);
    // 数据文件
    if (!DIR_BOOL(attr)) {
        char file_ext[4];
        if (str_split((const char *) long_name, '.', file_name, file_ext) == -1) {
            strncpy(file_name, (char *) long_name, 8);
            dirent_s_cur.DIR_Name[8] = 0x20;
            dirent_s_cur.DIR_Name[9] = 0x20;
            dirent_s_cur.DIR_Name[10] = 0x20;
        } else {
            str_toupper(file_ext);
            /* bug: no strncpy here! it will cover DIR_Attr */
            // strncpy((char *) dirent_s_cur.DIR_Name + 8, file_ext, 3); // extend name
            memcpy((char *) dirent_s_cur.DIR_Name + 8, file_ext, 3);
            const int len = strlen(file_ext);
            if (len == 2) {
                dirent_s_cur.DIR_Name[10] = 0x20;
            } else if (len == 1) {
                dirent_s_cur.DIR_Name[10] = 0x20;
                dirent_s_cur.DIR_Name[9] = 0x20;
            }
        }

        str_toupper(file_name);
        strncpy(dirent_s_cur.DIR_Name, file_name, 8);
        if (strlen((char *) long_name) > 8) {
            long_idx = fat32_find_same_name_cnt(ip_parent, file_name);
            dirent_s_cur.DIR_Name[6] = '~';
            dirent_s_cur.DIR_Name[7] = long_idx + 0x31;
        }
    } else {
        // 目录文件
        strncpy(file_name, (char *) long_name, 11);

        str_toupper(file_name);
        strncpy(dirent_s_cur.DIR_Name, file_name, 8);
        if (strlen((const char *) long_name) > 8) {
            long_idx = fat32_find_same_name_cnt(ip_parent, file_name);

            dirent_s_cur.DIR_Name[6] = '~';
            dirent_s_cur.DIR_Name[7] = long_idx + 0x31;
            memset(dirent_s_cur.DIR_Name + 8, 0x20, 3);
        }
    }
    dirent_s_cur.DIR_FileSize = 0;

    const uint first_c = fat32_cluster_alloc(ip_parent->i_dev);
    dirent_s_cur.DIR_FstClusHI = DIR_FIRST_HIGH(first_c);
    dirent_s_cur.DIR_FstClusLO = DIR_FIRST_LOW(first_c);

    /*push long dirent into stack*/
    Stack_t fcb_stack;
    stack_init(&fcb_stack);
    // int iter_order = 1;      // the compiler says it's an unused variable
    const uchar checksum = ChkSum(dirent_s_cur.DIR_Name);
    int char_idx = 0;
    // every long name entry
    const int ord_max = CEIL_DIVIDE(name_len, FAT_LFN_LENGTH);
    for (int i = 1; i <= ord_max; i++) {
        dirent_l_t dirent_l_cur;
        memset((void *) &(dirent_l_cur), 0xFF, sizeof(dirent_l_cur));
        if (char_idx == name_len)
            break;

        // order
        if (i == ord_max)
            dirent_l_cur.LDIR_Ord = LAST_LONG_ENTRY_SET(i);
        else
            dirent_l_cur.LDIR_Ord = i;

        // Name
        int end_flag = 0;
        for (int i = 0; i < 5 && !end_flag; i++) {
            dirent_l_cur.LDIR_Name1[i] = LONG_NAME_CHAR_SET(long_name[char_idx]);
            if (!LONG_NAME_CHAR_VALID(long_name[char_idx]))
                end_flag = 1;
            char_idx++;
        }
        for (int i = 0; i < 6 && !end_flag; i++) {
            dirent_l_cur.LDIR_Name2[i] = LONG_NAME_CHAR_SET(long_name[char_idx]);
            if (!LONG_NAME_CHAR_VALID(long_name[char_idx]))
                end_flag = 1;
            char_idx++;
        }
        for (int i = 0; i < 2 && !end_flag; i++) {
            dirent_l_cur.LDIR_Name3[i] = LONG_NAME_CHAR_SET(long_name[char_idx]);
            if (!LONG_NAME_CHAR_VALID(long_name[char_idx]))
                end_flag = 1;
            char_idx++;
        }

        // Attr  and  Type
        dirent_l_cur.LDIR_Attr = ATTR_LONG_NAME;
        dirent_l_cur.LDIR_Type = 0;

        // check sum
        dirent_l_cur.LDIR_Chksum = checksum;

        // must set to zero
        dirent_l_cur.LDIR_Nlinks = 0;
        stack_push(&fcb_stack, dirent_l_cur);
    }

    dirent_l_t fcb_l_tmp;
    while (!stack_is_empty(&fcb_stack)) {
        fcb_l_tmp = stack_pop(&fcb_stack);
        memmove(fcb_char, &fcb_l_tmp, sizeof(fcb_l_tmp));
        fcb_char = fcb_char + sizeof(fcb_l_tmp);
        ret_cnt++;
    }
    // the first long dirent
    fcb_l_tmp.LDIR_Nlinks = 1;
    memmove(fcb_char, &dirent_s_cur, sizeof(dirent_s_cur));
    stack_free(&fcb_stack);
    return ret_cnt + 1;
    // TODO: 获取当前时间和日期，还有TimeTenth
}

uint fat32_find_same_name_cnt(struct inode *ip, const char *name) {
    struct trav_control tc;
    tc.start_off = 0;
    tc.end_off = ip->i_size;
    tc.kbuf = NULL;
    strncpy(tc.name_search, name, strlen(name));
    int cnt = 0;
    tc.retval = (void *) &cnt;
    fat32_inode_general_trav(ip, &tc, fat32_find_same_name_cnt_handler);
    return cnt;
}

uint fat32_dir_fcb_insert_offset(struct inode *dp, const uchar fcb_cnt_req) {
    struct trav_control tc;
    tc.start_off = 0;
    tc.end_off = dp->i_size;
    tc.kbuf = NULL;
    uint offset_ret_final = 0;
    tc.retval = (void *) &offset_ret_final;
    tc.fcb_cnt_req = fcb_cnt_req;
    tc.offset_ret_base = dp->i_size / sizeof(dirent_l_t);
    tc.fcb_free_cnt = 0;
    fat32_inode_general_trav(dp, &tc, fat32_dir_fcb_insert_offset_handler);
    return offset_ret_final;
}

int fat32_is_dir_empty(struct inode *dp) {
    struct trav_control tc;
    tc.start_off = 0;
    tc.end_off = dp->i_size;
    tc.kbuf = NULL;
    int judge = 1;
    tc.retval = (void *) &judge;
    fat32_inode_general_trav(dp, &tc, fat32_isdirempty_handler);
    return judge;
}

int fat32_inode_delete(struct inode *dp, struct inode *ip) {
    const int str_len = strlen(ip->fat32_i.fname);
    const int off = ip->fat32_i.parent_off;
    ASSERT(off > 0);
    const int long_dir_len = CEIL_DIVIDE(str_len, FAT_LFN_LENGTH); // 上取整
    char fcb_char[FCB_MAX_LENGTH] = {0};
    for (int i = 0; i < long_dir_len + 1; i++)
        fcb_char[i * 32] = 0xE5;
    if (off - long_dir_len <= 0) {
        panic("off - long_dir_len <= 0");
    }
    const uint tot = fat32_inode_write(dp, 0, fcb_char, (off - long_dir_len) * sizeof(dirent_s_t),
                                       (long_dir_len + 1) * sizeof(dirent_s_t));
    ASSERT(tot == (long_dir_len + 1) * sizeof(dirent_l_t));

    dp->i_hash_table->op->hash_delete(dp->i_hash_table, ip, 0, 1);

    return 0;
}

void fat32_zero_cluster(const uint64 c_num) {
    const int first_sector = FirstSectorofCluster(c_num);
    for (int s = 0; s < (fat32_sb.sectors_per_block); s++) {
        struct buffer_head *bp = bread(fat32_sb.s_dev, first_sector + s);
        memset(bp->data, 0, BSIZE);
        bwrite(bp);
        brelse(bp);
    }
    return;
}

void fat32_short_name_parser(dirent_s_t dirent_s, char *name_buf) {
    int len_name = 0;
    for (int i = 0; i < 8; i++) {
        if (dirent_s.DIR_Name[i] != 0x20) {
            name_buf[len_name++] = dirent_s.DIR_Name[i];
        }
    }
    if (dirent_s.DIR_Name[8] != 0x20) {
        name_buf[len_name++] = '.';
        for (int i = 8; i < 11; i++) {
            if (dirent_s.DIR_Name[i] != 0x20) {
                name_buf[len_name++] = dirent_s.DIR_Name[i];
            }
        }
    }
    name_buf[len_name] = '\0';
}

void i_mapping_destroy(struct inode *ip) {
    struct address_space *mapping = ip->i_mapping;
    acquire(&ip->tree_lock); // !!!
    if (mapping == NULL) {
        release(&ip->tree_lock); // !!!
        return;
    }

    struct radix_tree_node *node = mapping->page_tree.rnode;
    if (node == NULL) {
        release(&ip->tree_lock); // !!!
        return;
    }
    if (!radix_tree_is_indirect_ptr(node)) {
        kfree((void *) page_to_pa((struct page *) node));
    } else {
        node = radix_tree_indirect_to_ptr(node);
        radix_tree_free_whole_tree(node, mapping->page_tree.height, 1);
    }

    kfree(mapping);
    ip->i_mapping = NULL;

    release(&ip->tree_lock); // !!!
}

void i_mapping_init(struct inode *ip) {
    struct address_space *mapping = kzalloc(sizeof(struct address_space));
    // printfMAGENTA("fat32_i_mapping_init, mm-- : %d pages\n", get_free_mem() / 4096);
    ip->i_mapping = mapping;
    mapping->host = ip; // !!!
    mapping->nrpages = 0;
    INIT_RADIX_TREE(&mapping->page_tree, GFP_FS);
    mapping->last_idx = 0;
    mapping->readahead_cnt = 0;
    mapping->readahead_end = 0;
}

void i_mapping_writeback(struct inode *ip) {
    // atomic !!!
    if (!list_empty_atomic(&ip->dirty_list, &ip->i_lock)) {

        release(&inode_table.lock);
        int ret = sync_inode(ip);
        acquire(&inode_table.lock);

        // remove inode from dirty list
        if (ret == 0) {
            list_del_reinit(&ip->dirty_list);
            ip->i_writeback = 0;
        }
    }
}

void fs_clean() {
    struct filesystem *fs = get_fs_by_mount_point("/");
    if (fs == NULL) {
        return;
    }

    if (fs->fs_type == FAT32) {
        acquire(&inode_table.lock);
        struct inode *ip = NULL;

        for (ip = inode_table.inode_entry; ip < &inode_table.inode_entry[NINODE]; ip++) {
            if (ip->ref) {

                // write back dirty pages of inode
                i_mapping_writeback(ip);

                // destory i_mapping
                i_mapping_destroy(ip);

                // destory hash table
                inode_hash_table_destroy(ip);
            }
        }
        i_mapping_writeback(fat32_sb.root);
        i_mapping_destroy(fat32_sb.root);
        inode_hash_table_destroy(fat32_sb.root);

        release(&inode_table.lock);
        shutdown_bitmap_writeback();
    } else if (fs->fs_type == EXT4) {
        vfs_ext_flush(fs);
    }
}

void fat32_inode_general_trav(struct inode *dp, struct trav_control *tc, trav_handler fn) {
    // must a directory!!!
    if (!DIR_BOOL((dp->fat32_i.Attr)))
        panic("not DIR\n");
    tc->dp = dp;

    // name_buf and fcb_stack only for dirlookup and getdents
    if (tc->ops == TRAV_DIRLOOKUP || tc->ops == TRAV_GETDENTS) {
        Stack_t fcb_stack;
        char name_buf[NAME_LONG_MAX] = {0};
        stack_init(&fcb_stack);
        tc->fcb_stack = &fcb_stack;
        tc->name_buf = name_buf;
    }

    // off and sz
    int start_off = tc->start_off;
    int end_off = tc->end_off;
    int sz = end_off - start_off;

    int free_flag = 0;
    // read all blocks of this file
    if (tc->kbuf == NULL) {
        char *kbuf;
        if ((kbuf = kzalloc(sz)) == 0) {
            panic("fat32_inode_general_trav : no enough memory\n");
        }
        // printfMAGENTA("tc->kbuf, mm-- : %d pages\n", get_free_mem() / 4096);
        tc->kbuf = kbuf;
        free_flag = 1;
    }

    fat32_inode_read(dp, 0, (uint64) tc->kbuf, start_off, sz);


    // find it or stop
    tc->stop = 0;

    // check every fcb
    tc->iter_n = dp->fat32_i.cluster_start;
    for (tc->idx = 0; start_off + tc->idx * 32 < end_off; tc->idx++) {
        tc->off = ((tc->start_off) >> 5) + (tc->idx); // start_off/32 + idx
        // perform fn
        fn(tc);
        if (tc->off && tc->off % FCB_PER_CLUS == 0) {
            tc->iter_n = fat32_next_cluster(tc->iter_n);
        }
        if (tc->stop) {
            break;
        }
    }

    // don't forget kfree
    if (free_flag) {
        kfree(tc->kbuf);
    }

    // over
    if (tc->ops == TRAV_DIRLOOKUP || tc->ops == TRAV_GETDENTS) {
        stack_free(tc->fcb_stack);
        if (!tc->stop) {
            tc->retval = NULL;
            tc->dp->off_hint = 0;
        }
    }
}

void fat32_inode_travel_fcb_handler(struct trav_control *tc) {
    const dirent_s_t *fcb_s = (dirent_s_t *) (tc->kbuf) + tc->idx;
    const dirent_l_t *fcb_l = (dirent_l_t *) (tc->kbuf) + tc->idx;
    tc->fcb_s = *fcb_s;

    if (NAME0_FREE_ALL(fcb_s->DIR_Name[0])) {
        tc->stop = 1;
        return;
    }
    // only this fcb is free
    if (NAME0_FREE_ONLY(fcb_s->DIR_Name[0])) {
        if (!stack_is_empty(tc->fcb_stack)) {
            panic("there is something wrong with disk\n");
        }
        return;
    }
    // long_entry
    if (LONG_NAME_BOOL(fcb_l->LDIR_Attr)) {
        stack_push(tc->fcb_stack, *fcb_l);
    }
    // short entry
    else {
        // pop long entry stack to get full name of file
        memset(tc->name_buf, 0, sizeof(tc->name_buf));
        const ushort long_valid = fat32_longname_popstack(tc->fcb_stack, fcb_s->DIR_Name, tc->name_buf);
        // if the long directory is invalid, we use name of short entry
        if (!long_valid) {
            fat32_short_name_parser(*fcb_s, tc->name_buf);
        }
        // ino
        const uint32 cluster_start = DIR_FIRST_CLUS(fcb_s->DIR_FstClusHI, fcb_s->DIR_FstClusLO);

        // apply operations
        switch (tc->ops) {
            case TRAV_DIRLOOKUP: {
                FAT_entry_t iter_n = tc->iter_n;
                int first_sector = FirstSectorofCluster(iter_n);
                tc->i_ino = SECTOR_TO_FATINUM(first_sector, tc->off % FCB_PER_CLUS);
                fat32_inode_dirlookup_handler(tc);
            } break;
            case TRAV_GETDENTS:
                tc->i_ino = UNIQUE_INO(tc->off, cluster_start);
                fat32_inode_getdents_handler(tc);
                break;
            default:
                panic("fat32_inode_travel_using_stack : error\n");
        }
    }
}

void fat32_inode_dirlookup_handler(struct trav_control *tc) {
    if (fat32_namecmp(tc->name_search, tc->name_buf) == 0) {
        if (tc->poff)
            *tc->poff = tc->off;


        struct inode *ip_search = fat32_inode_get(tc->dp->i_dev, tc->i_ino, tc->name_search, tc->off);
        ip_search->parent = tc->dp;

        // insert cache into the hash table (except . and ..)
        if (tc->name_buf[0] != '.') {
            // FIXME: in the previous implementation, ip_search is actually NULL
            int ret = tc->dp->i_hash_table->op->hash_insert(tc->dp->i_hash_table, ip_search, 0);
        }

        // save hint
        tc->dp->off_hint = tc->off + 1;

        // it is time to return
        tc->retval = ip_search;
        tc->stop = 1;
    }
}

void fat32_inode_getdents_handler(struct trav_control *tc) {
    char buf_tmp[NAME_LONG_MAX + 30];
    struct __dirent *dirent_buf = buf_tmp;

    dirent_buf->d_off = ++tc->file_idx; // start from 1

    if (tc->fcb_s.DIR_Dev) {
        dirent_buf->d_type = T_CHR;
    } else if (DIR_BOOL(tc->fcb_s.DIR_Attr)) {
        dirent_buf->d_type = T_DIR;
    } else {
        dirent_buf->d_type = T_REG;
    }
    const int fname_len = strlen(tc->name_buf);
    strncpy(dirent_buf->d_name, tc->name_buf, fname_len); // !!!!!
    dirent_buf->d_name[fname_len] = '\0';
    dirent_buf->d_reclen = dirent_len(dirent_buf);
    memmove(tc->kbuf + *(ssize_t *) tc->retval, dirent_buf, dirent_buf->d_reclen);
    *(ssize_t *) tc->retval += dirent_buf->d_reclen;
}

void fat32_dir_fcb_insert_offset_handler(struct trav_control *tc) {
    dirent_s_t *fcb_s = (dirent_s_t *) (tc->kbuf) + tc->idx;
    // bug like this : (dirent_s_t *)(tc->kbuf + tc->idx);

    if (!NAME0_FREE_BOOL(fcb_s->DIR_Name[0])) {
        tc->fcb_free_cnt = 0;
        *(int *) tc->retval = tc->offset_ret_base;
    } else {
        if (tc->fcb_free_cnt == 0) {
            *(int *) tc->retval = tc->start_off / 32 + tc->idx; // remember /32
        }
        tc->fcb_free_cnt++;
        if (tc->fcb_free_cnt == tc->fcb_cnt_req) {
            tc->stop = 1;
            return;
        }
    }
}

void fat32_isdirempty_handler(struct trav_control *tc) {
    const dirent_s_t *fcb_s = (dirent_s_t *) tc->kbuf + tc->idx;

    if (!NAME0_FREE_BOOL(fcb_s->DIR_Name[0])) {
        if (fat32_namecmp(fcb_s->DIR_Name, ".") && fat32_namecmp(fcb_s->DIR_Name, "..")) {
            tc->stop = 1;
            *(int *) tc->retval = 0; // default is 1
        }
    }
}

void fat32_find_same_name_cnt_handler(struct trav_control *tc) {
    const dirent_s_t *fcb_s = (dirent_s_t *) (tc->kbuf) + tc->idx;

    if (NAME0_FREE_ALL(fcb_s->DIR_Name[0])) {
        tc->stop = 1;
        return;
    }

    if (!LONG_NAME_BOOL(fcb_s->DIR_Attr)) {
        if (!strncmp(fcb_s->DIR_Name, tc->name_search, 6) && fcb_s->DIR_Name[6] == '~') {
            *(int *) tc->retval += 1; // initial value is 0
        }
    }
}

void stack_init(Stack_t *stack) {
    stack->data = (elemtype *) kmalloc(30 * 32);
    if (stack->data == NULL) {
        panic("stack_init : there is no free space\n");
    }
    stack->top = -1;
}

void stack_push(Stack_t *stack, elemtype item) {
    if (stack_is_full(stack)) {
        panic("Stack Overflow!");
    }
    stack->data[++stack->top] = item;
}

elemtype stack_pop(Stack_t *stack) {
    if (stack_is_empty(stack)) {
        panic("Stack Underflow!");
    }
    return stack->data[stack->top--];
}

elemtype stack_peek(Stack_t *stack) {
    if (stack_is_empty(stack)) {
        panic("Stack is empty!");
    }
    return stack->data[stack->top];
}

int serialize_meminfo(char *buf, int size) {
    snprintf(buf, size, fmt,

             /* MemTotal */
             TOTAL_MEM / 1024,

             /* MemFree */
             get_free_mem() / 1024,

             /* MemAvailable */
             (TOTAL_MEM - get_free_mem()) / 1024,

             /* Buffers */
             BUFFER / 1024,

             /* Cached */
             CACHED / 1024,

             /* SwapCached */
             TOTAL_SWAP / 1024,

             /* SwapTotal */
             TOTAL_SWAP / 1024,

             /* SwapFree */
             TOTAL_SWAP / 1024,

             /* Shmem and Slab */
             0, 0);

    return strlen(buf) + 1;
}

