size_t get_pid_from_path(const char *path) {
    size_t pid = 0;
    if (path == NULL) {
        return -1;
    }
    if (strlen(path) < 6) {
        return -1;
    }
    if (strncmp(path, "/proc/", 6) != 0) {
        return -1;
    }
    if (strncmp(path + 6, "self", 4) == 0) {
        return proc_current()->pid;
    }
    const char *p = path + 6;
    while (*p != '\0' && *p != '/') {
        if (*p < '0' || *p > '9') {
            return -1;
        }
        pid = pid * 10 + (*p - '0');
        p++;
    }
    return pid;
}

const char *get_op_from_path(const char *path) {
    if (path == NULL) {
        return NULL;
    }
    if (strlen(path) < 6) {
        return NULL;
    }
    if (strncmp(path, "/proc/", 6) != 0) {
        return NULL;
    }
    if (strncmp(path + 6, "self", 4) == 0) {
        if (*(path + 10) == '\0') {
            return NULL;
        }
        if (*(path + 10) == '/') {
            return path + 11;
        }
        return NULL;
    }
    const char *p = path + 6;
    while (*p != '\0' && *p != '/') {
        p++;
    }
    if (*p == '\0') {
        return NULL;
    }
    if (*(p + 1) == '\0') {
        return NULL;
    }
    return p + 1;
}

int procfs_proc_read(pid_t pid, const char *op, const uint64 addr, int n) {
    if (!strcmp(op, "oom_score_adj")) {
        return serialize_proc_oom_score_adj(pid, addr, n);
    } else if (!strcmp(op, "stat")) {
        return serialize_proc_stat(pid, addr, n);
    } else if (!strcmp(op, "smaps")) {
        return serialize_proc_smaps(pid, addr, n);
    } else {
        return -1;
    }
}

int procfs_proc_write(pid_t pid, const char *op, const uint64 addr, int n) {
    printf("procfs_proc_write: %s\n", op);
    if (!strcmp(op, "oom_score_adj")) {
        return write_into_oom_score_adj(pid, addr, n);
    } else {
        return -1;
    }
}

int procfs_proc_fstat(pid_t pid, const char *op, struct kstat *st) {
    if (!strcmp(op, "oom_score_adj")) {
        /* root user can write */
        st->st_mode = EXT4_INODE_MODE_FILE | 0x0644;
        st->st_nlink = 1;
        st->st_size = 4;
        return 0;
    } else {
        return -1;
    }
}

