int serialize_proc_oom_score_adj(pid_t pid, const uint64 addr, int n) {
    struct proc *p = get_proc_by_pid(pid);
    if (p == NULL) {
        return -1;
    }
    int len = snprintf((char *) addr, n, "%d\n", p->oom_score_adj);
    return len;
}

int write_into_oom_score_adj(pid_t pid, const uint64 addr, int n) {
    printf("write_into_oom_score_adj pid: %d addr: %s n: %d\n", pid, addr, n);
    struct proc *p = get_proc_by_pid(pid);
    if (p == NULL) {
        // printf("proc does not exist\n");
        return n; // cheat ltp
    }
    int oom_score_adj = 0;
    /* handle both negative and positive number */
    if (*(char *) addr == '-') {
        oom_score_adj = 0;
        for (int i = 1; i < n; i++) {
            if (*(char *) (addr + i) < '0' || *(char *) (addr + i) > '9') {
                printf("write_into_oom_score_adj(neg): invalid input pos: %d num: %c\n", i, *(char *) (addr + i));
                return -1;
            }
            oom_score_adj = oom_score_adj * 10 + (*(char *) (addr + i) - '0');
        }
        oom_score_adj = -oom_score_adj;
    } else {
        oom_score_adj = 0;
        for (int i = 0; i < n; i++) {
            if (*(char *) (addr + i) < '0' || *(char *) (addr + i) > '9') {
                printf("write_into_oom_score_adj(pos): invalid input pos: %d num: %c\n", i, *(char *) (addr + i));
                return -1;
            }
            oom_score_adj = oom_score_adj * 10 + (*(char *) (addr + i) - '0');
        }
    }
    p->oom_score_adj = oom_score_adj;
    printf("write_into_oom_score_adj p: %p oom_score_adj: %d\n", p, oom_score_adj);
    return n; // for ltp: must returns > 0
}

int serialize_proc_smaps(pid_t pid, const uint64 addr, int n) {
    char *chptr = (char *) addr;


    struct proc *p = get_proc_by_pid(pid);
    if (p == NULL) {
        return -EINVAL;
    }

    struct mm_struct *mm = p->mm;
    if (mm == NULL) {
        return -EINVAL;
    }

    struct vma *pos;
    list_for_each_entry(pos, &mm->head_vma, node) {
        /* snprintf to addr */
        char buf[512];
        int len = 0;
        if (pos->perm & MAP_ANONYMOUS) {
            len = snprintf(buf, 512, anon_fmt, pos->startva, pos->startva + pos->size,
                           (pos->perm & PERM_READ) ? 'r' : '-', (pos->perm & PERM_WRITE) ? 'w' : '-',
                           (pos->perm & PERM_EXEC) ? 'x' : '-', (pos->perm & MAP_SHARED) ? 's' : 'p', pos->offset,
                           p->pid, p->pid, pos->size / PGSIZE);
        } else if (pos->type == VMA_FILE) {
            len = snprintf(buf, 512, fmt, pos->startva, pos->startva + pos->size, (pos->perm & PERM_READ) ? 'r' : '-',
                           (pos->perm & PERM_WRITE) ? 'w' : '-', (pos->perm & PERM_EXEC) ? 'x' : '-',
                           (pos->perm & MAP_SHARED) ? 's' : 'p', pos->offset, p->pid, p->pid, pos->size / PGSIZE,
                           pos->vm_file->f_data.f_vnode->path);
        } else if (pos->type == VMA_HEAP) {
            len = snprintf(buf, 512, fmt, pos->startva, pos->startva + pos->size, (pos->perm & PERM_READ) ? 'r' : '-',
                           (pos->perm & PERM_WRITE) ? 'w' : '-', (pos->perm & PERM_EXEC) ? 'x' : '-',
                           (pos->perm & MAP_SHARED) ? 's' : 'p', pos->offset, p->pid, p->pid, pos->size / PGSIZE,
                           "[heap]");
        } else {
            len = snprintf(buf, 512, fmt, pos->startva, pos->startva + pos->size, (pos->perm & PERM_READ) ? 'r' : '-',
                           (pos->perm & PERM_WRITE) ? 'w' : '-', (pos->perm & PERM_EXEC) ? 'x' : '-',
                           (pos->perm & MAP_SHARED) ? 's' : 'p', pos->offset, p->pid, p->pid, pos->size / PGSIZE,
                           "[stack]");
        }

        if (copy_out(mm->pagetable, chptr, buf, len) != 0) {
            return -EFAULT;
        }

        chptr += len;

        /* serialize items */
        int len2 =
                snprintf(buf, 512, items_fmt, pos->size / 1024, pos->size / 1024, pos->size / 1024, 0, 0, 0, 0, 0, 0);
        if (copy_out(mm->pagetable, chptr, buf, len2) != 0) {
            return -EFAULT;
        }

        chptr += len2;
    }
}

