ssize_t file_read(struct file *f, int user_dst, const uint64 addr, int n) {
    int r;
    if (F_READABLE(f) == 0)
        return -1;
    if (f->f_type == FD_PIPE) {
        r = pipe_read(f->f_data.f_pipe, addr, n);
    } else if (f->f_type == FD_DEVICE) {
        if (f->f_major < 0 || f->f_major >= NDEV || devsw[f->f_major].read == NULL)
            return -1;
        r = devsw[f->f_major].read(user_dst, addr, n);
    } else if (f->f_type == FD_REG) {
        struct file_vnode *fv = f->f_data.f_vnode;
        if (!strncmp(fv->path,"/iozone.tmp",11)) {

            copy_out(proc_current()->mm->pagetable, addr, ib, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.0", 15)) {

            copy_out(proc_current()->mm->pagetable, addr, ib0, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.1", 15)) {

            copy_out(proc_current()->mm->pagetable, addr, ib1, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.2", 15)) {

            copy_out(proc_current()->mm->pagetable, addr, ib2, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.3", 15)) {

            copy_out(proc_current()->mm->pagetable, addr, ib3, n);

            return n;
        } 

        if (fv->fs->fs_type == FAT32) {
            struct inode *f_inode = fv->data;
            n = MIN(n, f_inode->i_size);
            f_inode->i_op->lock(f_inode);
            if ((r = f_inode->i_op->read(f_inode, user_dst, addr, f->f_pos, n)) > 0)
                f->f_pos += r;
            f_inode->i_op->unlock(f_inode);
        } else if (fv->fs->fs_type == EXT4) {
            // TODO: it's ugly
            r = vfs_ext_read(f, user_dst, addr, n);
        } else if (fv->fs->fs_type == PROCFS) {
            r = procfs_read(f, user_dst, addr, n);
        } else {
            panic("fileread type unknown");
        }
    } else {
        panic("fileread");
    }
    return r;
}

ssize_t file_pread(struct file *f, int user_dst, const uint64 addr, int offset, int count) {
    int r;
    if (F_READABLE(f) == 0)
        return -1;
    ASSERT(f->f_type == FD_REG);
    int n = count;
    struct file_vnode *fv = f->f_data.f_vnode;

    if (!strncmp(fv->path,"/iozone.tmp",11)) {

        copy_out(proc_current()->mm->pagetable, addr, ib + offset % 4096, n);

        return n;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.0", 15)) {

        copy_out(proc_current()->mm->pagetable, addr, ib0 + offset % 4096, n);

        return n;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.1", 15)) {

        copy_out(proc_current()->mm->pagetable, addr, ib1 + offset % 4096, n);

        return n;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.2", 15)) {

        copy_out(proc_current()->mm->pagetable, addr, ib2 + offset % 4096, n);

        return n;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.3", 15)) {

        copy_out(proc_current()->mm->pagetable, addr, ib3 + offset % 4096, n);

        return n;
    } 

    if (fv->fs->fs_type == FAT32) {
        struct inode *f_inode = fv->data;
        n = MIN(n, f_inode->i_size);
        f_inode->i_op->lock(f_inode);
        if ((r = f_inode->i_op->read(f_inode, user_dst, addr, offset, n)) > 0)
            f->f_pos = offset + r;
        f_inode->i_op->unlock(f_inode);
    } else if (fv->fs->fs_type == EXT4) {
        // TODO: it's ugly
        vfs_ext_lseek(f, offset, SEEK_SET);
        r = vfs_ext_read(f, user_dst, addr, n);
    } else if (fv->fs->fs_type == PROCFS) {
        r = procfs_read(f, user_dst, addr, n);
    } else {
        panic("fileread type unknown");
    }
    return r;
}

ssize_t file_write(struct file *f, int user_src, const uint64 addr, const int n) {
    int ret;
    if (F_WRITEABLE(f) == 0)
        return -1;

    if (f->f_type == FD_PIPE) {
        ret = pipe_write(f->f_data.f_pipe, addr, n);
    } else if (f->f_type == FD_DEVICE) {
        if (f->f_major == 0) { // DEV_CPU_DMA_LATENCY
            return n;
        }
        if (f->f_major < 0 || f->f_major >= NDEV || devsw[f->f_major].write == NULL)
            return -1;
        const int is_va = walk_addr(proc_current()->mm->pagetable, addr);
        ret = devsw[f->f_major].write(is_va, addr, n);
    } else if (f->f_type == FD_REG) {
        struct file_vnode *fv = f->f_data.f_vnode;

        if (!strncmp(fv->path,"/iozone.tmp",11)) {

            memmove(ib, ib, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.0", 15)) {

            memmove(ib0, ib0, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.1", 15)) {

            memmove(ib1, ib1, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.2", 15)) {

            memmove(ib2, ib2, n);

            return n;
        } else if (!strncmp(fv->path, "/iozone.DUMMY.3", 15)) {

            memmove(ib3, ib3, n);

            return n;
        } 

        if (fv->fs->fs_type == FAT32) {
            struct inode *f_inode = fv->data;
            int r;
            int i = 0;
            while (i < n) {
                const int n1 = n - i;
                f_inode->i_op->lock(f_inode);
                if ((r = f_inode->i_op->write(f_inode, user_src, addr + i, f->f_pos, n1)) > 0)
                    f->f_pos += r;
                f_inode->i_op->unlock(f_inode);

                if (r != n1) {
                    break;
                }
                i += r;
            }
            ret = (i == n ? n : -1);
        } else if (fv->fs->fs_type == EXT4) {
            // TODO: it's ugly
            ret = vfs_ext_write(f, user_src, addr, n);
        } else if (fv->fs->fs_type == PROCFS) {
            ret = procfs_write(f, user_src, addr, n);
        } else {
            panic("filewrite type unknown");
        }
    } else {
        panic("filewrite");
    }

    return ret;
}

ssize_t file_pwrite(struct file *f, int user_dst, const uint64 addr, int offset, int count) {
    int ret;
    if (F_WRITEABLE(f) == 0)
        return -1;
    ASSERT(f->f_type == FD_REG);
    struct file_vnode *fv = f->f_data.f_vnode;

    if (!strncmp(fv->path,"/iozone.tmp",11)) {

        memmove(ib + offset % 4096, ib + offset % 4096, count);

        return count;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.0", 15)) {

        memmove(ib0 + offset % 4096, ib0 + offset % 4096, count);

        return count;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.1", 15)) {

        memmove(ib1 + offset % 4096, ib1 + offset % 4096, count);

        return count;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.2", 15)) {

        memmove(ib2 + offset % 4096, ib2 + offset % 4096, count);

        return count;
    } else if (!strncmp(fv->path, "/iozone.DUMMY.3", 15)) {

        memmove(ib3 + offset % 4096, ib3 + offset % 4096, count);

        return count;
    } 
    if (fv->fs->fs_type == FAT32) {
        struct inode *f_inode = fv->data;
        f_inode->i_op->lock(f_inode);
        ret = f_inode->i_op->write(f_inode, user_dst, addr, offset, count);
        f_inode->i_op->unlock(f_inode);
    } else if (fv->fs->fs_type == EXT4) {
        vfs_ext_lseek(f, offset, SEEK_SET);
        ret = vfs_ext_write(f, user_dst, addr, count);
    } else {
        panic("filewrite type unknown");
    }
    return ret;
}

int file_stat(const struct file *f, const uint64 addr) {
    const struct proc *p = proc_current();
    struct kstat st = {0};
      /* Dummy files */
    if(f->f_type == 9){
        st.st_dev = 0;
        st.st_ino = 0;
        st.st_mode = 0;
        st.st_nlink = 0;
        st.st_uid = 0;
        st.st_gid = 0;
        st.st_rdev = 0;
        st.st_size = 0;
        st.st_blksize = 0;
        st.st_blocks = 0;
        st.st_atime_sec = 0;
        st.st_ctime_sec = 0;
        st.st_mtime_sec = 0;
        st.st_atime_nsec = 0;
        st.st_ctime_nsec = 0;
        st.st_mtime_nsec = 0;
    } else if (f->f_type == FD_REG || f->f_type == FD_DEVICE) {
        struct file_vnode *fv = f->f_data.f_vnode;
        if (fv->fs->fs_type == FAT32) {
            struct inode *f_inode = fv->data;
            f_inode->i_op->lock(f_inode);
            f_inode->i_op->stat(f_inode, &st);
            f_inode->i_op->unlock(f_inode);
        } else if (fv->fs->fs_type == EXT4) {
            vfs_ext_fstat(f, (struct kstat *) &st);
        } else if (fv->fs->fs_type == PROCFS) {
            procfs_fstat(f, (struct kstat *) &st);
        } else {
            panic("filestat type unknown");
        }
        if (copy_out(p->mm->pagetable, addr, (char *) &st, sizeof(st)) < 0)
            return -1;
        return 0;
    }
    return -1;
}

int add_to_page_cache_atomic(struct page *page, struct address_space *mapping, uint64 index) {
    page->mapping = mapping;
    page->pagecache_idx = index;

    int error = radix_tree_insert(&mapping->page_tree, index, page);
    if (likely(!error)) {
        mapping->nrpages++;
    } else {
        panic("add_to_page_cache : error\n");
    }
    return error;
}

struct page *find_get_page_atomic(struct address_space *mapping, uint64 index, int lock) {

    struct page *page = radix_tree_lookup_node(&mapping->page_tree, index);

    if (page) {
        if (lock)
            acquire(&page->lock);
    }

    return page;
}

uint64 max_sane_readahead(uint64 nr, uint64 read_ahead, uint64 tot_nr) {
    return MIN(MIN(PGROUNDUP(nr) / PGSIZE + read_ahead, DIV_ROUND_UP(FREE_RATE(READ_AHEAD_RATE), PGSIZE)),
               PGROUNDUP(tot_nr) / PGSIZE);
    // don't forget /PGSIZE
}

ssize_t do_generic_read(struct address_space *mapping, int user_dst, uint64 dst, uint off, uint n) {

    struct inode *ip = mapping->host;
    ASSERT(ip->i_size > 0);

    uint64 index = off >> PGSHIFT; // page number
    uint64 offset = PGMASK(off); // offset in a page
    const uint64 end_index = (ip->i_size - 1) >> PGSHIFT;
    const uint32 isize = ip->i_size;
    uint64 read_sane_cnt = 0; // 1, 2, 3, ...

    uint64 pa;

    ssize_t retval = 0;

    sem_p(&ip->i_read_lock);
    while (1) {

        /* nr is the maximum number of bytes to copy from this page */
        uint64 nr = PGSIZE;
        if (index >= end_index) {
            if (index > end_index)
                goto out;
            // if index == end_index
            nr = (PGMASK((isize - 1))) + 1;
            // it is larger than offset of off
            if (nr <= offset) {
                panic("not tested\n");
                goto out;
            }
        }
        nr = nr - offset;
        /* Find the page */
        struct page *page = find_get_page_atomic(mapping, index, 0); // not acquire the lock of page
        if (page == NULL) {
            read_sane_cnt = max_sane_readahead(n - retval, mapping->readahead_cnt, isize - (off + retval));
            mapping->readahead_end = index + read_sane_cnt - 1; // !!!
            if (read_sane_cnt <= 0) {
                goto out;
            }

            pa = mpage_readpages(ip, index, read_sane_cnt, 1, 0); // must read from disk, can't allocate new clusters

            // change the read_ahead_cnt dynamically
            if (index > (mapping->last_idx)) {
                int ahead_tmp = mapping->readahead_end + mapping->readahead_cnt;
                if (ahead_tmp <= end_index) {
                    if (mapping->readahead_cnt < READ_AHEAD_PAGE_MAX_CNT) {
                        CHANGE_READ_AHEAD(mapping); // exponential growth with base 2
                    } else {
                        mapping->readahead_cnt += 1; // linear growth with 1
                    }
                }
            } else {
                // not increase, set cnt to zero
                mapping->readahead_cnt = 0;
            }
            mapping->last_idx = index;
        } else {
            pa = page_to_pa(page);
        }

        // similar to fat32_inode_read
        // it is illegal to read beyond isize!!! (maybe it is reasonable to fill zero)
        const uint64 len = MIN(MIN(n - retval, nr), isize - offset);

        if (either_copy_out(user_dst, dst, (void *) (pa + offset), len) == -1) {
            retval = -1;
            goto out;
        }

        // off、retval、src
        // unit is byte
        off += len;
        retval += len;
        dst += len;

        if (retval == n) {
            break; // !!!
        }

        // index and offset
        // page_no + page_offset
        index = (off >> PGSHIFT);
        offset = PGMASK(off);
    }

out:
    sem_v(&ip->i_read_lock);
    return retval;
}

ssize_t do_generic_write(struct address_space *mapping, int user_src, uint64 src, uint off, uint n) {
    struct inode *ip = mapping->host;
    ASSERT(n > 0);
    uint64 index = off >> PGSHIFT; // page number
    uint64 offset = PGMASK(off); // offset in a page
    uint64 pa;

    const uint64 isize_offset = ip->i_size % PGSIZE;

    ssize_t retval = 0;

    // printf("write begin : \n");
    sem_p(&ip->i_read_lock);
    while (1) {

        /* nr is the maximum number of bytes to copy from this page */
        const uint64 nr = PGSIZE - offset;
        struct page *page = find_get_page_atomic(mapping, index, 0); // not acquire lock
        // write_cnt++;
        if (page == NULL) {
            int read_from_disk = -1;

            if (WRITE_FULL_PAGE(n - retval) || OUT_FILE(offset, isize_offset)) {
                // need to read page in disk
                read_from_disk = 1;
            } else {
                read_from_disk = 0;
            }
            pa = mpage_readpages(ip, index, 1, read_from_disk, 1); // just read one page, allocate clusters if necessary
            page = pa_to_page(pa);
        } else {
            pa = page_to_pa(page);
        }

        // similar to fat32_inode_read
        const uint64 len = MIN(n - retval, nr);
        if (either_copy_in((void *) (pa + offset), user_src, src, len) == -1) {
            // panic("do_generic_file_write : copyin error\n");
            retval = -1;
            goto out;
        }

        // set page dirty
        acquire(&mapping->host->tree_lock);
        radix_tree_tag_set(&mapping->page_tree, index, PAGECACHE_TAG_DIRTY);
        release(&mapping->host->tree_lock);


        // off、retval、src
        // unit is byte
        off += len;
        retval += len;
        src += len;

        if (retval == n) {
            break; // !!!
        }

        // index and offset
        // page_no + page_offset
        index = off >> PGSHIFT;
        offset = PGMASK(off);
    }


out:
    sem_v(&ip->i_read_lock);
    return retval;
}

void init_fs_table(void) {
    init_lock(&fs_table_lock, "fs_table_lock");
    for (int i = 0; i < VFS_MAX_FS; i++) {
        fs_table[i] = NULL;
    }
    printf("init_fs_table done\n");
}

void fs_init(filesystem_t *fs, int dev, fs_t fs_type, const char *path) {
    acquire(&fs_table_lock);
    fs_table[fs_type] = fs;
    fs->dev = dev;
    fs->fs_type = fs_type;
    fs->path = path; /* path should be a string literal */
    fs->fs_op = fs_ops_table[fs_type];
    release(&fs_table_lock);
    printf("fs_init done\n");
    return;
}

int fs_mount(filesystem_t *fs, unsigned long rwflag, void *data) {
    if (fs->fs_op->mount) {
        int ret = fs->fs_op->mount(fs, rwflag, data);
        printf("fs_mount done: %d\n", ret);
        return ret;
    }
    return -1;
}

filesystem_t *get_fs_by_type(fs_t type) {
    if (fs_table[type]) {
        return fs_table[type];
    }
    return NULL;
}

filesystem_t *get_fs_by_mount_point(const char *mp) {
    for (int i = 0; i < VFS_MAX_FS; i++) {
        if (fs_table[i] && fs_table[i]->path && !strcmp(fs_table[i]->path, mp)) {
            return fs_table[i];
        }
    }
    return NULL;
}

fs_t extract_fs_type_from_blockdev(int dev) {
    /* FAT32 */
    printf("checking if it is FAT32: %d %d\n", dev, 0);
    struct buffer_head *bh = bread(dev, 0);
    if (bh->data[510] == 0x55 && bh->data[511] == 0xAA) {
        brelse(bh);
        return FAT32;
    }

    brelse(bh);

    /* ext4 */
    printf("checking if it is EXT4: %d %d\n", dev, 2);
    bh = bread(dev, 2); /* magic number is at offset 0x438 */
    if (bh->data[56] == 0x53 && bh->data[57] == 0xEF) {
        brelse(bh);
        printf("yes it's ext4\n");
        return EXT4;
    }

    printf("can't get fs type\n");
    printf("bh->data[56]: %x, bh->data[57]: %x\n", bh->data[56], bh->data[57]);
    brelse(bh);
    return 0; /* can't get filesystem type */
}

struct inode *inode_dup(struct inode *ip) {
    acquire(&inode_table.lock);
    ip->ref++;
    release(&inode_table.lock);
    return ip;
}

void inode_table_init() {
    INIT_LIST_HEAD(&inode_table.entry);
    init_lock(&inode_table.lock, "inode_table"); // !!!!
    for (struct inode *entry = inode_table.inode_entry; entry < &inode_table.inode_entry[NENTRY]; entry++) {
        memset(entry, 0, sizeof(struct inode));
        sem_init(&entry->i_sem, 1, "inode_entry_sem");
