static uint64 __i_hash_key(void *inode_name) {
    const uint64 inode_name_len = strlen(inode_name);
    return full_name_hash(inode_name, inode_name_len);
}

static void *__i_hash_lookup(struct hash_table *table, void *key, int release, int holding) {
    const uint64 key_hash = __i_hash_key(key);
    const struct hash_entry *entry = hash_get_entry(table, key, holding);
    if (entry == NULL) {
        if (release) {
            release(&table->lock);
        }
        return NULL;
    }
    struct inode *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, i_hash_node) {
        if (__i_hash_key(pos->fat32_i.fname) == key_hash) {
            if (release) {
                release(&table->lock);
            }
            return pos;
        }
    }
    if (release) {
        release(&table->lock);
    }
    return NULL;
}

static void *get_inode_name(struct inode *i) {
    // TODO: Implement for other file system
    // Too ugly here, it should have been OO.
    void *inode_name;
    switch (i->fs_type) {
        case FAT32:
            inode_name = i->fat32_i.fname;
            break;
        default:
            inode_name = NULL;
            break;
    }
    return inode_name;
}

static int __i_hash_insert(struct hash_table *table, void *inode, int holding) {
    struct inode *i = inode;
    void *inode_name = get_inode_name(i);
    const struct inode *i_old = __i_hash_lookup(table, inode_name, 0, holding); // no release
    if (i_old != NULL) {
        // same inode name exists
        release(&table->lock);
        return -1;
    }
    // here we can be sure that we're holding the lock
    struct hash_entry *entry = hash_get_entry(table, inode_name, 1);
    INIT_LIST_HEAD(&i->i_hash_node);
    list_add_tail(&i->i_hash_node, &entry->list);
    release(&table->lock);
    return 0;
}

static void __i_hash_delete(struct hash_table *table, void *inode, int holding, int release) {
    struct inode *i = (struct inode *) inode;
    void *inode_name = get_inode_name(i);
    const struct hash_entry *entry = hash_get_entry(table, inode_name, holding);
    if (entry == NULL) {
        if (release) {
            release(&table->lock);
        }
        return;
    }
    struct inode *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, i_hash_node) {
        if (pos == i) {
            list_del(&pos->i_hash_node);
            if (release) {
                release(&table->lock);
            }
            return;
        }
    }
    if (release) {
        release(&table->lock);
    }
    return;
}

void inode_hash_table_init(struct inode *dp) {
    dp->i_hash_table = (struct hash_table *) kmalloc(sizeof(struct hash_table));
    dp->i_hash_table->size = INODE_HASH_SIZE;
    dp->i_hash_table->op = &inode_hash_table_op;
    init_lock(&dp->i_hash_table->lock, "inode hash table lock");
    hash_table_entry_init(dp->i_hash_table);
}

void inode_hash_table_destroy(struct inode *dp) {
    if (dp->i_hash_table == NULL) {
        return;
    }
    for (int i = 0; i < dp->i_hash_table->size; i++) {
        struct hash_entry *entry = &dp->i_hash_table->hash_head[i];
        // delete the whole list
        list_del(&entry->list);
    }

    kfree(dp->i_hash_table->hash_head);
    kfree(dp->i_hash_table);
}

int sync_inode(struct inode *ip) {
    acquire(&ip->i_lock);
    if (ip->i_writeback) {
        release(&ip->i_lock);
        return -1;
    }
    ip->i_writeback = 1;
    release(&ip->i_lock);

    // page write back (all)
    mpage_writepage(ip, 1); // allocate if necessary

    // update fcb in parent
    if (ip->dirty_in_parent) {
        fat32_inode_update(ip);
    }

    return 0;
}

void writeback_inodes(uint64 nr_to_write) {
    // nr_to_write is not important
    struct inode *ip_cur = NULL;
    struct inode *ip_tmp = NULL;

    acquire(&fat32_sb.dirty_lock);
    list_for_each_entry_safe(ip_cur, ip_tmp, &fat32_sb.s_dirty_inodes, dirty_list) {
        release(&fat32_sb.dirty_lock);

        sem_p(&ip_cur->i_sem); // important ??? maybe
        int ret = sync_inode(ip_cur);
        sem_v(&ip_cur->i_sem);

        acquire(&fat32_sb.dirty_lock);
        if (ret == 0) {
            list_del_reinit(&ip_cur->dirty_list);
            ip_cur->i_writeback = 0;
        }
    }
    release(&fat32_sb.dirty_lock);
}

void block_full_pages(struct inode *ip, struct bio *bio_p, uint64 src, uint64 index, uint64 cnt, int alloc) {
    // fill the bio using fat32_get_block
    const uint32 off = index * PGSIZE;
    const uint32 n = cnt * PGSIZE;
    const uint32 bsize = ip->i_sb->sector_size;

    // pay attention to alloc!!!
    const int blocks_n = ip->i_op->get_block(ip, bio_p, off, n, alloc);
    if (alloc == 1) // it is ok, if only read
        ASSERT(blocks_n * bsize == n);

    // copy bio_vec into dst
    struct bio_vec *vec_cur = NULL;
    list_for_each_entry(vec_cur, &bio_p->list_entry, list) {
        vec_cur->data = (uchar *) src;
        src += vec_cur->block_len * bsize;
    }
}

void rw_pages(struct inode *ip, uint64 src, uint64 index, int rw, uint64 cnt, int alloc) {
    struct bio bio_cur;

    // init bio
    INIT_LIST_HEAD(&bio_cur.list_entry);
    bio_cur.bi_rw = rw;
    bio_cur.bi_bdev = ip->i_dev;

    // fill bio with bio_vec
    block_full_pages(ip, &bio_cur, src, index, cnt, alloc);

    // submit bio
    if (!list_empty(&bio_cur.list_entry)) {
        submit_bio(&bio_cur, 1); // free bio_vec of bio
    }
}

void rw_pages_batch(struct inode *ip, struct page_entry *p_entry, int rw, int alloc) {
    struct page_item *p_cur_out = NULL;
    int batch_size = 1;

    // out : we don't use list_for_each_entry_safe in order to change p_cur_out in inner
    list_for_each_entry(p_cur_out, &p_entry->entry, list) {
        struct page_item *p_cur_in = NULL;
        struct page_item *p_nxt_in = NULL;

        struct page_item *p_tmp_head_in = p_cur_out; // !!!
        batch_size = 1;
        // inner :
        list_for_each_entry_safe_condition(p_cur_in, p_nxt_in, &p_tmp_head_in->list, list,
                                           &p_cur_in->list != &p_entry->entry) {
            if (PAGE_ADJACENT(p_cur_out, p_cur_in)) {
                p_cur_out = p_cur_in; // !!!!!!!!!
                batch_size++;
            } else {
                break;
            }
        }
        rw_pages(ip, p_tmp_head_in->pa, p_tmp_head_in->index, rw, batch_size,
                 alloc); // don't write batch_size as batch_size * PGSIZE
    }

    // must remember to free page list
    page_list_free(p_entry);
}

void page_list_free(struct page_entry *p_entry) {
    struct page_item *p_cur = NULL;
    struct page_item *p_tmp = NULL;
    list_for_each_entry_safe(p_cur, p_tmp, &p_entry->entry, list) { kfree(p_cur); }
}

uint64 mpage_readpages(struct inode *ip, uint64 index, uint64 cnt, int read_from_disk, int alloc) {
    struct page_entry p_entry;
    struct address_space *mapping = ip->i_mapping;
    ASSERT(cnt > 0);
    INIT_LIST_HEAD(&p_entry.entry); // !!!
    p_entry.n_pages = 0; // !!!!!! bug

    // the process below may be some complex
    // [start_idx, end_idx) is valid
    // we use two pointer to filter valid interval
    uint64 first_pa = 0;
    uint64 pa = 0;
    for (uint64 start_idx = 0; start_idx < cnt;) {
        if (!find_get_page_atomic(mapping, index + start_idx, 0)) {
            // not find it, not holding lock
            uint64 end_idx = start_idx + 1;
            while (end_idx < cnt) {
                if (find_get_page_atomic(mapping, index + end_idx, 0)) {
                    // find it, not holding lock
                    break;
                }
                end_idx++;
            }

            // allocpages:
            if ((pa = (uint64) kzalloc(PGSIZE * (end_idx - start_idx))) == 0) {
                printfRed("end_idx : %d, start_idx : %d\n", end_idx, start_idx);
                panic("mpage_readpages, pa, : no enough memory\n");
            }

            if (first_pa == 0) {
                first_pa = pa; // !!!
            }

            struct page_item *p_item = NULL;
            for (int z = start_idx; z < end_idx; z++) {
                uint64 pa_tmp = pa + (z - start_idx) * PGSIZE;
                uint64 index_tmp = index + z;
                struct page *page = pa_to_page(pa_tmp);
                add_to_page_cache_atomic(page, mapping, index_tmp); // don't forget it

                if (cnt == 1 && read_from_disk == 0) {
                    return first_pa; // !!!
                }

                // page list item :
                if ((p_item = (struct page_item *) kzalloc(sizeof(struct page_item))) == NULL) {
                    panic("mpage_readpages, p_item, : no enough memory\n");
                }
                // printfMAGENTA("mpage_readpages: page_item alloc, mm-- : %d pages\n", get_free_mem() / 4096);
                p_item->index = index_tmp; // !!!
                p_item->pa = pa_tmp; // !!!

                INIT_LIST_HEAD(&p_item->list);

                // join p_item into p_entry
                list_add_tail(&p_item->list, &p_entry.entry);
                p_entry.n_pages++;
            }

            start_idx = end_idx + 1;
        } else {
            if (start_idx == 0) {
                panic("mpage_readpages ,start idx : error\n");
            }
            start_idx++;
        }
    }

    if (read_from_disk)
        // read pages using page list
        rw_pages_batch(ip, &p_entry, DISK_READ, alloc);

    return first_pa;
}

void mpage_writepage(struct inode *ip, int alloc) {
    struct address_space *mapping = ip->i_mapping;
    acquire(&ip->tree_lock);
    if (mapping == NULL) {
        panic("mapping is NULL\n");
    }
    if (mapping->page_tree.height == 0 && mapping->page_tree.rnode == NULL) {
        release(&ip->tree_lock);
        return;
    }

    struct page_entry p_entry;
    INIT_LIST_HEAD(&p_entry.entry); // !!!
    p_entry.n_pages = 0; // !!! bug

    int ret = radix_tree_general_gang_lookup_elements(&(mapping->page_tree), &p_entry, page_list_add, 0,
                                                      maxitems_invald, PAGECACHE_TAG_DIRTY);
    ASSERT(ret > 0);
    if (mapping->page_tree.height == 0 && ret != 1) {
        panic("mpage_writepage : error\n");
    }
    release(&ip->tree_lock);

    // write pages using page list
    rw_pages_batch(ip, &p_entry, DISK_WRITE, alloc);
}

void page_list_add(void *entry, void *item, uint64 index, void *node) {
    struct page_entry *p_entry = (struct page_entry *) entry;
    struct page_item *p_item = NULL;
    if ((p_item = (struct page_item *) kzalloc(sizeof(struct page_item))) == NULL) {
        panic("mpage_readpages, page_list_add, : no enough memory\n");
    }

    // printfMAGENTA("page_list_add(page cache write back), mm ++: %d pages\n", get_free_mem() / 4096);

    // p_item
    struct page *page = (struct page *) item;
    p_item->index = index;
    p_item->pa = page_to_pa(page);

    INIT_LIST_HEAD(&p_item->list);

    // join p_item into p_entry
    list_add_tail(&p_item->list, &p_entry->entry);
    // bug like this :     list_add_tail&p_entry->entry, &p_item->list);
    p_entry->n_pages++;
}

void file_init(void) {
    init_lock(&_ftable.lock, "_ftable");
    memset(_ftable.file, 0, sizeof(_ftable.file));    
}

struct file *file_dup(struct file *f) {
    acquire(&_ftable.lock);
    if (f->f_count < 1)
        panic("filedup");
    f->f_count++;
    release(&_ftable.lock);
    return f;
}

struct file *file_alloc(void) {
    acquire(&_ftable.lock);
    for (struct file *f = _ftable.file; f < _ftable.file + NFILE; f++) {
        if (f->f_count == 0) {
            f->f_count = 1;
            f->f_op = get_fileops[proc_current()->cwd.fs->fs_type]();
            release(&_ftable.lock);
            return f;
        }
    }
    release(&_ftable.lock);
    return 0;
}

int fd_alloc(struct file *f) {
    struct proc *p = proc_current();
    acquire(&p->tlock);
    for (int fd = 0; fd < p->max_ofile; fd++) {
        if (p->_ofile[fd] == 0) {
            p->_ofile[fd] = f;
            release(&p->tlock);
            return fd;
        }
    }
    release(&p->tlock);
    return -1;
}

void generic_fileclose(struct file *f) {
    struct file ff;

    acquire(&_ftable.lock);
    if (f->f_count < 1)
        panic("generic_fileclose");
    if (--f->f_count > 0) {
        release(&_ftable.lock);
        return;
    }
    ff = *f;
    f->f_count = 0;
    f->f_type = FD_NONE;
    release(&_ftable.lock);

    if (ff.f_type == FD_PIPE) {
        const int wrable = F_WRITEABLE(&ff);
        pipe_close(ff.f_data.f_pipe, wrable);
    } else if (ff.f_type == FD_REG || ff.f_type == FD_DEVICE) {
        struct file_vnode *fv = ff.f_data.f_vnode;
        if (fv->fs->fs_type == FAT32) {
            struct inode *f_inode = fv->data;
            f_inode->i_op->put(f_inode);
        } else if (fv->fs->fs_type == EXT4) {
            // TODO: it's ugly
            vfs_ext_fclose(&ff);
            if (ff.removed) {
                vfs_ext_rm(fv->path);
                ff.removed = 0;
            }
        } else if (fv->fs->fs_type == PROCFS) {
            procfs_fclose(&ff);
        }
        kfree(fv);
        ff.f_data.f_vnode = 0;
    }
}

struct inode *find_inode(char *path, int dirfd, char *name) {
    ASSERT(path);
    struct inode *ip;
    struct proc *p = proc_current();
    if (*path == '/' || dirfd == AT_FDCWD) {
        // 绝对路径 || 相对于当前路径，忽略 dirfd
        ip = name == NULL ? namei(path) : namei_parent(path, name);
        if (ip == 0) {
            return 0;
        }
        return ip;
    }
    // path为相对于 dirfd目录的路径
    struct file *f;
    if (dirfd < 0 || dirfd >= NOFILE || (f = p->_ofile[dirfd]) == 0) {
        return 0;
    }
    struct file_vnode oldcwd = p->cwd;
    p->cwd = *f->f_data.f_vnode;
    ip = name == NULL ? namei(path) : namei_parent(path, name);
    if (ip == 0) {
        return 0;
    }
    p->cwd = oldcwd;

    return ip;
}

static char *skepelem(char *path, char *name) {
    while (*path == '/' || *path == '.')
        path++;
    if (*path == 0)
        return 0;
    const char *s = path;
    while (*path != '/' && *path != 0)
        path++;
    const int len = path - s;
    if (len >= PATH_LONG_MAX)
        memmove(name, s, PATH_LONG_MAX);
    else {
        memmove(name, s, len);
        name[len] = 0;
    }
    while (*path == '/')
        path++;
    return path;
}

static struct inode *inode_namex(char *path, const int nameeparent, char *name) {
    struct inode *ip = NULL, *next = NULL, *cwd = proc_current()->cwd.data;
    // ASSERT(cwd);
    // TODO BUG: cwd may be NULL
    if (*path == '/') {
        ASSERT(cwd->i_sb);
        ASSERT(cwd->i_sb->root);
        struct inode *root_ip = cwd->i_sb->root;
        ip = root_ip->i_op->dup(root_ip);
    } else if (strncmp(path, "..", 2) == 0) {
        ip = cwd->parent->i_op->dup(cwd->parent);
    } else {
        ip = cwd->i_op->dup(cwd);
    }

    while ((path = skepelem(path, name)) != 0) {
        ip->i_op->lock(ip);
        if (!ip->i_op->dir(ip)) {
            ip->i_op->unlock_put(ip);
            return 0;
        }
        if (nameeparent && *path == '\0') {
            ip->i_op->unlock(ip);
            return ip;
        }

        if (strncmp(name, "..", 2) == 0) {
            next = ip->i_op->dup(ip->parent);
        } else if (strncmp(name, ".", 1) == 0) {
            next = ip->i_op->dup(ip);
        } else if ((next = ip->i_op->dirlookup(ip, name, 0)) == 0) {
            ip->i_op->unlock_put(ip);
            return 0;
        }
        ip->i_op->unlock_put(ip);
        ip = next;
    }

    if (nameeparent) {
        ip->i_op->put(ip);
        return 0;
    }

    if (ip->i_op == NULL) {
        ASSERT(cwd->fs_type == FAT32);
        ip->i_op = get_inodeops[cwd->fs_type]();
    }

    return ip;
}

void get_absolute_path(const char *path, const char *cwd, char *absolute_path) {
    if (path == NULL) {
        strncpy(absolute_path, cwd, strlen(cwd));
    } else if (path[0] == '/') {
        strcpy(absolute_path, path);
    } else {
        strcpy(absolute_path, cwd);
        strcat(absolute_path, "/");
        strcat(absolute_path, path);
    }
    // handle ./ and ../
    char *p = absolute_path;
    while (*p != '\0') {
        if (*p == '.' && *(p + 1) == '/') {
            strcpy(p, p + 2);
        } else if (*p == '.' && *(p + 1) == '.' && *(p + 2) == '/') {
            char *q = p - 2;
            while (q >= absolute_path && *q != '/') {
                q--;
            }
            if (q >= absolute_path) {
                strcpy(q + 1, p + 3);
                p = q;
            } else {
                strcpy(absolute_path, p + 3);
                p = absolute_path;
            }
        } else {
            p++;
        }
    }

    /* handle trailing . and .. */
    p = absolute_path + strlen(absolute_path) - 2;
    if ((*p == '/' || *p == '.') && *(p + 1) == '.' && *(p + 2) == '\0') {
        *p = *(p + 1) = *(p + 2) = '\0';
    }
    p--;
    if (*p == '/' && *(p + 1) == '.' && *(p + 2) == '.' && *(p + 3) == '\0') {
        if (p == absolute_path) {
            *(p + 1) = *(p + 2) = *(p + 3) = '\0';
            return;
        }
        char *q = p - 1;
        while (q >= absolute_path && *q != '/') {
            q--;
        }
        if (q >= absolute_path) {
            *q = '\0';
            p = q;
        } else {
            strcpy(absolute_path, p + 4);
            p = absolute_path;
        }
    }


    while (absolute_path[0] == '/' && absolute_path[1] == '/') {
        strcpy(absolute_path, absolute_path + 1);
    }
    size_t len = strlen(absolute_path);
    if (absolute_path[len - 1] == '/') {
        absolute_path[len - 1] = '\0';
        --len;
    }
    if (strlen(absolute_path) == 0) {
        strcpy(absolute_path, "/");
    } else if (absolute_path[0] != '/') {
        size_t len2 = strlen(absolute_path);
        char *x = absolute_path + len2;
        *(x + 1) = 0;
        while (x > absolute_path) {
            *x = *(x - 1);
            x--;
        }
        *x = '/';
    }
}

struct inode *namei(char *path) {
    fs_t fs_type = proc_current()->cwd.fs->fs_type;
    if (fs_type == FAT32) {
        char name[NAME_LONG_MAX];
        return inode_namex(path, 0, name);
    } else if (fs_type == EXT4) {
        char path_abs[PATH_LONG_MAX];
        get_absolute_path(path, proc_current()->cwd.path, path_abs);
        return vfs_ext_namei(path_abs);
    }
}

static uint64 __ipc_hash_key(void *node) {
    struct kern_ipc_perm *ipcp = (struct kern_ipc_perm *) node;
    return (uint64) ipcid_to_idx(ipcp->id);
}

static void *__ipc_hash_lookup(struct hash_table *table, void *node, int release, int holding) {
    const uint64 key_hash = __ipc_hash_key(node);
    const struct hash_entry *entry = hash_get_entry(table, node, holding);
    if (entry == NULL) {
        if (release) {
            release(&table->lock);
        }
        return NULL;
    }
    struct kern_ipc_perm *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, ipc_hash_node) {
        if (__ipc_hash_key(pos) == key_hash) {
            if (release) {
                release(&table->lock);
            }
            return pos;
        }
    }
    if (release) {
        release(&table->lock);
    }
    return NULL;
}

static int __ipc_hash_insert(struct hash_table *table, void *node, int holding) {
    struct kern_ipc_perm *ipcp = (struct kern_ipc_perm *) node;
    const struct kern_ipc_perm *ipcp_old = __ipc_hash_lookup(table, ipcp, 0, holding);
    if (ipcp_old != NULL) {
        release(&table->lock);
        return -1;
    }
    struct hash_entry *entry = hash_get_entry(table, ipcp, 1);
    if (entry == NULL) {
        if (!holding) {
            release(&table->lock);
        }
        return -1;
    }
    INIT_LIST_HEAD(&ipcp->ipc_hash_node);
    list_add_tail(&ipcp->ipc_hash_node, &entry->list);
    if (!holding) {
        release(&table->lock);
    }
    return 0;
}

static void ipc_hash_delete(struct hash_table *table, void *node, int holding, int release) {
    struct kern_ipc_perm *ipcp = (struct kern_ipc_perm *) node;
    struct hash_entry *entry = hash_get_entry(table, ipcp, holding);
    if (entry == NULL) {
        if (release) {
            release(&table->lock);
        }
        return;
    }
    struct kern_ipc_perm *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, ipc_hash_node) {
        if (__ipc_hash_key(pos) == __ipc_hash_key(ipcp)) {
            list_del(&pos->ipc_hash_node);
            if (release) {
                release(&table->lock);
            }
            return;
        }
    }
    if (release) {
        release(&table->lock);
    }
}

void ipc_init_ids(struct ipc_ids *ids) {
    ids->in_use = 0;
    ids->seq = 0;
    sem_init(&ids->rwsem, 1, "ipc_ids_rwsem");
    do {
        union {
            volatile typeof((0)) tmp;
            typeof(((&((ids)->next_ipc_id))->counter)) result;
        } u = {.tmp = ((0))};
        (((&((ids)->next_ipc_id))->counter)) = u.result;
    } while (0);
    int seq_limit = INT_MAX / SEQ_MULTIPLIER;
    if (seq_limit > USHORT_MAX)
        ids->seq_max = USHORT_MAX;
    else
        ids->seq_max = seq_limit;
    ids->key_ht = NULL;
}

void ipc_hashtable_init(struct ipc_ids *ids) {
    ids->key_ht = (struct hash_table *) kmalloc(sizeof(struct hash_table));
    if (ids->key_ht == NULL) {
        panic("hash table init : no free space\n");
    }
    init_lock(&ids->key_ht->lock, "ipc_key_hash_table");
    ids->key_ht->size = NIPCIDX;
    hash_table_entry_init(ids->key_ht);
    ids->key_ht->op = &ipc_hash_table_op;
}

int ipc_hash_insert(struct ipc_ids *ids, struct kern_ipc_perm *new) {
    return ids->key_ht->op->hash_insert(ids->key_ht, (void *) new, 0);
}

struct kern_ipc_perm *ipc_hash_lookup(struct ipc_ids *ids, int id) {
    const uint64 key_hash = id;
    struct hash_table *table = ids->key_ht;
    struct hash_entry *entry = &table->hash_head[key_hash % table->size];
    acquire(&table->lock);
    if (entry == NULL) {
        release(&table->lock);
        return NULL;
    }
    struct kern_ipc_perm *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, ipc_hash_node) {
        if (__ipc_hash_key(pos) == key_hash) {
            release(&table->lock);
            return pos;
        }
    }
    release(&table->lock);
    return NULL;
}

int ipc_addid(struct ipc_ids *ids, struct kern_ipc_perm *new, int size) {
    int idx = 0;
    int err;
    if (size > IPCMNI)
        size = IPCMNI;
    if (ids->in_use >= size)
        return -ENOSPC;
    init_lock(&new->lock, "ipc_perm_lock");
    new->deleted = 0;
    acquire(&new->lock);
    idx = alloc_ipc_id(ids);
    if (ids->key_ht == NULL) {
        ipc_hashtable_init(ids);
    }
    new->seq = ids->seq++;
    if (ids->seq > ids->seq_max)
        ids->seq = 0;
    new->id = ipc_buildid(idx, new->seq);
    err = ipc_hash_insert(ids, new);
    if (err) {
        release(&new->lock);
        return err;
    }
    ids->in_use++;
    return idx;
}

int ipcperms(struct kern_ipc_perm *ipcp, short flag) {
    /* flag will most probably be 0 or S_...UGO from <linux/stat.h> */
    /* is there some bit set in requested_mode but not in granted_mode? */
    return security_ipc_permission(ipcp, flag);
}

int ipc_check_perms(struct kern_ipc_perm *ipcp, struct ipc_ops *ops, struct ipc_params *params) {
    int err;
    if (ipcperms(ipcp, params->flg))
        err = -EACCES;
    else {
        err = ops->associate(ipcp, params->flg);
        if (!err)
            err = ipcp->id;
    }
    return err;
}

int ipcget_new(struct ipc_namespace *ns, struct ipc_ids *ids, const struct ipc_ops *ops, struct ipc_params *params) {
    int err;
    sem_p(&ids->rwsem);
    err = ops->getnew(ns, params);
    sem_v(&ids->rwsem);
    return err;
}

int ipcget_public(struct ipc_namespace *ns, struct ipc_ids *ids, const struct ipc_ops *ops, struct ipc_params *params) {
    panic("ipcget_public : not tested");
    return 0;
}

int ipcget(struct ipc_namespace *ns, struct ipc_ids *ids, const struct ipc_ops *ops, struct ipc_params *params) {
    if (params->key == IPC_PRIVATE)
        return ipcget_new(ns, ids, ops, params);
    else
