struct kern_ipc_perm *ipc_lock(struct ipc_ids *ids, int id) {
    struct kern_ipc_perm *out;
    int lid = ipcid_to_idx(id);
    if (ids->key_ht == NULL) {
        ipc_hashtable_init(ids);
    }
    out = ipc_hash_lookup(ids, lid);
    if (out == NULL) {
        panic("ipc hash lookup error\n");
    }
    acquire(&out->lock);
    /* ipc_rmid() may have already freed the ID while ipc_lock
     * was spinning: here verify that the structure is still valid
     */
    if (out->deleted) {
        release(&out->lock);
        panic("ipc lock : error, has deleted\n");
    }
    return out;
}

struct kern_ipc_perm *ipc_lock_check(struct ipc_ids *ids, int id) {
    struct kern_ipc_perm *out;
    out = ipc_lock(ids, id);
    if (ipc_checkid(out, id)) {
        panic("ipc_lock_check : error\n");
    }
    return out;
}

struct kern_ipc_perm *ipcctl_pre_down(struct ipc_ids *ids, int id, int cmd, struct kern_ipc_perm *perm,
                                      int extra_perm) {
    struct kern_ipc_perm *ipcp;
    sem_p(&ids->rwsem);
    ipcp = ipc_lock_check(ids, id);
    if (cmd == IPC_SET) {
        panic("ipcctl_pre_down : IPC_SET not tested\n");
    }
    return ipcp;
}

void ipc_rmid(struct ipc_ids *ids, struct kern_ipc_perm *ipcp) {
    ids->key_ht->op->hash_delete(ids->key_ht, (void *) ipcp, 0, 1);
    ids->in_use--;
    ipcp->deleted = 1;
    return;
}

void ipc_update_perm(struct kern_ipc_perm *in, struct kern_ipc_perm *out) {
    out->uid = in->uid;
    out->gid = in->gid;
    out->mode = (out->mode & ~S_IRWXUGO) | (in->mode & S_IRWXUGO);
}

int pipe_alloc(struct file **f0, struct file **f1) {
    struct pipe *pi;

    pi = 0;
    *f0 = *f1 = 0;
    if ((*f0 = file_alloc()) == 0 || (*f1 = file_alloc()) == 0)
        goto bad;
    if ((pi = (struct pipe *) kalloc()) == 0)
        goto bad;
    pi->readopen = 1;
    pi->writeopen = 1;
    pi->nwrite = 0;
    pi->nread = 0;
    init_lock(&pi->lock, "pipe");

    sem_init(&pi->read_sem, 0, "read_sem");
    sem_init(&pi->write_sem, 0, "write_sem");

    (*f0)->f_type = FD_PIPE;
    (*f0)->f_flags = O_RDONLY;
    (*f0)->f_data.f_pipe = pi;

    (*f1)->f_type = FD_PIPE;
    (*f1)->f_flags = O_WRONLY;
    (*f1)->f_data.f_pipe = pi;
    return 0;

bad:
    if (pi)
        kfree((char *) pi);
    if (*f0)
        generic_fileclose(*f0);
    if (*f1)
        generic_fileclose(*f1);
    return -1;
}

void pipe_close(struct pipe *pi, int writable) {
    acquire(&pi->lock);
    if (writable) {
        pi->writeopen = 0;
        sem_v(&pi->read_sem);
    } else {
        pi->readopen = 0;
        sem_v(&pi->write_sem);
    }
    if (pi->readopen == 0 && pi->writeopen == 0) {
        release(&pi->lock);
        kfree((char *) pi);
    } else
        release(&pi->lock);
}

int pipe_write(struct pipe *pi, uint64 addr, int n) {
    int i = 0;
    struct proc *pr = proc_current();

    acquire(&pi->lock);
    while (i < n) {
        if (pi->readopen == 0 || proc_is_killed(pr)) {
            release(&pi->lock);
            return -1;
        }
        if (pi->nwrite == pi->nread + PIPESIZE) { // DOC: pipewrite-full
            sem_v(&pi->read_sem);

            release(&pi->lock);
            sem_p(&pi->write_sem);
            acquire(&pi->lock);
        } else {
            char ch;
            if (copy_in(pr->mm->pagetable, &ch, addr + i, 1) == -1)
                break;
            pi->data[pi->nwrite++ % PIPESIZE] = ch;
            i++;
        }
    }
    sem_v(&pi->read_sem);
    release(&pi->lock);

    return i;
}

int pipe_read(struct pipe *pi, uint64 addr, int n) {
    int i;
    struct proc *pr = proc_current();
    char ch;

    acquire(&pi->lock);
    while (pi->nread == pi->nwrite && pi->writeopen) { // DOC: pipe-empty
        if (proc_is_killed(pr)) {
            release(&pi->lock);
            return -1;
        }
        release(&pi->lock);
        sem_p(&pi->read_sem);
        acquire(&pi->lock);
    }
    for (i = 0; i < n; i++) { // DOC: piperead-copy
        if (pi->nread == pi->nwrite)
            break;
        ch = pi->data[pi->nread % PIPESIZE];
        if (copy_out(pr->mm->pagetable, addr + i, &ch, 1) == -1)
            break;
        ++pi->nread;
    }
    sem_v(&pi->write_sem);
    release(&pi->lock);
    return i;
}

int pipe_empty(struct pipe *p) {
    acquire(&p->lock);
    int ret = (p->nread == p->nwrite);
    release(&p->lock);
    return ret;
}

int pipe_full(struct pipe *p) {
    acquire(&p->lock);
    int ret = ((p->nread + PIPESIZE) == p->nwrite);
    release(&p->lock);
    return ret;
}

void shm_init_ns(struct ipc_namespace *ns) {
    ns->shm_ctlmax = SHMMAX;
    ns->shm_ctlall = SHMALL;
    ns->shm_ctlmni = SHMMNI;
    ns->shm_tot = 0;
    ipc_init_ids(&shm_ids(ns));
}

struct file *shmem_kernel_file_setup(const char *name, loff_t size) {
    struct inode *ip;
    struct filesystem *fs = get_fs_by_mount_point("/");
    struct file *fp;
    if (fs->fs_type == FAT32) {
        struct inode *dp = fat32_sb.root;
        if ((ip = dp->i_op->create(dp, name, T_REG, 0, 0)) == 0) {
            panic("shmem_kernel_file_setup : create error\n");
        }
        assist_openat(ip, O_RDWR, 0, &fp);
    } else if (fs->fs_type == EXT4) {
        struct file *f;
        char root_path[2] = "/";
        char absolute_path[PATH_LONG_MAX] = {0};
        get_absolute_path(name, root_path, absolute_path);
        if ((f = file_alloc()) == 0) {
            panic("shmem_kernel_file_setup : file_alloc error\n");
        }

        int fd;
        if ((fd = fd_alloc(f)) < 0) {
            generic_fileclose(f);
            panic("shmem_kernel_file_setup : file_alloc error\n");
        }
        f->f_flags = O_RDWR | O_CREATE;
        f->f_mode = 0;
        f->f_count = 1;
        struct file_vnode *fv = kcalloc(1, sizeof(struct file_vnode));
        fv->fs = get_fs_by_type(EXT4);
        strcpy(fv->path, absolute_path);
        f->f_data.f_vnode = fv;
        if (vfs_ext_openat(f) < 0) {
            generic_fileclose(f);
            proc_current()->_ofile[fd] = 0; // free fd
            panic("shmem_kernel_file_setup : vfs_ext_openat error\n");
        }
        fp = f;
    }
    return fp;
}

struct shmid_kernel *shm_lock_check(struct ipc_namespace *ns, int shmid) {
    struct kern_ipc_perm *ipcp = ipc_lock_check(&shm_ids(ns), shmid);
    return container_of(ipcp, struct shmid_kernel, shm_perm);
}

int new_seg(struct ipc_namespace *ns, struct ipc_params *params) {
    key_t key = params->key;
    int shmflg = params->flg;
    size_t size = params->size;
    int id;
    struct shmid_kernel *shp;

    // round up
    size_t numpages = (size + PGSIZE - 1) >> PGSHIFT;

    struct file *fp = NULL;
    char name[13];
    // vm_flags_t acctflag = 0;

    if (size < SHMMIN || size > ns->shm_ctlmax)
        return -EINVAL;

    if (numpages << PGSHIFT < size)
        return -ENOSPC;

    if (ns->shm_tot + numpages < ns->shm_tot || ns->shm_tot + numpages > ns->shm_ctlall)
        return -ENOSPC;

    // no memory
    shp = kzalloc(sizeof(struct shmid_kernel));
    if (unlikely(!shp))
        return -ENOMEM;

    shp->shm_perm.key = key;
    shp->shm_perm.mode = (shmflg & S_IRWXUGO);

    snprintf(name, 13, "00SYSV%06d", key);
    if (key == IPC_PRIVATE) {
        key = private_shm_id++;
        snprintf(name, 2, "%02d", key);
        name[2] = 'S';
    }
    if (shmflg & SHM_HUGETLB) {
        panic("SHM_HUGETLB not tested\n");
    } else {
        if (shmflg & SHM_NORESERVE) {
            panic("not tested\n");
        }
        fp = shmem_kernel_file_setup(name, size);
    }
    struct proc *p = proc_current();
    shp->shm_segsz = size;
    shp->shm_nattch = 0;
    shp->shm_file = fp;
    shp->shm_creator = p;

    // 	/* ipc_addid() locks shp upon success. */
    id = ipc_addid(&shm_ids(ns), &shp->shm_perm, ns->shm_ctlmni);
    if (id < 0)
        panic("no id");
    list_add(&shp->shm_clist, &p->sysvshm.shm_clist);
    filesystem_t *fs = get_fs_by_mount_point("/");
    if (fs->fs_type == FAT32) {
        struct inode *ip = shp->shm_file->f_data.f_vnode->data;
        ip->i_ino = shp->shm_perm.id;
    } else if (fs->fs_type == EXT4) {

    }

    ns->shm_tot += numpages;
    id = shp->shm_perm.id;

    release(&shp->shm_perm.lock);
    return id;
}

int shm_more_checks(struct kern_ipc_perm *ipcp, struct ipc_params *params) {
    struct shmid_kernel *shp;
    shp = container_of(ipcp, struct shmid_kernel, shm_perm);
    if (shp->shm_segsz < params->size)
        return -EINVAL;

    return 0;
}

void shm_destroy(struct ipc_namespace *ns, struct shmid_kernel *shp) {
    ns->shm_tot -= (shp->shm_segsz + PGSIZE - 1) >> PGSHIFT;
    shm_rmid(ns, shp);
    release(&shp->shm_perm.lock);
    // generic_fileclose(shp->shm_file);
    security_shm_free(shp);
}

struct shmid_kernel *shm_lock(struct ipc_namespace *ns, int id) {
    struct kern_ipc_perm *ipcp = ipc_lock(&shm_ids(ns), id);
    return container_of(ipcp, struct shmid_kernel, shm_perm);
}

int do_sigaction(int sig, struct sigaction *act, struct sigaction *old_act) {
    struct tcb *t = thread_current();
    struct sigaction *k;

    if (!valid_signal(sig)) {
        return -1;
    }
    k = &t->sig->action[sig - 1];
    acquire(&t->sig->siglock);
    if (old_act)
        *old_act = *k;

    if (act) {
        sig_del_set_mask(act->sa_mask, sig_gen_mask(SIGKILL) | sig_gen_mask(SIGSTOP));
        *k = *act;
    }
    release(&t->sig->siglock);
    return 0;
}

int do_sigprocmask(int how, sigset_t *set, sigset_t *oldset) {
    struct tcb *t = thread_current();

    acquire(&t->sig->siglock);
    if (oldset)
        *oldset = t->blocked;

    int error = 0;
    switch (how) {
        case SIG_BLOCK:
            t->blocked.sig = sig_or(t->blocked.sig, set->sig);
            break;
        case SIG_UNBLOCK:
            t->blocked.sig = sig_and(t->blocked.sig, set->sig);
            break;
        case SIG_SETMASK:
            t->blocked.sig = set->sig;
            break;
        default:
            error = -1;
    }

    release(&t->sig->siglock);
    return error;
}

int signal_queue_pop(uint64 mask, struct sigpending *pending) {
    ASSERT(pending != NULL);
    struct sigqueue *sig_cur;
    struct sigqueue *sig_tmp;

    if (!sig_test_mask(pending->signal, mask)) {
        printfRed("this signal is invalid\n");
        return 0;
    }

    sig_del_set_mask(pending->signal, mask);
    list_for_each_entry_safe(sig_cur, sig_tmp, &pending->list, list) {
        if (valid_signal(sig_cur->info.si_signo) && (mask & sig_gen_mask(sig_cur->info.si_signo))) {
            list_del_reinit(&sig_cur->list);
            kfree(sig_cur);
        }
    }
    return 1;
}

int signal_queue_flush(struct sigpending *pending) {
    ASSERT(pending != NULL);
    struct sigqueue *sig_cur;
    struct sigqueue *sig_tmp;
    sig_empty_set(&pending->signal);
    list_for_each_entry_safe(sig_cur, sig_tmp, &pending->list, list) {
        list_del_reinit(&sig_cur->list);
        kfree(sig_cur);
    }
    return 1;
}

void signal_info_init(sig_t sig, siginfo_t *info, int opt) {
    // USER
    if (opt == 0) {
        info->si_signo = sig;
        info->si_code = SI_USER;
        // KERNEL
    } else if (opt == 1) {
        info->si_signo = sig;
        info->si_code = SI_KERNEL;
    } else {
        panic("signal info : error\n");
    }
}

int signal_send(siginfo_t *info, struct tcb *t) {
    ASSERT(t != NULL);
    ASSERT(info != NULL);

    // signo
    sig_t sig = info->si_signo;
    // if (sig_ignored(t, sig) || sig_existed(t, sig)) {
    //     return 0;
    // }
    if (sig_existed(t, sig)) {
        return 0;
    }

    // be killed immediately !!!
    if (sig == SIGKILL || sig == SIGSTOP || sig == SIGTERM) {
        t->killed = 1;
    }

    struct sigqueue *q;
    if ((q = (struct sigqueue *)kalloc()) == NULL) {
        printf("signal_send : no space in heap\n");
        return 0;
    }
    q->info = *info;          // !!!
    t->sigpending++;
    INIT_LIST_HEAD(&q->list); // bug!!!

    list_add_tail(&q->list, &t->pending.list);
    sig_add_set(t->pending.signal, sig);

    return 1;
}

void sigpending_init(struct sigpending *sig) {
    sig_empty_set(&sig->signal);
    INIT_LIST_HEAD(&sig->list);
}

int signal_handle(struct tcb *t) {
    if (t->sigpending == 0)
        return 0;
    if (t->sigprocessing != 0) {
        // printfRed("tid : %d is handing the signal %d\n", t->tid, t->sigprocessing); // debug
    }

    struct sigqueue *sig_cur = NULL;
    struct sigqueue *sig_tmp = NULL;
    struct sigaction sig_act;

    list_for_each_entry_safe(sig_cur, sig_tmp, &t->pending.list, list) {
        int sig_no = sig_cur->info.si_signo;
        if (!valid_signal(sig_no)) { // bug!!!
            panic("signal handle : invalid signo\n");
        }
        if (sig_ignored(t, sig_no)) {
            continue;
        }
        sig_act = sig_action(t, sig_no);
        if (sig_act.sa_handler == SIG_DFL) {
            signal_DFL(t, sig_no);
            t->sigpending--;
            list_del_reinit(&sig_cur->list);
            kfree(sig_cur);
        } else if (sig_act.sa_handler == SIG_IGN) {
            continue;
        } else {
            do_handle(t, sig_no, &sig_act);
            t->sigpending--;
            t->sigprocessing = sig_no;
            list_del_reinit(&sig_cur->list);
            kfree(sig_cur);
            break;
        }
    }
    return 1;
}

int do_handle(struct tcb *t, int sig_no, struct sigaction *sig_act) {
    sigset_t *oldset = &(t->blocked);

    int ret = setup_rt_frame(sig_act, sig_no, oldset, t->trapframe);
    return ret;
}

void signal_DFL(struct tcb *t, sig_t signo) {
    int cpid;
    uint64 wstatus = 0;
    switch (signo) {
    case SIGKILL:
        // case SIGSTOP:
        thread_setkilled(t);
        break;
    case SIGCHLD:
        cpid = waitpid(-1, wstatus, 0);
        printfRed("child , pid = %d exit with status : %d\n", cpid, wstatus);
        break;
    default:
        break;
    }
}

void *get_sigframe(struct sigaction *sig, struct trapframe *tf, size_t framesize) {
    uint64 sp;
    /* Default to using normal stack */
    sp = tf->sp;
    /*
     * If we are on the alternate signal stack and would overflow it, don't.
     * Return an always-bogus address instead so we will die with SIGSEGV.
     */
    // if (on_sig_stack(sp) && !likely(on_sig_stack(sp - framesize)))
    // 	return (void __user __force *)(-1UL);

    /* This is the X/Open sanctioned signal stack switching. */
    // sp = sigsp(sp, ksig) - framesize;
    sp -= framesize;

    /* Align the stack frame. */
    sp &= ~0xfUL;

    return (void *)sp;
}

int setup_rt_frame(struct sigaction *sig, sig_t signo, sigset_t *set, struct trapframe *tf) {
    // struct proc *p = proc_current();
    struct rt_sigframe *frame;
    frame = get_sigframe(sig, tf, sizeof(*frame));
    signal_frame_setup(set, tf, frame, signo);

    tf->ra = (uint64)SIGRETURN;
    tf->epc = (uint64)sig->sa_handler;
    tf->sp = (uint64)frame;
    tf->a0 = (uint64)signo; /* a0: signal number */
    tf->a1 = 0;             // tf->a1  = (uint64)(&frame->info); /* a1: siginfo pointer */
    tf->a2 = tf->sp;        // tf->a2 = (uint64)(&frame->uc); /* a2: ucontext pointer */
    return 0;
}

int signal_frame_setup(sigset_t *set, struct trapframe *tf, struct rt_sigframe *rtf, sig_t signo) {
    struct ucontext uc;
    uc.uc_sigmask = *set;
    uc.uc_mcontext.tf = *tf;
    uc.sigprocessing = signo;
    struct proc *p = proc_current();
    if (copy_out(p->mm->pagetable, (uint64)&rtf->uc, (char *)&uc, sizeof(struct ucontext)))
        return -1;

    ucontext_t uc_riscv;
    memset((void *)&uc_riscv, 0, sizeof(uc_riscv));
    if (copy_out(p->mm->pagetable, (uint64)&rtf->uc_riscv, (char *)&uc_riscv, sizeof(ucontext_t))) {
        return -1;
    }
    return 0;
}

int signal_frame_restore(struct tcb *t, struct rt_sigframe *rtf) {
    struct ucontext uc;
    struct proc *p = proc_current();
    if (copy_in(p->mm->pagetable, (char *)&uc, (uint64)&rtf->uc, sizeof(struct ucontext)) != 0)
        return -1;
    t->blocked = uc.uc_sigmask;
    *(t->trapframe) = uc.uc_mcontext.tf;
    t->sigprocessing = uc.sigprocessing;

    ucontext_t uc_riscv;
    if (copy_in(p->mm->pagetable, (char *)&uc_riscv, (uint64)&rtf->uc_riscv, sizeof(ucontext_t)) != 0)
        return -1;
    uint64 MC_PC = uc_riscv.uc_mcontext.__gregs[0];// for libc-test (pthread_cancel)
    if(MC_PC) {
        t->trapframe->epc = MC_PC; 
    }
    return 0;
}

