static int skip_atoi(const char **s) {
    int i = 0;

    while (is_digit(**s))
        i = i * 10 + *((*s)++) - '0';
    return i;
}

static void number(long num, int base, int size, int precision, int type) {
    char tmp[66];
    const char *digits = "0123456789abcdefghijklmnopqrstuvwxyz";

    if (type & LARGE)
        digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    if (type & LEFT)
        type &= ~ZEROPAD;
    const char c = (type & ZEROPAD) ? '0' : ' ';
    char sign = 0;
    if (type & SIGN) {
        if (num < 0) {
            sign = '-';
            num = -num;
            size--;
        } else if (type & PLUS) {
            sign = '+';
            size--;
        } else if (type & SPACE) {
            sign = ' ';
            size--;
        }
    }
    if (type & SPECIAL) {
        if (base == 16)
            size -= 2;
        else if (base == 8)
            size--;
    }
    int i = 0;
    if (num == 0)
        tmp[i++] = '0';
    else
        while (num != 0)
            tmp[i++] = digits[do_div(num, base)];
    if (i > precision)
        precision = i;
    size -= precision;
    if (!(type & (ZEROPAD + LEFT)))
        while (size-- > 0)
            console_putc(' ');
    if (sign)
        console_putc(sign);
    if (type & SPECIAL) {
        if (base == 8)
            console_putc('0');
        else if (base == 16) {
            console_putc('0');
            console_putc(digits[33]);
        }
    }
    if (!(type & LEFT)) {
        while (size-- > 0)
            console_putc(c);
    }
    while (i < precision--)
        console_putc('0');
    while (i-- > 0)
        console_putc(tmp[i]);
    while (size-- > 0)
        console_putc(' ');
}

void vprintf(const char *fmt, va_list args) {
    int len;
    unsigned long num;
    int i, base;
    char *s;

    int flags; /* flags to number() */

    int field_width; /* width of output field */
    int precision; /* min. # of digits for integers; max
                 number of chars for from string */
    int qualifier; /* 'l', or 'L' for integer fields */

    for (; *fmt; ++fmt) {
        if (*fmt != '%') {
            console_putc(*fmt);
            continue;
        }

        /* process flags */
        flags = 0;
    repeat:
        ++fmt; /* this also skips first '%' */
        switch (*fmt) {
            case '-':
                flags |= LEFT;
                goto repeat;
            case '+':
                flags |= PLUS;
                goto repeat;
            case ' ':
                flags |= SPACE;
                goto repeat;
            case '#':
                flags |= SPECIAL;
                goto repeat;
            case '0':
                flags |= ZEROPAD;
                goto repeat;
        }

        /* get field width */
        field_width = -1;
        if (is_digit(*fmt))
            field_width = skip_atoi(&fmt);
        else if (*fmt == '*') {
            ++fmt;
            /* it's the next argument */
            field_width = va_arg(args, int);
            if (field_width < 0) {
                field_width = -field_width;
                flags |= LEFT;
            }
        }

        /* get the precision */
        precision = -1;
        if (*fmt == '.') {
            ++fmt;
            if (is_digit(*fmt))
                precision = skip_atoi(&fmt);
            else if (*fmt == '*') {
                ++fmt;
                /* it's the next argument */
                precision = va_arg(args, int);
            }
            if (precision < 0)
                precision = 0;
        }

        /* get the conversion qualifier */
        qualifier = -1;
        if (*fmt == 'l' || *fmt == 'L') {
            qualifier = *fmt;
            ++fmt;
        }

        /* default base */
        base = 10;

        switch (*fmt) {
            case 'c':
                if (!(flags & LEFT))
                    while (--field_width > 0)
                        console_putc(' ');
                console_putc((unsigned char) va_arg(args, int));
                while (--field_width > 0)
                    console_putc(' ');
                continue;

            case 's':
                s = va_arg(args, char *);
                if (!s)
                    s = "<NULL>";

                len = strnlen(s, precision);

                if (!(flags & LEFT))
                    while (len < field_width--)
                        console_putc(' ');
                for (i = 0; i < len; ++i)
                    console_putc(*s++);
                while (len < field_width--)
                    console_putc(' ');
                continue;

            case 'p':
                if (field_width == -1) {
                    field_width = 2 * sizeof(void *);
                    flags |= ZEROPAD;
                }
                number((unsigned long) va_arg(args, void *), 16, field_width, precision, flags);
                continue;

            /* integer number formats - set up the flags and "break" */
            case 'o':
                base = 8;
                break;

            case 'X':
                flags |= LARGE;
            case 'x':
                base = 16;
                break;

            case 'd':
            case 'i':
                flags |= SIGN;
            case 'u':
                break;

            default:
                if (*fmt != '%')
                    console_putc('%');
                if (*fmt)
                    console_putc(*fmt);
                else
                    --fmt;
                continue;
        }
        if (qualifier == 'l')
            num = va_arg(args, unsigned long);
        else if (flags & SIGN)
            num = va_arg(args, int);
        else
            num = va_arg(args, unsigned int);
        number(num, base, field_width, precision, flags);
    }
}

void printf(char *fmt, ...) {
    va_list ap;
    // int i, c, locking;
    // char *s;

    // cannot debug lock when execute printf, it will cause recursive call
    const int locking = pr.locking;
    if (locking)
        acquire(&pr.lock);

    if (fmt == 0)
        panic("null fmt");

    va_start(ap, fmt);
    vprintf(fmt, ap);
    va_end(ap);

    if (locking)
        release(&pr.lock);
}

void panic(char *s) {
    pr.locking = 0;
    // print backtrace
    printf("panic: ");
    printf(s);
    printf("\n");
    backtrace();
    panicked = 1; // freeze uart output from other CPUs
    for (;;)
        ;
}

