}

void backtrace() {
    uint64 fp = r_fp();
    Log("kernel backtrace");
    while (fp < PGROUNDUP(fp) && fp > PGROUNDDOWN(fp)) {
        const uint64 last_ra = *(uint64 *) (fp - 8);
        fp = *(uint64 *) (fp - 16);
        printf("%p\n", last_ra);
    }
}

