void printf_bin(uchar *num, int len) {
    for (int i = 0; i < len; i++) {
        const unsigned char *p = &num[i];
        for (int k = 7; k >= 0; k--) {
            if (*p & (1 << k))
                printf("1");
            else
                printf("0");
        }
        printf(" ");
    }
    printf("\r\n");
}

