struct {
    char *lo;
    char *hi;
}

void _quicksort(void *const pbase, size_t total_elems, size_t size, __compar_fn_t cmp) {
    char *base_ptr = (char *) pbase;

    const size_t max_thresh = MAX_THRESH * size;

    if (total_elems == 0)
        /* Avoid lossage with unsigned arithmetic below.  */
        return;

    if (total_elems > MAX_THRESH) {
        char *lo = base_ptr;
        char *hi = &lo[size * (total_elems - 1)];
        stack_node stack[STACK_SIZE];
        stack_node *top = stack;

        PUSH(NULL, NULL);

        while (STACK_NOT_EMPTY) {
            char *left_ptr;
            char *right_ptr;

            /* Select median value from among LO, MID, and HI. Rearrange
               LO and HI so the three values are sorted. This lowers the
               probability of picking a pathological pivot value and
               skips a comparison for both the LEFT_PTR and RIGHT_PTR in
               the while loops. */

            char *mid = lo + size * ((hi - lo) / size >> 1);

            if ((*cmp)((void *) mid, (void *) lo) < 0)
                SWAP(mid, lo, size);
            if ((*cmp)((void *) hi, (void *) mid) < 0)
                SWAP(mid, hi, size);
            else
                goto jump_over;
            if ((*cmp)((void *) mid, (void *) lo) < 0)
                SWAP(mid, lo, size);
        jump_over:;

            left_ptr = lo + size;
            right_ptr = hi - size;

            /* Here's the famous ``collapse the walls'' section of quicksort.
               Gotta like those tight inner loops!  They are the main reason
               that this algorithm runs much faster than others. */
            do {
                while ((*cmp)((void *) left_ptr, (void *) mid) < 0)
                    left_ptr += size;

                while ((*cmp)((void *) mid, (void *) right_ptr) < 0)
                    right_ptr -= size;

                if (left_ptr < right_ptr) {
                    SWAP(left_ptr, right_ptr, size);
                    if (mid == left_ptr)
                        mid = right_ptr;
                    else if (mid == right_ptr)
                        mid = left_ptr;
                    left_ptr += size;
                    right_ptr -= size;
                } else if (left_ptr == right_ptr) {
                    left_ptr += size;
                    right_ptr -= size;
                    break;
                }
            } while (left_ptr <= right_ptr);

            /* Set up pointers for next iteration.  First determine whether
               left and right partitions are below the threshold size.  If so,
               ignore one or both.  Otherwise, push the larger partition's
               bounds on the stack and continue sorting the smaller one. */

            if ((size_t) (right_ptr - lo) <= max_thresh) {
                if ((size_t) (hi - left_ptr) <= max_thresh)
                    /* Ignore both small partitions. */
                    POP(lo, hi);
                else
                    /* Ignore small left partition. */
                    lo = left_ptr;
            } else if ((size_t) (hi - left_ptr) <= max_thresh)
                /* Ignore small right partition. */
                hi = right_ptr;
            else if ((right_ptr - lo) > (hi - left_ptr)) {
                /* Push larger left partition indices. */
                PUSH(lo, right_ptr);
                lo = left_ptr;
            } else {
                /* Push larger right partition indices. */
                PUSH(left_ptr, hi);
                hi = right_ptr;
            }
        }
    }

    /* Once the BASE_PTR array is partially sorted by quicksort the rest
       is completely sorted using insertion sort, since this is efficient
       for partitions below MAX_THRESH size. BASE_PTR points to the beginning
       of the array to sort, and END_PTR points at the very last element in
       the array (*not* one beyond it!). */

#define min(x, y) ((x) < (y) ? (x) : (y))

    {
        char *const end_ptr = &base_ptr[size * (total_elems - 1)];
        char *tmp_ptr = base_ptr;
        char *thresh = min(end_ptr, base_ptr + max_thresh);
        char *run_ptr;

        /* Find smallest element in first threshold and place it at the
           array's beginning.  This is the smallest array element,
           and the operation speeds up insertion sort's inner loop. */

        for (run_ptr = tmp_ptr + size; run_ptr <= thresh; run_ptr += size)
            if ((*cmp)((void *) run_ptr, (void *) tmp_ptr) < 0)
                tmp_ptr = run_ptr;

        if (tmp_ptr != base_ptr)
            SWAP(tmp_ptr, base_ptr, size);

        /* Insertion sort, running from left-hand-side up to right-hand-side.  */

        run_ptr = base_ptr + size;
        while ((run_ptr += size) <= end_ptr) {
            tmp_ptr = run_ptr - size;
            while ((*cmp)((void *) run_ptr, (void *) tmp_ptr) < 0)
                tmp_ptr -= size;

            tmp_ptr += size;
            if (tmp_ptr != run_ptr) {
                char *trav;

                trav = run_ptr + size;
                while (--trav >= run_ptr) {
                    char c = *trav;
                    char *hi, *lo;

                    for (hi = lo = trav; (lo -= size) >= tmp_ptr; hi = lo)
                        *hi = *lo;
                    *hi = c;
                }
            }
        }
    }
}

void qsort(void *__base, size_t __nmemb, size_t __size, __compar_fn_t _compar) {
    _quicksort(__base, __nmemb, __size, _compar);
}

void Queue_init(Queue_t *q, char *name, enum queue_type type) {
    init_lock(&q->lock, name);
    INIT_LIST_HEAD(&q->list);
    strncpy(q->name, name, strlen(name));
    q->type = type;
}

int Queue_isempty_atomic(Queue_t *q) {
    acquire(&q->lock);
    int empty = list_empty(&(q->list));
    release(&q->lock);
    return empty;
}

struct list_head *queue_entry(void *node, enum queue_type type) {
    struct list_head *list = NULL;
    switch (type) {
        case TCB_STATE_QUEUE:
            list = &(((struct tcb *) node)->state_list);
            break;
        case PCB_STATE_QUEUE:
            list = &(((struct proc *) node)->state_list);
            break;
        case TCB_WAIT_QUEUE:
            list = &(((struct tcb *) node)->wait_list);
            break;
        default:
            panic("this type is invalid\n");
    }
    return list;
}

void *queue_first_node(Queue_t *q) {
    void *node = NULL;
    switch (q->type) {
        case TCB_STATE_QUEUE:
            node = list_first_entry(&(q->list), struct tcb, state_list);
            break;
        case PCB_STATE_QUEUE:
            node = list_first_entry(&(q->list), struct proc, state_list);
            break;
        case TCB_WAIT_QUEUE:
            node = list_first_entry(&(q->list), struct tcb, wait_list);
            break;
        default:
            panic("this type is invalid\n");
    }
    return node;
}

void Queue_push_back(Queue_t *q, void *node) {
    struct list_head *list = queue_entry(node, q->type);
    list_add_tail(list, &(q->list));
}

void Queue_push_back_atomic(Queue_t *q, void *node) {
    acquire(&q->lock);
    struct list_head *list = queue_entry(node, q->type);
    list_add_tail(list, &(q->list));
    release(&q->lock);
}

void Queue_remove(void *node, enum queue_type type) {
    struct list_head *list = queue_entry(node, type);
    list_del_reinit(list);
}

void Queue_remove_atomic(Queue_t *q, void *node) {
    acquire(&q->lock);
    struct list_head *list = queue_entry(node, q->type);
    list_del_reinit(list);
    release(&q->lock);
}

void *Queue_pop(Queue_t *q, int remove) {
    if (Queue_isempty(q))
        return NULL;
    void *node = queue_first_node(q);
    // remove it from queue??
    if (remove)
        Queue_remove(node, q->type);
    return node;
}

void *Queue_provide_atomic(Queue_t *q, int remove) {
    acquire(&q->lock);
    void *t = Queue_pop(q, remove);
    release(&q->lock);
    // may return NULL
    return t;
}

static inline void tag_clear(struct radix_tree_node *node, uint32 tag, int offset) {
    clear_bit(offset, node->tags[tag]);
}

static inline int tag_get(struct radix_tree_node *node, uint32 tag, int offset) {
    return test_bit(offset, node->tags[tag]);
}

static inline void root_tag_set(struct radix_tree_root *root, uint32 tag) {
    root->gfp_mask |= (gfp_t) (1 << (tag + __GFP_BITS_SHIFT));
}

static inline int root_tag_get(struct radix_tree_root *root, uint32 tag) {
    return (unsigned) root->gfp_mask & (1 << (tag + __GFP_BITS_SHIFT));
}

static inline void root_tag_clear(struct radix_tree_root *root, uint32 tag) {
    root->gfp_mask &= (gfp_t) ~(1 << (tag + __GFP_BITS_SHIFT));
}

static inline int any_tag_set(struct radix_tree_node *node, uint32 tag) {
    for (int idx = 0; idx < RADIX_TREE_TAG_LONGS; idx++) {
        if (node->tags[tag][idx])
            return 1;
    }
    return 0;
}

uint64 radix_tree_maxindex(uint height) {
    if (height > RADIX_TREE_MAX_PATH) {
        panic("radix_tree : error\n");
    }
    return (1 << (height * RADIX_TREE_MAP_SHIFT)) - 1; // at easy way to get maxindex
}

void *radix_tree_tag_set(struct radix_tree_root *root, uint64 index, uint32 tag) {
    uint32 height, shift;
    struct radix_tree_node *slot;

    height = root->height;
    ASSERT(index <= radix_tree_maxindex(height));

    slot = radix_tree_indirect_to_ptr(root->rnode);
    shift = (height - 1) * RADIX_TREE_MAP_SHIFT;

    while (height > 0) {
        int offset;

        offset = (index >> shift) & RADIX_TREE_MAP_MASK;
        if (!tag_get(slot, tag, offset))
            tag_set(slot, tag, offset);
        slot = slot->slots[offset];
        ASSERT(slot != NULL);
        shift -= RADIX_TREE_MAP_SHIFT;
        height--;
    }

    /* set the root's tag bit */
    if (slot && !root_tag_get(root, tag))
        root_tag_set(root, tag);

    return slot;
}

void *radix_tree_tag_clear(struct radix_tree_root *root, uint64 index, uint32 tag) {
    struct radix_tree_path path[RADIX_TREE_MAX_PATH + 1], *pathp = path;
    struct radix_tree_node *slot = NULL;
    uint32 height, shift;

    height = root->height;
    /*index is too large*/
    if (index > radix_tree_maxindex(height))
        goto out;

    shift = (height - 1) * RADIX_TREE_MAP_SHIFT;
    pathp->node = NULL;
    slot = radix_tree_indirect_to_ptr(root->rnode);

    while (height > 0) {
        int offset;

        if (slot == NULL) // no path
            goto out;

        offset = (index >> shift) & RADIX_TREE_MAP_MASK;
        pathp[1].offset = offset;
        pathp[1].node = slot;
        slot = slot->slots[offset];
        pathp++;
        shift -= RADIX_TREE_MAP_SHIFT;
        height--;
    }

    if (slot == NULL)
        goto out;

    while (pathp->node) {
        if (!tag_get(pathp->node, tag, pathp->offset))
            goto out;
        tag_clear(pathp->node, tag, pathp->offset);
        if (any_tag_set(pathp->node, tag))
            goto out;
        pathp--;
    }

    /* clear the root's tag bit */
    if (root_tag_get(root, tag))
        root_tag_clear(root, tag);

out:
    return slot;
}

int radix_tree_tag_get(struct radix_tree_root *root, uint64 index, uint32 tag) {
    uint32 height, shift;
    struct radix_tree_node *node;

    /* check the root's tag bit */
    if (!root_tag_get(root, tag))
        return 0;

    node = root->rnode;
    if (node == NULL)
        return 0;

    if (!radix_tree_is_indirect_ptr(node))
        return (index == 0);
    node = radix_tree_indirect_to_ptr(node);

    height = node->height;
    if (index > radix_tree_maxindex(height))
        return 0;

    shift = (height - 1) * RADIX_TREE_MAP_SHIFT;

    while (1) {
        int offset;

        if (node == NULL)
            return 0;

        offset = (index >> shift) & RADIX_TREE_MAP_MASK;

        /*
         * This is just a debug check.  Later, we can bale as soon as
         * we see an unset tag.
         */
        if (!tag_get(node, tag, offset)) {
            // saw_unset_tag = 1;
        }
        if (height == 1)
            return !!tag_get(node, tag, offset);
        node = node->slots[offset];
        shift -= RADIX_TREE_MAP_SHIFT;
        height--;
    }
}

struct radix_tree_node *radix_tree_node_alloc(struct radix_tree_root *root) {
    struct radix_tree_node *ret = NULL;
    ret = (struct radix_tree_node *) kzalloc(sizeof(struct radix_tree_node));
    // printfGreen("radix_tree_node_alloc, mm: %d pages\n", get_free_mem()/4096);
    if (ret == NULL) {
        panic("radix_tree_node_init : no memory\n");
    }
    ret->count = 0;
    for (int i = 0; i < RADIX_TREE_MAP_SIZE; i++)
        ret->slots[i] = NULL;
    return ret;
}

static void *radix_tree_lookup_element(struct radix_tree_root *root, uint64 index, int is_slot) {
    uint32 height, shift;
    struct radix_tree_node *node, **slot;

    node = root->rnode;
    if (!radix_tree_is_indirect_ptr(node)) {
        // data item
        if (index > 0)
            return NULL;
        return is_slot ? (void *) &root->rnode : node;
    }

    node = radix_tree_indirect_to_ptr(node);

    height = node->height;
    if (index > radix_tree_maxindex(height))
        return NULL;

    shift = (height - 1) * RADIX_TREE_MAP_SHIFT;
    // height : 1 , shift : 0
    // height : 2 , shift : 6

    // similar to three level page table
    do {
        slot = (struct radix_tree_node **) (node->slots + ((index >> shift) & RADIX_TREE_MAP_MASK)); // offset mask
        node = *slot;
        if (node == NULL)
            return NULL;
        shift -= RADIX_TREE_MAP_SHIFT;
        height--;
    } while (height > 0);

    return is_slot ? (void *) slot : node;
}

void *radix_tree_lookup_node(struct radix_tree_root *root, uint64 index) {
    return radix_tree_lookup_element(root, index, 0);
}

void **radix_tree_lookup_slot(struct radix_tree_root *root, uint64 index) {
    return (void **) radix_tree_lookup_element(root, index, 1);
}

int radix_tree_insert(struct radix_tree_root *root, uint64 index, void *item) {
    struct radix_tree_node *node = NULL, *slot;
    uint32 height, shift;
    int offset;
    int error;

    // it is a data item
    ASSERT(!radix_tree_is_indirect_ptr(item));

    /* Make sure the tree is high enough.  */
    if (index > radix_tree_maxindex(root->height)) {
        error = radix_tree_extend(root, index);
        if (error)
            return error;
        // if it is not high enough, we should expand it
    }

    slot = radix_tree_indirect_to_ptr(root->rnode);
    height = root->height;
    shift = (height - 1) * RADIX_TREE_MAP_SHIFT;

    offset = 0;
    while (height > 0) {
        if (slot == NULL) {
            /* Have to add a child node.  */
            if ((slot = radix_tree_node_alloc(root)) == NULL)
                return -1;
            slot->height = height;
            if (node) {
                node->slots[offset] = slot;
                node->count++;
                // add a slot
            } else {
                root->rnode = radix_tree_ptr_to_indirect(slot);
                // the initial value of node is NULL
            }
        }

        /* Go a level down */
        offset = (index >> shift) & RADIX_TREE_MAP_MASK;
        node = slot;
        slot = node->slots[offset];
        shift -= RADIX_TREE_MAP_SHIFT;
        height--;
    }

    if (slot != NULL)
        return -1;

    if (node) {
        node->count++;
        node->slots[offset] = item;
        // find the leaf, so count++ and insert item into slots
        ASSERT(!tag_get(node, 0, offset));
        ASSERT(!tag_get(node, 1, offset));
    } else {
        root->rnode = item;
        ASSERT(!root_tag_get(root, 0));
        ASSERT(!root_tag_get(root, 1));
    }

    return 0;
}

int radix_tree_extend(struct radix_tree_root *root, uint64 index) {
    struct radix_tree_node *node;
    uint32 height;
    int tag;

    /* Figure out what the height should be.  */
    height = root->height + 1;
    while (index > radix_tree_maxindex(height))
        height++;

    if (root->rnode == NULL) {
        root->height = height;
        return 0;
    }

    do {
        uint32 newheight;
        if (!(node = radix_tree_node_alloc(root)))
            return -1;

        /* Increase the height.  */
        node->slots[0] = radix_tree_indirect_to_ptr(root->rnode);

        /* Propagate the aggregated tag info into the new root */
        for (tag = 0; tag < RADIX_TREE_MAX_TAGS; tag++) {
            if (root_tag_get(root, tag))
                tag_set(node, tag, 0);
        }

        newheight = root->height + 1;
        node->height = newheight;
        node->count = 1;
        node = radix_tree_ptr_to_indirect(node);
        root->rnode = node;
        root->height = newheight;
    } while (height > root->height);
    return 0;
}

void radix_tree_shrink(struct radix_tree_root *root) {
    /* try to shrink tree height */
    while (root->height > 0) {
        struct radix_tree_node *to_free = root->rnode;
        void *newptr;

        ASSERT(radix_tree_is_indirect_ptr(to_free));
        to_free = radix_tree_indirect_to_ptr(to_free);

        /*
         * The candidate node has more than one child, or its child
         * is not at the leftmost slot, we cannot shrink.
         */
        if (to_free->count != 1)
            break;
        if (!to_free->slots[0])
            break;

        newptr = to_free->slots[0];
        if (root->height > 1)
            newptr = radix_tree_ptr_to_indirect(newptr);
        root->rnode = newptr;
        root->height--;
        radix_tree_node_free(to_free);
    }
}

void *radix_tree_delete(struct radix_tree_root *root, uint64 index) {
    /*
     * The radix tree path needs to be one longer than the maximum path
     * since the "list" is null terminated.
     */
    struct radix_tree_path path[RADIX_TREE_MAX_PATH + 1], *pathp = path;
    struct radix_tree_node *slot = NULL;
    struct radix_tree_node *to_free;
    uint32 height, shift;
    int tag;
    int offset;

    height = root->height;
    if (index > radix_tree_maxindex(height))
        goto out;

    slot = root->rnode;
    if (height == 0) {
        root_tag_clear_all(root);
        root->rnode = NULL;
        goto out;
    }
    slot = radix_tree_indirect_to_ptr(slot);

    shift = (height - 1) * RADIX_TREE_MAP_SHIFT;
    pathp->node = NULL;

    do {
        if (slot == NULL)
            goto out;

        pathp++;
        offset = (index >> shift) & RADIX_TREE_MAP_MASK;
        pathp->offset = offset;
        pathp->node = slot;
        slot = slot->slots[offset];
        shift -= RADIX_TREE_MAP_SHIFT;
        height--;
    } while (height > 0);

    if (slot == NULL)
        goto out;

    /*
     * Clear all tags associated with the just-deleted item
     */
    for (tag = 0; tag < RADIX_TREE_MAX_TAGS; tag++) {
        if (tag_get(pathp->node, tag, pathp->offset))
            radix_tree_tag_clear(root, index, tag);
    }

    to_free = NULL;
    /* Now free the nodes we do not need anymore */
    while (pathp->node) {
        pathp->node->slots[pathp->offset] = NULL;
        pathp->node->count--;
        /*
         * Queue the node for deferred freeing after the
         * last reference to it disappears (set NULL, above).
         */
        if (to_free)
            radix_tree_node_free(to_free);

        if (pathp->node->count) {
            if (pathp->node == radix_tree_indirect_to_ptr(root->rnode))
                radix_tree_shrink(root);
            goto out;
        }

        /* Node with zero slots in use so free it */
        to_free = pathp->node;
        pathp--;
    }
    root_tag_clear_all(root);
    root->height = 0;
    root->rnode = NULL;
    if (to_free)
        radix_tree_node_free(to_free);
out:
    return slot;
}

void radix_tree_node_free(struct radix_tree_node *node) {
    tag_clear(node, 0, 0);
    tag_clear(node, 1, 0);
    node->slots[0] = NULL;
    node->count = 0;
    kfree(node);
}

int radix_tree_lookup_batch_elements(struct radix_tree_node *slot, void *page_head, page_op function, uint64 index,
                                     uint64 max_items, uint64 *next_index, int tag) {
    uint32 nr_found = 0;
    uint32 shift, height;

    // we merge the implements of __lookup and __lookup_tag
    uint32 height_min = (tag_valid(tag)) ? 0 : 1;
    uint64 i;

    height = slot->height;
    if (height == 0)
        goto out;
    shift = (height - 1) * RADIX_TREE_MAP_SHIFT;

    while (height > height_min) {
        i = (index >> shift) & RADIX_TREE_MAP_MASK;
        for (;;) {
            // we merge the implements of __lookup and __lookup_tag
            if (tag_valid(tag) && tag_get(slot, tag, i))
                break;
            if (!tag_valid(tag) && slot->slots[i] != NULL)
                break;

            index &= ~((1UL << shift) - 1);
            index += 1UL << shift;
            if (index == 0)
                goto out; /* 32-bit wraparound */
            i++;
            if (i == RADIX_TREE_MAP_SIZE)
                goto out;
        }
        height--;

        // we merge the implements of __lookup and __lookup_tag
        if (tag_valid(tag) && height == 0) {
            break;
        }

        shift -= RADIX_TREE_MAP_SHIFT;
        slot = (slot->slots[i]);
        if (slot == NULL)
            goto out;
    }

    /* Bottom level: grab some items */
    for (i = index & RADIX_TREE_MAP_MASK; i < RADIX_TREE_MAP_SIZE; i++) {
        index++;
        if (tag_valid(tag) && !tag_get(slot, tag, i))
            continue;
        if (slot->slots[i]) {
            // function(page_head, &(slot->slots[i]), index - 1, slot->slots[i]);
            function(page_head, slot->slots[i], index - 1, slot->slots[i]);

            nr_found++;
            if (nr_found == max_items)
                goto out;
        }
    }

out:
    *next_index = index;
    return nr_found;
}

int radix_tree_general_gang_lookup_elements(struct radix_tree_root *root, void *page_head, page_op function,
                                            uint64 first_index, uint64 max_items, int tag) {
    uint64 max_index;
    struct radix_tree_node *node;
    uint64 cur_index = first_index;
    int ret;

    // tag is valid
    /* check the root's tag bit */
    if (tag_valid(tag)) {
        if (!root_tag_get(root, tag))
            return 0;
    }

    node = root->rnode;
    if (!node)
        return 0;
    if (!radix_tree_is_indirect_ptr(node)) {
        if (first_index > 0)
            return 0;
        function(page_head, node, 0, NULL);
        return 1;
    }

    node = radix_tree_indirect_to_ptr(node);
    max_index = radix_tree_maxindex(node->height);

    ret = 0;
    while (ret < max_items) {
        uint32 slots_found;
        uint64 next_index; /* Index of next search */
        if (cur_index > max_index)
            break;

        slots_found = radix_tree_lookup_batch_elements(node, page_head, function, cur_index, max_items - ret,
                                                       &next_index, tag);

        ret += slots_found;
        if (next_index == 0)
            break;

        if (unlikely(maxitems_valid(max_items)))
            break; // !!!

        cur_index = next_index;
    }

    return ret;
}

void radix_tree_free_whole_tree(struct radix_tree_node *node, uint32 max_height, uint32 height) {
    for (int i = 0; i < (1 << RADIX_TREE_MAP_SHIFT); i++) {
        if (node->slots[i]) {
            if (height == max_height) {
                struct page *page = (struct page *) (node->slots[i]);
                if (page->allocated == 1) { // don't forget it
                    uint64 pa = page_to_pa(page);
                    kfree((void *) pa); // must use page_to_pa
                                        // printfBlue("memory : %d PAGES\n", get_free_mem()/4096);
                } else {
                }
            } else {
                radix_tree_free_whole_tree((struct radix_tree_node *) node->slots[i], max_height, height + 1);
            }
        }
    }
    kfree(node);
}

static int skip_atoi(const char **s) {
    int i = 0;

    while (is_digit(**s))
        i = i * 10 + *((*s)++) - '0';
    return i;
}

static char *number(char *str, long num, int base, int size, int precision, int type) {
    char c, sign, tmp[66];
    const char *digits = "0123456789abcdefghijklmnopqrstuvwxyz";
    int i;

    if (type & LARGE)
        digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    if (type & LEFT)
        type &= ~ZEROPAD;
    c = (type & ZEROPAD) ? '0' : ' ';
    sign = 0;
    if (type & SIGN) {
        if (num < 0) {
            sign = '-';
            num = -num;
            size--;
        } else if (type & PLUS) {
            sign = '+';
            size--;
        } else if (type & SPACE) {
            sign = ' ';
            size--;
        }
    }
    if (type & SPECIAL) {
        if (base == 16)
            size -= 2;
        else if (base == 8)
            size--;
    }
    i = 0;
    if (num == 0)
        tmp[i++] = '0';
    else
        while (num != 0)
            tmp[i++] = digits[do_div(num, base)];
    if (i > precision)
        precision = i;
    size -= precision;
    if (!(type & (ZEROPAD + LEFT)))
        while (size-- > 0)
            *str++ = ' ';
    if (sign)
        *str++ = sign;
    if (type & SPECIAL) {
        if (base == 8)
            *str++ = '0';
        else if (base == 16) {
            *str++ = '0';
            *str++ = digits[33];
        }
    }
    if (!(type & LEFT)) {
        while (size-- > 0)
            *str++ = c;
    }
    while (i < precision--)
        *str++ = '0';
    while (i-- > 0)
        *str++ = tmp[i];
    while (size-- > 0)
        *str++ = ' ';
    return str;
}

int vsprintf(char *buf, const char *fmt, va_list args) {
    int len;
    unsigned long num;
    int i, base;
    char *str;
    char *s;

    int flags; /* flags to number() */

    int field_width; /* width of output field */
    int precision; /* min. # of digits for integers; max
                 number of chars for from string */
    int qualifier; /* 'l', or 'L' for integer fields */

    for (str = buf; *fmt; ++fmt) {
        if (*fmt != '%') {
            *str++ = *fmt;
            continue;
        }

        /* process flags */
        flags = 0;
    repeat:
        ++fmt; /* this also skips first '%' */
        switch (*fmt) {
            case '-':
                flags |= LEFT;
                goto repeat;
            case '+':
                flags |= PLUS;
                goto repeat;
            case ' ':
                flags |= SPACE;
                goto repeat;
            case '#':
                flags |= SPECIAL;
                goto repeat;
            case '0':
                flags |= ZEROPAD;
                goto repeat;
        }

        /* get field width */
        field_width = -1;
        if (is_digit(*fmt))
            field_width = skip_atoi(&fmt);
        else if (*fmt == '*') {
            ++fmt;
            /* it's the next argument */
            field_width = va_arg(args, int);
            if (field_width < 0) {
                field_width = -field_width;
                flags |= LEFT;
            }
        }

        /* get the precision */
        precision = -1;
        if (*fmt == '.') {
            ++fmt;
            if (is_digit(*fmt))
                precision = skip_atoi(&fmt);
            else if (*fmt == '*') {
                ++fmt;
                /* it's the next argument */
                precision = va_arg(args, int);
            }
            if (precision < 0)
                precision = 0;
        }

        /* get the conversion qualifier */
        qualifier = -1;
        if (*fmt == 'l' || *fmt == 'L') {
            qualifier = *fmt;
            ++fmt;
        }

        /* default base */
        base = 10;

        switch (*fmt) {
            case 'c':
                if (!(flags & LEFT))
                    while (--field_width > 0)
                        *str++ = ' ';
                *str++ = (unsigned char) va_arg(args, int);
                while (--field_width > 0)
                    *str++ = ' ';
                continue;

            case 's':
                s = va_arg(args, char *);
                if (!s)
                    s = "<NULL>";

                len = strnlen(s, precision);

                if (!(flags & LEFT))
                    while (len < field_width--)
                        *str++ = ' ';
                for (i = 0; i < len; ++i)
                    *str++ = *s++;
                while (len < field_width--)
                    *str++ = ' ';
                continue;

            case 'p':
                if (field_width == -1) {
                    field_width = 2 * sizeof(void *);
                    flags |= ZEROPAD;
                }
                str = number(str, (unsigned long) va_arg(args, void *), 16, field_width, precision, flags);
                continue;

            case 'n':
                if (qualifier == 'l') {
                    long *ip = va_arg(args, long *);
                    *ip = (str - buf);
                } else {
                    int *ip = va_arg(args, int *);
                    *ip = (str - buf);
                }
                continue;

            /* integer number formats - set up the flags and "break" */
            case 'o':
                base = 8;
                break;

            case 'X':
                flags |= LARGE;
            case 'x':
                base = 16;
                break;

            case 'd':
            case 'i':
                flags |= SIGN;
            case 'u':
                break;

            default:
                if (*fmt != '%')
                    *str++ = '%';
                if (*fmt)
                    *str++ = *fmt;
                else
                    --fmt;
                continue;
        }
        if (qualifier == 'l')
            num = va_arg(args, unsigned long);
        else if (flags & SIGN)
            num = va_arg(args, int);
        else
            num = va_arg(args, unsigned int);
        str = number(str, num, base, field_width, precision, flags);
    }
    *str = '\0';
    return str - buf;
}

int vsnprintf(char *buf, int size, const char *fmt, va_list args) {
    int len;
    unsigned long num;
    int i, base;
    char *str;
    char *s;

    int flags; /* flags to number() */

    int field_width; /* width of output field */
    int precision; /* min. # of digits for integers; max
                 number of chars for from string */
    int qualifier; /* 'l', or 'L' for integer fields */

    int write_cnt = 0;
    if (size == 0) {
        return 0;
    }

    for (str = buf; *fmt; ++fmt) {
        if (*fmt != '%') {
            vsnprintf_writechar(size, write_cnt, str, *fmt);
            continue;
        }

        /* process flags */
        flags = 0;
    repeat:
        ++fmt; /* this also skips first '%' */
        switch (*fmt) {
            case '-':
                flags |= LEFT;
                goto repeat;
            case '+':
                flags |= PLUS;
                goto repeat;
            case ' ':
                flags |= SPACE;
                goto repeat;
            case '#':
                flags |= SPECIAL;
                goto repeat;
            case '0':
                flags |= ZEROPAD;
                goto repeat;
        }

        /* get field width */
        field_width = -1;
        if (is_digit(*fmt))
            field_width = skip_atoi(&fmt);
        else if (*fmt == '*') {
            ++fmt;
            /* it's the next argument */
            field_width = va_arg(args, int);
            if (field_width < 0) {
                field_width = -field_width;
                flags |= LEFT;
            }
        }

        /* get the precision */
        precision = -1;
        if (*fmt == '.') {
            ++fmt;
            if (is_digit(*fmt))
                precision = skip_atoi(&fmt);
            else if (*fmt == '*') {
                ++fmt;
                /* it's the next argument */
                precision = va_arg(args, int);
            }
            if (precision < 0)
                precision = 0;
        }

        /* get the conversion qualifier */
        qualifier = -1;
        if (*fmt == 'l' || *fmt == 'L') {
            qualifier = *fmt;
            ++fmt;
        }

        /* default base */
        base = 10;

        switch (*fmt) {
            case 'c':
                if (!(flags & LEFT))
                    while (--field_width > 0)
                        vsnprintf_writechar(size, write_cnt, str, ' ');
                vsnprintf_writechar(size, write_cnt, str, (unsigned char) va_arg(args, int));
                while (--field_width > 0)
                    vsnprintf_writechar(size, write_cnt, str, ' ');
                continue;

            case 's':
                s = va_arg(args, char *);
                if (!s)
                    s = "<NULL>";

                len = strnlen(s, precision);

                if (!(flags & LEFT))
                    while (len < field_width--)
                        vsnprintf_writechar(size, write_cnt, str, ' ');
                for (i = 0; i < len; ++i)
                    vsnprintf_writechar(size, write_cnt, str, *s++);
                while (len < field_width--)
                    vsnprintf_writechar(size, write_cnt, str, ' ');
                continue;

            case 'p':
                if (field_width == -1) {
                    field_width = 2 * sizeof(void *);
                    flags |= ZEROPAD;
                }
                str = number(str, (unsigned long) va_arg(args, void *), 16, field_width, precision, flags);
                write_cnt = (field_width >= (size - 1 - write_cnt)) ? 0 : write_cnt - field_width;
                if (write_cnt == 0) {
                    goto finish;
                }
                continue;

            case 'n':
                if (qualifier == 'l') {
                    long *ip = va_arg(args, long *);
                    *ip = (str - buf);
                } else {
                    int *ip = va_arg(args, int *);
                    *ip = (str - buf);
                }
                continue;

            /* integer number formats - set up the flags and "break" */
            case 'o':
                base = 8;
                break;

            case 'X':
                flags |= LARGE;
            case 'x':
                base = 16;
                break;

            case 'd':
            case 'i':
                flags |= SIGN;
            case 'u':
                break;

            default:
                if (*fmt != '%')
                    vsnprintf_writechar(size, write_cnt, str, ' ');
                if (*fmt)
                    vsnprintf_writechar(size, write_cnt, str, *fmt);
                else
                    --fmt;
                continue;
        }
        if (qualifier == 'l')
            num = va_arg(args, unsigned long);
        else if (flags & SIGN)
            num = va_arg(args, int);
        else
            num = va_arg(args, unsigned int);
        str = number(str, num, base, field_width, precision, flags);
    }

finish:
    *str = '\0';
    return ((size > (str - buf)) ? (str - buf) : size);
}

int snprintf(char *buf, int size, const char *fmt, ...) {
    va_list args;
    int i;

    va_start(args, fmt);
    i = vsnprintf(buf, size, fmt, args);
    va_end(args);
    return i;
}

int sprintf(char *buf, const char *fmt, ...) {
    va_list args;
    int i;

    va_start(args, fmt);
    i = vsprintf(buf, fmt, args);
    va_end(args);
    return i;
}

void *memset(void *dst, int c, uint n) {
    char *cdst = (char *) dst;
    int i;
    for (i = 0; i < n; i++) {
        cdst[i] = c;
    }
    return dst;
}

int memcmp(const void *v1, const void *v2, uint n) {
    const uchar *s1, *s2;

    s1 = v1;
    s2 = v2;
    while (n-- > 0) {
        if (*s1 != *s2)
            return *s1 - *s2;
        s1++, s2++;
    }

    return 0;
}

void *memmove(void *dst, const void *src, uint n) {
    const char *s;
    char *d;

    if (n == 0)
        return dst;

    s = src;
    d = dst;
    if (s < d && s + n > d) {
        s += n;
        d += n;
        while (n-- > 0) {
            *--d = *--s;
        }

    } else
        while (n-- > 0) {

            *d++ = *s++;
        }

    return dst;
}

int memcpy(void *dst, const void *src, uint n) {
    memmove(dst, src, n);
    return 0;
}

int strncmp(const char *p, const char *q, uint n) {
    while (n > 0 && *p && *p == *q)
        n--, p++, q++;
    if (n == 0)
        return 0;
    return (uchar) *p - (uchar) *q;
}

int strcmp(const char *p, const char *q) {
    while (*p && *p == *q)
        p++, q++;
    return (uchar) *p - (uchar) *q;
}

