}

char *strchr(const char *str, int c) {
    while (*str != '\0') {
        if (*str == (char) c) {
            return (char *) str;
        }
        str++;
    }
    if (c == '\0') {
        return (char *) str;
    }
    return NULL;
}

int str_split(const char *str, const char ch, char *str1, char *str2) {
    char *p = strchr(str, ch);
    if (p == NULL) {
        return -1;
    }
    strncpy(str1, str, p - str);
    strncpy(str2, p + 1, strlen(str) - 1 - (p - str));

    return 1;
}

char *strcat(char *dest, const char *src) {
    char *p = dest;
    while (*p) {
        ++p;
    }
    while (*src) {
        *p++ = *src++;
    }
    *p = '\0';
    return dest;
}

void timer_init() {
    timer_entry_init(&timer_head, "timer_entry");
    Info("timer init [ok]\n");
}

void timer_entry_init(struct timer_entry *t_entry, char *name) {
    init_lock(&t_entry->lock, name);
    INIT_LIST_HEAD(&t_entry->entry);
}

void add_timer_atomic(struct timer_list *timer, uint64 expires, fn_when_expire fn, void *data) {
    timer->data = data;
    timer->expires_end = expires + TIME2NS(rdtime());
    timer->expires = expires;
    timer->fn = fn;
    if (!list_empty(&timer->list)) {
        return;
    }

    acquire(&timer_head.lock);
    list_add_tail(&timer->list, &timer_head.entry);
    release(&timer_head.lock);
}

void delete_timer_atomic(struct timer_list *timer) {
    acquire(&timer_head.lock);
    list_del_reinit(&timer->list);
    release(&timer_head.lock);
}

void timer_list_decrease_atomic(struct timer_entry *head) {
    struct timer_list *timer_cur;
    struct timer_list *timer_tmp;

    acquire(&head->lock);
    list_for_each_entry_safe(timer_cur, timer_tmp, &head->entry, list) {
        if (TIME_OUT(timer_cur)) {
            timer_cur->fn(timer_cur->data);
            if (timer_cur->count == -1) {
                // if(timer_cur->interval)
                if (timer_cur->interval == -1)
                    // special for pdflush
                    timer_cur->expires_end = timer_cur->expires + TIME2NS(rdtime());
                else
                    // special for setitimer
                    timer_cur->expires_end = timer_cur->interval + TIME2NS(rdtime());
            } else {
                list_del_reinit(&timer_cur->list);
                timer_cur->expires_end = 0;
                timer_cur->expires = 0;
            }
        }
    }
    release(&head->lock);
}

static uint64 page_to_offset(struct phys_mem_pool *pool, struct page *page) {
    return (page - pool->page_metadata) * PGSIZE;
}

static struct page *offset_to_page(struct phys_mem_pool *pool, uint64 offset) {
    ASSERT(offset % PGSIZE == 0);
    return (offset / PGSIZE + pool->page_metadata);
}

static struct page *get_buddy(struct phys_mem_pool *pool, struct page *page) {
    ASSERT(page->order < BUDDY_MAX_ORDER);
    const uint64 this_off = page_to_offset(pool, page);
    const uint64 buddy_off = this_off ^ (1UL << (page->order + 12));

    /* Check whether the buddy belongs to pool */
    if (buddy_off >= pool->mem_size) {
        return NULL;
    }

    return offset_to_page(pool, buddy_off);
}

void mm_init() {
    // readonly! can not modify!
    printf("phys top: %p\n", PHYSTOP);
    pagemeta_start = (struct page *) PGROUNDUP((uint64) end);
    printf("pagemeta_start %x\n", pagemeta_start);
    printf("NPAGES: %p\n", NPAGES);
    printf("PAGES PER CPU: %p\n", PAGES_PER_CPU);
    for (int i = 0; i < NCPU; i++) {
        init_buddy(&mem_pools[i], (struct page *) PGROUNDUP((uint64) end) + i * PAGES_PER_CPU,
                   (uint64) START_MEM + i * PAGES_PER_CPU * PGSIZE, PAGES_PER_CPU);
    }
}

void init_buddy(struct phys_mem_pool *pool, struct page *start_page, uint64 start_addr, uint64 page_num) {
    printf("%p pagemeta start: %x\n", cur, start_page);
    printf("%p pagemeta end: %x\n", cur, (uint64) start_page + page_num * sizeof(struct page));
    ASSERT((uint64) start_page + page_num * sizeof(struct page) < START_MEM);
    pool->start_addr = start_addr;
    pool->page_metadata = start_page;
    pool->mem_size = PGSIZE * page_num;

    cur++;

    /* Init the spinlock */
    init_lock(&pool->lock, "buddy_phy_mem_pools_lock");

    /* Init the free lists */
    for (int order = 0; order <= BUDDY_MAX_ORDER; ++order) {
        INIT_LIST_HEAD(&pool->freelists[order].lists);
        pool->freelists[order].num = 0;
    }

    /* Clear the page_metadata area. */
    memset(pool->page_metadata, 0, page_num * sizeof(struct page));

    /* Init the page_metadata area. */
    struct page *page;
    for (int page_idx = 0; page_idx < page_num; ++page_idx) {
        page = start_page + page_idx;
        page->allocated = 1;
        page->order = 0;
        init_lock(&page->lock, "page_lock");
    }

    /* Put each physical memory page into the free lists. */
    for (int page_idx = 0; page_idx < page_num; ++page_idx) {
        page = start_page + page_idx;
        buddy_free_pages(pool, page);
    }

    /* make sure the buddy_free_pages works correctly */
    uint64 memsize = 0;
    for (int i = 0; i <= BUDDY_MAX_ORDER; i++) {
        memsize += pool->freelists[i].num * PGSIZE * (1 << i);
    }
    printf("memsize: %u\n", memsize / 1024 / 1024);
    // ASSERT(memsize == pool->mem_size);
}

struct page *buddy_get_pages(struct phys_mem_pool *pool, const uint64 order) {
    pop_off();

    ASSERT(order <= BUDDY_MAX_ORDER);
    struct page *page = NULL;

    acquire(&pool->lock);
    for (int i = order; i <= BUDDY_MAX_ORDER; i++) {
        const struct list_head *lists = &pool->freelists[i].lists;
        if (!list_empty(lists)) {
            page = list_first_entry(lists, struct page, list);
            list_del(&page->list);
            pool->freelists[page->order].num--;
            break;
        }
    }

    if (page == NULL) {
        release(&pool->lock);
        return NULL;
    }

    if (page->order > order) {
        page = split_page(pool, order, page);
    }
    page->allocated = 1;
    ASSERT(page->order == order);
    release(&pool->lock);
    return page;
}

static struct page *split_page(struct phys_mem_pool *pool, const uint64 order, struct page *page) {
    ASSERT(page->order > order);

    while (page->order > order) {
        page->order--;
        struct page *buddy = get_buddy(pool, page);
        ASSERT(buddy->allocated == 0);
        buddy->order = page->order;

        list_add(&buddy->list, &pool->freelists[buddy->order].lists);
        pool->freelists[buddy->order].num++;
    }
    return page;
}

void buddy_free_pages(struct phys_mem_pool *pool, struct page *page) {
    acquire(&pool->lock);
    page->allocated = 0;

    if (page->order < BUDDY_MAX_ORDER) {
        page = merge_page(pool, page);
    }

    struct list_head *list = &pool->freelists[page->order].lists;
    list_add(&page->list, list);
    pool->freelists[page->order].num++;
    release(&pool->lock);
}

static struct page *merge_page(struct phys_mem_pool *pool, struct page *page) {
    if (page->order == BUDDY_MAX_ORDER) {
        return page;
    }

    static int max = 0;

    struct page *buddy = get_buddy(pool, page);
    if (buddy == NULL) {
        // this page doesn't have buddy
        return page;
    }

    ASSERT(buddy != NULL);
    if (buddy->allocated == 0 && buddy->order == page->order) {
        // get the buddy page out of the list
        list_del(&buddy->list);
        pool->freelists[buddy->order].num--;

        // merge buddy with current page
        struct page *merge = ((uint64) buddy < (uint64) page ? buddy : page);
        merge->order++;
        if (merge->order > max) {
            max = merge->order;
            // Log("%d", max);
        }
        return merge_page(pool, merge);
    }
    return page;
}

uint64 get_free_mem() {
    uint64 memsize = 0;
    for (int cpu = 0; cpu < NCPU; cpu++) {
        struct phys_mem_pool *pool = &mem_pools[cpu];
        acquire(&pool->lock);
        for (int i = 0; i <= BUDDY_MAX_ORDER; i++) {
            memsize += pool->freelists[i].num * PGSIZE * (1 << i);
        }
        release(&pool->lock);
    }
    return memsize;
}

struct page *steal_mem(const int cur_id, const uint64 order) {
    struct page *page = NULL;
    for (int i = 0; i < NCPU; i++) {
        if (i == cur_id) {
            continue;
        }
        // TODO
        push_off();
        page = buddy_get_pages(&mem_pools[i], order);
        if (page != NULL) {
            return page;
        }
    }
    ASSERT(page == NULL);
    return page;
}

uint64 size_to_page_order(const uint64 size) {

    uint64 order = 0;
    const uint64 page_num = ROUND_UP(size, PGSIZE) / PGSIZE;
    uint64 tmp = page_num;

    while (tmp > 1) {
        tmp >>= 1;
        order += 1;
    }

    if (page_num > (1 << order)) {
        order += 1;
    }

    return order;
}

void *kmalloc(const size_t size) {
    uint64 order;
    if (size <= PGSIZE) {
        order = 0;
    } else {
        order = size_to_page_order(size);
    }

    push_off();
    const int id = cpuid();
    ASSERT(id >= 0 && id < NCPU);
    struct page *page = buddy_get_pages(&mem_pools[id], order);

    if (page == NULL) {
        page = steal_mem(id, order);
        if (page == NULL) {
            return 0;
        }
    }

    acquire(&page->lock);
    ASSERT(page->count == 0);
    page->count = 1;
    release(&page->lock);
    return (void *) page_to_pa(page);
}

void *kzalloc(const size_t size) {

    void *ptr = kmalloc(size);

    /* lack of memory */
    if (ptr == NULL)
        return NULL;

    memset(ptr, 0, size);
    return ptr;
}

void *kalloc(void) {
    const int order = 0;

    push_off();
    const int id = cpuid();
    ASSERT(id >= 0 && id < NCPU);
    struct page *page = buddy_get_pages(&mem_pools[id], order);

    if (page == NULL) {
        page = steal_mem(id, order);
        if (page == NULL) {
            return 0;
        }
    }

    acquire(&page->lock);
    ASSERT(page->count == 0);
    page->count = 1;
    release(&page->lock);
    return (void *) page_to_pa(page);
}

void kfree(void *pa) {
    struct page *page = pa_to_page((uint64) pa);
    acquire(&page->lock);
    ASSERT(page->count >= 1);
    page->count--;
    if (page->count >= 1) {
        release(&page->lock);
        return;
    }
    ASSERT(page->count == 0);
    release(&page->lock);

    ASSERT(page->allocated == 1);
    const int id = get_pages_cpu(page);
    ASSERT(id >= 0 && id < NCPU);
    buddy_free_pages(&mem_pools[id], page);
}

void share_page(const uint64 pa) {
    struct page *page = pa_to_page(pa);
    acquire(&page->lock);
    ASSERT(page->count >= 1);
    page->count++;
    release(&page->lock);
}

struct mm_struct *alloc_mm() {
    struct mm_struct *mm = kzalloc(sizeof(struct mm_struct));
    if (mm == NULL) {
        return NULL;
    }
    mm->start_brk = mm->brk = 0;
    mm->heap_vma = NULL;
    INIT_LIST_HEAD(&mm->head_vma);
    sem_init(&mm->mmap_sem, 1, "mmap_sem");
    init_lock(&mm->lock, "mm_lock");
    mm->pagetable = proc_pagetable();
    if (mm->pagetable == NULL) {
        kfree(mm);
        return NULL;
    }
    return mm;
}

void free_mm(struct mm_struct *mm, const int thread_idx) {
    if (mm == NULL) {
        Info("free_mm: mm is NULL\n");
        return;
    }

    if (mm->pagetable)
        proc_free_pagetable(mm, thread_idx);

    mm->pagetable = 0;
    mm->brk = 0;
    kfree(mm);
}

uint64 sys_munmap(void) {
    vaddr_t addr;
    size_t length;
    arg_addr(0, &addr);
    arg_ulong(1, &length);

    /* free all mappings within the range */
    struct mm_struct *mm = proc_current()->mm;
    struct vma *vma;
    struct vma *next;
    list_for_each_entry_safe(vma, next, &mm->head_vma, node) {
        if (vma->startva + vma->size > addr && vma->startva < addr + length) {
            vmspace_unmap(mm, vma->startva, vma->size);
        }
    }

    return 0;
}

static uint64 mkperm(int prot, int flags) {
    uint64 perm = 0;
    if (flags & MAP_SHARED) {
        perm |= PERM_SHARED;
    }
    return (perm | prot);
}

void *do_mmap(vaddr_t addr, size_t length, int prot, int flags, struct file *fp, off_t offset) {
    struct mm_struct *mm = proc_current()->mm;
    vaddr_t mapva = 0;
    if (addr == 0) {
        mapva = find_mapping_space(mm, addr, length);
    } else {
        if ((flags & MAP_FIXED) == 0) {
            Info("mmap: not support");
            return MAP_FAILED;
        }

        uint64 start, end;
        start = addr;
        end = addr + length;
        struct vma *vma;
        if ((vma = find_vma_for_va(mm, addr)) != NULL) {
            if (start != vma->startva) {
                if (split_vma(mm, vma, start, 1) < 0) {
                    return MAP_FAILED;
                }
            }

            if (end != vma->startva + vma->size) {
                if (split_vma(mm, vma, end, 0) < 0) {
                    return MAP_FAILED;
                }
            }

            if (vma->type == VMA_HEAP) {
                struct vma *pos;

                list_for_each_entry(pos, &mm->head_vma, node) {
                    if (pos->type == VMA_HEAP && pos->startva + pos->size == mm->brk) {
                        mm->heap_vma = pos;
                    }
                }
            }
            if (vma != NULL) {
                del_vma_from_vmspace(&mm->head_vma, vma);
            }
            mapva = addr;
        }
    }
    if (flags & MAP_ANONYMOUS || fp == NULL) {
        if (vma_map(mm, mapva, length, mkperm(prot, flags), VMA_ANON) < 0) {
            return MAP_FAILED;
        }
    } else {
        if (vma_map_file(mm, mapva, length, mkperm(prot, flags), VMA_FILE, offset, fp) < 0) {
            return MAP_FAILED;
        }
    }

    return (void *) (mapva);
}

void *sys_mmap(void) {
    vaddr_t addr;
    size_t length;
    int prot;
    int flags;
    int fd;
    off_t offset;
    struct file *fp;
    arg_addr(0, &addr);
    arg_ulong(1, &length);
    arg_int(2, &prot);
    arg_int(3, &flags);
    if (arg_fd(4, &fd, &fp) < 0) {
        fp = NULL;
        if ((flags & MAP_ANONYMOUS) == 0) {
            // Log("hit");
        }
    }
    arg_long(5, &offset);

    // printf("mmap: addr=%p, length=%p, prot=%p, flags=%p, fd=%d, offset=%p\n", addr, length, prot, flags, fd, offset);

    if (offset != 0) {
        // Info("mmap: not support");
        // return MAP_FAILED;
    }
    struct mm_struct *m = proc_current()->mm;
    acquire(&m->lock);
    void *retval = do_mmap(addr, length, prot, flags, fp, offset);
    release(&m->lock);

    // printfYELLOW("after mmaping:\n");
    // print_vma(&m->head_vma);

    return retval;
}

uint64 sys_mprotect(void) {
    vaddr_t start;
    size_t len;
    int prot;
    arg_addr(0, &start);
    arg_ulong(1, &len);
    arg_int(2, &prot);
    if (!len)
        return 0;

    len = PGROUNDUP(len);
    uint64 end = start + len;
    if (end < start)
        return -1;

    if (prot & ~(PROT_READ | PROT_WRITE | PROT_EXEC))
        return -1;

    struct vma *vma = find_vma_for_va(proc_current()->mm, start);
    if (!vma) {
        return -1;
    }

    struct mm_struct *mm = proc_current()->mm;
    if (vma->startva != start) {
        if (split_vma(mm, vma, start, 1) < 0) {
            return -1;
        }
    }

    if (vma->startva + vma->size != end) {
        if (split_vma(mm, vma, end, 0) < 0) {
            return -1;
        }
    }

    vma->perm = prot;
    return 0;
}

static uint32 perm_vma2pte(uint32 vma_perm) {
    uint32 pte_perm = 0;
    if (perm_readable(vma_perm)) {
        pte_perm |= PTE_R;
    }
    if (perm_writable(vma_perm)) {
        pte_perm |= PTE_W;
    }
    if (perm_executable(vma_perm)) {
        pte_perm |= PTE_X;
    }
    return pte_perm;
}

int page_fault(uint64 cause, pagetable_t pagetable, vaddr_t st_val) {
    /* the va exceed the MAXVA is illegal */
    if (PGROUNDDOWN(st_val) >= MAXVA) {
        printf("exceed the MAXVA");
        return -1;
    }
    const struct vma *vma = find_vma_for_va(proc_current()->mm, st_val);
    if (vma != NULL) {
        if (!CHECK_PERM(cause, vma)) {
            PAGEFAULT("permission checked failed");
            return -1;
        }
        // printfMAGENTA("page fault: cause: %p, sepc: %p, va: %p, vma: %p\n", cause, r_sepc(), st_val, vma);
        // printfMAGENTA("current vma: %#p-%#p, file:%p\n", vma->startva, vma->startva + vma->size, vma->vm_file);
        // print_vma(&proc_current()->mm->head_vma);
        pte_t *pte;
        const int level = walk(pagetable, st_val, 0, 0, &pte);
        if (pte == NULL || (*pte == 0)) {
            uvm_alloc(pagetable, PGROUNDDOWN(st_val), PGROUNDUP(st_val + 1), perm_vma2pte(vma->perm));
            if (vma->type == VMA_FILE) {
                const paddr_t pa = walk_addr(pagetable, st_val);
                struct inode *f_inode;
                if (vma->vm_file->f_type == FAT32)
                    f_inode = vma->vm_file->f_data.f_vnode->data;
                else
                    f_inode = vfs_ext_namei(vma->vm_file->f_data.f_vnode->path);
                if (!f_inode) {
                    printfMAGENTA("page fault: cause: %p, sepc: %p, va: %p, vma: %p\n", cause, r_sepc(), st_val, vma);
                    printfMAGENTA("current vma: %#p-%#p, file:%p\n", vma->startva, vma->startva + vma->size, vma->vm_file);
                }
                f_inode->i_op->lock(f_inode);
                f_inode->i_op->read(f_inode, 0, pa, vma->offset + PGROUNDDOWN(st_val) - vma->startva, PGSIZE);
                f_inode->i_op->unlock(f_inode);
            }
        } else {
            const uint64 pa = PTE2PA(*pte);
            const uint flags = PTE_FLAGS(*pte);
            ASSERT(flags & PTE_V);
            // vm_print(proc_current()->mm->pagetable, 1, 0, 0, 0);
            /* copy-on-write handler */
            if (is_a_cow_page(flags)) {
                return cow(pte, level, pa, flags);
            }
            return -1;
        }

    } else {
        PAGEFAULT("va is not in the vmas");
        printf("va: %p\n", st_val);
        print_vma(&proc_current()->mm->head_vma);
        return -1;
    }

    return 0;
}

int is_a_cow_page(const int flags) {
    /* write to an unshared page is illegal */
    if ((flags & PTE_SHARE) == 0) {
        PAGEFAULT("cow: try to write a readonly page");
        return 0;
    }

    /* write to readonly shared page is illegal */
    if ((flags & PTE_READONLY) > 0) {
        PAGEFAULT("cow: try to write a readonly shared page");
        return 0;
    }
    return 1;
}

int cow(pte_t *pte, const int level, const paddr_t pa, const int flags) {
    void *mem;
    if (level == SUPERPAGE) {
        // 2MB superpage
        if ((mem = kmalloc(SUPERPGSIZE)) == 0) {
            return -1;
        }
        memmove(mem, (void *) pa, SUPERPGSIZE);
    } else if (level == COMMONPAGE) {
        // common page
        if ((mem = kmalloc(PGSIZE)) == 0) {
            return -1;
        }
        memmove(mem, (void *) pa, PGSIZE);
    } else {
        PAGEFAULT("the level of leaf pte is wrong");
        return -1;
    }

    *pte = PA2PTE((uint64) mem) | flags | PTE_W;
    kfree((void *) pa);
    return 0;
}

pagetable_t kvmmake(void) {

    const pagetable_t kpgtbl = kzalloc(PGSIZE);

    // uart registers
#if defined(VISIONFIVE)
    kvm_map(kpgtbl, UART0, UART0, 0x10000, PTE_R | PTE_W, COMMONPAGE);
#else
    kvm_map(kpgtbl, UART0, UART0, PGSIZE, PTE_R | PTE_W, COMMONPAGE);
#endif

#if defined(QEMU)
    // virtio mmio disk interface
    kvm_map(kpgtbl, VIRTIO0, VIRTIO0, PGSIZE, PTE_R | PTE_W, COMMONPAGE);
#endif

#if defined(VISIONFIVE)
    // sdcard mmio interface
    kvm_map(kpgtbl, SD_BASE, SD_BASE, PGSIZE, PTE_R | PTE_W, COMMONPAGE);
#endif

    // PLIC
    kvm_map(kpgtbl, PLIC, PLIC, 0x400000, PTE_R | PTE_W, SUPERPAGE);

    // CLINT_MTIME
    // map in kernel pagetable, so we can access it in s-mode
    kvm_map(kpgtbl, CLINT_MTIME, CLINT_MTIME, PGSIZE, PTE_R, COMMONPAGE);

    // map kernel text executable and read-only.
    vaddr_t super_aligned_sz = SUPERPG_DOWN((uint64) etext - KERNBASE);
    if (super_aligned_sz != 0) {
        kvm_map(kpgtbl, KERNBASE, KERNBASE, super_aligned_sz, PTE_R | PTE_X, SUPERPAGE);
    }
    kvm_map(kpgtbl, KERNBASE + super_aligned_sz, KERNBASE + super_aligned_sz,
            (uint64) etext - KERNBASE - super_aligned_sz, PTE_R | PTE_X, COMMONPAGE);

    // map kernel data and the physical RAM we'll make use of.
    super_aligned_sz = SUPERPG_DOWN(PHYSTOP - (uint64) etext);
    kvm_map(kpgtbl, (uint64) etext, (uint64) etext, PHYSTOP - (uint64) etext - super_aligned_sz, PTE_R | PTE_W,
            COMMONPAGE);
    kvm_map(kpgtbl, SUPERPG_ROUNDUP((uint64) etext), SUPERPG_ROUNDUP((uint64) etext), super_aligned_sz, PTE_R | PTE_W,
            SUPERPAGE);

    // map the trampoline for trap entry/exit to
    // the highest virtual address in the kernel.
    kvm_map(kpgtbl, TRAMPOLINE, (uint64) trampoline, PGSIZE, PTE_R | PTE_X, COMMONPAGE);

    // allocate and map a kernel stack for each process.
    tcb_mapstacks(kpgtbl);

    return kpgtbl;
}

void kvm_init(void) {
    kernel_pagetable = kvmmake();
    printf("kvmninit done\n");
}

void kvm_init_hart() {
    // wait for any previous writes to the page table memory to finish.
    sfence_vma();

    w_satp(MAKE_SATP(kernel_pagetable));

// #ifdef QEMU
    // flush stale entries from the TLB.
    sfence_vma();
// #endif

    printf("hart %d: kvm_init_hart done\n", cpuid());
}

int walk(pagetable_t pagetable, uint64 va, int alloc, int low_level, pte_t **pte) {
    if (va >= MAXVA)
        panic("walk");

    for (int level = LEVELS - 1; level > low_level; level--) {
        pte_t *pte_tmp = &pagetable[PN(level, va)];
        if (*pte_tmp & PTE_V) {
            // find a superpage leaf PTE
            if ((*pte_tmp & PTE_R) || (*pte_tmp & PTE_X)) {
                *pte = pte_tmp;
                /* assert: only support 2MB leaf-pte */
                ASSERT(level == 1);
                return level;
            }
            pagetable = (pagetable_t) PTE2PA(*pte_tmp);
        } else {
            if (!alloc || (pagetable = (pde_t *) kzalloc(PGSIZE)) == 0) {
                *pte = 0;
                return -1;
            }
            *pte_tmp = PA2PTE(pagetable) | PTE_V;
        }
    }
    *pte = (pte_t *) &pagetable[PN(low_level, va)];
    return 0;
}

paddr_t get_phyaddr(pagetable_t pagetable, vaddr_t va) {
    const vaddr_t aligned_va = PGROUNDDOWN(va);
    const paddr_t aligned_pa = walk_addr(pagetable, va);
    if (aligned_pa == 0) {
        return 0;
    }
    return aligned_pa + (va - aligned_va);
}

uint64 walk_addr(pagetable_t pagetable, uint64 va) {
    pte_t *pte;

    if (va >= MAXVA)
        return 0;

    const int level = walk(pagetable, va, 0, 0, &pte);
    ASSERT(level <= 1);
    if (pte == 0 || (*pte & PTE_V) == 0 || (*pte & PTE_U) == 0)
        return 0;
    const uint64 pa = PTE2PA(*pte);
    if (level == COMMONPAGE) {
        return pa;
    }
    if (level == SUPERPAGE) {
        return pa + (PGROUNDDOWN(va) - SUPERPG_DOWN(va));
    }
    panic("can not reach here");
}

void kvm_map(pagetable_t kernelPageTable, uint64 va, uint64 pa, uint64 size, int perm, int low_level) {
    if (map_pages(kernelPageTable, va, size, pa, perm, low_level) != 0)
        panic("kvm_map");
}

int map_pages(pagetable_t pageTable, uint64 va, uint64 size, uint64 pa, int perm, int lowLevel) {
    uint64 a, last;
    pte_t *pte;

#ifdef VISIONFIVE
    perm |= PTE_A | PTE_D;
#endif

    if (size == 0)
        panic("map_pages: size");

    uint64 page_size;
    switch (lowLevel) {
        case 0: {
            page_size = PGSIZE;
            a = PGROUNDDOWN(va);
            last = PGROUNDDOWN(va + size - 1);
            break;
        }
        case 1: {
            page_size = SUPERPGSIZE;
            /* if this is a superpage mapping, the va needs to be superpage aligned */
            ASSERT(va % SUPERPGSIZE == 0);
            a = SUPERPG_DOWN(va);
            last = SUPERPG_DOWN(va + size - 1);
            break;
        }
        default:
            panic("map_pages: not support");
            break;
    }

    for (;;) {
        walk(pageTable, a, 1, lowLevel, &pte);
        if (pte == 0) {
            return -1;
        }
        if (*pte & PTE_V) {
            vm_print(pageTable, 1, 0, 0, 0);
            Log("remap pte is %x", *pte);
            Log("remap pa is %x", PTE2PA(*pte));
            panic("map_pages: remap");
        }
        *pte = PA2PTE(pa) | perm | PTE_V;
        if (a == last)
            break;
        a += page_size;
        pa += page_size;
    }
    return 0;
}

void uvm_unmap(pagetable_t pagetable, uint64 va, uint64 n_pages, int do_free, int on_demand) {
    pte_t *pte;

    if ((va % PGSIZE) != 0)
        panic("uvm_unmap: not aligned");

    const uint64 end_va = va + n_pages * PGSIZE;

    for (uint64 a = va; a < end_va; a += PGSIZE) {
        const int level = walk(pagetable, a, 0, 0, &pte);
        if (pte == 0) {
            if (on_demand == 1) {
                continue;
            }
            panic("uvm_unmap: walk");
        }
        if ((*pte & PTE_V) == 0) {
            if (on_demand == 1) {
                continue;
            }
            vm_print(pagetable, 1, 0, 0, 0);
            printf("va is %p\n", va);
            panic("uvm_unmap: not mapped");
        }
        if (PTE_FLAGS(*pte) == PTE_V)
            panic("uvm_unmap: not a leaf");

        ASSERT(level <= 1);

        if (do_free) {
            uint64 pa = PTE2PA(*pte);
            kfree((void *) pa);
        }
        const uint64 pte_flags = PTE_FLAGS(*pte);
        *pte = 0;

        if (level == SUPERPAGE) {
            if (a != SUPERPG_DOWN(a) && a == va) {
                uvm_alloc(pagetable, SUPERPG_DOWN(a), a, pte_flags);
            }
            a += (SUPERPGSIZE - PGSIZE);
        }
    }
}

pagetable_t uvm_create() {
    const pagetable_t pagetable = kalloc();
    if (pagetable == 0)
        return 0;
    memset(pagetable, 0, PGSIZE);
    return pagetable;
}

uint64 uvm_alloc(pagetable_t pagetable, uint64 start_va, uint64 end_va, int xperm) {
    char *mem;

    if (end_va < start_va)
        return start_va;

    const uint64 aligned_sz = PGROUNDUP(start_va);
    const uint64 super_aligned_sz = SUPERPG_ROUNDUP(start_va);
    const uint64 min = (end_va <= super_aligned_sz ? end_va : super_aligned_sz);

    for (uint64 a = aligned_sz; a < min; a += PGSIZE) {
        mem = kzalloc(PGSIZE);
        if (mem == 0) {
            uvm_dealloc(pagetable, a, start_va);
            return 0;
        }
        if (map_pages(pagetable, a, PGSIZE, (uint64) mem, PTE_R | PTE_U | xperm, COMMONPAGE) != 0) {
            kfree(mem);
            uvm_dealloc(pagetable, a, start_va);
            return 0;
        }
    }

    if (end_va <= super_aligned_sz) {
        ASSERT(min == end_va);
        return end_va;
    }
    uint64 addr;
    const uint64 newsz_down = SUPERPG_DOWN(end_va);
    for (addr = super_aligned_sz; addr < newsz_down; addr += SUPERPGSIZE) {
        mem = kzalloc(SUPERPGSIZE);
        if (mem == 0) {
            uvm_dealloc(pagetable, addr, start_va);
            return 0;
        }
        if (map_pages(pagetable, addr, SUPERPGSIZE, (uint64) mem, PTE_R | PTE_U | xperm, SUPERPAGE) != 0) {
            kfree(mem);
            uvm_dealloc(pagetable, addr, start_va);
            return 0;
        }
    }

    for (addr = newsz_down; addr < end_va; addr += PGSIZE) {
        mem = kzalloc(PGSIZE);
        if (mem == 0) {
            uvm_dealloc(pagetable, addr, start_va);
            return 0;
        }
        if (map_pages(pagetable, addr, PGSIZE, (uint64) mem, PTE_R | PTE_U | xperm, COMMONPAGE) != 0) {
            kfree(mem);
            uvm_dealloc(pagetable, addr, start_va);
            return 0;
        }
    }

    return end_va;
}

uint64 uvm_dealloc(pagetable_t pagetable, uint64 oldsz, uint64 newsz) {
    if (newsz >= oldsz)
        return oldsz;

    if (PGROUNDUP(newsz) < PGROUNDUP(oldsz)) {
        const int npages = (PGROUNDUP(oldsz) - PGROUNDUP(newsz)) / PGSIZE;
        uvm_unmap(pagetable, PGROUNDUP(newsz), npages, 1, 0);
    }

    return newsz;
}

void free_walk(pagetable_t pagetable) {
    if (pagetable == 0)
        return;
    // there are 2^9 = 512 PTEs in a page table.
    for (int i = 0; i < 512; i++) {
        const pte_t pte = pagetable[i];
        if ((pte & PTE_V) && (pte & (PTE_R | PTE_W | PTE_X)) == 0) {
            // this PTE points to a lower-level page table.
            const uint64 child = PTE2PA(pte);
            free_walk((pagetable_t) child);
            pagetable[i] = 0;
        } else if (pte & PTE_V) {
            Info("pa: %p\n", PTE2PA(pte));
            panic("free_walk: leaf");
        }
    }
    if (pagetable)
        kfree((void *) pagetable);
}

void uvm_free(mm_ptr_t mm) {
    free_all_vmas(mm);
    free_walk(mm->pagetable);
}

int uvm_copy(mm_ptr_t src, mm_ptr_t dst) {
    uint64 i;
    struct vma *pos = NULL;
    list_for_each_entry(pos, &src->head_vma, node) {
        paddr_t pa;
        pte_t *pte;
        int level;
        if (pos->type == VMA_STACK) {
            for (uint64 offset = 0; offset < pos->size; offset += PGSIZE) {
                level = walk(src->pagetable, pos->startva + offset, 0, 0, &pte);
                if (!(level <= 1 && level >= 0)) {
                    panic("uvmcopy : level error\n");
                }
                pa = PTE2PA(*pte);
                paddr_t new = (paddr_t) kalloc();
                if (new == 0) {
                    Info("uvmcopy: no free mem");
                    return -1;
                }
                memmove((void *) new, (void *) pa, PGSIZE);
                if (map_pages(dst->pagetable, pos->startva + offset, PGSIZE, new, PTE_W | PTE_R | PTE_U, COMMONPAGE) !=
                    0) {
                    panic("uvmcopy: map failed");
                    return -1;
                }
            }
            continue;
        }
        const vaddr_t startva = pos->startva;
        const vaddr_t endva = startva + pos->size;
        ASSERT(startva % PGSIZE == 0 && endva % PGSIZE == 0);
        for (vaddr_t i = startva; i < endva; i += PGSIZE) {
            level = walk(src->pagetable, i, 0, 0, &pte);
            if (pte == NULL || *pte == 0) {
                continue;
            }
            if (!(level <= 1 && level >= 0)) {
                panic("uvmcopy : level error\n");
            }

            if (pos->type != VMA_FILE || !(pos->perm & PERM_SHARED)) {
                // if (pos->type != VMA_FILE) {
                if ((*pte & PTE_W) == 0 && (*pte & PTE_SHARE) == 0) {
                    *pte = *pte | PTE_READONLY;
                }
                /* shared page */
                if ((*pte & PTE_W) == 0 && (*pte & PTE_READONLY) != 0) {
                    *pte = *pte | PTE_READONLY;
                }
                *pte = *pte | PTE_SHARE;
                *pte = *pte & ~PTE_W;
            }

            pa = PTE2PA(*pte);
            const uint flags = PTE_FLAGS(*pte);

            if (level == SUPERPAGE) {
                /* level == 1 ~ map superpage */
                ASSERT(i == SUPERPG_DOWN(i));
                if (map_pages(dst->pagetable, i, SUPERPGSIZE, pa, flags, SUPERPAGE) != 0) {
                    goto err;
                }
                i += (SUPERPGSIZE - PGSIZE);
            } else if (level == COMMONPAGE) {
                /* level == 0 ~ map common page */
                if (map_pages(dst->pagetable, i, PGSIZE, pa, flags, COMMONPAGE) != 0) {
                    goto err;
                }
            }
            /* call share_page after mappages success! */
            share_page(pa);
        }
    }
    return 0;

err:
    uvm_unmap(dst, 0, i / PGSIZE, 0, 0);
    return -1;
}

void uvm_clear(pagetable_t pagetable, uint64 va) {
    pte_t *pte;

    walk(pagetable, va, 0, 0, &pte);
    if (pte == 0)
        panic("uvm_clear");
    *pte &= ~PTE_U;
}

int copy_out(pagetable_t pagetable, uint64 dst_va, char *src, uint64 len) {
    while (len > 0) {
        const uint64 va0 = PGROUNDDOWN(dst_va);
        pte_t *pte;
        /* since walk will panic if va0 > maxva, so we have to handle this error before walk */
        if (va0 >= MAXVA) {
            return -1;
        }
        walk(pagetable, va0, 0, 0, &pte);
        if (pte == 0 || *pte == 0) {
            if (page_fault(STORE_PAGEFAULT, pagetable, dst_va) < 0) {
                return -1;
            }
        }
        const int flags = PTE_FLAGS(*pte);
        if ((flags & PTE_W) == 0 && is_a_cow_page(flags)) {
            if (page_fault(STORE_PAGEFAULT, pagetable, dst_va) < 0) {
                return -1;
            }
        }
        const uint64 pa0 = walk_addr(pagetable, va0);
        if (pa0 == 0)
            return -1;
        uint64 n = PGSIZE - (dst_va - va0);
        if (n > len)
            n = len;
        memmove((void *) (pa0 + (dst_va - va0)), src, n);

        len -= n;
        src += n;
        dst_va = va0 + PGSIZE;
    }
    return 0;
}

int copy_in(pagetable_t pagetable, char *dst, uint64 src_va, uint64 len) {

    while (len > 0) {
        const uint64 va0 = PGROUNDDOWN(src_va);
        const uint64 pa0 = walk_addr(pagetable, va0);
        if (pa0 == 0)
            return -1;
        uint64 n = PGSIZE - (src_va - va0);
        if (n > len)
            n = len;
        memmove(dst, (void *) (pa0 + (src_va - va0)), n);

        len -= n;
        dst += n;
        src_va = va0 + PGSIZE;
    }
    return 0;
}

int copy_in_str(pagetable_t pagetable, char *dst, uint64 src_va, uint64 max) {
    int got_null = 0;

    while (got_null == 0 && max > 0) {
        const uint64 va0 = PGROUNDDOWN(src_va);
        const uint64 pa0 = walk_addr(pagetable, va0);
        if (pa0 == 0)
            return -1;
        uint64 n = PGSIZE - (src_va - va0);
        if (n > max)
            n = max;

        char *p = (char *) (pa0 + (src_va - va0));
        while (n > 0) {
            if (*p == '\0') {
                *dst = '\0';
                got_null = 1;
                break;
            } else {
                *dst = *p;
            }
            --n;
            --max;
            p++;
            dst++;
        }

        src_va = va0 + PGSIZE;
    }
    if (got_null) {
        return 0;
    }
    return -1;
}

void vm_print_indent(int level, int vpn) {
    switch (level) {
        case 0:
            printf(" ..%d: ", vpn);
            break;
        case 1:
            printf(" .. ..%d: ", vpn);
            break;
        case 2:
            printf(" .. .. ..%d: ", vpn);
            break;
        default:
            panic("should not reach here");
    }
}

void vm_print(pagetable_t pagetable, int is_root, int level, int single, uint64 va_base) {
    if (is_root) {
        printf("page table %p\n", pagetable);
    }

    uint64 vagap;
    switch (level) {
        case 0:
            vagap = SUPERPGSIZE * 512;
            break;
        case 1:
            vagap = SUPERPGSIZE;
            break;
        case 2:
            vagap = PGSIZE;
            break;
        default:
            panic("wrong argument");
    }

    for (int i = 0; i < 512; i++) {
        const pte_t pte = pagetable[i];
        if (pte & PTE_V) {
            vm_print_indent(level, i);
            if (!single && (pte & (PTE_W | PTE_X | PTE_R)) == 0) {
                // not a leaf-pte
                printf("pte %p pa %p\n", pte, PTE2PA(pte));
                vm_print((pagetable_t) PTE2PA(pte), 0, level + 1, 0, va_base + i * vagap);
            } else {
                // a leaf-pte
                printf("leaf pte %p pa %p ", pte, PTE2PA(pte));
                PTE("RSW %d%d D %d U %d X %d W %d R %d  va is %p\n", (pte & PTE_READONLY) > 0, (pte & PTE_SHARE) > 0,
                    (pte & PTE_D) > 0, (pte & PTE_U) > 0, (pte & PTE_X) > 0, (pte & PTE_W) > 0, (pte & PTE_R) > 0,
                    va_base + i * vagap);
            }
        }
    }
}

int uvm_thread_stack(mm_ptr_t mm, int ustack_page) {
    const vaddr_t stack_down = USTACK;
    if (uvm_alloc(mm->pagetable, stack_down, stack_down + ustack_page * PGSIZE, PTE_W | PTE_R) == 0) {
        return -1;
    }
    vma_map(mm, USTACK, ustack_page * PGSIZE, PERM_READ | PERM_WRITE, VMA_STACK);
    uvm_clear(mm->pagetable, USTACK);
    return 0;
}

struct trapframe *uvm_thread_trapframe(pagetable_t pagetable, int thread_idx) {
    const paddr_t pa = (paddr_t) kzalloc(PGSIZE);

    if (map_pages(pagetable, TRAPFRAME - thread_idx * PGSIZE, PGSIZE, pa, PTE_R | PTE_W, 0) < 0) {
        kfree((void *) pa);
        return NULL;
    }

    return (struct trapframe *) pa;
}

void vmas_init() {
    init_lock(&vmas_lock, "vmas_lock");
    memset(vmas, 0, sizeof(vmas));
    printf("vmas_init done\n");
}

static struct vma *alloc_vma(void) {
    // 1. slab allocator
    // 2. fine grained lock
    acquire(&vmas_lock);
    for (int i = 0; i < NVMA; i++) {
        if (vmas[i].used == 0) {
            vmas[i].used = 1;
            release(&vmas_lock);
            return &vmas[i];
        }
    }
    release(&vmas_lock);
    return 0;
}

void free_vma(struct vma *vma) {
    acquire(&vmas_lock);
    vma->used = 0;
    release(&vmas_lock);
}

static int check_vma_intersect(struct list_head *vma_head, struct vma *checked_vma) {
    struct vma *pos;

    const vaddr_t checked_start = checked_vma->startva;
    const vaddr_t checked_end = checked_start + checked_vma->size - 1;

    list_for_each_entry(pos, vma_head, node) {
        const vaddr_t start = pos->startva;
        const vaddr_t end = pos->startva + pos->size;
        if ((checked_start >= start && checked_start < end) || (checked_end >= start && checked_end < end)) {
            return 1;
        }
    }
    return 0;
}

static int add_vma_to_vmspace(struct list_head *head, struct vma *vma) {
    if (check_vma_intersect(head, vma) != 0) {
        print_vma(head);
        printf("new vma: %#p-%#p\n", vma->startva, vma->startva + vma->size);
        Log("add_vma_to_vmspace: vma overlap\n");
        ASSERT(0);
        return -1;
    }

    list_add(&vma->node, head);
    return 0;
}

static int is_vma_in_vmspace(struct list_head *vma_head, struct vma *vma) {
    struct vma *pos;

    list_for_each_entry(pos, vma_head, node) {
        if (pos == vma) {
            return 1;
        }
    }

    return 0;
}

void del_vma_from_vmspace(struct list_head *vma_head, struct vma *vma) {
    if (is_vma_in_vmspace(vma_head, vma)) {
        list_del(&(vma->node));
    }
    free_vma(vma);
}

int vma_map_file(struct mm_struct *mm, uint64 va, size_t len, uint64 perm, uint64 type, off_t offset, struct file *fp) {
    struct vma *vma;
    /* the file isn't writable and perm has PERM_WRITE is illegal
       but if the PERM_SHARED is not set(means PERM_PRIVATE), then it's ok */
    if (!F_WRITEABLE(fp) && ((perm & PERM_WRITE) && (perm & PERM_SHARED))) {
        return -1;
    }
    if ((vma = vma_map_range(mm, va, len, perm, type)) == NULL) {
        return -1;
    }
    // vma->fd = fd;
    vma->offset = offset;
    vma->vm_file = fp;
    vma->vm_file->f_op->dup(vma->vm_file);
    return 0;
}

int vma_map(struct mm_struct *mm, uint64 va, size_t len, uint64 perm, uint64 type) {
    struct vma *vma;
    if ((vma = vma_map_range(mm, va, len, perm, type)) == NULL) {
        return -1;
    } else {
        if (type == VMA_HEAP) {
            mm->heap_vma = vma;
        }
        return 0;
    }
}

struct vma *vma_map_range(struct mm_struct *mm, uint64 va, size_t len, uint64 perm, uint64 type) {
    struct vma *vma;
    vma = alloc_vma();
    if (vma == NULL) {
        return 0;
    }

    // not support
    ASSERT(va % PGSIZE == 0);

    vma->startva = PGROUNDDOWN(va);
    if (len < PGSIZE) {
        len = PGSIZE;
    }
    vma->size = PGROUNDUP(len);
    vma->perm = perm;
    vma->type = type;

    if (add_vma_to_vmspace(&mm->head_vma, vma) < 0) {
        goto free_vma;
    }
    return vma;

free_vma:
    free_vma(vma);
    return 0;
}

static void writeback(pagetable_t pagetable, struct file *fp, vaddr_t start, size_t len) {
    ASSERT(start % PGSIZE == 0);
    ASSERT(fp != NULL);

    if (!strncmp(fp->f_data.f_vnode->path, "/dev/shm", 8)) {
        return;
    }

    pte_t *pte;
    const vaddr_t endva = start + len;
    for (vaddr_t addr = start; addr < endva; addr += PGSIZE) {
        walk(pagetable, addr, 0, 0, &pte);
        if (pte == NULL || (*pte & PTE_V) == 0) {
            continue;
        }
        /* only writeback dirty pages(pages with PTE_D) */
        if (PTE_FLAGS(*pte) & PTE_D) {
            fp->f_op->write(fp, 1, addr, (PGSIZE > (endva - addr) ? (endva - addr) : PGSIZE));
        }
    }
}

int vmspace_unmap(struct mm_struct *mm, vaddr_t va, size_t len) {
    struct vma *vma = find_vma_for_va(mm, va);
    if (!vma) {
        return -1;
    }

    const vaddr_t start = vma->startva;
    const size_t size = vma->size;

    if ((va != start)) {
        Log("we only support unmap at the start now.\n");
        return -1;
    }

    const size_t origin_len = len;
    len = PGROUNDUP(len);

    if (vma->type == VMA_FILE) {
        if ((vma->perm & PERM_SHARED) && (vma->perm & PERM_WRITE)) {
            writeback(mm->pagetable, vma->vm_file, start, origin_len);
        }
        generic_fileclose(vma->vm_file);
    }

    if (size > len) {
        /* unmap part of the vma */
        vma->startva += len;
        vma->size -= len;
        uvm_unmap(mm->pagetable, start, PGROUNDUP(size) / PGSIZE, 1, 1);
        return 0;
    }

    del_vma_from_vmspace(&mm->head_vma, vma);

    // Note: non-leaf pte still not recycle
    uvm_unmap(mm->pagetable, start, PGROUNDUP(size) / PGSIZE, 1, 1);

    return 0;
}

struct vma *find_vma_for_va(struct mm_struct *mm, vaddr_t addr) {
    struct vma *pos;
    list_for_each_entry(pos, &mm->head_vma, node) {
        const vaddr_t start = pos->startva;
        const vaddr_t end = pos->startva + pos->size;
        if (addr >= start && addr < end) {
            return pos;
        }
    }
    return NULL;
}

vaddr_t find_mapping_space(struct mm_struct *mm, vaddr_t start, size_t size) {
    struct vma *pos;
    vaddr_t max = MMAP_START;
    list_for_each_entry(pos, &mm->head_vma, node) {
        if (pos->type == VMA_INTERP) {
            continue;
        }
        if (pos->type == VMA_STACK) {
            continue;
        }
        vaddr_t endva = pos->startva + pos->size;
        if (max < endva) {
            max = endva;
        }
    }
    ASSERT(max % PGSIZE == 0);
    max = PGROUNDUP(max);

    // assert code: make sure the max address is not in pagetable(not mapping)
    pte_t *pte;
    int ret;
    ret = walk(mm->pagetable, max, 0, 0, &pte);
    ASSERT(ret == -1 || *pte == 0);
    return max;
}

int vma_copy(struct mm_struct *srcmm, struct mm_struct *dstmm) {
    struct vma *pos;
    list_for_each_entry(pos, &srcmm->head_vma, node) {
        if (pos->type == VMA_FILE) {
            if (vma_map_file(dstmm, pos->startva, pos->size, pos->perm, pos->type, pos->offset, pos->vm_file) < 0) {
                return -1;
            }
        } else {
            if (vma_map(dstmm, pos->startva, pos->size, pos->perm, pos->type) < 0) {
                return -1;
            }
        }
    }
    return 0;
}

void vma_free(struct proc *p) {
    struct vma *pos;
    struct vma *pos2;
    list_for_each_entry_safe(pos, pos2, &p->mm->head_vma, node) {
        if (vmspace_unmap(p->mm, pos->startva, pos->size) < 0) {
            panic("vmafree: unmap failed");
        }
    }
}

void free_all_vmas(struct mm_struct *mm) {
    struct vma *pos_cur;
    struct vma *pos_tmp;
    list_for_each_entry_safe(pos_cur, pos_tmp, &mm->head_vma, node) {
        if (pos_cur->type == VMA_HEAP && pos_cur->size == 0) {
            del_vma_from_vmspace(&mm->head_vma, pos_cur);
            continue;
        }
        if (vmspace_unmap(mm, pos_cur->startva, pos_cur->size) < 0) {
            panic("free_all_vmas: unmap failed");
        }
    }
}

int split_vma(struct mm_struct *mm, struct vma *vma, unsigned long addr, int new_below) {

    struct vma *new = alloc_vma();
    if (!new) {
        // TODO, SLOB!!!!!
        // Warn("split_vma: no free mem");
        return -1;
    }

    /* most fields are the same, copy all */
    *new = *vma;

    if (new_below) {
        /* 
         * avoid misalignment
         * we need to ensure enough space for current vma, so just round up
         */
        addr = PGROUNDDOWN(addr);

        /* addr is just the end of vma after alignment, so don't allocate new vma */
        if (addr == vma->startva) {
            free_vma(new);
            return 0;
        }

        vma->size = vma->startva + vma->size - addr;
        vma->startva = addr;
        vma->offset += (addr - new->startva);
        new->size = addr - new->startva;
    } else {
        /* the same as "new below" */
        addr = PGROUNDUP(addr);

        if (addr == vma->startva + vma->size) {
            free_vma(new);
            return 0;
        }

        new->startva = addr;
        new->size = vma->startva + vma->size - addr;
        vma->size = addr - vma->startva;
        new->offset += (addr - vma->startva);
    }

    /* dup file */
    if (new->vm_file && new->vm_file->f_count >= 1)
        new->vm_file->f_op->dup(new->vm_file);

    if (add_vma_to_vmspace(&mm->head_vma, new) < 0) {
        free_vma(new);
        Info("split_vma: add_vma_to_vmspace failed");
        return -1;
    }
    return 0;
}

void print_vma(struct list_head *head_vma) {
    struct vma *pos;
    // VMA("%s vmas:\n", proc_current()->name);
    printfYELLOW("=====================\n");
    list_for_each_entry(pos, head_vma, node) {
        VMA("%#p-%#p %dKB\t", pos->startva, pos->startva + pos->size, pos->size / 1024);
        if (pos->perm & PERM_READ) {
            VMA("r");
        } else {
            VMA("-");
        }
        if (pos->perm & PERM_WRITE) {
            VMA("w");
        } else {
            VMA("-");
        }
        if (pos->perm & PERM_EXEC) {
            VMA("x");
        } else {
            VMA("-");
        }
        if (pos->perm & PERM_SHARED) {
            VMA("s");
        } else {
            VMA("p");
        }
        switch (pos->type) {
            case VMA_TEXT:
                VMA("  VMA_TEXT  ");
                break;
            case VMA_STACK:
                VMA("  VMA_STACK  ");
                break;
            case VMA_HEAP:
                VMA("  VMA_HEAP  ");
                break;
            case VMA_FILE:
                VMA("  VMA_FILE  ");
                VMA("%p", pos->offset);
                break;
            case VMA_ANON:
                VMA("  VMA_ANON  ");
                break;
            case VMA_INTERP:
                VMA("  libc.so  ");
                break;
            default:
                panic("no such vma type");
        }
        VMA("\n");
    }
}

static char *get_proghdr_type(int type) {
    if (type >= ELF_PROG_LOOS && type <= ELF_PROG_HIOS) {
        switch (type) {
            case ELF_PROG_GNU_EH_FRAME:
                return "GNU_EH_FRAME";
            case ELF_PROG_GNU_STACK:
                return "GNU_STACK";
            case ELF_PROG_GNU_RELRO:
                return "GNU_RELRO";
            case ELF_PROG_SUNWBSS:
                return "SUNWBSS";
            case ELF_PROG_SUNWSTACK:
                return "SUNWSTACK";
            default:
                return "OS_SPECIFIC";
        }
    } else if (type >= ELF_PROG_LOPROC && type <= ELF_PROG_HIPROC) {
        return "PROC_SPECIFIC";
    } else if (type >= 0 && type <= 8) {
        return proghdr_type[type];
    } else {
        return "UNKNOWN";
    }
}

int flags2perm(int flags) {
    int perm = 0;
    if (flags & 0x1)
        perm = PTE_X;
    if (flags & 0x2)
        perm |= PTE_W;
    if (flags & 0x4)
        perm |= PTE_R;
    return perm;
}

int flags2vmaperm(int flags) {
    int perm = 0;
    if (flags & 0x1)
        perm = PERM_EXEC;
    if (flags & 0x2)
        perm |= PERM_WRITE;
    if (flags & 0x4)
        perm |= PERM_READ;
    return perm;
}

static int loadseg(pagetable_t pagetable, uint64 va, struct inode *ip, uint offset, uint size) {
    uint i, n;
    uint64 pa;

    for (i = 0; i < size; i += PGSIZE) {
        pa = walk_addr(pagetable, va + i);
        if (pa == 0)
            panic("loadseg: address should exist");
        if (size - i < PGSIZE)
            n = size - i;
        else
            n = PGSIZE;
        if (ip->i_op->read(ip, 0, (uint64) pa, offset + i, n) != n)
            return -1;
    }

    return 0;
}

static int load_elf_interp(char *path) {
    int i, off;
    uint64 sz = 0;
    struct commit commit;

    struct mm_struct *mm;
    mm = ldso.mm = alloc_mm();
    if (mm == NULL) {
        panic("alloc_mm failed");
    }

    if ((sz = loader(path, mm, &commit)) == 0) {
        goto bad;
    }

    ldso.elf_bss = commit.elf_bss;
    ldso.last_bss = commit.last_bss;
    ldso.size = commit.size;
    ldso.entry = commit.entry;
    ldso.valid = 1;

    return 0;

bad:
    return -1;
}

static int map_interpreter(struct mm_struct *mm) {
    ASSERT(ldso.valid == 1);

    pagetable_t ldso_pagetable = ldso.mm->pagetable;
    pagetable_t src_pagetable = mm->pagetable;
    vaddr_t ldva = LDSO;
    paddr_t ldpa;
    pte_t *pte;
    int flags;
    for (vaddr_t i = 0; i < ldso.size; i += PGSIZE, ldva += PGSIZE) {
        walk(ldso_pagetable, i, 0, 0, &pte);
        flags = PTE_FLAGS(*pte);
        ldpa = PTE2PA(*pte);
        if (map_pages(src_pagetable, ldva, PGSIZE, ldpa, flags, 0) < 0) {
            panic("mappages failed");
            return -1;
        }
    }

    struct vma *pos;
    list_for_each_entry(pos, &(ldso.mm->head_vma), node) {
        if (vma_map(mm, pos->startva + LDSO, pos->size, pos->perm, VMA_INTERP) < 0) {
            return -1;
        }
    }
    kfree(ldso.mm);
    kfree(ldso.mm->pagetable);
    return 0;
}

static inline vaddr_t get_stack_va(const vaddr_t sp, const paddr_t sp_addr, const paddr_t stack_top) {
    return sp - (stack_top - sp_addr);
}

void print_ustack(pagetable_t pagetable, uint64 stacktop, uint64 sp) {
    char *pa = (char *) get_phyaddr(pagetable, sp - 1) + 1;
    // Log("pa is %p", pa);
    /* just print the first 100 of the ustack */
    printfYELLOW("printing ustack, sp=%p, stacktop=%p\n", sp, stacktop);
    for (uint64 i = sp; i < stacktop; i += 8) {
        if (i % 16 == 0) {
            printfGreen("aligned -> ");
        } else {
            printfGreen("           ");
        }

        if (i == p_argc || i == p_argv || i == p_envp || i == p_auxv) {
            printfBlue("%#p:", i);
        } else {
            printfGreen("%#p:", i);
        }

        for (int j = 0; j < 8; j++) {
            char c = (char) *(paddr_t *) (get_phyaddr(pagetable, i) + j);
            if ((int) c > 0x20 && (int) c <= 0x7e) {
                printfGreen("%c", c);
            }
        }
        printf("\t");
        for (int j = 0; j < 8; j++) {
            printf("%02x ", (uint8) * (paddr_t *) (get_phyaddr(pagetable, i) + j));
        }
        printf("\n");
    }
}

int ustack_init(struct proc *p, pagetable_t pagetable, struct commit *commit, vaddr_t sp, char *const argv[],
                char *const envp[], int shell) {
    /* sp has to be the top address of a page */
    ASSERT(sp % PGSIZE == 0);
    uint64 sp_addr = get_phyaddr(pagetable, sp - 1) + 1;
    paddr_t stack_base = sp_addr - USTACK_PAGE * PGSIZE, stack_top = sp_addr;

    uint64 argc = 0, envpc = 0;
    vaddr_t argv_addr[MAXARG], envp_addr[MAXENV];
    /* Information block */
    if (argv != 0) {
        if (shell) {
            for (; argv[argc]; argc++) {
                paddr_t cp = (paddr_t) argv[argc];
                sp_addr -= strlen((const char *) cp) + 1;
                sp_addr -= sp_addr % align;
                if (sp_addr < stack_base)
                    return -1;
                memmove((void *) sp_addr, (void *) cp, strlen((const char *) cp) + 1);
                argv_addr[argc] = get_stack_va(sp, sp_addr, stack_top);
            }
        } else
            for (; argv[argc]; argc++) {
                if (argc >= MAXARG)
                    return -1;
                paddr_t cp = get_phyaddr(p->mm->pagetable, (vaddr_t) argv[argc]);
                if (cp == 0) {
                    return -1;
                }
                sp_addr -= strlen((const char *) cp) + 1;
                sp_addr -= sp_addr % align;
                if (sp_addr < stack_base)
                    return -1;
                memmove((void *) sp_addr, (void *) cp, strlen((const char *) cp) + 1);
                argv_addr[argc] = get_stack_va(sp, sp_addr, stack_top);
            }
    }
    argv_addr[argc] = 0;

    if (envp != 0) {
        for (; envp[envpc]; envpc++) {
            if (envpc >= MAXENV)
                return -1;
            paddr_t cp = get_phyaddr(p->mm->pagetable, (vaddr_t) envp[envpc]);
            if (cp == 0) {
                return -1;
            }
            sp_addr -= strlen((const char *) cp) + 1;
            sp_addr -= sp_addr % align;
            if (sp_addr < stack_base)
                return -1;
            memmove((void *) sp_addr, (void *) cp, strlen((const char *) cp) + 1);
            envp_addr[envpc] = get_stack_va(sp, sp_addr, stack_top);
        }
    }
    envp_addr[envpc] = 0;
    // make sure the stack is aligned
    if ((sp_addr % 16 == 0 && (argc + envpc + 2 + 1) % 2 == 1) ||
        (sp_addr % 16 != 0 && (argc + envpc + 1 + AUX_CNT) % 2 == 0)) {
        sp_addr -= 8;
    }

    uint64 auxv[AUX_CNT * 2] = {0};
    for (int i = 0; i < AUX_CNT; i++) {
        if (i + 1 > AT_RANDOM) {
            break;
        }
        // if (i == AT_EXECFN) {
        //     continue;
        // }
        auxv[i * 2] = i + 1;
    }
    auxv[AT_PAGESZ * 2 - 1] = PGSIZE;
    if (commit->interp || (strncmp(commit->path, "lmbench_all", 11) == 0)) {
        // printfGreen("hit\n");
        auxv[AT_BASE * 2 - 1] = LDSO;
        auxv[AT_PHDR * 2 - 1] = commit->phoff;
        auxv[AT_PHENT * 2 - 1] = commit->phentsize;
        auxv[AT_PHNUM * 2 - 1] = commit->phnum;
        auxv[AT_ENTRY * 2 - 1] = commit->entry;
    }
    // uint64 random[2] = {0xea0dad5a44586952, 0x5a1fa5497a4a283d};
    // memmove((void *)&auxv[AT_RANDOM * 2 - 1], random, 16);
    auxv[AT_RANDOM * 2 - 1] = get_stack_va(sp, sp_addr, stack_top);

    auxv[AT_SECURE * 2 - 1] = 0;
    auxv[AT_NULL * 2 - 1] = 0;

    /* push the aux vector */
    sp_addr -= AUX_CNT * 2 * sizeof(uint64);
    sp_addr -= sp_addr % align; /* reserve 8 bits for null auxv entry */
    if (sp_addr < stack_base)
        return -1;
    p_auxv = get_stack_va(sp, sp_addr, stack_top);
    memmove((void *) sp_addr, (void *) auxv, AUX_CNT * 2 * sizeof(uint64));


    /* push the array of envp[] pointers */
    sp_addr -= (envpc + 1) * sizeof(uint64);
    sp_addr -= sp_addr % align;
    if (sp_addr < stack_base)
        return -1;
    p_envp = get_stack_va(sp, sp_addr, stack_top);
    memmove((void *) sp_addr, (void *) envp_addr, (envpc + 1) * sizeof(uint64));
    commit->a2 = get_stack_va(sp, sp_addr, stack_top);

    /* push the array of argv[] pointers */
    sp_addr -= (argc + 1) * sizeof(uint64);
    sp_addr -= sp_addr % align;
    if (sp_addr < stack_base)
        return -1;
    p_argv = get_stack_va(sp, sp_addr, stack_top);
    memmove((void *) sp_addr, (void *) argv_addr, (argc + 1) * sizeof(uint64));
    commit->a1 = get_stack_va(sp, sp_addr, stack_top);
    sp_addr -= align;
    p_argc = get_stack_va(sp, sp_addr, stack_top);
    *(uint64 *) sp_addr = argc;
    commit->sp = get_stack_va(sp, sp_addr, stack_top); // initial stack pointer

    // printfMAGENTA("sp is %p\n", commit->sp);
    // print_ustack(pagetable, USTACK + USTACK_PAGE * PGSIZE, commit->sp);

    return argc;
}

static uint64 loader(char *path, const mm_ptr_t mm, struct commit *commit) {
    int i, off;
    uint64 sz = 0;
    struct elfhdr elf;
    struct proghdr *phnew;
    struct inode *ip;
    uint64 last_bss = 0, elf_bss = 0;

    // printfCYAN("loader: path: %s\n", path);

    if ((ip = namei(path)) == 0) {
        return 0;
    }
    ip->i_op->lock(ip);

    // Check ELF header
    if (ip->i_op->read(ip, 0, (uint64) &elf, 0, sizeof(elf)) != sizeof(elf))
        goto bad_elf_header;

    if (elf.magic != ELF_MAGIC)
        goto bad_elf_header;

    phnew = (struct proghdr *) kmalloc(elf.phnum * elf.phentsize);

    // Load program into memory.
    struct proghdr *ph;
    for (i = 0, off = (int) elf.phoff, ph = phnew; i < elf.phnum; i++, off += elf.phentsize, ph++) {
        if (ip->i_op->read(ip, 0, (uint64) ph, off, elf.phentsize) != sizeof(struct proghdr))
            goto unlock_put;
        if (i == 0) { /* first ph */
            if (strncmp(path, "lmbench_all", 11) == 0) {
                commit->phoff = elf.phoff;
            } else {
                commit->phoff = ph->vaddr;
            }
        }
        if (ph->type == ELF_PROG_INTERP) {
            commit->interp = 1;
        }
        if (ph->type != ELF_PROG_LOAD)
            continue;
        if (ph->memsz < ph->filesz)
            goto unlock_put;
        if (ph->vaddr + ph->memsz < ph->vaddr)
            goto unlock_put;
        uint64 offset = 0, size = 0;
        vaddr_t vaddr_down = PGROUNDDOWN(ph->vaddr);
        if (ph->vaddr % PGSIZE != 0) {
            paddr_t pa = (paddr_t) kmalloc(PGSIZE);
            if (map_pages(mm->pagetable, vaddr_down, PGSIZE, pa, flags2perm(ph->flags) | PTE_U, COMMONPAGE) < 0) {
                kfree((void *) pa);
                goto unlock_put;
            }
            offset = ph->vaddr - vaddr_down;
            size = PGROUNDUP(ph->vaddr) - ph->vaddr;
            if (ip->i_op->read(ip, 0, (uint64) pa + offset, ph->off, size) != size) {
                goto unlock_put;
            }
        } else {
            ASSERT(vaddr_down == ph->vaddr);
        }
        uint64 sz1;
        ASSERT((ph->vaddr + size) % PGSIZE == 0);
        if ((sz1 = uvm_alloc(mm->pagetable, ph->vaddr + size, ph->vaddr + ph->memsz, flags2perm(ph->flags))) == 0)
            goto unlock_put;

        sz = sz1;
        // sz = PGROUNDUP(sz);
        if (loadseg(mm->pagetable, ph->vaddr + size, ip, ph->off + size, ph->filesz - size) < 0)
            goto unlock_put;

        vaddr_t vaddr_up = PGROUNDUP(ph->vaddr + ph->memsz);
        if (vma_map(mm, vaddr_down, vaddr_up - vaddr_down, flags2vmaperm(ph->flags), VMA_TEXT) < 0) {
            goto unlock_put;
        }

        uint64 tmp = ph->vaddr + ph->filesz;
        if (tmp > elf_bss)
            elf_bss = tmp;
        tmp = ph->vaddr + ph->memsz;
        if (tmp > last_bss)
            last_bss = tmp;
    }
    ip->i_op->unlock_put(ip);
    ip = 0;
    kfree(phnew);
    // printfRed("loader: entry: %p\n", elf.entry);
    if (strncmp(path, "lmbench_all", 11) == 0) {
        // printf("hit loader: path: %s\n", path);
        void *pa = kzalloc(PGSIZE);
        memmove((void *) pa + elf.phoff, (void *) phnew, elf.phnum * elf.phentsize);
        map_pages(mm->pagetable, 0, PGSIZE, (paddr_t) pa, PTE_R | PTE_W | PTE_X | PTE_U, COMMONPAGE);
        if (vma_map(mm, 0, PGSIZE, PERM_READ | PERM_WRITE, VMA_TEXT) < 0) {
            goto unlock_put;
        }
    }
    commit->elf_bss = elf_bss;
    commit->last_bss = last_bss;
    commit->size = sz;
    commit->entry = elf.entry;
    commit->phentsize = elf.phentsize;
    commit->phnum = elf.phnum;
    commit->path = path;
    return sz;

unlock_put:
    kfree(phnew);
bad_elf_header:
    ip->i_op->unlock_put(ip);
    return 0;
}

int do_execve(char *path, char *const argv[], char *const envp[], int shell) {
    struct commit commit;
    struct proc *p = proc_current();
    struct tcb *t = thread_current();
    char *s, *last;
    uint64 sz;
    memset(&commit, 0, sizeof(commit));
    struct mm_struct *mm = alloc_mm();

    /* Load the ELF_PROG_LOAD segments */
    if ((sz = loader(path, mm, &commit)) == 0) {
        goto bad;
    }

    if (commit.interp) {
        const char *interp_path = strncmp(commit.path, "ltp", 3) == 0 ? "/lib/glibc/ld-2.31.so" : "lib/musl/libc.so";
        if (load_elf_interp(interp_path) < 0) {
            goto bad;
        }
        if (map_interpreter(mm) < 0) {
            goto bad;
        }
    }

    sz = PGROUNDUP(sz);
    uint64 sz1;
    if (uvm_thread_stack(mm, USTACK_PAGE) != 0)
        goto bad;

    const uint64 sp = USTACK_TOP;

    /* Initialize the stack */
    const int argc = ustack_init(p, mm->pagetable, &commit, sp, argv, envp, shell);
    if (argc < 0) {
        goto bad;
    }

    /* Save program name for debugging */
    for (last = s = path; *s; s++)
        if (*s == '/')
            last = s + 1;
    strncpy(p->name, last, sizeof(p->name));

    /* thread name */
    char name_tmp[THREAD_NAME_MAXLEN];
    snprintf(name_tmp, THREAD_NAME_MAXLEN, "%s-%d", p->name, p->tg->group_leader->tidx);
    strncpy(p->tg->group_leader->name, name_tmp, THREAD_NAME_MAXLEN);

    t->trapframe->sp = commit.sp;
    t->trapframe->a1 = commit.a1;
    t->trapframe->a2 = commit.a2;
    if (commit.interp) {
        t->trapframe->epc = ldso.entry + LDSO;
    } else {
        t->trapframe->epc = commit.entry;
    }


    mm->start_brk = mm->brk = sz;
    mm->heap_vma = NULL;

    /* free the old pagetable and commit new pagetable */
    struct mm_struct *oldmm = p->mm;
    free_mm(oldmm, atomic_read(&p->tg->thread_cnt));
    p->mm = mm;
    thread_trapframe(t, 1);

    return argc; // this ends up in a0, the first argument to main(argc, argv)

bad:
    free_mm(mm, 0);
    return -1;
}

void deleteChild(struct proc *parent, struct proc *child) {
    if (nosibling(child)) {
        parent->first_child = NULL;
    } else {
        struct proc *first_child = firstchild(parent);
        if (child == first_child) {
            parent->first_child = nextsibling(first_child);
        }
        list_del_reinit(&child->sibling_list);
    }
}

void appendChild(struct proc *parent, struct proc *child) {
    if (nochildren(parent)) {
        parent->first_child = child;
    } else {
        list_add_tail(&child->sibling_list, &(firstchild(parent)->sibling_list));
    }
}

struct proc *alloc_proc(void) {
    struct proc *p;
    // fetch an unused proc from unused queue
    // fetch an unused thread from unused queue as its group leader
    p = (struct proc *) Queue_provide_atomic(&unused_p_q, 1);
    if (p == NULL)
        return 0;

    acquire(&p->lock); // return with lock

    p->pid = alloc_pid;
    cnt_pid_inc; // increase the count of pid

    // state
    PCB_Q_changeState(p, PCB_USED);

    // proc family
    p->first_child = NULL;
    INIT_LIST_HEAD(&p->sibling_list);

    // thread group (list head) sets to NULL
    if ((p->tg = (struct thread_group *) kalloc()) == 0) {
        free_proc(p);
        release(&p->lock);
        return 0;
    }
    thread_group_init(p->tg);

    // ipc namespace
    if ((p->ipc_ns = (struct ipc_namespace *) kalloc()) == 0) {
        free_proc(p);
        release(&p->lock);
        return 0;
    }

    // shared memory
    shm_init_ns(p->ipc_ns);
    INIT_LIST_HEAD(&p->sysvshm.shm_clist);
    // for prlimit
    proc_prlimit_init(p);


    p->mm = alloc_mm();
    if (p->mm == 0) {
        free_proc(p);
        release(&p->lock);
        return 0;
    }
    INIT_LIST_HEAD(&p->mm->head_vma);

    // for setitimer
    p->real_timer.expires = 0;
    p->real_timer.interval = 0;
    INIT_LIST_HEAD(&p->real_timer.list);

    // semaphore for waitpid
    sem_init(&p->sem_wait_chan_parent, 0, "wait_parent");
    sem_init(&p->sem_wait_chan_self, 0, "wait_self");

    return p;
}

struct proc *create_proc() {
    struct tcb *t = NULL;
    struct proc *p = NULL;
    if ((p = alloc_proc()) == 0) {
        return 0;
    }
    if ((t = alloc_thread(thread_forkret)) == 0) {
        free_proc(p);
        return 0;
    }

    proc_join_thread(p, t, NULL);


    release(&t->lock);

    return p;
}

void free_proc(struct proc *p) {
    if (p->mm)
        free_mm(p->mm, p->tg->thread_idx);
    p->mm = 0;
    if (p->tg)
        kfree((void *) p->tg);
    p->tg = 0;
    if (p->ipc_ns) {
        if (shm_ids(p->ipc_ns).key_ht) {
            struct hash_table *table = shm_ids(p->ipc_ns).key_ht;
            acquire(&table->lock);
            for (uint64 i = 0; i < table->size; i++) {
                struct kern_ipc_perm *pos, *n;
                list_for_each_entry_safe(pos, n, &table->hash_head[i].list, ipc_hash_node) { kfree(pos); }
            }
            release(&table->lock);
            kfree(table);
        }
        kfree((void *) p->ipc_ns);
    }
    p->ipc_ns = 0;
    if (!list_empty(&p->sysvshm.shm_clist)) {
        struct shmid_kernel *shmid_cur = NULL;
        struct shmid_kernel *shmid_tmp = NULL;
        list_for_each_entry_safe(shmid_cur, shmid_tmp, &p->sysvshm.shm_clist, shm_clist) {
            kfree(shmid_cur->shm_file->private_data);
            kfree(shmid_cur);
        }
    }
    p->pid = 0;
    p->parent = 0;
    p->name[0] = 0;
    p->killed = 0;
    p->exit_stat = 0;

    PCB_Q_changeState(p, PCB_UNUSED);
}

void user_init(void) {
    struct proc *p = NULL;

    p = create_proc();
    init_proc = p;

    strncpy(p->name, "/init", 10);
    strncpy(p->tg->group_leader->name, "/init-0", 10);
    p->mm->brk = 0;
    console.f_type = T_CHR;
    console.f_mode = O_RDWR;
    console.f_major = CONSOLE;

    TCB_Q_changeState(p->tg->group_leader, TCB_RUNNABLE);
    release(&p->lock);
}

void uvm_init(struct mm_struct *mm, uchar *src, uint sz) {
    char *mem;
    pagetable_t pagetable = mm->pagetable;
    int page_num = (sz + PGSIZE - 1) / PGSIZE;
    uvm_alloc(pagetable, 0, page_num * PGSIZE, PTE_W | PTE_X);
    for (int i = 0; i < page_num; i++) {
        mem = (char *) get_phyaddr(pagetable, 0 + i * PGSIZE);
        if (i == page_num - 1) {
            memmove(mem, src + PGSIZE * i, sz - PGSIZE * i);
        }
        memmove(mem, src + PGSIZE * i, PGSIZE);
    }
    if (vma_map(mm, 0, page_num * PGSIZE, PERM_READ | PERM_WRITE, VMA_TEXT) < 0) {
        panic("uvm_init: vma_map failed");
    }
    uvm_thread_stack(mm, USTACK_PAGE);
}

void comp_init() {
    op = 1;
    struct proc *p = NULL;
    struct tcb *t = NULL;
    p = create_proc();
    init_proc = p;
    t = p->tg->group_leader;
    strncpy(p->name, "/init", 10);
    p->mm->brk = 0;

    uvm_init(p->mm, initcode, initcode_len);
    const int page_num = (initcode_len + PGSIZE - 1) / PGSIZE;
    const uint64 sp = USTACK_TOP;
    p->mm->start_brk = p->mm->brk = page_num * PGSIZE;
    t->trapframe->epc = 0;
    t->trapframe->sp = sp;
    TCB_Q_changeState(t, TCB_RUNNABLE);
    release(&p->lock);
}

void init_ret(void) {
    // fat32_fs_mount(ROOTDEV, &fat32_sb); // initialize fat32 superblock obj and root inode obj.
    fs_t fs_type = extract_fs_type_from_blockdev(ROOTDEV);
    filesystem_t *fs = kmalloc(sizeof(filesystem_t));

    printf("starting fs_init\n");

    /* initialize and mount fs */
    fs_init(fs, ROOTDEV, fs_type, "/");
    void *fs_sb = fs_type == FAT32 ? &fat32_sb : NULL; // FAT32 superblock is initialized outside.
    fs_mount(fs, 0, fs_sb);

    /* initialize procfs */
    struct filesystem *procfs = kmalloc(sizeof(struct filesystem));
    fs_init(procfs, ROOTDEV, PROCFS, "/proc");
    fs_mount(procfs, 0, NULL);

    /* make up cwd */
    struct file_vnode *cwd = &proc_current()->cwd;
    strcpy(cwd->path, "/");
    cwd->fs = fs;
    switch (fs_type) {
        case FAT32:
            cwd->data = fat32_sb.root->i_op->dup(fat32_sb.root);
            break;
        case EXT4:
            // NOTE: in EXT4 you just need a path and a fs.
            break;
        default:
            panic("init_ret: unknown fs type");
    }
    if (!op)
        proc_current()->tg->group_leader->trapframe->a0 = do_execve("/boot/init", NULL, NULL, 0);
    Info("init_ret: success\n");
}

void proc_init(void) {
    struct proc *p;
    atomic_set(&next_pid, 1);
    atomic_set(&count_pid, 0);

    PCB_Q_ALL_INIT();
    memset(proc, 0, sizeof(proc));

    for (int i = 0; i < NPROC; i++) {
        p = proc + i;
        sprintf(proc_lock_name[i], "proc_%d", i);
        init_lock(&p->lock, proc_lock_name[i]);

        p->state = PCB_UNUSED;
        p->killed = 0;
        init_lock(&p->tlock, "tlock");
        Queue_push_back(&unused_p_q, p);
    }

    printf("proc_init done\n");
}

struct proc *get_proc_by_pid(pid_t pid) {
    struct proc *p;
    for (p = proc; p < &proc[NPROC]; p++) {
        acquire(&p->lock);
        if (p->pid == pid) {
            release(&p->lock);
            return p;
        }
        release(&p->lock);
    }
    return NULL;
}

void thread_forkret(void) {
    // Still holding p->lock from scheduler.
    release(&thread_current()->lock);
    if (thread_current() == init_proc->tg->group_leader) {
        init_ret();
    }
    thread_user_trap_ret();
}

int do_clone(int flags, uint64 stack, pid_t p_tid, uint64 tls, const pid_t *c_tid) {
    struct proc *p = proc_current();
    struct proc *np = NULL;
    struct tcb *t = NULL;

    if (flags & CLONE_THREAD) {
        if ((t = alloc_thread(thread_forkret)) == NULL) {
            return -1;
        }
        if (proc_join_thread(p, t, NULL) < 0) {
            free_thread(t);
        }
    } else {
        // Allocate process.
        if ((np = create_proc()) == 0) {
            return -1;
        }
        t = np->tg->group_leader;
    }

    // copy saved user registers.
    *(t->trapframe) = *(p->tg->group_leader->trapframe);
    // Cause fork to return 0 in the child.
    t->trapframe->a0 = 0;

    // set the tls (Thread-local Storage，TLS)
    // RISC-V使用TP寄存器
    if (flags & CLONE_SETTLS) {
        t->trapframe->tp = tls;
    }

    // 子线程中存储子线程 ID 的变量指针
    if (flags & CLONE_CHILD_SETTID) {
        if (copy_out(p->mm->pagetable, c_tid, (char *) &t->tid, sizeof(tid_t)) < 0)
            return -1;
    }

    if (flags & CLONE_CHILD_CLEARTID) {
        // when the child exits,  Clear (zero)
        t->clear_child_tid = c_tid;
    }

    if (stack) {
        t->trapframe->sp = stack;
    }

    // TODO : signal
    if (flags & CLONE_SIGHAND) {
        t->sig = p->tg->group_leader->sig;
        atomic_add(&t->sig->refcount, 1);
        // TODO: sigmask
    } else {
        sighandinit(t);
    }

    // store the parent pid
    if (flags & CLONE_PARENT_SETTID) {
        if (copy_out(p->mm->pagetable, p_tid, (char *) &t->tid, sizeof(tid_t)) == -1)
            return -1;
    }

    // for pthread create
    if (np == NULL) {
        // acquire(&t->lock);
        TCB_Q_changeState(t, TCB_RUNNABLE);
        release(&t->lock);
        return t->tid;
    }

    acquire(&p->lock);
    /* Copy vma */
    if (vma_copy(p->mm, np->mm) < 0) {
        free_proc(np);
        release(&p->lock);
        release(&np->lock);
        return -1;
    }

    // Copy user memory from parent to child.
    if (flags & CLONE_VM) {
        np->mm->pagetable = p->mm->pagetable;
    } else {
        if (uvm_copy(p->mm, np->mm) < 0) {
            free_proc(np);
            release(&p->lock);
            release(&np->lock);
            return -1;
        }
    }

    np->mm->brk = p->mm->brk;
    np->mm->start_brk = p->mm->start_brk;
    release(&p->lock);

    // increment reference counts on open file descriptors.
    if (flags & CLONE_FILES) {
    } else {
        for (int i = 0; i < NOFILE; i++)
            if (p->_ofile[i])
                np->_ofile[i] = p->_ofile[i]->f_op->dup(p->_ofile[i]);
        // TODO : clone a completely same fdtable
    }

    // TODO : vfs inode cmd
    np->cwd = p->cwd;
    if (np->cwd.fs->fs_type == FAT32) {
        struct inode *f_inode = np->cwd.data;
        f_inode->i_op->dup(f_inode);
    } else if (np->cwd.fs->fs_type == EXT4) {
        // Nothing to do here.
    }

    strncpy(np->name, p->name, sizeof(p->name));

    const int pid = np->pid;
    np->parent = p;

    acquire(&p->lock);
    appendChild(p, np);
    release(&p->lock);
    release(&np->lock);


    acquire(&t->lock);
    TCB_Q_changeState(t, TCB_RUNNABLE);
    release(&t->lock);

    return pid;
}

static void exit_wakeup(struct proc *p, struct tcb *t) {
    if (t->clear_child_tid != 0) {
        int val = 0;
        if (copy_out(p->mm->pagetable, t->clear_child_tid, (char *) &val, sizeof(val)))
            panic("exit error\n");
        futex_wakeup(t->clear_child_tid, 1);
    }
}

int exit_proc(int status) {
    struct proc *p = proc_current();
    struct tcb *t = thread_current();
    struct thread_group *tg = p->tg;

    if (p == init_proc)
        panic("init exiting");
    vma_free(p);

    // Close all open files.
    for (int fd = 0; fd < NOFILE; fd++) {
        if (p->_ofile[fd]) {
            struct file *f = p->_ofile[fd];
            generic_fileclose(f);
            p->_ofile[fd] = 0;
        }
    }

    if (p->cwd.fs->fs_type == FAT32) {
        struct inode *f_inode = p->cwd.data;
        f_inode->i_op->put(f_inode);
    } else if (p->cwd.fs->fs_type == EXT4) {
        // Nothing to do here.
    }
    memset(&p->cwd, 0, sizeof p->cwd);

    delete_timer_atomic(&p->real_timer);

    // Give any children to init.
    re_parent(p);

    acquire(&p->lock);

    p->exit_stat = status << 8;

    PCB_Q_changeState(p, PCB_ZOMBIE);

    //  only valid for the group leader of proc
    sem_v(&p->parent->sem_wait_chan_parent);
    sem_v(&p->sem_wait_chan_self);

    return 0;
}

void do_exit(int status) {
    struct proc *p = proc_current();
    struct tcb *t = thread_current();
    struct thread_group *tg = p->tg;

    exit_wakeup(p, t);
    // =======atomic=======
    int last_thread = 0;
    if (!(atomic_decrease(&tg->thread_cnt) - 1)) {
        exit_proc(status);
        last_thread = 1;
    }
    acquire(&tg->lock);
    list_del_reinit(&t->thread);
    release(&tg->lock);

    acquire(&t->lock);
    free_thread(t);
    if (last_thread) {
        release(&p->lock);
    }
    thread_sched();
    panic("do_exit should never return");
    return;
}

void do_exit_group(struct proc *p) {
    struct tcb *caller = thread_current();
    struct thread_group *tg = p->tg;
    struct tcb *t_cur = NULL;
    struct tcb *t_tmp = NULL;
    acquire(&p->tg->lock);
    list_for_each_entry_safe(t_cur, t_tmp, &tg->threads, thread) {
        if (t_cur == caller)
            continue;
        acquire(&t_cur->lock); // maybe necessary?
        list_del_reinit(&t_cur->thread);
        atomic_sub(&tg->thread_cnt, 1);

        exit_wakeup(p, t_cur); // !!! bug
        free_thread(t_cur);
        release(&t_cur->lock);
    }
    release(&p->tg->lock);
}

int waitpid(pid_t pid, uint64 status, int options) {
    struct proc *p = proc_current();
    if (pid < -1)
        pid = -pid;

    ASSERT(pid != 0);

    if (nochildren(p)) {
        return -ECHILD;
    }

    if (proc_is_killed(p)) {
        return -1;
    }
    while (1) {
        sem_p(&p->sem_wait_chan_parent);
        struct proc *p_child = NULL;
        struct proc *p_tmp = NULL;
        struct proc *p_first = firstchild(p);
        int flg = 1;
        list_for_each_entry_safe_given_first(p_child, p_tmp, p_first, sibling_list, flg) {
            // shell won't exit !!!
            if (pid > 0 && p_child->pid == pid) {
                sem_p(&p_child->sem_wait_chan_self);
            }
            acquire(&p_child->lock);
            if (p_child->state == PCB_ZOMBIE) {
                // set p_times.tms_cstime and tms_cutime
                p->p_times.tms_cstime += p_child->p_times.tms_stime;
                p->p_times.tms_cutime += p_child->p_times.tms_utime;

                pid_t t_pid = p_child->pid;
                // pid = p_child->pid;
                if (status != 0 && copy_out(p->mm->pagetable, status, (char *) &(p_child->exit_stat),
                                            sizeof(p_child->exit_stat)) < 0) {
                    release(&p_child->lock);
                    return -1;
                }
                free_proc(p_child);

                acquire(&p->lock);
                deleteChild(p, p_child);
                release(&p->lock);

                release(&p_child->lock);
                return pid > 0 ? pid : t_pid;
            }
            release(&p_child->lock);
        }
        printf("%d\n", p->pid);
        panic("waitpid : invalid wakeup for semaphore!");
    }
}

void re_parent(struct proc *p) {
    struct proc *p_child = NULL;
    if (!nochildren(p)) {
        struct proc *p_first_c = firstchild(p);
        struct proc *p_tmp = NULL;
        int flag = 1;

        list_for_each_entry_safe_given_first(p_child, p_tmp, p_first_c, sibling_list, flag) {
            acquire(&p_child->lock);

            acquire(&p->lock);
            deleteChild(p, p_child);
            release(&p->lock);
            acquire(&init_proc->lock);
            appendChild(init_proc, p_child);
            release(&init_proc->lock);

            p_child->parent = init_proc;
            if (p_child->state == PCB_ZOMBIE) {
                sem_v(&init_proc->sem_wait_chan_parent); // !!!!!
            }
            release(&p_child->lock);

            if (p->first_child == NULL) {
                break; // !!!!
            }
        }
        ASSERT(nochildren(p));
    } else {
    }
}

int proc_kill(int pid, sig_t signo) {
    struct proc *p;
    if ((p = get_proc_by_pid(pid)) == NULL)
        return 0; /* don't return -1 here */
    proc_sendsignal_all_thread(p, signo, 0);
    return 0;
}

void proc_set_killed(struct proc *p) {
    acquire(&p->lock);
    p->killed = 1;
    release(&p->lock);
}

int proc_is_killed(struct proc *p) {
    acquire(&p->lock);
    int k = p->killed;
    release(&p->lock);
    return k;
}

