void PCB_Q_changeState(struct proc *p, enum procstate state_new) {
    Queue_t *pcb_q_new = STATES[state_new];
    Queue_t *pcb_q_old = STATES[p->state];

    Queue_remove_atomic(pcb_q_old, (void *) p);

    Queue_push_back_atomic(pcb_q_new, (void *) p);

    p->state = state_new;
}

void TCB_Q_changeState(struct tcb *t, enum thread_state state_new) {
    Queue_t *tcb_q_new = T_STATES[state_new];
    Queue_t *tcb_q_old = T_STATES[t->state];

    if (t->state != TCB_RUNNING) {
        Queue_remove_atomic(tcb_q_old, (void *) t);
    } else {
        Queue_remove((void *) t, TCB_STATE_QUEUE);
    }
    Queue_push_back_atomic(tcb_q_new, (void *) t);

    t->state = state_new;
}

void thread_yield(void) {
    struct tcb *t = thread_current();
    acquire(&t->lock);

    TCB_Q_changeState(t, TCB_RUNNABLE);

    thread_sched();
    release(&t->lock);
}

void thread_wakeup(struct tcb *t) {
    ASSERT(t->wait_chan_entry != NULL);
    Queue_remove_atomic(t->wait_chan_entry, (void *)t);
    ASSERT(t->state == TCB_SLEEPING);
    t->wait_chan_entry = NULL;
    TCB_Q_changeState(t, TCB_RUNNABLE);
}

void thread_wakeup_atomic(void *t) {
    struct tcb *th = (struct tcb *)t;
    acquire(&th->lock);
    // printf("th %p: tid: %d, wait_chan_entry: %p, state: %d\n", th, th->tid, th->wait_chan_entry, th->state);
    ASSERT(th->wait_chan_entry != NULL);
    Queue_remove_atomic(th->wait_chan_entry, (void *)th);
    ASSERT(th->state == TCB_SLEEPING);
    th->wait_chan_entry = NULL;
    TCB_Q_changeState(t, TCB_RUNNABLE);
    release(&th->lock);
}

int thread_sched(void) {
    int intena;
    struct tcb *thread = thread_current();
    // if (!holding(&thread->lock))
    //     panic("sched thread->lock");
    if (mycpu()->noff != 1) {
        printf("noff: %d\n", mycpu()->noff);
        panic("sched locks");
    }
    if (thread->state == TCB_RUNNING)
        panic("sched running");
    if (intr_get())
        panic("sched interruptible");

    intena = mycpu()->intena;

    // set timer for thread
    int set_timer = thread->time_out; // !!!
    struct timer_list timer;
    timer.expires = 0;
    timer.count = 1;                 // only once
    if (set_timer != 0) {
        INIT_LIST_HEAD(&timer.list); // bug!!!
        add_timer_atomic(&timer, thread->time_out, thread_wakeup_atomic, (void *)thread);
    }

    swtch(&thread->ctx, &mycpu()->context);
    mycpu()->intena = intena;

    if (set_timer != 0) {
        thread->time_out = 0; // bug !!!
        delete_timer_atomic(&timer);
    }

    return timer.expires == 0; // if it is 0, is is reasonable
}

void thread_scheduler(void) {
    struct tcb *t;
    struct thread_cpu *c = mycpu();

    c->thread = 0;
    for (;;) {
        // Avoid deadlock by ensuring that devices can interrupt.
        intr_on();
        t = (struct tcb *) Queue_provide_atomic(&runnable_t_q, 1);
        if (t == NULL)
            continue;
        acquire(&t->lock);
        t->state = TCB_RUNNING;
        c->thread = t;
        swtch(&c->context, &t->ctx);
        c->thread = 0;
        release(&t->lock);
    }
}

void tcb_init(void) {
    struct tcb *t;
    atomic_set(&next_tid, 1);
    atomic_set(&count_tid, 0);
    // memset(thread, 0, sizeof(thread));

    TCB_Q_ALL_INIT();
    for (int i = 0; i < NTCB; i++) {
        t = thread + i;
        init_lock(&t->lock, tcb_lock_name[i]); // init its spinlock

        t->state = TCB_UNUSED;
        t->kstack = KSTACK((int) (t - thread));
        Queue_push_back(&unused_t_q, t);
    }

    printf("tcb_init done\n");
}

struct tcb *thread_current(void) {
    push_off();
    struct thread_cpu *c = mycpu();
    struct tcb *thread = c->thread;
    pop_off();
    return thread;
}

struct tcb *alloc_thread(thread_callback fn) {
    struct tcb *t;

    t = (struct tcb *) Queue_provide_atomic(&unused_t_q, 1);
    if (t == NULL)
        return 0;
    acquire(&t->lock);

    // spinlock and threads list head

    INIT_LIST_HEAD(&t->thread);

    t->tid = alloc_tid;
    cnt_tid_dec;

    // signal
    t->sigpending = 0;
    sig_empty_set(&t->blocked);
    sigpending_init(&(t->pending));

    // Set up new context to start executing at forkret, which returns to user space.
    memset(&t->ctx, 0, sizeof(t->ctx));
    t->ctx.ra = (uint64) fn;
    t->ctx.sp = t->kstack + PGSIZE;

    TCB_Q_changeState(t, TCB_USED);

    // for clone
    t->set_child_tid = 0;
    t->clear_child_tid = 0;

    t->killed = 0;
    t->wait_chan_entry = NULL;
    t->time_out = 0;

    return t;
}

void free_thread(struct tcb *t) {
    // free & unmap trapframe
    acquire(&t->p->mm->lock);
    if (t->trapframe)
        uvm_unmap(t->p->mm->pagetable, THREAD_TRAPFRAME(t->tidx), 1, 1, 1);
    else
        uvm_unmap(t->p->mm->pagetable, THREAD_TRAPFRAME(t->tidx), 1, 0, 1);
    release(&t->p->mm->lock);

    if (t->wait_chan_entry != NULL) {
        ASSERT(t->state == TCB_SLEEPING);
        t->wait_chan_entry = NULL;
    }
    if (t->sig) {
        int ref = atomic_sub(&t->sig->refcount, 1) - 1;
        if (ref == 0) {
            kfree((void *)t->sig);
        }
        t->sig = NULL;
    }

    cnt_tid_dec;

    t->trapframe = 0;
    t->tid = 0;
    t->tidx = 0;
    t->name[0] = 0;
    t->exit_status = 0;
    t->p = 0;
    t->sigpending = 0;
    t->sigprocessing = 0;
    memset(&t->ctx, 0, sizeof(t->ctx));

    signal_queue_flush(&t->pending);
    t->killed = 0;

    TCB_Q_changeState(t, TCB_UNUSED);
}

int proc_join_thread(struct proc *p, struct tcb *t, char *name) {
    struct thread_group *tg = p->tg;

    atomic_add(&tg->thread_cnt, 1);
    acquire(&tg->lock);
    if (tg->group_leader == NULL) {
        tg->group_leader = t;
    }
    list_add_tail(&t->thread, &p->tg->threads);
    tg->thread_group_id = p->pid;
    t->tidx = tg->thread_idx++;
    t->p = p;
    release(&p->tg->lock);

    acquire(&t->p->mm->lock);
    if ((t->trapframe = uvm_thread_trapframe(p->mm->pagetable, t->tidx)) == 0) {   
        release(&t->p->mm->lock);
        return -1;
    }
    release(&t->p->mm->lock);

    if (name == NULL) {
        char name_tmp[THREAD_NAME_MAXLEN];
        snprintf(name_tmp, THREAD_NAME_MAXLEN, "%s-%d", p->name, t->tidx);
        strncpy(t->name, name_tmp, THREAD_NAME_MAXLEN);
    } else {
        strncpy(t->name, name, THREAD_NAME_MAXLEN);
    }

    return 0;
}

void thread_setkilled(struct tcb *t) {
    acquire(&t->lock);
    t->killed = 1;
    release(&t->lock);
}

int thread_killed(struct tcb *t) {
    acquire(&t->lock);
    int k = t->killed;
    release(&t->lock);
    return k;
}

void proc_sendsignal_all_thread(struct proc *p, sig_t signo, int opt) {
    struct tcb *t_cur = NULL;
    struct tcb *t_tmp = NULL;
    siginfo_t info;
    acquire(&p->tg->lock);
    list_for_each_entry_safe(t_cur, t_tmp, &p->tg->threads, thread) {
        signal_info_init(signo, &info, opt);

        acquire(&t_cur->lock);
        thread_send_signal(t_cur, &info);
        release(&t_cur->lock);
    }
    release(&p->tg->lock);
    if (signo == SIGKILL || signo == SIGSTOP) {
        proc_set_killed(p);
    }
}

void thread_group_init(struct thread_group *tg) {
    init_lock(&tg->lock, "thread group lock");
    tg->group_leader = NULL;
    atomic_set(&tg->thread_cnt, 0);
    tg->thread_idx = 0;
    INIT_LIST_HEAD(&tg->threads);
}

void sighandinit(struct tcb *t) {
    if ((t->sig = (struct sighand *)kzalloc(sizeof(struct sighand))) == 0) {
        panic("no space for sighand\n");
    }
    init_lock(&t->sig->siglock, "signal handler lock");
    atomic_set(&(t->sig->refcount), 1);
}

void thread_send_signal(struct tcb *t_cur, siginfo_t *info) {
    signal_send(info, t_cur);

    if (t_cur->state == TCB_SLEEPING) {
        thread_wakeup(t_cur);
    }

    switch(info->si_signo) {
        case SIGKILL:  
        case SIGSTOP:
            t_cur->killed = 1;
            break;
        default:
            break;
    }

    return;
}

void do_tkill(struct tcb *t, sig_t signo) {
    siginfo_t info;
    signal_info_init(signo, &info, 0);
    acquire(&t->lock);
    thread_send_signal(t, &info);
    release(&t->lock);
}

void create_thread(struct proc *p, struct tcb *t, char *name, thread_callback callback) {
    ASSERT(p != NULL);

    if ((t = alloc_thread(callback)) == 0) {
        panic("no free thread\n");
    }

    proc_join_thread(p, t, name);

    TCB_Q_changeState(t, TCB_RUNNABLE);
    release(&t->lock);
}

struct tcb *get_thread_by_tid(tid_t tid) {
    struct tcb *t = NULL;
    for (int i = 0; i < NTCB; i++) {
        t = thread + i;
        acquire(&t->lock);
        if (t->tid == tid) {
            release(&t->lock);
            return t;
        }
        release(&t->lock);
    }
    return NULL;
}

struct tcb *get_thread_by_tidx(pid_t pid, tid_t tidx) {
    struct proc *p = get_proc_by_pid(pid);
    if (p == NULL) {
        return NULL;
    }

    struct tcb *t_cur = NULL;
    struct tcb *t_tmp = NULL;
    acquire(&p->tg->lock);
    list_for_each_entry_safe(t_cur, t_tmp, &p->tg->threads, thread) {
        acquire(&t_cur->lock);
        if (t_cur->tidx == tidx) {
            release(&t_cur->lock);
            release(&p->tg->lock);
            return t_cur;
        }
        release(&t_cur->lock);
    }
    release(&p->tg->lock);

    return NULL;
}

static inline void save_stime_to_proc(struct proc *p, struct tcb *t, uint64 curtime) {
