static struct filesystem *get_fs_from_path(const char *path) {
    char abs_path[PATH_LONG_MAX] = {0};
    get_absolute_path(path, "/", abs_path);

    size_t len = strlen(abs_path);
    char *pstart = abs_path, *pend = abs_path + len - 1;
    while (pend > pstart) {
        if (*pend == '/') {
            *pend = '\0';
            filesystem_t *fs = get_fs_by_mount_point(pstart);
            if (fs) {
                return fs;
            }
        }
        pend--;
    }

    if (pend == pstart) {
        return get_fs_by_mount_point("/");
    }

    return NULL;
}

int arg_fd(int n, int *pfd, struct file **pf) {
    int fd;
    struct file *f;
    struct proc *p = proc_current();
    arg_int(n, &fd);
    if (fd < 0 || fd >= p->max_ofile)
        return -1;

    // in case another thread writes after the current thead reads
    acquire(&p->tlock);
    if ((f = proc_current()->_ofile[fd]) == 0) {
        release(&p->tlock);
        return -1;
    }
    if (pfd)
        *pfd = fd;
    if (pf)
        *pf = f;
    release(&p->tlock);
    return 0;
}

static struct inode *assist_icreate(char *path, int dirfd, uchar type, short major, short minor) {
    struct inode *dp = NULL, *ip = NULL;
    char name[MAXPATH] = {0};
    if ((dp = find_inode(path, dirfd, name)) == 0) {
        return 0;
    }
    ASSERT(dp->i_op);
    ip = dp->i_op->create(dp, name, type, major, minor); // don't check, caller will do this
    return ip;
}

int assist_openat(struct inode *ip, int flags, int omode, struct file **fp) {
    struct file *f;
    int fd;
    if ((f = file_alloc()) == 0 || (fd = fd_alloc(f)) < 0) {
        if (f)
            generic_fileclose(f);
        ip->i_op->unlock_put(ip);
        return -EMFILE;
    }

    if (ip->i_type == T_CHR) {
        f->f_type = FD_DEVICE;
        f->f_major = ip->i_dev;
    } else {
        f->f_type = FD_REG;
        f->f_pos = 0;
    }

    struct file_vnode *fv = kcalloc(1, sizeof(struct file_vnode));
    fv->fs = get_fs_by_type(FAT32);
    fv->data = ip;

    f->f_data.f_vnode = fv;
    f->f_flags = flags; // TODO(): &
    f->f_mode = omode; // TODO(): &
    f->f_count = 1;


    if ((flags & O_TRUNC) && ip->i_type == T_REG) {
        ip->i_size = 0;
        f->f_pos = 0;
    }
    if (fp)
        *fp = f;

    ip->i_op->unlock(ip);
}

uint64 sys_mknod(void) {
    char path[MAXPATH];
    int major, minor;

    arg_int(1, &major);
    arg_int(2, &minor);

    if (arg_str(0, path, MAXPATH) < 0) {
        return -1;
    }

    struct filesystem *fs = get_fs_from_path(path);
    if (fs == NULL) {
        return -1;
    }

    if (fs->fs_type == FAT32) {
        struct inode *ip;
        if ((ip = assist_icreate(path, AT_FDCWD, T_CHR, major, minor)) == 0) {
            return -1;
        }
        ip->i_op->unlock_put(ip);
    } else if (fs->fs_type == EXT4) {
        char absolute_path[PATH_LONG_MAX] = {0};
        get_absolute_path(path, proc_current()->cwd.path, absolute_path);
        dev_t dev = major;
        if (vfs_ext_mknod(absolute_path, T_CHR, dev) < 0) {
            return -1;
        }
    } else {
        return -1;
    }

    return 0;
}

