}

uint64 sys_dup(void) {
    struct file *f;
    int fd;

    if (arg_fd(0, 0, &f) < 0)
        return -EBADF;
    if ((fd = fd_alloc(f)) < 0)
        return -EMFILE;

    ASSERT(f->f_op);
    f->f_op->dup(f);
    return fd;
}

uint64 sys_dup3(void) {
    struct file *f;
    struct proc *p = proc_current();
    int oldfd, newfd, flags;

    if (arg_fd(0, &oldfd, &f) < 0) {
        return -1;
    }
    arg_int(1, &newfd);
    if (newfd < 0 || newfd >= NOFILE) {
        return -1;
    }
    arg_int(2, &flags);
    ASSERT(flags == 0);
    if (oldfd == newfd) {
        return newfd;
    }

    acquire(&p->tlock); // 可以修改为粒度小一些的锁;可以往_file结构里加锁，或者fdtable
    if (p->_ofile[newfd] == 0) {
        p->_ofile[newfd] = f;
        release(&p->tlock);
    } else {
        generic_fileclose(p->_ofile[newfd]);
        p->_ofile[newfd] = f;
        release(&p->tlock);
    }

    f->f_op->dup(f);
    return newfd;
}

uint64 sys_openat(void) {
    char path[PATH_LONG_MAX];
    int dirfd, flags, omode;
    struct file *f;
    struct inode *ip;
    int n;
    arg_int(0, &dirfd);
    if ((n = arg_str(1, path, PATH_LONG_MAX)) < 0) {
        return -1;
    }
    arg_int(2, &flags);
    arg_int(3, &omode);

    // printf("path: %s\n", path);

    if (!strcmp(path, "/lib/glibc/libc.so.6")) {
        strncpy(path, "/lib/glibc/libc-2.31.so", 24);
    }

    if (!strcmp(path, "/lib/glibc/libpthread.so.0")) {
        strncpy(path, "/lib/glibc/libpthread-2.31.so", 30);
    }

    if (!strcmp(path, "/lib/glibc/libm.so.6")) {
        strncpy(path, "/lib/glibc/libm-2.31.so", 24);
    }

    struct filesystem *fs = get_fs_from_path(path);
    if (fs == NULL) {
        return -1;
    }
    if (fs->fs_type == FAT32) {
        if ((flags & O_CREATE) == O_CREATE) {
            if ((ip = assist_icreate(path, dirfd, T_REG, 0, 0)) == 0) {
                return -1;
            }
        } else {
            if ((ip = find_inode(path, dirfd, 0)) == 0) {
                return -1;
            }
            ip->i_op->lock(ip);
            if ((flags & O_DIRECTORY) && ip->i_type != T_DIR) {
                ip->i_op->unlock_put(ip);
                return -1;
            }
        }

        if (ip->i_type == T_CHR && (ip->i_dev < 0 || ip->i_dev >= NDEV)) {
            ip->i_op->unlock_put(ip);
            return -1;
        }
        int fd = assist_openat(ip, flags, omode, NULL);
        return fd;

    } else if (fs->fs_type == EXT4) {
        // get path from dirfd
        const char *dirpath =
                dirfd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[dirfd]->f_data.f_vnode->path;

        char absolute_path[PATH_LONG_MAX] = {0};
        get_absolute_path(path, dirpath, absolute_path);

        if ((f = file_alloc()) == 0) {
            return -1;
        }

        int fd;
        if ((fd = fd_alloc(f)) < 0) {
            generic_fileclose(f);
            return -EMFILE;
        }

        f->f_flags = flags; // TODO(): &
        f->f_mode = omode; // TODO(): &
        f->f_count = 1;
        struct file_vnode *fv = kcalloc(1, sizeof(struct file_vnode));
        fv->fs = get_fs_by_type(EXT4);
        strcpy(fv->path, absolute_path);
        f->f_data.f_vnode = fv;

        if (vfs_ext_openat(f) < 0) {
            generic_fileclose(f);
            proc_current()->_ofile[fd] = 0; // free fd
            return -1;
        }
        return fd;
    } else if (fs->fs_type == PROCFS) {
        // printf("OPENING FILE IN PROCFS\n");

        // get path from dirfd
        const char *dirpath =
                dirfd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[dirfd]->f_data.f_vnode->path;

        char absolute_path[PATH_LONG_MAX] = {0};
        get_absolute_path(path, dirpath, absolute_path);

        if ((f = file_alloc()) == 0) {
            return -1;
        }

        int fd;
        if ((fd = fd_alloc(f)) < 0) {
            generic_fileclose(f);
            return -EMFILE;
        }

        f->f_flags = flags; // TODO(): &
        f->f_mode = omode; // TODO(): &
        f->f_count = 1;
        struct file_vnode *fv = kcalloc(1, sizeof(struct file_vnode));
        fv->fs = get_fs_by_type(PROCFS);
        strcpy(fv->path, absolute_path);
        f->f_data.f_vnode = fv;

        if (procfs_openat(f) < 0) {
            generic_fileclose(f);
            proc_current()->_ofile[fd] = 0; // free fd
            return -1;
        }
        return fd;
    }

    return -1;
}

