uint64 sys_read(void) {
    struct file *f;
    int n;
    uint64 p;

    arg_addr(1, &p);
    if (arg_int(2, &n) < 0) {
        return -1;
    }
    if (arg_fd(0, 0, &f) < 0)
        return -1;

    return f->f_op->read(f, 1, p, n);
}

