}

uint64 sys_linkat(void) {
    char newpath[MAXPATH], oldpath[MAXPATH];
    int olddirfd, newdirfd, flags;

    if (arg_str(1, oldpath, MAXPATH) < 0 || arg_str(3, newpath, MAXPATH) < 0) {
        return -1;
    }
    arg_int(0, &olddirfd);
    arg_int(2, &newdirfd);
    arg_int(4, &flags);
    ASSERT(flags == 0);

    struct filesystem *fs = get_fs_from_path(oldpath);
    if (fs == NULL) {
        return -1;
    }

    if (fs->fs_type == FAT32) {
        char oldname[MAXPATH], newname[MAXPATH];
        struct inode *oldip, *newdp;
        if ((newdp = find_inode(newpath, newdirfd, newname)) == 0) {
            return -1;
        }
        if ((oldip = find_inode(oldpath, olddirfd, oldname)) == 0) {
            return -1;
        }

        if (newdp->i_op->dirlookup(newdp, newname, 0) != 0) {
            return 0;
        }
    } else if (fs->fs_type == EXT4) {
        const char *old_dirfd_path = olddirfd == AT_FDCWD ? proc_current()->cwd.path
                                                          : proc_current()->_ofile[olddirfd]->f_data.f_vnode->path;
        const char *new_dirfd_path = newdirfd == AT_FDCWD ? proc_current()->cwd.path
                                                          : proc_current()->_ofile[newdirfd]->f_data.f_vnode->path;
        char oldpath_abs[PATH_LONG_MAX] = {0};
        char newpath_abs[PATH_LONG_MAX] = {0};
        get_absolute_path(oldpath, old_dirfd_path, oldpath_abs);
        get_absolute_path(newpath, new_dirfd_path, newpath_abs);
        if (vfs_ext_link(oldpath_abs, newpath_abs) < 0) {
            return -1;
        }
    }

    return 0;
}

static struct file *find_file_referred_by_any_proc(const char *path) {
    extern struct proc proc[NPROC];
    struct proc *p;
    for (int i = 0; i < NPROC; i++) {
        p = &proc[i];
        if (p->state == PCB_UNUSED) {
            continue;
        }
        for (int j = 0; j < NOFILE; j++) {
            if (p->_ofile[j] && p->_ofile[j]->f_count > 0 && p->_ofile[j]->f_data.f_vnode &&
                !strcmp(p->_ofile[j]->f_data.f_vnode->path, path)) {
                return p->_ofile[j];
            }
        }
    }
    return NULL;
}

uint64 sys_unlinkat(void) {
    char name[NAME_LONG_MAX], path[PATH_LONG_MAX];
    int dirfd, flags;
    uint off;
    arg_int(0, &dirfd); // don't need to check, because find_inode will do
    arg_int(2, &flags);
    // ASSERT(flags == 0);
    if (arg_str(1, path, PATH_LONG_MAX) < 0)
        return -1;

    struct filesystem *fs = get_fs_from_path(path);
    if (fs->fs_type == FAT32) {
        struct inode *ip, *dp;
        if ((dp = find_inode(path, dirfd, name)) == 0) {
            printfRed("unlinkat: find_inode failed\n");
            return -1;
        }

        if (__namecmp(name, ".") == 0 || __namecmp(name, "..") == 0) {
            return -1;
        }

        dp->i_op->lock(dp);
        if ((ip = dp->i_op->dirlookup(dp, name, &off)) == 0) {
            goto bad;
        }

        ip->i_op->lock(ip);
        if (ip->i_nlink < 1)
            panic("unlink: nlink < 1");
        if (ip->i_type == T_DIR && !ip->i_op->dir_empty(ip)) {
            ip->i_op->unlock_put(ip);
            goto bad;
        }

        dp->i_op->delete (dp, ip);


        ip->i_nlink--;
        ip->i_op->update(ip);
        ip->i_op->unlock_put(ip);

        dp->i_op->unlock_put(dp);

        return 0;

    bad:
        dp->i_op->unlock_put(dp);

        return -1;
    } else if (fs->fs_type == EXT4) {
        const char *dirfd_path =
                dirfd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[dirfd]->f_data.f_vnode->path;
        char path_abs[PATH_LONG_MAX] = {0};
        get_absolute_path(path, dirfd_path, path_abs);
        struct file *f = find_file_referred_by_any_proc(path_abs);
        if (f) {
            /* mark it */
            f->removed = 1;
        } else if (vfs_ext_rm(path_abs) < 0) { /* no file referred by proc */
            return -1;
        }
    }
    return 0;
}

uint64 sys_mkdirat(void) {
    char path[PATH_LONG_MAX];
    int dirfd;
    mode_t mode;
    arg_int(0, &dirfd);
    if (arg_int(2, (int *) &mode) < 0) {
        return -1;
    }
    if (arg_str(1, path, PATH_LONG_MAX) < 0) {
        return -1;
    }
    struct filesystem *fs = get_fs_from_path(path);
    if (fs == NULL) {
        return -1;
    }
    if (fs->fs_type == FAT32) {
        struct inode *ip;
        if ((ip = assist_icreate(path, dirfd, T_DIR, 0, 0)) == 0) {
            return -1;
        }
        ip->i_op->unlock_put(ip);

    } else if (fs->fs_type == EXT4) {
        const char *dirfd_path =
                dirfd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[dirfd]->f_data.f_vnode->path;
        char path_abs[PATH_LONG_MAX] = {0};
        get_absolute_path(path, dirfd_path, path_abs);
        if (vfs_ext_mkdir(path_abs, mode) < 0) {
            return -1;
        }
    }

    return 0;
}

uint64 sys_getdents64(void) {
    struct file *f;
    uint64 buf; // user pointer to struct dirent
    int len;
    ssize_t nread;
    char *kbuf;

    if (arg_fd(0, 0, &f) < 0)
        return -1;

    if (f->f_type != FD_REG) {
        return -1;
    }

    if (f->f_data.f_vnode->fs->fs_type == FAT32) {
        struct inode *ip = f->f_data.f_vnode->data;
        ASSERT(ip);
        if (ip->i_type != T_DIR) {
            return -1;
        }
        if (f->f_pos == ip->i_size) {
            return 0;
        }
        arg_addr(1, &buf);
        arg_int(2, &len);
        if (len < 0) {
            return -1;
        }
        const ssize_t sz = MAX(ip->i_sb->cluster_size, len);
        if ((kbuf = kmalloc(sz)) == 0) {
            return -1;
        }
        memset(kbuf, 0, len); // !!!!
        ASSERT(ip->i_op);
        ASSERT(ip->i_op->getdents);
        if ((nread = ip->i_op->getdents(ip, kbuf, sz)) < 0) {
            kfree(kbuf);
            return -1;
        }
        len = MIN(len, sz);

        if (either_copy_out(1, buf, kbuf, len) < 0) { // copy lenth may less than nread
            kfree(kbuf);
            return -1;
        }
        kfree(kbuf);
        f->f_pos = ip->i_size;
    } else if (f->f_data.f_vnode->fs->fs_type == EXT4) {
        arg_addr(1, &buf);
        arg_int(2, &len);
        if (len < 0) {
            return -1;
        }
        if ((kbuf = kmalloc(len)) == 0) {
            return -1;
        }
        memset(kbuf, 0, len);
        if ((nread = vfs_ext_getdents(f, kbuf, len)) < 0) {
            kfree(kbuf);
            return -1;
        }
        len = MIN(len, nread);
        if (either_copy_out(1, buf, kbuf, len) < 0) {
            kfree(kbuf);
            return -1;
        }
        kfree(kbuf);
    }
    return nread;
}

uint64 sys_fstat(void) {
    struct file *f;
    uint64 st;

    arg_addr(1, &st);
    if (arg_fd(0, 0, &f) < 0)
        return -1;

    return f->f_op->fstat(f, st);
}

uint64 sys_chdir(void) {
    char path[PATH_LONG_MAX];
    char abs_path[PATH_LONG_MAX] = {0};
    struct proc *p = proc_current();

    if (arg_str(0, path, PATH_LONG_MAX) < 0) {
        return -1;
    }

    struct filesystem *fs = get_fs_from_path(path);
    if (fs == NULL) {
        return -1;
    }

    if (fs->fs_type == FAT32) {
        struct inode *ip;
        if ((ip = namei(path)) == 0) {
            return -1;
        }

        ip->i_op->lock(ip);
        if (ip->i_type != T_DIR) {
            ip->i_op->unlock_put(ip);
            return -1;
        }

        ip->i_op->unlock(ip);

        /* if FAT32, set cwd.data here */
        p->cwd.data = ip;

    } else if (fs->fs_type == EXT4) {
        get_absolute_path(path, p->cwd.path, abs_path);
        if (vfs_ext_is_dir(abs_path) != EOK) {
            return -1;
        }
    }

    get_absolute_path(path, p->cwd.path, abs_path); // double copy here, may be optimized
    strncpy(p->cwd.path, abs_path, PATH_LONG_MAX);
    return 0;
}

uint64 sys_pipe2(void) {
    uint64 fdarray; // user pointer to array of two integers
    struct file *rf, *wf;
    int fd1;
    struct proc *p = proc_current();

    arg_addr(0, &fdarray);
    if (pipe_alloc(&rf, &wf) < 0) // 分配两个 pipe 文件
        return -1;
    int fd0 = -1;
    if ((fd0 = fd_alloc(rf)) < 0 || (fd1 = fd_alloc(wf)) < 0) { // 给当前进程分配两个文件描述符，代指那两个管道文件
        if (fd0 >= 0)
            p->_ofile[fd0] = 0;
        generic_fileclose(rf);
        generic_fileclose(wf);
        return -1;
    }
    if (copy_out(p->mm->pagetable, fdarray, (char *) &fd0, sizeof(fd0)) < 0 ||
        copy_out(p->mm->pagetable, fdarray + sizeof(fd0), (char *) &fd1, sizeof(fd1)) < 0) {
        p->_ofile[fd0] = 0;
        p->_ofile[fd1] = 0;
        generic_fileclose(rf);
        generic_fileclose(wf);
        return -1;
    }
    return 0;
}

uint64 sys_fstatat(void) {
    char pathname[MAXPATH];
    int dirfd, flags;
    uint64 statbuf;
    arg_int(0, &dirfd);
    if (arg_str(1, pathname, MAXPATH) < 0) {
        return -1;
    }
    arg_addr(2, &statbuf);
    arg_int(3, &flags);

    struct filesystem *fs = get_fs_from_path(pathname);
    if (fs == NULL) {
        return -1;
    }

    if (fs->fs_type == FAT32) {
        struct inode *ip;
        // TODO : for libc-test，we should add special process for /dev/null、/dev/zero
        if ((ip = find_inode(pathname, dirfd, 0)) == 0) {
            return -ENOENT;
        }

        ip->i_op->lock(ip);

        struct stat kbuf;
        kbuf.st_dev = ip->i_dev;
        kbuf.st_ino = ip->i_ino;
        kbuf.st_mode = ip->i_mode;
        kbuf.st_nlink = ip->i_nlink;
        kbuf.st_uid = ip->i_uid;
        kbuf.st_gid = ip->i_gid;
        kbuf.st_rdev = ip->i_rdev;
        kbuf.st_size = ip->i_size;
        kbuf.st_blksize = ip->i_sb->s_blocksize;
        kbuf.st_blocks = ip->i_blocks * ip->i_sb->cluster_size / 512; // 512B per block

        // for libc-test stat
        kbuf.st_atim.tv_nsec = 0;
        kbuf.st_atim.tv_sec = 0;
        kbuf.st_mtim.tv_nsec = 0;
        kbuf.st_mtim.tv_sec = 0;
        kbuf.st_ctim.tv_nsec = 0;
        kbuf.st_ctim.tv_sec = 0;

        ip->i_op->unlock(ip);

        if (either_copy_out(1, statbuf, &kbuf, sizeof(struct stat)) < 0) {
            return -1;
        }
    } else if (fs->fs_type == EXT4) {
        struct stat kbuf;
        const char *dirfd_path =
                dirfd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[dirfd]->f_data.f_vnode->path;
        char path_abs[PATH_LONG_MAX] = {0};
        get_absolute_path(pathname, dirfd_path, path_abs);
        int r = vfs_ext_stat(path_abs, &kbuf);
        if (r < 0) {
            return r;
        }
        if (either_copy_out(1, statbuf, &kbuf, sizeof(struct stat)) < 0) {
            return -1;
        }
    } else if (fs->fs_type == PROCFS) {
        struct kstat kbuf;
        const char *dirfd_path =
                dirfd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[dirfd]->f_data.f_vnode->path;
        char path_abs[PATH_LONG_MAX] = {0};
        get_absolute_path(pathname, dirfd_path, path_abs);
        int r = procfs_fstat(path_abs, &kbuf);
        if (r < 0) {
            return r;
        }
        if (either_copy_out(1, statbuf, &kbuf, sizeof(struct kstat)) < 0) {
            return -1;
        }
    }

    return 0;
}

uint64 sys_lseek(void) {
    struct file *f;
    uint64 offset;
    int whence;
    if (arg_fd(0, 0, &f) < 0) {
        return -1;
    }
    arg_addr(1, &offset);
    arg_int(2, &whence);
    if (f->f_type != FD_REG) {
        return -1;
    }

    if (f->f_data.f_vnode->fs->fs_type == EXT4) {

        // f**king iozone
        if (!strncmp(f->f_data.f_vnode->path, "/iozone.", 8)) {
            if (whence == SEEK_END) {
                return 0;
            }
            return offset;
        }

        if (((struct ext4_file *) f->f_data.f_vnode->data)->fsize < (uint64) offset) {
            return offset;
        }
        return vfs_ext_lseek(f, offset, whence);
    } else {
        switch (whence) {
            case SEEK_SET:
                f->f_pos = offset;
                break;
            case SEEK_CUR:
                f->f_pos += offset;
                break;
            case SEEK_END:
                f->f_pos = ((struct inode *) (f->f_data.f_vnode->data))->i_size + offset;
                break;
            default:
                panic("error type\n");
        }
    }
    return MAX(0, f->f_pos);
}

uint64 sys_readv(void) {
    struct file *f;
    int iovcnt;
    ssize_t nread = 0;
    uint64 iov;
    void *kbuf;
    if (arg_fd(0, 0, &f) < 0) {
        return -1;
    }
    arg_addr(1, &iov);
    if (arg_int(2, &iovcnt) < 0) {
        return -1;
    }

    const int totsz = sizeof(struct iovec) * iovcnt;
    if ((kbuf = kmalloc(totsz)) == 0) {
        if (likely(kbuf)) {
            kfree(kbuf);
        }
        return -1;
    }

    if (either_copy_in(kbuf, 1, iov, totsz) < 0) {
        if (likely(kbuf)) {
            kfree(kbuf);
        }
        return -1;
    }

    int filesz = 0;
    if (f->f_data.f_vnode->fs->fs_type == FAT32) {
        struct inode *ip = f->f_data.f_vnode->data;
        filesz = ip->i_size;
    } else if (f->f_data.f_vnode->fs->fs_type == EXT4) {
        vfs_ext_get_filesize(f->f_data.f_vnode->path, &filesz);
    }

    // hack iozone
    if (!strncmp(f->f_data.f_vnode->path, "/iozone.", 8)) {
        filesz = 4096;
    }

    struct iovec *p = (struct iovec *) kbuf;

    const struct proc *p_current = proc_current();
    // special for urandom
    if (!strncmp(f->f_data.f_vnode->path, "/dev/urandom", 12)) {
        for (int i = 0; i != iovcnt; i++) {
            uchar *buf_tmp;
            if ((buf_tmp = kmalloc(p->iov_len)) == NULL) {
                panic("sys_readv : no free space\n");
            }
            copy_out(p_current->mm->pagetable, (uint64) p->iov_base, (void *) buf_tmp, p->iov_len);
            kfree(buf_tmp);
            nread += p->iov_len;
            ++p;
        }
    } else {
        int nr = 0;
        // general process
        for (int i = 0; i != iovcnt && filesz > 0; ++i) {
            if ((nr = f->f_op->read(f, 1, (uint64) p->iov_base, MIN(p->iov_len, filesz))) < 0) {
                if (likely(kbuf)) {
                    kfree(kbuf);
                }
                return -1;
            }
            nread += nr;
            filesz -= nr;
            ++p;
        }
    }

    kfree(kbuf);
    return nread;
}

uint64 sys_writev(void) {
    struct file *f;
    int iovcnt;
    ssize_t nwrite = 0;
    uint64 iov;
    void *kbuf;

    arg_addr(1, &iov);
    if (arg_int(2, &iovcnt) < 0) {
        return -1;
    }
    if (arg_fd(0, 0, &f) < 0) {
        return -1;
    }

    if (f->f_type == FD_REG) {
        /* writev shouldn't be used for writing directories */
        if (f->f_data.f_vnode->fs->fs_type == FAT32) {
            struct inode *ip = f->f_data.f_vnode->data;
            ip->i_op->lock(ip);
            if (ip->i_type == T_DIR) {
                ip->i_op->unlock(ip);
                return -1;
            }
            ip->i_op->unlock(ip);
        } else if (f->f_data.f_vnode->fs->fs_type == EXT4) {
            if (vfs_ext_is_dir(f->f_data.f_vnode->path) == EOK) {
                return -1;
            }
        }
    }

    const int totsz = sizeof(struct iovec) * iovcnt;
    if ((kbuf = kmalloc(totsz)) == 0) {
        if (likely(kbuf)) {
            kfree(kbuf);
        }
        return -1;
    }

    if (either_copy_in(kbuf, 1, iov, totsz) < 0) {
        if (likely(kbuf)) {
            kfree(kbuf);
        }
        return -1;
    }

    int nw = 0;
    const struct iovec *p = (struct iovec *) kbuf;
    for (int i = 0; i != iovcnt; i++) {
        if ((nw = f->f_op->write(f, 1, (uint64) p->iov_base, p->iov_len)) < 0) {
            if (likely(kbuf)) {
                kfree(kbuf);
            }
            return -1;
        }
        nwrite += nw;
        ++p;
    }

    kfree(kbuf);
    return nwrite;
}

uint64 sys_faccessat(void) {
    int fd, mode, flags;
    char path[MAXPATH];
    arg_int(0, &fd);
    arg_int(2, &mode);
    arg_int(3, &flags);
    if (arg_str(1, path, MAXPATH) < 0) {
        return -1;
    }

    struct filesystem *fs = get_fs_from_path(path);
    if (fs == NULL) {
        return -1;
    }

    if (fs->fs_type == FAT32) {
        struct inode *ip;
        if ((ip = find_inode(path, fd, 0)) == 0) {
            return -1;
        }

        ip->i_op->lock(ip);
        if (mode == F_OK) {
            ip->i_op->unlock_put(ip);
            return 0;
        }

        if (mode == R_OK) {
            if (ip->i_mode & S_IRUSR) {
                ip->i_op->unlock_put(ip);
                return 0;
            }
        }

        if (mode == W_OK) {
            if (ip->i_mode & S_IWUSR) {
                ip->i_op->unlock_put(ip);
                return 0;
            }
        }

        if (mode == X_OK) {
            if (ip->i_mode & S_IXUSR) {
                ip->i_op->unlock_put(ip);
                return 0;
            }
        }

        ip->i_op->unlock_put(ip);
        return -1;
    } else if (fs->fs_type == EXT4) {
        const char *dirfd_path =
                fd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[fd]->f_data.f_vnode->path;
        char path_abs[PATH_LONG_MAX] = {0};
        get_absolute_path(path, dirfd_path, path_abs);
        if (vfs_ext_faccessat(path_abs, mode) < 0) {
            return -1;
        }
    }

    return 0;
}

static uint64 do_fcntl(struct file *f, int cmd) {
    int ret, arg;
    switch (cmd) {
        case F_DUPFD: {
            int new_fd;
            if ((new_fd = fd_alloc(f)) > 0) {
                f->f_op->dup(f);
            }
            ret = new_fd;
        } break;

        case F_GETFD:
        case F_GETFL:
            ret = f->f_flags;
            break;

        case F_SETFD:
            ret = 0;
            break;

        case F_SETFL:
            if (arg_int(2, &arg) < 0) {
                ret = -1;
            } else {
                if ((((arg & O_NONBLOCK) == O_NONBLOCK) || ((arg & O_APPEND) == O_APPEND))) {
                    f->f_flags |= arg;
                    if (f->f_data.f_vnode->fs->fs_type == FAT32) {
                        f->f_pos = ((struct inode *) f->f_data.f_vnode->data)->i_size + 1;
                    } else if (f->f_data.f_vnode->fs->fs_type == EXT4) {
                        vfs_ext_lseek(f, 0, SEEK_END);
                    }
                    ret = 0;
                }
                ret = -1;
            }
            break;

        case F_DUPFD_CLOEXEC: {
            int new_fd;
            if ((new_fd = fd_alloc(f)) > 0) {
                f->f_op->dup(f);
            }
            ret = new_fd;
        } break;
        default:
            ret = 0;
            break;
    }

    return ret;
}

uint64 sys_fcntl(void) {
    struct file *f;
    int cmd;
    if (arg_fd(0, 0, &f) < 0) {
        return -EBADF;
    }
    arg_int(1, &cmd);
    return do_fcntl(f, cmd);
}

static uint64 do_renameat2(struct inode *ip, int new_dir_fd, char *new_path, int flags) {
    char name[MAXPATH];
    struct inode *dp;
    ASSERT(flags == 0);
    struct inode *new_ip = find_inode(new_path, new_dir_fd, NULL);
    if (unlikely(ip == new_ip)) {
        /* points to same inode */
        return 0;
    }

    ip->i_op->lock(ip);
    if (likely(!new_ip)) {
        /* new inode does not exist, create one */
        goto create;
    }

    if (ip->i_type == T_REG) {
        /* inode exists and it is a file */
        new_ip->i_op->lock(new_ip);
        if (new_ip->i_type == T_DIR) {
            /* new inode can't be a directory */
            new_ip->i_op->unlock_put(new_ip);
            ip->i_op->unlock_put(ip);
            return -1;
        }
        /* delete the old file */
        ASSERT(new_ip->parent->i_sem.value > 0);
        new_ip->parent->i_op->lock(new_ip->parent);
        goto unlink_create;
    }
    if (ip->i_type == T_DIR) {
        /* inode is a directory */
        new_ip->i_op->lock(new_ip);
        if (!(new_ip->i_type != T_DIR) || !new_ip->i_op->dir_empty(new_ip)) {
            /* if new inode is a directory,
               it should be empty */
            new_ip->i_op->unlock_put(new_ip);
            ip->i_op->unlock_put(ip);
            return -1;
        }
        /* delete the old file */
        ASSERT(new_ip->parent->i_sem.value > 0);
        new_ip->parent->i_op->lock(new_ip->parent);
        goto unlink_create;
    }

unlink_create:
    /* unlink new inode first */
    {
        struct inode *new_ip_parent = new_ip->parent;
        new_ip_parent->i_op->delete (new_ip_parent, new_ip);
        if (new_ip->i_nlink < 1) {
            panic("remove: nlink < 1");
        }
        new_ip->i_nlink--;
        new_ip->i_op->update(new_ip);
        new_ip->i_op->unlock_put(new_ip);
        new_ip_parent->i_op->unlock_put(new_ip_parent);
    }

create:
    /* copy entry */
    printfGreen("new_path is %s\n", new_path);
    if ((dp = find_inode(new_path, new_dir_fd, name)) == 0) {
        ip->i_op->unlock_put(ip);
        return -1;
    }
    printfGreen("name is %s\n", name);

    /*
        suggest we have two files:
        /A/a.txt
        /A/B/a.txt
    */

    /* mv /A/a.txt /A/B/a.txt => /A/B/a.txt */
    dp->i_op->lock(dp);
    printfGreen("dp is %s, ip is %s\n", dp->fat32_i.fname, ip->fat32_i.fname);
    const char *new_name = NULL; /* by default, 'new_name' is NULL,
                              telling icpentry_rename not to rename the fcb
                              and just copy it */
    if (strncmp(name, ip->fat32_i.fname, strlen(ip->fat32_i.fname))) {
        /*
         * the 'name' variable, which will be the file's new name,
         * is not the same as ip's original fname,
         * set 'new_name' to 'name'.
         */
        new_name = name;
    }
    if (dp->i_op->cpentry_rename(dp, ip, new_name) < 0) {
        dp->i_op->unlock_put(dp);
        ip->i_op->unlock_put(ip);
        return -1;
    }
    dp->i_op->unlock_put(dp);

    /* remove original entry */
    ASSERT(ip->parent->i_op);
    struct inode *parent = ip->parent;
    ASSERT(parent->i_sem.value > 0);
    parent->i_op->lock(parent);
    parent->i_op->delete (parent, ip);
    parent->i_op->unlock_put(parent);
    ip->i_op->unlock_put(ip);

    return 0;
}

uint64 sys_renameat2(void) {
    uint flags;
    int old_dir_fd, new_dir_fd;
    char old_path[MAXPATH], new_path[MAXPATH];
    arg_int(0, &old_dir_fd);
    arg_int(2, &new_dir_fd);
    if (arg_str(1, old_path, MAXPATH) < 0) {
        return -1;
    }
    if (arg_str(3, new_path, MAXPATH) < 0) {
        return -1;
    }
    arg_int(4, (int *) &flags);
    ASSERT(flags == 0);

    struct filesystem *fs = get_fs_from_path(old_path);
    if (fs == NULL) {
        return -1;
    }

    if (fs->fs_type == FAT32) {
        struct inode *old_ip;
        if ((old_ip = find_inode(old_path, old_dir_fd, 0)) == 0) {
            return -1;
        }

        return do_renameat2(old_ip, new_dir_fd, new_path, flags);
    } else if (fs->fs_type == EXT4) {
        const char *old_dirfd_path = old_dir_fd == AT_FDCWD ? proc_current()->cwd.path
                                                            : proc_current()->_ofile[old_dir_fd]->f_data.f_vnode->path;
        const char *new_dirfd_path = new_dir_fd == AT_FDCWD ? proc_current()->cwd.path
                                                            : proc_current()->_ofile[new_dir_fd]->f_data.f_vnode->path;
        char oldpath_abs[PATH_LONG_MAX] = {0};
        char newpath_abs[PATH_LONG_MAX] = {0};
        get_absolute_path(old_path, old_dirfd_path, oldpath_abs);
        get_absolute_path(new_path, new_dirfd_path, newpath_abs);
        if (vfs_ext_frename(oldpath_abs, newpath_abs) < 0) {
            return -1;
        }
    }

    return 0;
}

static uint64 do_sendfile(struct file *rf, struct file *wf, off_t *poff, size_t count) {
    void *kbuf;
    off_t offset;
    ssize_t nread, nwrite;
    if ((kbuf = kzalloc(count)) == 0) {
        return -1;
    }
    if (poff) {
        either_copy_in(&offset, 1, (uint64) poff, sizeof(off_t));
    } else {
        offset = rf->f_pos;
    }

    if (rf->f_data.f_vnode->fs->fs_type == EXT4) {
        if (poff) {
            if ((nread = vfs_ext_readat(rf, 0, (uint64) kbuf, count, offset)) <= 0) {
                goto bad;
            }
        } else {
            if ((nread = vfs_ext_read(rf, 0, (uint64) kbuf, count)) <= 0) {
                goto bad;
            }
            count = MIN(count, nread);
            nread = 0; /* rf->f_pos has already been set inside vfs_ext_read */
        }
    } else if (rf->f_data.f_vnode->fs->fs_type == FAT32) {
        struct inode *rdip = rf->f_data.f_vnode->data;
        if ((nread = rdip->i_op->read(rdip, 0, (uint64) kbuf, offset, count)) <= 0) {
            goto bad;
        }
    }

    if (wf->f_type == FD_PIPE) {
        // TODO: pipe_write may have bugs here
        if ((nwrite = pipe_write(wf->f_data.f_pipe, (uint64) kbuf, count)) < 0) {
            goto bad;
        }
    } else if (wf->f_type == FD_REG) {
        /* use file_write here */
        if ((nwrite = wf->f_op->write(wf, 0, (uint64) kbuf, count)) < 0) {
            goto bad;
        }
    } else if (wf->f_type == FD_DEVICE) {
        // TODO: is f_pos correct after write?
        if ((nwrite = wf->f_op->write(wf, 0, (uint64) kbuf, count)) < 0) {
            goto bad;
        }
    } else {
        /* unsupported file type  */
        goto bad;
    }

    offset += nread;

    if (poff) {
        either_copy_out(1, (uint64) poff, &offset, sizeof(offset));
    } else {
        rf->f_pos += nread;
        // wf->f_pos += nwrite;
    }
    kfree(kbuf);
    return nwrite;

bad:
    if (kbuf) {
        kfree(kbuf);
    }
    return -1;
}

uint64 sys_sendfile(void) {
    struct file *rf, *wf;
    off_t *poff;
    size_t count;
    if (arg_fd(0, 0, &wf) < 0 || arg_fd(1, 0, &rf) < 0) {
        return -EBADF;
    }
    arg_long(3, (long *) &count);
    if (count < 0) {
        return -1;
    }
    if (count == 0) {
        return 0;
    }
    arg_addr(2, (uint64 *) &poff); // TODO: maybe bugs here
    if (rf->f_type != FD_REG || !F_READABLE(rf)) {
        return -1;
    }
    if (!F_WRITEABLE(wf)) {
        return -1;
    }

    return do_sendfile(rf, wf, poff, count);
}

static long do_ioctl(struct file *f, unsigned int cmd, unsigned long arg) {
    int error = -1;

    if (!f->f_op) {
        return error;
    }

    if (f->f_op->ioctl) {
        error = f->f_op->ioctl(f, cmd, arg);
    }

    extern struct termios term;
    if (cmd == TCSETS) {
        struct termios newterm;
        if (copy_in(proc_current()->mm->pagetable, (char *) &newterm, arg, sizeof(newterm)) < 0)
            return -1;
        term = newterm;
    } else if (cmd == TCGETS) {
        if (copy_out(proc_current()->mm->pagetable, arg, (char *) &term, sizeof(term)) < 0)
            return -1;
    }

    return 0;
}

uint64 sys_ioctl(void) {
    struct file *f;
    uint64 cmd;
    uint64 arg;
    if (arg_fd(0, 0, &f) < 0) {
        return -1;
    }
    arg_long(1, &cmd);
    arg_long(2, &arg);
    return do_ioctl(f, cmd, arg);
}

uint64 sys_statfs(void) {
    char path[MAXPATH];
    uint64 ustat_p;
    struct statfs kbuf;
    if (arg_str(0, path, MAXPATH) < 0) {
        return -1;
    }
    arg_addr(1, &ustat_p);

    struct filesystem *fs = get_fs_by_mount_point("/"); /* a hack here */
    if (!fs) {
        return -1;
    }
    if (fs->fs_op->statfs(fs, &kbuf) != 0) {
        return -1;
    }
    struct proc *p = proc_current();
    if (copy_out(p->mm->pagetable, (uint64) ustat_p, &kbuf, sizeof(struct statfs)) < 0) {
        return -1;
    }
    return 0;
}

static int utimes_common(struct inode *ip, struct timespec *times) {
    if (!times) {
        ip->i_atime = NS_to_S(TIME2NS(rdtime()));
        ip->i_mtime = NS_to_S(TIME2NS(rdtime()));
    }

    if (times[0].tv_nsec == UTIME_NOW) {
        ip->i_atime = NS_to_S(TIME2NS(rdtime()));
    } else if (times[0].tv_nsec == UTIME_OMIT) {
        /* omit it */
    } else {
        ip->i_atime = NS_to_S(TIMESEPC2NS(times[0]));
    }

    if (times[1].tv_nsec == UTIME_NOW) {
        ip->i_mtime = NS_to_S(TIME2NS(rdtime()));
    } else if (times[1].tv_nsec == UTIME_OMIT) {
        /* omit it */
    } else {
        ip->i_mtime = NS_to_S(TIMESEPC2NS(times[1]));
    }
    return 0;
}

long do_utimes(int dfd, char *filename, struct timespec *times, int flags) {
    int err = -EINVAL;

    if (flags & ~AT_SYMLINK_NOFOLLOW)
        return -EINVAL;

    if (filename == NULL && dfd != AT_FDCWD) {
        struct file *file = NULL;

        if (flags & AT_SYMLINK_NOFOLLOW)
            return -EINVAL;

        arg_fd(0, &dfd, &file);

        if (!file)
            return -EBADF;

        if (file->f_data.f_vnode->fs->fs_type == FAT32) {
            err = utimes_common((struct inode *) file->f_data.f_vnode->data, times);
        } else if (file->f_data.f_vnode->fs->fs_type == EXT4) {
            err = vfs_ext_futimens(file, times);
        }

    } else {
        struct filesystem *fs = get_fs_from_path(filename);

        if (fs == NULL) {
            return -1;
        }

        if (fs->fs_type == EXT4) {
            char *dirfd_path =
                    dfd == AT_FDCWD ? proc_current()->cwd.path : proc_current()->_ofile[dfd]->f_data.f_vnode->path;
            char path_abs[PATH_LONG_MAX] = {0};
            get_absolute_path(filename, dirfd_path, path_abs);
            err = vfs_ext_utimens(filename, times);
        } else if (fs->fs_type == FAT32) {
            struct inode *ip;
            if ((ip = find_inode(filename, dfd, 0)) == 0) {
                return -ENOENT;
            }
            err = utimes_common(ip, times);
        }
    }

    return err;
}

uint64 sys_utimensat(void) {
    int fd;
    char path[MAXPATH];
    uint64 times_addr;
    int flags;
    arg_int(0, &fd);
    uint64 path_addr;
    arg_addr(1, &path_addr);
    if (path_addr == 0 || arg_str(1, path, MAXPATH) < 0) {
        path[0] = '\0';
    }
    arg_addr(2, &times_addr);
    arg_int(3, &flags);

    struct timespec tstimes[2];

    if (times_addr) {
        if (copy_in(proc_current()->mm->pagetable, (char *) &tstimes, times_addr, 2 * sizeof(struct timespec)) < 0) {
            return -EFAULT;
        }
        if (tstimes[0].tv_sec == UTIME_OMIT && tstimes[1].tv_nsec == UTIME_OMIT)
            return 0;
    }

    return do_utimes(fd, path[0] ? path : NULL, times_addr ? tstimes : NULL, flags);
}

