int splice(struct file *f_in, off_t *off_in, struct file *f_out, off_t *off_out, int len) {
    int total = 0;
    int n;
    char buffer[512];

    while (len > 0) {
        int to_read = len;
        if (sizeof(buffer) < len) {
            to_read = sizeof(buffer);
        }

        if (f_in->f_type == FD_PIPE) {
            n = pipe_read(f_in->f_data.f_pipe, (uint64) buffer, to_read);
        } else if (f_in->f_type == FD_REG) {
            n = file_pread(f_in, 1, (uint64) buffer, off_in ? *off_in : 0, to_read);
            if (n > 0 && off_in) {
                *off_in += n;
            }
        } else {
            return -1;
        }

        if (n <= 0)
            break;

        if (f_out->f_type == FD_PIPE) {
            n = pipe_write(f_out->f_data.f_pipe, (uint64) buffer, n);
        } else if (f_out->f_type == FD_REG) {
            n = file_pwrite(f_out, 1, (uint64) buffer, off_out ? *off_out : 0, n);
            if (n > 0 && off_out) {
                *off_out += n;
            }
        } else {
            return -1;
        }

        if (n <= 0)
            break;

        total += n;
        len -= n;
    }

    return total;
}

uint64 sys_splice(void) {
    int fd_in, fd_out;
    int len;
    off_t *p_off_in, *p_off_out;

    struct file *fin, *fout;
    if (arg_fd(0, &fd_in, &fin) < 0) {
        return -1;
    }

    if (arg_addr(1, (uint64 *) &p_off_in) < 0) {
        return -1;
    }
    if (arg_fd(2, &fd_out, &fout) < 0) {
        return -1;
    }
    if (arg_addr(3, (uint64 *) &p_off_out) < 0) {
        return -1;
    }
    if (arg_int(4, &len) < 0) {
        return -1;
    }

    return splice(fin, p_off_in, fout, p_off_out, len);
}

