static void do_shm_rmid(struct ipc_namespace *ns, struct kern_ipc_perm *ipcp) {
    struct shmid_kernel *shp;
    shp = container_of(ipcp, struct shmid_kernel, shm_perm);
    if (shp->shm_nattch) {
        shp->shm_perm.mode |= SHM_DEST;
        shp->shm_perm.key = IPC_PRIVATE;
        release(&shp->shm_perm.lock);
    } else {
        shm_destroy(ns, shp);
    }
}

long do_shmat(int shmid, char *shmaddr, int shmflg, uint64 *raddr) {
    struct shmid_kernel *shp;
    uint64 addr;
    uint64 size;
    struct file *file;
    int err;
    uint64 flags;
    uint64 prot;
    int acc_mode;
    uint64 user_addr;
    struct ipc_namespace *ns;
    struct shm_file_data *sfd;
    mode_t f_mode;
    err = -EINVAL;
    if (shmid < 0)
        goto out;
    else if ((addr = (uint64) shmaddr)) {
        if (addr & (SHMLBA - 1)) {
            if (shmflg & SHM_RND)
                addr &= ~(SHMLBA - 1); /* round down */
            else {
                panic("do_shmat : not tested\n");
            }
        }
        flags = MAP_SHARED | MAP_FIXED;
    } else {
        if ((shmflg & SHM_REMAP))
            goto out;
        flags = MAP_SHARED;
    }
    if (shmflg & SHM_RDONLY) {
        prot = PROT_READ;
        acc_mode = S_IRUGO;
        f_mode = O_RDONLY;
    } else {
        prot = PROT_READ | PROT_WRITE;
        acc_mode = S_IRUGO | S_IWUGO;
        f_mode = O_WRONLY;
    }
    if (shmflg & SHM_EXEC) {
        prot |= PROT_EXEC;
        acc_mode |= S_IXUGO;
    }
    ns = proc_current()->ipc_ns;
    shp = shm_lock_check(ns, shmid);
    shp->shm_nattch++;
    size = shp->shm_segsz;
    shm_unlock(shp);
    err = -ENOMEM;
    if ((sfd = (struct shm_file_data *) kzalloc(sizeof(struct shm_file_data))) == 0) {
        panic("no free memory\n");
    }
    file = shp->shm_file;
    if (!file) {
        panic("occur error\n");
    }
    file->f_mode |= f_mode;
    file->private_data = sfd;
    sfd->id = shp->shm_perm.id;
    sfd->ns = ns;
    sfd->file = shp->shm_file;
    struct proc *p = proc_current();
    sem_p(&p->mm->mmap_sem);
    if (addr && !(shmflg & SHM_REMAP)) {
        panic("do_shmat : not tested\n");
    }
    user_addr = (uint64) do_mmap(addr, size, prot, flags, file, 0);
    if (user_addr == -1) {
        panic("error\n");
    }
    sfd->user_addr = user_addr;
    *raddr = user_addr;
    err = 0;
    sem_v(&p->mm->mmap_sem);
    sem_p(&shm_ids(ns).rwsem);
    shp = shm_lock(ns, shmid);
    shp->shm_nattch--;
    if (shp->shm_nattch == 0 && (shp->shm_perm.mode & SHM_DEST))
        shm_destroy(ns, shp);
    else
        shm_unlock(shp);
    sem_v(&shm_ids(ns).rwsem);
out:
    return err;
}

static int shmctl_down(struct ipc_namespace *ns, int shmid, int cmd, struct shmid_kernel *buf) {
    struct kern_ipc_perm *ipcp;
    struct shmid_kernel shmid_kern;
    int err;
    ipcp = ipcctl_pre_down(&shm_ids(ns), shmid, cmd, &shmid_kern.shm_perm, 0);
    switch (cmd) {
        case IPC_RMID:
            do_shm_rmid(ns, ipcp);
            goto out_up;
        case IPC_SET:
            ipc_update_perm(&shmid_kern.shm_perm, ipcp);
            break;
        default:
            err = -EINVAL;
    }
out_up:
    sem_v(&shm_ids(ns).rwsem);
    return err;
}

