uint64 sys_shmctl(void) {
    int shmid;
    int cmd;
    uint64 buf_addr;
    arg_int(0, &shmid);
    arg_int(1, &cmd);
    arg_addr(2, &buf_addr);
    struct shmid_kernel buf;
    int err;
    struct ipc_namespace *ns;
    if (cmd < 0 || shmid < 0) {
        err = -EINVAL;
        goto out;
    }
    struct proc *p = proc_current();
    ns = p->ipc_ns;
    switch (cmd) { /* replace with proc interface ? */
        case IPC_INFO: {
            do_IPC_INFO();
        }
        case SHM_INFO: {
            do_SHM_INFO();
        }
        case SHM_STAT:
        case IPC_STAT: {
            do_STAT();
        }
        case SHM_LOCK:
        case SHM_UNLOCK: {
            panic("shm_lock and shm_unlock not tested\n");
        }
        case IPC_RMID:
        case IPC_SET:
            if (cmd == IPC_SET) {
                if (copy_in(p->mm->pagetable, (char *) &buf, buf_addr, sizeof(buf)) < 0) {
                    return -EFAULT;
                }
            }
            err = shmctl_down(ns, shmid, cmd, &buf);
            return err;
        default:
            return -EINVAL;
    }
out:
    return err;
}

uint64 sys_shmat(void) {
    int shmid;
