uint64 sys_nanosleep(void) {
    /* NOTE:currently, we do not support rem! */
    uint64 req;
    arg_addr(0, &req);

    struct timespec ts_buf;
    if (copy_in(proc_current()->mm->pagetable, (char *) &ts_buf, req, sizeof(ts_buf)) == -1) {
        return -1;
    }

    uint64 interval_ns = TIMESEPC2NS(ts_buf);
    uint64 time0 = TIME2NS(rdtime());

    acquire(&ticks_lock);
    while (TIME2NS(rdtime()) - time0 < interval_ns) {
        if (proc_is_killed(proc_current())) {
            release(&ticks_lock);
            return -1;
        }
        cond_wait(&cond_ticks, &ticks_lock);
    }
    release(&ticks_lock);

    return 0;
}

