void do_sleep_ns(struct tcb *t, struct timespec ts) {
    uint64 interval_ns = TIMESEPC2NS(ts);

    acquire(&cond_ticks.waiting_queue.lock);
    t->time_out = interval_ns;
    cond_wait(&cond_ticks, &cond_ticks.waiting_queue.lock);
    release(&cond_ticks.waiting_queue.lock);
    return;
}

uint64 sys_clock_nanosleep(void) {
    int clockid;
    int flags;
    uint64 request_addr;
    uint64 remain_addr;
    struct timespec request;
    arg_int(0, &clockid);
    arg_int(1, &flags);
    arg_addr(2, &request_addr);
    arg_addr(3, &remain_addr);

    if (copy_in(proc_current()->mm->pagetable, (char *) &request, request_addr, sizeof(request)) < 0)
        return -EFAULT;

    if (remain_addr) {
        struct timespec remain;
        remain.tv_sec = 0;
        remain.tv_nsec = 0;
        if (copy_out(proc_current()->mm->pagetable, remain_addr, (char *) &remain, sizeof(remain)) < 0)
            return -EFAULT;
    }
    struct tcb *t = thread_current();

    if (flags == 0) {
        do_sleep_ns(t, request);
    } else if (flags == TIMER_ABSTIME) {
        uint64 request_ns = TIMESEPC2NS(request);
        uint64 now_ns = TIME2NS(rdtime());
        if (now_ns >= request_ns) {
            return 0;
        } else {
            acquire(&cond_ticks.waiting_queue.lock);
            t->time_out = request_ns - now_ns;
            cond_wait(&cond_ticks, &cond_ticks.waiting_queue.lock);
            release(&cond_ticks.waiting_queue.lock);
        }
    }

    switch (clockid) {
        case CLOCK_MONOTONIC:
            break;
        case CLOCK_REALTIME:
            break;
        case CLOCK_TAI:
            break;
        default:
            panic("clock_nanosleep, clockid not tested\n");
            break;
    }

    return 0;
}

