uint64 sys_rt_sigaction(void) {
    int signum;
    uint64 act_addr;
    uint64 oldact_addr;
    arg_int(0, &signum);
    arg_addr(1, &act_addr);
    arg_addr(2, &oldact_addr);

    struct sigaction act;
    struct sigaction oldact;
    int ret;

    struct proc *p = proc_current();
    if (act_addr) {
        /* If act is non-NULL, the new action for signal signum is installed from act */
        if (copy_in(p->mm->pagetable, (char *) &act, act_addr, sizeof(act)) < 0) {
            return -1;
        }
    }

    ret = do_sigaction(signum, act_addr ? &act : NULL, oldact_addr ? &oldact : NULL);

    if (!ret && oldact_addr) {
        /* If oldact is non-NULL, the previous action is saved in oldact */
        if (copy_out(p->mm->pagetable, oldact_addr, (char *) &oldact, sizeof(oldact)) < 0) {
            return -1;
        }
    }

    return ret;
}

uint64 sys_rt_sigprocmask(void) {
    int how;
    uint64 set_addr;
    uint64 oldset_addr;
    size_t sigset_size;
    arg_int(0, &how);
    arg_addr(1, &set_addr);
    arg_addr(2, &oldset_addr);
    arg_ulong(3, &sigset_size);

    if (sigmask_limit == 1) {
        return 0;
    }

    sigset_t set;
    sigset_t old_set;

    int ret = 0;

    if (sigset_size != sizeof(sigset_t))
        return -1;

    /* If set is NULL, then the signal mask is unchanged (i.e., how is ignored),
       but the current value of the signal mask is nevertheless returned in oldset */
    if (set_addr) {
        if (copy_in(proc_current()->mm->pagetable, (char *) &set, set_addr, sizeof(set.sig)) < 0) {
            return -1;
        }
    }
    sig_del_set_mask(set, sig_gen_mask(SIGKILL) | sig_gen_mask(SIGSTOP));
    ret = do_sigprocmask(how, &set, &old_set);

    /* If oldset is non-NULL, the previous value of the signal mask is stored in oldset */
    if (!ret && oldset_addr) {
        if (copy_out(proc_current()->mm->pagetable, oldset_addr, (char *) &old_set, sizeof(old_set.sig)) < 0) {
            return -1;
        }
    }
    return ret;
}

uint64 sys_rt_sigreturn(void) {
    struct tcb *t = thread_current();

    signal_frame_restore(t, (struct rt_sigframe *) t->trapframe->sp);
    sig_del_set_mask(t->pending.signal, sig_gen_mask(t->sigprocessing));

    return t->trapframe->a0;
}

