    int cmd = futex_op & FUTEX_CMD_MASK;
    // ktime_t t;
    if (timeout_addr && (cmd == FUTEX_WAIT
                         // cmd == FUTEX_LOCK_PI ||
                         // cmd == FUTEX_WAIT_BITSET ||
                         // cmd == FUTEX_WAIT_REQUEUE_PI
                         )) {
        if (copy_in(p->mm->pagetable, (char *) &timeout, timeout_addr, sizeof(struct timespec)) < 0) {
