    for (; *p != NULL; p++) {
        if (strncmp(name, *p, len) == 0 && (*p)[len] == '=') {
            return &((*p)[len + 1]);
        }
    }
    return NULL;
}

int execvp(const char *file, char *const argv[]) {
    char *path = getenv("PATH");
    char buf[100];
    char *dir, *p;
    int ret;

    if (strlen(path) > 100) {
        panic("the path is too long\n");
    }
    strcpy(buf, path);
    /* 在 PATH 环境变量中查找可执行文件 */
    for (p = buf; *p != '\0'; p++) {
        dir = p;
        while (*p != ':' && *p != '\0') {
            p++;
        }
        if (*p == ':') {
            *p = '\0';
        }

        char path_buf[512];
        sprintf(path_buf, "%s/%s", dir, file);

        // printf("%s\n", path_buf);
        // for (int i = 0; environ[i]; i++) {
        //   printf("%d %s\n", i, environ[i]);
        // }
        // printf("%s");
        /* 如果找到了可执行文件，则执行该程序 */
        ret = execve(path_buf, argv, environ);
        if (ret != -1) {
            return 0;
        }
    }
    execve(file, argv, environ);

    return -1;
}

void runcmd(struct cmd *cmd) {
    int p[2];
    struct backcmd *bcmd;
    struct execcmd *ecmd;
    struct listcmd *lcmd;
    struct pipecmd *pcmd;
    struct redircmd *rcmd;

    if (cmd == 0)
        exit(1);

    switch (cmd->type) {
        default:
            panic("runcmd");

        case EXEC:
            ecmd = (struct execcmd *) cmd;
            if (ecmd->argv[0] == 0)
                exit(1);

            char cmdpath[20] = "/";
            strcat(cmdpath, ecmd->argv[0]);
            // printf("%s\n", cmdpath);
            execvp(ecmd->argv[0], ecmd->argv);
            // execve(cmdpath, ecmd->argv, NULL);
            fprintf(2, "exec %s failed\n", ecmd->argv[0]);
            break;

        case REDIR:
            rcmd = (struct redircmd *) cmd;
            close(rcmd->fd);
            if (openat(AT_FDCWD, rcmd->file, rcmd->mode) < 0) {
                fprintf(2, "openat %s failed\n", rcmd->file);
                exit(1);
            }
            runcmd(rcmd->cmd);
            break;

        case LIST:
            lcmd = (struct listcmd *) cmd;
            if (fork1() == 0)
                runcmd(lcmd->left);
            wait(0);
            runcmd(lcmd->right);
            break;

        case PIPE:
            pcmd = (struct pipecmd *) cmd;
            if (pipe(p) < 0)
                panic("pipe");
            if (fork1() == 0) {
                close(1);
                dup(p[1]);
                close(p[0]);
                close(p[1]);
                runcmd(pcmd->left);
            }
            if (fork1() == 0) {
                close(0);
                dup(p[0]);
                close(p[0]);
                close(p[1]);
                runcmd(pcmd->right);
            }
            close(p[0]);
            close(p[1]);
            wait(0);
            wait(0);
            break;

        case BACK:
            bcmd = (struct backcmd *) cmd;
            if (fork1() == 0)
                runcmd(bcmd->cmd);
            break;
    }
    exit(0);
}

