void wc(int fd, char *name) {
    int i, n;
    int l, w, c, inword;

    l = w = c = 0;
    inword = 0;
    while ((n = read(fd, buf, sizeof(buf))) > 0) {
        for (i = 0; i < n; i++) {
            c++;
            if (buf[i] == '\n')
                l++;
            if (strchr(" \r\t\n\v", buf[i]))
                inword = 0;
            else if (!inword) {
                w++;
                inword = 1;
            }
        }
    }
    if (n < 0) {
        printf("wc: read error\n");
        exit(1);
    }
    printf("%d %d %d %s\n", l, w, c, name);
}

