void signal(sig_t signo, __signalfn_t handler) {
    struct sigaction my_sig;
    my_sig.sa_handler = handler;
    printf("signal: %d, handler: %p\n", signo, handler);
    rt_sigaction(signo, &my_sig, NULL);
}

