}

int main() {
    // print_pgtable();
    printf("\n\ntesting signal\n");

    signal(10, sig_1);
    signal(20, sig_2);
    signal(25, sig_4);

    kill(getpid(), 10);
    // kill(getpid(), 20);

    // block signal 10
    sigset_t mask;
    sigset_t oldmask;
    sig_empty_set(&mask);
    sig_add_set(mask, 10);
    rt_sigprocmask(SIG_BLOCK, &mask, &oldmask, sizeof(sigset_t));

    kill(getpid(), 10);

    // unblock signal 20
    // rt_sigprocmask(SIG_SETMASK, &oldmask, NULL, sizeof(sigset_t));

    kill(getpid(), 20);

    // unblock signal 10
    rt_sigprocmask(SIG_SETMASK, &oldmask, NULL, sizeof(sigset_t));


    printf("signal test end\n");

    return 0;
}

